const SUPA_URL = 'https://tzivizoacdyopwfzerrb.supabase.co';
const SUPA_KEY = 'sb_publishable_aE4_BZYwz6bGGvby4XXAgw_k8ULnrYh';

let pwaUser = null;

// ─── Client Supabase léger (sans SDK) ───
// Les méthodes signIn / signUp / signOut / refreshAccessToken n'utilisent PAS authFetch
// (publiques ou avec auth gérée explicitement). Toutes les autres passent par authFetch
// pour bénéficier du refresh transparent du JWT.
const supa = {
  async signIn(email, password) {
    const res = await fetch(SUPA_URL + '/auth/v1/token?grant_type=password', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'apikey': SUPA_KEY },
      body: JSON.stringify({ email, password })
    });
    return res.json();
  },

  async signUp(email, password, metadata) {
    const res = await fetch(SUPA_URL + '/auth/v1/signup', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'apikey': SUPA_KEY },
      body: JSON.stringify({ email, password, data: metadata })
    });
    return res.json();
  },

  async signOut(token) {
    await fetch(SUPA_URL + '/auth/v1/logout', {
      method: 'POST',
      headers: { 'apikey': SUPA_KEY, 'Authorization': 'Bearer ' + token }
    });
  },

  async refreshAccessToken(refreshToken) {
    if (!refreshToken) return null;
    const res = await fetch(SUPA_URL + '/auth/v1/token?grant_type=refresh_token', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'apikey': SUPA_KEY },
      body: JSON.stringify({ refresh_token: refreshToken })
    });
    if (!res.ok) return null;
    return res.json(); // { access_token, refresh_token, ... } ou null si refresh expiré
  },

  async getUser() {
    const res = await authFetch(SUPA_URL + '/auth/v1/user');
    return res.json();
  },

  async getUserRecord(email) {
    const res = await authFetch(SUPA_URL + '/rest/v1/user_data?email=eq.' + encodeURIComponent(email) + '&select=*');
    if(!res.ok) return null;
    const rows = await res.json();
    return rows && rows.length > 0 ? rows[0] : null;
  },

  async loadData(table) {
    const res = await authFetch(SUPA_URL + '/rest/v1/' + table + '?select=*', {
      headers: { 'Content-Type': 'application/json' }
    });
    if(!res.ok) return [];
    return res.json();
  },

  async saveData(table, data) {
    const baseHeaders = {
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    };
    // Essayer PATCH d'abord (mise à jour de la ligne existante)
    const patch = await authFetch(SUPA_URL + '/rest/v1/' + table + '?user_id=eq.' + data.user_id, {
      method: 'PATCH',
      headers: Object.assign({}, baseHeaders, {'Prefer': 'return=representation,count=exact'}),
      body: JSON.stringify({ data: data.data, updated_at: data.updated_at })
    });
    if(patch.ok) {
      const patched = await patch.json();
      if(patched && patched.length > 0) return true; // ligne mise à jour
    }
    // Si la ligne n'existe pas encore, faire un POST (insertion)
    const post = await authFetch(SUPA_URL + '/rest/v1/' + table, {
      method: 'POST',
      headers: baseHeaders,
      body: JSON.stringify(data)
    });
    if(!post.ok) {
      const err = await post.text();
      console.error('Supabase saveData error', post.status, err);
    }
    return post.ok;
  }
};

// Wrapper fetch avec auto-refresh sur 401 PGRST303.
// Refresh une seule fois par chaîne de requête pour éviter les boucles infinies.
async function authFetch(url, options = {}, _retry = 0) {
  const session = loadPwaSession();
  if (!session.token) throw new Error('Pas de session');
  const headers = Object.assign({}, options.headers || {}, {
    'apikey': SUPA_KEY,
    'Authorization': 'Bearer ' + session.token
  });
  let res = await fetch(url, Object.assign({}, options, { headers }));
  // #85 Fix bug critique — Storage Supabase renvoie 400 « "exp" claim timestamp
  // check failed » sur token expiré (et NON 401/403), donc le retry initial ne
  // se déclenchait jamais sur les requêtes /storage/v1/*. Étendu : 400 éligible
  // UNIQUEMENT pour les endpoints Storage (400 reste un code générique côté REST
  // PostgREST pour validation, on ne veut pas le retry sur ces cas-là).
  // ⚠ Logique dupliquée dans js/auth-detect.mjs (testée par tests/auth-detect.test.mjs)
  // — si tu modifies ici, répercute aussi là-bas sinon les tests dérivent du runtime.
  const isStorageEndpoint = url.includes('/storage/v1/');
  const statusEligible =
    res.status === 401 ||
    res.status === 403 ||
    (res.status === 400 && isStorageEndpoint);
  if (statusEligible && _retry === 0) {
    // Détection élargie : Supabase renvoie 401 PGRST303 sur /rest/v1/*, 403 bad_jwt
    // sur /auth/v1/*, 400 « claim » sur /storage/v1/*. Body scan couvre les 3 cas.
    const cloned = res.clone();
    let isJwtIssue = false;
    try {
      const body = await cloned.json();
      const code = (body.code || body.error_code || body.statusCode || '').toString().toLowerCase();
      const msg = (body.message || body.msg || body.error || '').toString().toLowerCase();
      isJwtIssue = code.includes('jwt') || code === 'pgrst303' || code === 'bad_jwt' ||
                   msg.includes('jwt') || msg.includes('expired') || msg.includes('token') ||
                   msg.includes('claim');
    } catch(e) {
      // Storage 400 sans body parsable → on présume JWT-issue (one-shot _retry protège).
      if (res.status === 400 && isStorageEndpoint) isJwtIssue = true;
    }
    if (isJwtIssue) {
      const refreshed = await supa.refreshAccessToken(session.refreshToken);
      if (refreshed && refreshed.access_token) {
        // Mettre à jour la session avec le nouveau token
        savePwaSession(refreshed.access_token, refreshed.refresh_token || session.refreshToken, session.user);
        if (typeof pwaUser !== 'undefined' && pwaUser) {
          pwaUser.token = refreshed.access_token;
        }
        // Retenter la requête originale UNE FOIS avec le nouveau token
        return authFetch(url, options, 1);
      } else {
        // Refresh échoué — refresh_token aussi expiré ou révoqué. Forcer logout propre.
        console.warn('Refresh token invalide. Déconnexion forcée.');
        clearPwaSession();
        alert('Votre session a expiré. Veuillez vous reconnecter.');
        if (typeof pwaLogout === 'function') pwaLogout();
        else location.reload();
        throw new Error('Session expirée');
      }
    }
  }
  return res;
}

// #85 Phase 1 — refresh préventif de session avant les appels Storage.
// Évite la race au boot (loadBilan → prefetchSportBilanDataPhotos déclenche
// authFetch AVANT que initPWA n'ait fini de valider/rafraîchir le token).
// Pattern : décode JWT côté client → si exp < now+60s → refresh proactif.
// Hoistée volontairement via function declaration (vs const arrow) pour
// insensibilité à l'ordre dans le fichier (cf TDZ fix #85 FICHES_SYSTEMES).
//
// Anti-tempête : un seul refresh en vol à la fois. Si deux helpers Storage
// tournent en parallèle (ex. prefetchSport + prefetchPosturo), ils awaitent
// la MÊME promesse de refresh — sinon ils brûleraient deux refresh_token
// concurrents et la rotation Supabase invaliderait le 2e.
let _refreshInFlight = null;
let _sessionRefreshTimer = null;

async function ensureSession() {
  const session = loadPwaSession();
  if (!session.token) return false;
  // Décode segment middle du JWT pour lire exp. Base64URL → Base64 standard
  // (- → +, _ → /), puis padding manquant (longueur multiple de 4) avant atob.
  // Sans padding, atob throw « InvalidCharacterError » sur certains tokens.
  let expMs;
  try {
    const seg = session.token.split('.')[1] || '';
    const b64 = seg.replace(/-/g, '+').replace(/_/g, '/');
    const padded = b64 + '='.repeat((4 - (b64.length % 4)) % 4);
    const payload = JSON.parse(atob(padded));
    if (!payload || typeof payload.exp !== 'number') return true; // pas d'exp → on présume valide
    expMs = payload.exp * 1000;
  } catch (e) {
    // Décode raté → on retourne true (laisse authFetch retry-on-fail prendre le relais).
    return true;
  }
  if (expMs > Date.now() + 60_000) return true; // valide encore > 60 s
  // Refresh préventif. Dé-dup via _refreshInFlight (anti-tempête concurrents).
  if (_refreshInFlight) {
    return _refreshInFlight;
  }
  _refreshInFlight = (async () => {
    try {
      const r = await supa.refreshAccessToken(session.refreshToken);
      if (!r || !r.access_token) return false;
      savePwaSession(r.access_token, r.refresh_token || session.refreshToken, session.user);
      if (typeof pwaUser !== 'undefined' && pwaUser) pwaUser.token = r.access_token;
      return true;
    } catch (e) {
      console.warn('[#85] ensureSession refresh fail :', e);
      return false;
    } finally {
      _refreshInFlight = null;
    }
  })();
  return _refreshInFlight;
}

// ─── Session persistante ───
function savePwaSession(token, refreshToken, user) {
  try {
    sessionStorage.setItem('bm_token', token);
    sessionStorage.setItem('bm_refresh', refreshToken || '');
    sessionStorage.setItem('bm_user', JSON.stringify(user));
  } catch(e) {}
}

function loadPwaSession() {
  try {
    const token = sessionStorage.getItem('bm_token');
    const refreshToken = sessionStorage.getItem('bm_refresh') || null;
    const user = JSON.parse(sessionStorage.getItem('bm_user') || 'null');
    return { token, refreshToken, user };
  } catch(e) { return { token: null, refreshToken: null, user: null }; }
}

function clearPwaSession() {
  try {
    sessionStorage.removeItem('bm_token');
    sessionStorage.removeItem('bm_refresh');
    sessionStorage.removeItem('bm_user');
  } catch(e) {}
  // #85 Fix D — stop le refresh préventif (sinon il continue après déconnexion).
  if (_sessionRefreshTimer) { clearInterval(_sessionRefreshTimer); _sessionRefreshTimer = null; }
}

// ─── Mot de passe oublié ───
// Affiche un prompt pour saisir l'email et envoie un lien de réinitialisation Supabase.
async function showForgotPassword() {
  const email = prompt('Entrez votre adresse email pour recevoir un lien de réinitialisation :');
  if (!email || !email.trim()) return;
  const trimmedEmail = email.trim();
  if (!trimmedEmail.includes('@')) {
    alert('Adresse email invalide.');
    return;
  }
  try {
    const res = await fetch(SUPA_URL + '/auth/v1/recover', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'apikey': SUPA_KEY },
      body: JSON.stringify({ email: trimmedEmail })
    });
    if (res.ok) {
      alert('✓ Si un compte est associé à ' + trimmedEmail + ', vous recevrez sous peu un email avec un lien pour réinitialiser votre mot de passe.\n\nVérifiez aussi vos spams.');
    } else {
      const err = await res.json().catch(() => ({}));
      console.error('Reset password error:', err);
      alert('Erreur lors de l\'envoi du lien. Veuillez réessayer ou contacter le support.');
    }
  } catch(e) {
    console.error('Reset password network error:', e);
    alert('Erreur réseau. Vérifiez votre connexion et réessayez.');
  }
}

// ─── Recovery flow (lien email reset password) ───
// Détecte hash #access_token=...&type=recovery dans l'URL au load, stocke le token
// global pour submitNewPassword, affiche le modal reset et nettoie l'URL.
function handleRecoveryToken() {
  var hash = window.location.hash || '';
  if (!hash || hash.indexOf('access_token=') === -1) return false;
  var params = new URLSearchParams(hash.substring(1)); // strip leading '#'
  var type = params.get('type');
  if (type !== 'recovery') return false;
  var token = params.get('access_token');
  if (!token) return false;
  _recoveryToken = token;
  // Cleanup URL (retire le hash pour ne pas re-trigger au refresh)
  window.history.replaceState({}, '', window.location.pathname);
  // Affiche modal reset, masque login form
  var loginForm = document.getElementById('pwa-login-form');
  var resetForm = document.getElementById('pwa-reset-password-form');
  if (loginForm) loginForm.style.display = 'none';
  if (resetForm) resetForm.style.display = 'block';
  return true;
}

// Soumet le nouveau mot de passe via PUT /auth/v1/user (Bearer = _recoveryToken).
// Validations client : non-vide, longueur ≥ 8, pwd === confirm.
async function submitNewPassword() {
  const newPwd = document.getElementById('reset-pwd-new').value;
  const confirmPwd = document.getElementById('reset-pwd-confirm').value;
  const errEl = document.getElementById('reset-pwd-err');
  const okEl = document.getElementById('reset-pwd-ok');
  const btn = document.getElementById('reset-pwd-btn');
  // Reset feedback zones
  if (errEl) { errEl.style.display = 'none'; errEl.textContent = ''; }
  if (okEl) { okEl.style.display = 'none'; okEl.textContent = ''; }
  // Validations client
  if (!newPwd || !confirmPwd) {
    if (errEl) { errEl.textContent = 'Veuillez remplir les deux champs.'; errEl.style.display = 'block'; }
    return;
  }
  if (newPwd.length < 8) {
    if (errEl) { errEl.textContent = 'Le mot de passe doit contenir au moins 8 caractères.'; errEl.style.display = 'block'; }
    return;
  }
  if (newPwd !== confirmPwd) {
    if (errEl) { errEl.textContent = 'Les deux mots de passe ne correspondent pas.'; errEl.style.display = 'block'; }
    return;
  }
  if (!_recoveryToken) {
    if (errEl) { errEl.textContent = 'Lien de récupération expiré ou invalide. Veuillez redemander un email de réinitialisation.'; errEl.style.display = 'block'; }
    return;
  }
  if (btn) { btn.disabled = true; btn.textContent = 'Mise à jour…'; }
  try {
    const res = await fetch(SUPA_URL + '/auth/v1/user', {
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json',
        'apikey': SUPA_KEY,
        'Authorization': 'Bearer ' + _recoveryToken
      },
      body: JSON.stringify({ password: newPwd })
    });
    if (res.ok) {
      _recoveryToken = null;
      if (okEl) { okEl.textContent = '✓ Mot de passe mis à jour. Redirection…'; okEl.style.display = 'block'; }
      setTimeout(function() { window.location.href = './'; }, 2000);
    } else {
      const err = await res.json().catch(() => ({}));
      console.error('Update password error:', err);
      if (btn) { btn.disabled = false; btn.textContent = 'Mettre à jour le mot de passe'; }
      if (errEl) { errEl.textContent = 'Erreur lors de la mise à jour. Le lien a peut-être expiré.'; errEl.style.display = 'block'; }
    }
  } catch(e) {
    console.error('Update password network error:', e);
    if (btn) { btn.disabled = false; btn.textContent = 'Mettre à jour le mot de passe'; }
    if (errEl) { errEl.textContent = 'Erreur réseau. Vérifiez votre connexion et réessayez.'; errEl.style.display = 'block'; }
  }
}

// ─── Login ───
async function pwaLogin() {
  const email = document.getElementById('pwa-email').value.trim();
  const pwd = document.getElementById('pwa-pwd').value;
  const errEl = document.getElementById('pwa-login-err');
  const btn = document.getElementById('pwa-login-btn');
  errEl.style.display = 'none';

  if(!email || !pwd) {
    errEl.textContent = 'Veuillez remplir tous les champs.';
    errEl.style.display = 'block'; return;
  }

  btn.disabled = true; btn.textContent = 'Connexion...';

  try {
    const data = await supa.signIn(email, pwd);
    if(data.access_token) {
      const isAdmin = email.toLowerCase() === 'sciopraxi@gmail.com';
      pwaUser = { email, token: data.access_token, id: data.user?.id, isAdmin, user_metadata: data.user?.user_metadata || {} };
      savePwaSession(data.access_token, data.refresh_token, pwaUser);
      await onPwaLoginSuccess();
    } else {
      errEl.textContent = data.error_description || data.msg || 'Email ou mot de passe incorrect.';
      errEl.style.display = 'block';
      btn.disabled = false; btn.textContent = 'Se connecter';
    }
  } catch(e) {
    errEl.textContent = 'Erreur de connexion. Vérifiez votre connexion internet.';
    errEl.style.display = 'block';
    btn.disabled = false; btn.textContent = 'Se connecter';
  }
}

// ─── Fetch user_data au login (task #57) ───────────────────────────
// L'app a 2 stores découplés : auth.users.user_metadata (acces, trial_start,
// modules, nom, prenom) ET la table user_data (licence_payee, formule,
// engagement, date_debut_abonnement, stripe_customer_id). Pas de trigger DB
// qui synchronise. checkAccessStatus a besoin des 2, donc on fetch user_data
// une fois au login et on stash dans pwaUser.user_data.
//
// Trois états distincts de pwaUser.user_data (cf. Q2 commit 3) :
//   - undefined : fetch jamais lancé (1re frame, transitoire) → 'loading'
//   - null      : fetch lancé et échoué → 'blocked' (fail-secure)
//   - {...}     : fetch OK → matrice normale
async function fetchUserDataAtLogin() {
  if (!pwaUser?.email) {
    pwaUser && (pwaUser.user_data = null);
    return;
  }
  try {
    const row = await supa.getUserRecord(pwaUser.email);
    // getUserRecord retourne null si pas de row, ou l'objet user_data.
    // Pour la matrice : pas de row = utilisateur sans entrée payante = équivalent
    // à licence_payee=false + formule=null. On stocke un objet vide pour bien
    // distinguer du fetch échoué (null).
    pwaUser.user_data = row || {};
  } catch (e) {
    console.error('[access] fetchUserDataAtLogin failed:', e);
    pwaUser.user_data = null;
  }
}

// ─── Après login réussi ───
async function onPwaLoginSuccess() {
  // Reset guard data race (task #64) — si l'user fait logout puis re-login
  // rapidement, _dataLoaded pourrait être relicat true de la session précédente.
  _dataLoaded = false;
  // #85 Fix D — refresh préventif périodique (50 min, sous la durée standard
  // d'1h de l'access_token Supabase). clearInterval dans pwaLogout/clearPwaSession.
  if (_sessionRefreshTimer) clearInterval(_sessionRefreshTimer);
  _sessionRefreshTimer = setInterval(ensureSession, 50 * 60 * 1000);
  document.getElementById('pwa-login').style.display = 'none';
  document.getElementById('biomeca-app').style.display = '';
  showAdminPanelIfNeeded();
  nav('pg-patients');

  // Afficher onglet Paramètres si admin
  const paramsBtn = document.getElementById('tn-params');
  if(paramsBtn) paramsBtn.style.display = pwaUser?.isAdmin ? '' : 'none';

  // Afficher nom dans la topbar
  const tbName = document.getElementById('tb-name');
  if(tbName && !patients.length) tbName.textContent = 'Aucun patient';

  // Recharger user_metadata frais depuis Supabase
  try {
    const freshUser = await supa.getUser();
    if(freshUser?.user_metadata) {
      pwaUser.user_metadata = freshUser.user_metadata;
    }
  } catch(e) {}
  // Fetch user_data (licence_payee, formule, etc.) pour gating d'accès task #57.
  // Doit s'exécuter AVANT checkAccessStatus pour qu'il ait les 2 stores en mémoire.
  await fetchUserDataAtLogin();
  // Compute access level et mute le DOM (bandeau + overlay). Plus de setTimeout
  // 500ms : les awaits ci-dessus garantissent que pwaUser est complet.
  checkAccessStatus();
  // Charger les données depuis Supabase
  await loadSupabaseData();
}

// ─── Chargement des données ───
async function loadSupabaseData() {
  if(!pwaUser?.token) return;

  try {
    // Charger patients depuis Supabase (table user_data)
    const rows = await supa.loadData('user_data');
    const myRow = rows.find(r => r.user_id === pwaUser.id);
    if(myRow && myRow.data) {
      const d = typeof myRow.data === 'string' ? JSON.parse(myRow.data) : myRow.data;
      patients = d.patients || [];
      praticiens = d.praticiens || [];
      _dataLoaded = true;  // Task #64 — patients global est peuplé, saveToSupabase peut écrire
      _loadedFromFallback = false; // #114-1a — mémoire vient du cloud confirmé.
      // Appliquer les modules depuis user_metadata Supabase (fraîches, task #58).
      // Refonte enum droits → array modules : la source de vérité est désormais
      // user_metadata.modules (array de 'postural'|'podopedia'|'podo_sport').
      // Fallback [] si absent (cas legacy avant migration A0, ou flow landing
      // public pré-task #63 où user_metadata n'est pas encore initialisé).
      try {
        const freshUser = await supa.getUser();
        const freshMeta = freshUser?.user_metadata || {};
        pwaUser.user_metadata = freshMeta;
        window._userModules = Array.isArray(freshMeta.modules) ? freshMeta.modules : [];
      } catch(e) {
        window._userModules = Array.isArray(pwaUser?.user_metadata?.modules) ? pwaUser.user_metadata.modules : [];
      }
    } else {
      patients = [];
      praticiens = [];
      _dataLoaded = true;  // Task #64 — nouvel user légitimement vide, saves autorisés
      _loadedFromFallback = false; // #114-1a — pas de cloud row mais Supabase atteint.
    }
    // Migration : anciens bilans (p.bilans[]) → p.bilansSport[]
    let migrated = false;
    patients.forEach(p => {
      if(p.bilans && p.bilans.length > 0 && !p.bilansSport) {
        p.bilansSport = p.bilans.map((b,i) => ({
          label: b.label || ('Sportif Contrôle ' + (i+1)),
          type: i===0 ? 'initial' : 'controle',
          date: b.date || '',
          mesures: b.mesures || {},
          bilanData: b.bilanData || {}
        }));
        migrated = true;
      }
      // Migrer bilan initial (p.mesures) s'il existe et pas encore dans bilansSport.
      // Fix doublon bilan sport — GARDE-FOU : && !p.currentBilanSportSousType.
      // Cette migration legacy ne cible que des p.mesures orphelins (schema
      // pré-bilansSport, sans flag de cycle de vie). Si l'utilisateur a un
      // bilan en cours actif (currentBilanSportSousType set), c'est le flow
      // moderne creer/finalize qui gère l'archivage — la migration ne doit
      // PAS injecter un phantom initial qui sera dupliqué par finalize.
      // Sans ce garde, le `_bilanId` lazy-créé par saveBilanSilent rend
      // `Object.keys(p.mesures).length > 0` truthy dès la 1re saisie clinique,
      // déclenchant la migration au prochain reload PWA → doublon « Sportif
      // Initial » après Finaliser.
      if(p.mesures && Object.keys(p.mesures).length > 0 && !p.currentBilanSportSousType) {
        if(!p.bilansSport) p.bilansSport = [];
        const hasInitial = p.bilansSport.some(b => b.type === 'initial');
        if(!hasInitial) {
          p.bilansSport.unshift({
            label: 'Sportif Initial',
            type: 'initial',
            date: p.bilanInitialDate || '',
            mesures: JSON.parse(JSON.stringify(p.mesures)),
            bilanData: JSON.parse(JSON.stringify(p.bilanData||{}))
          });
          migrated = true;
        }
      }
      // hotfix — CLEANUP one-shot retiré : avait supprimé une vraie entrée
      // de bilan en prod (l'heuristique date-vide + dernière-occurrence ne
      // distinguait pas fiablement un phantom de migration d'une entrée
      // finalisée légitime). La déduplication sera ré-implémentée plus tard
      // avec sauvegarde préalable et validation explicite. Le garde-fou
      // !p.currentBilanSportSousType ci-dessus prévient toute NOUVELLE
      // création de phantom — c'est suffisant pour stopper la régression.
    });
    // Migration #39 (29 avril 2026) : currentBilanType + currentBilanSousType
    // → currentBilanSportSousType / currentBilanPosturoSousType (indépendants).
    const flagsMigrated = migrateBilanFlags(patients);
    if(migrated || flagsMigrated) { console.log('Migration bilans OK'); savePatients(); }
  } catch(e) {
    // Fallback localStorage si Supabase indisponible.
    // #65 — clé localStorage unifiée sur bm4-patients/bm4-praticiens : le
    // fallback lit désormais la même clé que savePatients écrit (avant : -pwa,
    // écrite seulement sur échec Supabase → périmée → écrasait la bonne
    // version au reload hors-ligne).
    patients = JSON.parse(localStorage.getItem('bm4-patients') || '[]');
    praticiens = JSON.parse(localStorage.getItem('bm4-praticiens') || '[]');
    // Migration #39 sur le fallback aussi
    if (migrateBilanFlags(patients)) {
      try { localStorage.setItem('bm4-patients', JSON.stringify(patients)); } catch(_) {}
    }
    _dataLoaded = true;  // Task #64 — fallback considéré comme valide, saves autorisés
    _loadedFromFallback = true; // #114-1a — mémoire issue du cache local non confirmée.
  }

  currentPatient = null; bilanData = {};
  renderPatientList();
  renderPratList();
  populatePratSelect();
  if(patients.length > 0) selectPatient(patients[patients.length - 1]);
}

// ─── Sauvegarde vers Supabase ───
async function saveToSupabase() {
  if(!pwaUser?.token) return;
  // Guard data race (task #64) : tant que loadSupabaseData n'a pas peuplé les
  // globales patients/praticiens, on REFUSE le POST en DB pour ne pas écraser
  // user_data.data avec un état incohérent (patients=[] en RAM avant fetch).
  // Le localStorage reste mis à jour par savePatients() upstream — donc rien
  // n'est perdu en RAM, le prochain save (post-load) propagera bien en DB.
  if(!_dataLoaded) {
    console.warn('[#64] saveToSupabase() called before loadSupabaseData completed — SKIP to prevent data loss', {
      email: pwaUser?.email,
      patientsCount: patients.length,
      praticiensCount: praticiens.length,
    });
    return;
  }
  // #114-1a — Reconcile fallback : si la mémoire vient du cache local non
  // confirmé (catch de loadSupabaseData → cloud injoignable au boot), on
  // re-tente une lecture cloud AVANT d'écrire. Si le cloud est plus riche
  // (count d'unités > mémoire), refuse d'écraser et propose un reload pour
  // récupérer la version cloud. Sinon → flag levé, save normal poursuit.
  // Si cloud toujours injoignable au reconcile, on ne bloque PAS (l'utilisateur
  // doit pouvoir continuer à travailler hors-ligne ; le save écrira au moins
  // le localStorage canonique via #65).
  if (_loadedFromFallback) {
    try {
      const rows = await supa.loadData('user_data');
      const myRow = rows.find(r => r.user_id === pwaUser.id);
      const cloud = myRow?.data ? (typeof myRow.data === 'string' ? JSON.parse(myRow.data) : myRow.data) : null;
      if (cloud && Array.isArray(cloud.patients)) {
        const cloudUnits = _countDataUnits(cloud.patients);
        const memUnits   = _countDataUnits(patients);
        if (cloudUnits > memUnits) {
          const reload = confirm(
            '⚠️ Le serveur contient une version PLUS complète de vos données que celle ' +
            'chargée au démarrage (probablement à cause d\'une coupure réseau).\n\n' +
            'Pour éviter d\'écraser des données, la sauvegarde a été suspendue.\n\n' +
            'Recharger maintenant pour récupérer la version du serveur ?'
          );
          if (reload) location.reload();
          return; // NE PAS écraser le cloud
        }
      }
      _loadedFromFallback = false; // cloud confirmé non plus riche → sûr pour la suite.
    } catch (e) {
      console.warn('[#114-1a] reconcile cloud injoignable, save local poursuivi :', e?.message);
    }
  }
  const data = { patients, praticiens };
  // Task #38 — message banner uniforme entre les 2 paths fail.
  const SYNC_FAIL_MSG = '⚠️ Synchronisation cloud échouée. Vos données sont sauvegardées localement et seront resynchronisées au prochain enregistrement.';
  try {
    const ok = await supa.saveData('user_data', {
      user_id: pwaUser.id,
      data: data,
      updated_at: new Date().toISOString()
    });
    if(!ok) {
      // Path !ok (response API non OK) — task #38.
      // #65 — clé unifiée bm4-patients/bm4-praticiens (cf fallback ci-dessus).
      localStorage.setItem('bm4-patients', JSON.stringify(patients));
      localStorage.setItem('bm4-praticiens', JSON.stringify(praticiens));
      console.error('[#38] saveToSupabase failed', {
        event: 'sync_failed_response_not_ok',
        email: pwaUser?.email,
        patientsCount: patients.length,
        praticiensCount: praticiens.length,
        timestamp: new Date().toISOString(),
      });
      _showSyncErrorBanner(SYNC_FAIL_MSG);
      _syncErrorShown = true;
      // Hook Sentry défensif (V2 — actif quand Sentry intégré). Voir task #69.
      if (typeof Sentry !== 'undefined' && Sentry?.captureMessage) {
        Sentry.captureMessage('saveToSupabase: response not ok', { level: 'error', tags: { event: 'sync_failed_response_not_ok' } });
      }
    } else if (_syncErrorShown) {
      // Path success post-fail : recovery détectée → hide banner + log structuré.
      _hideSyncErrorBanner();
      console.log('[#38] saveToSupabase recovered', {
        event: 'sync_recovered',
        email: pwaUser?.email,
        timestamp: new Date().toISOString(),
      });
    }
  } catch(e) {
    // Path exception (réseau, RLS, etc.) — task #38.
    // #65 — clé unifiée bm4-patients/bm4-praticiens (cf fallback ci-dessus).
    localStorage.setItem('bm4-patients', JSON.stringify(patients));
    localStorage.setItem('bm4-praticiens', JSON.stringify(praticiens));
    console.error('[#38] saveToSupabase exception', {
      event: 'sync_failed_exception',
      email: pwaUser?.email,
      patientsCount: patients.length,
      praticiensCount: praticiens.length,
      error: e instanceof Error ? e.message : String(e),
      timestamp: new Date().toISOString(),
    });
    _showSyncErrorBanner(SYNC_FAIL_MSG);
    _syncErrorShown = true;
    if (typeof Sentry !== 'undefined' && Sentry?.captureException) {
      Sentry.captureException(e, { tags: { event: 'sync_failed_exception' } });
    }
  }
}

// ─── Déconnexion ───
// ─── Admin: gestion utilisateurs ───
async function adminCreateUser() {
  const email = document.getElementById('admin-email').value.trim();
  const pwd = document.getElementById('admin-pwd').value.trim();
  const nom = document.getElementById('admin-nom').value.trim();
  const prenom = document.getElementById('admin-prenom').value.trim();
  const acces = document.getElementById('admin-acces').value;
  const errEl = document.getElementById('admin-create-err');
  const okEl = document.getElementById('admin-create-ok');
  const btn = document.getElementById('admin-create-btn');
  errEl.style.display = 'none'; okEl.style.display = 'none';
  if(!email || !pwd) { errEl.textContent = 'Email et mot de passe requis.'; errEl.style.display = 'block'; return; }
  if(pwd.length < 8) { errEl.textContent = 'Mot de passe trop court (min. 8 caractères).'; errEl.style.display = 'block'; return; }
  btn.disabled = true; btn.textContent = 'Création...';
  try {
    const data = await supa.signUp(email, pwd, { nom, prenom, acces });
    if(data.id || data.user?.id) {
      okEl.textContent = `✓ Accès créé pour ${email} (${acces}). Un email de confirmation a été envoyé.`;
      okEl.style.display = 'block';
      document.getElementById('admin-email').value = '';
      document.getElementById('admin-pwd').value = '';
      document.getElementById('admin-nom').value = '';
      document.getElementById('admin-prenom').value = '';
      // Rafraîchir la liste des utilisateurs autorisés
      setTimeout(() => renderParamsPratList(), 1000);
    } else {
      errEl.textContent = data.msg || data.error_description || 'Erreur lors de la création.';
      errEl.style.display = 'block';
    }
  } catch(e) {
    errEl.textContent = 'Erreur réseau.';
    errEl.style.display = 'block';
  }
  btn.disabled = false; btn.textContent = "Créer l'accès";
}


