// tryStartTrial — déclenche l'Edge Function start-trial (task #57).
//
// Gère explicitement les 4 cas de retour (cf. Q3) :
//   - 200 OK                    : refresh pwaUser.user_metadata local depuis
//                                 la réponse, retourne { ok:true }. Caller recall
//                                 checkAccessStatus pour calculer le nouveau niveau.
//   - 409 trial_already_started : race condition serveur (autre tab a démarré).
//                                 Re-fetch supa.getUser() pour synchroniser,
//                                 retourne { ok:true }. Caller recall.
//   - 409 acces_already_set     : un admin a set acces entretemps. Même
//                                 traitement que ci-dessus (re-fetch + recall).
//   - 401 / 500 / erreur réseau : retourne { ok:false }. Caller set
//                                 _accessLevel='blocked' (fail-secure).
async function tryStartTrial() {
  try {
    const res = await authFetch(SUPA_URL + '/functions/v1/start-trial', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: '{}',
    });
    if (res.status === 200) {
      const data = await res.json();
      if (data && data.ok && data.trial_start && pwaUser) {
        pwaUser.user_metadata = pwaUser.user_metadata || {};
        pwaUser.user_metadata.trial_start = data.trial_start;
        pwaUser.user_metadata.acces = 'essai';
      }
      return { ok: true };
    }
    if (res.status === 409) {
      // Race : trial_already_started ou acces_already_set. Re-fetch pour sync.
      try {
        const fresh = await supa.getUser();
        if (fresh && fresh.user_metadata && pwaUser) {
          pwaUser.user_metadata = fresh.user_metadata;
        }
      } catch (e) {
        console.warn('[access] re-fetch user post-409 failed:', e);
      }
      return { ok: true };
    }
    const errText = await res.text().catch(() => '');
    console.error('[access] start-trial failed:', res.status, errText);
    return { ok: false };
  } catch (e) {
    console.error('[access] start-trial network error:', e);
    return { ok: false };
  }
}

// computeAccessLevel — fonction pure, testable en unitaire (task #57).
//
// Matrice 3-niveaux (cf. spec PR E1+E2) :
//   - 'full'     : isAdmin OU (licence_payee=true AND formule≠null)
//                  OU essai en cours (trial_start ≤ 14j)
//   - 'readonly' : licence_payee=true AND formule=null AND essai expiré/inexistant
//   - 'blocked'  : licence_payee=false AND pas d'essai actif
//
// États transitoires :
//   - userData === undefined → 'loading' (fetch jamais lancé)
//   - userData === null      → 'blocked' (fetch échoué, fail-secure)
//
// État illégitime : licence_payee=false AND formule≠null. Ne peut résulter
// que d'une incohérence DB (cf. Q1 — décision défensive "blocked" + log).
//
// `meta`     : object pwaUser.user_metadata ({ acces, trial_start, ... })
// `userData` : object | null | undefined (pwaUser.user_data)
// `isAdmin`  : bool (extrait de pwaUser.isAdmin)
// `now`      : timestamp ms (Date.now() par défaut, injectable pour tests)
//
// Note pureté : la fonction lit `pwaUser.email` global UNIQUEMENT pour le
// diagnostic console.error (état illégitime). Aucune lecture de pwaUser
// n'influence la valeur de retour — les tests Vitest peuvent donc l'appeler
// sans mocker le global, le log apparaîtra juste sans email enrichi.
//
// Note duplication : la même fonction est ré-exportée depuis js/access.mjs
// pour les tests Vitest (pattern identique à js/calc.mjs). Si tu modifies
// ici, répercute aussi dans access.mjs sinon les tests dérivent du runtime.
function computeAccessLevel({ isAdmin, meta, userData }, now) {
  if (isAdmin) return 'full';
  if (userData === undefined) return 'loading';
  if (userData === null) return 'blocked';

  const licence = userData.licence_payee === true;
  const formule = userData.formule;
  const trialStart = meta && meta.trial_start;
  const nowMs = typeof now === 'number' ? now : Date.now();

  // État illégitime : formule sans licence. Log + blocked défensif (cf. Q1).
  if (!licence && formule) {
    console.error('[access] Illegitimate state detected: formule set without licence', {
      email: pwaUser && pwaUser.email,
      formule,
    });
    return 'blocked';
  }

  // Essai actif : 14 jours à partir de trial_start.
  let trialActive = false;
  if (trialStart) {
    const elapsedDays = (nowMs - new Date(trialStart).getTime()) / 86400000;
    trialActive = elapsedDays >= 0 && elapsedDays <= 14;
  }

  // Niveau 1 : full
  if (licence && formule) return 'full';
  if (trialActive) return 'full';
  // Niveau 2 : readonly (licence à vie sans abonnement actif)
  if (licence && !formule) return 'readonly';
  // Niveau 3 : blocked (défaut)
  return 'blocked';
}

// checkAccessStatus — gating 3-niveaux avec auto-trial (task #57).
//
// Calcule window._accessLevel à partir de pwaUser.user_metadata + pwaUser.user_data,
// puis mute le DOM (#trial-banner + #trial-expired-overlay) selon le résultat.
//
// CAVEAT — refresh nécessaire après actions admin : ne re-fetch PAS automatiquement
// les sources si elles changent côté serveur. Si un admin modifie licence_payee
// ou formule via admin-users après le login d'un user, ce user gardera son niveau
// d'accès calculé au login jusqu'à un page reload manuel. Cohérent avec le
// comportement existant de loadAbonnementInfo (qui ne fetch que sur ouverture du
// modal Mon compte). Un refresh proactif (websocket / polling / event-driven)
// serait une PR séparée.
//
// Auto-trial : si l'utilisateur tomberait en 'blocked' uniquement parce qu'il n'a
// jamais payé ET n'a jamais démarré son essai (4 conditions : !licence && !formule
// && !trial_start && !acces), on dispatch start-trial en fire-and-forget puis on
// se rappelle pour calculer le nouveau niveau (pattern Q3).
//
// Renommé depuis l'ancien checkTrialStatus — la sémantique est plus large
// maintenant (gating 3-niveaux, pas juste countdown d'essai).
function checkAccessStatus() {
  // Bypass admin total — pas de loading, pas de fetch nécessaire, DOM neutre.
  if (pwaUser?.isAdmin) {
    window._accessLevel = 'full';
    _hideAccessBanner();
    _hideAccessOverlay();
    applyReadOnlyUI(window._accessLevel);
    return;
  }

  const meta = pwaUser?.user_metadata || {};
  const userData = pwaUser?.user_data;
  const level = computeAccessLevel({ isAdmin: false, meta, userData }, Date.now());

  // Auto-trial dispatch : 'blocked' + 4 conditions vides → on tente le démarrage.
  // Pendant l'attente, état 'loading' (DOM neutre, pas de bandeau ni overlay).
  // applyReadOnlyUI n'est PAS appelée pendant le dispatch : courte fenêtre (~100-300ms),
  // la défense en profondeur (early-returns + showAccessRestrictedModal dans les fonctions
  // cibles) protège quand même contre un click légitime trop rapide.
  if (level === 'blocked' && userData && typeof userData === 'object'
      && !userData.licence_payee && !userData.formule
      && !meta.trial_start && !meta.acces) {
    window._accessLevel = 'loading';
    _hideAccessBanner();
    _hideAccessOverlay();
    tryStartTrial().then(r => {
      if (!r.ok) {
        // Fail-secure : start-trial a échoué (réseau/500/401). On reste blocked.
        window._accessLevel = 'blocked';
        _showAccessOverlay({ cause: 'never_paid' });
        applyReadOnlyUI('blocked');
      } else {
        // Succès (200) ou race 409 : pwaUser.user_metadata est à jour, on recalcule.
        // Le recall propagera applyReadOnlyUI proprement, pas besoin de le call ici.
        checkAccessStatus();
      }
    });
    return;
  }

  // Dispatch normal selon level
  window._accessLevel = level;

  if (level === 'loading') {
    // État transitoire (userData encore undefined, ne devrait pas arriver post-login
    // mais filet de sécurité). DOM neutre.
    _hideAccessBanner();
    _hideAccessOverlay();
    applyReadOnlyUI(window._accessLevel);
    return;
  }

  if (level === 'full') {
    _hideAccessOverlay();
    // Si l'essai est actif (trial_start ≤ 14j), on affiche le countdown — UX
    // existante préservée (l'utilisateur sait combien il lui reste).
    if (meta.trial_start) {
      const elapsedDays = (Date.now() - new Date(meta.trial_start).getTime()) / 86400000;
      const remaining = 14 - Math.floor(elapsedDays);
      if (remaining > 0 && remaining <= 14) {
        _showAccessBanner({
          text: remaining === 1 ? "Dernier jour d'essai !" : 'Essai gratuit — ' + remaining + ' jours restants',
          background: remaining <= 3 ? '#e74c3c' : '',
        });
        applyReadOnlyUI(window._accessLevel);
        return;
      }
    }
    _hideAccessBanner();
    applyReadOnlyUI(window._accessLevel);
    return;
  }

  if (level === 'readonly') {
    _hideAccessOverlay();
    _showAccessBanner({
      text: "Votre abonnement est suspendu. Vos patients et bilans restent consultables. Reprenez votre abonnement pour créer de nouveaux bilans et exporter en PDF.",
      background: '#e67e22',
    });
    applyReadOnlyUI(window._accessLevel);
    return;
  }

  if (level === 'blocked') {
    _hideAccessBanner();
    // Cause : essai expiré (trial_start présent) vs jamais payé (cas fallback rare
    // — l'auto-trial gère normalement ce cas en amont, sauf si conditions auto-trial
    // pas réunies ex. user créé manuellement par admin sans acces ni licence).
    const cause = meta.trial_start ? 'trial_expired' : 'never_paid';
    _showAccessOverlay({ cause });
    applyReadOnlyUI(window._accessLevel);
    return;
  }
}

// ─── canChangeModule — DUPLIQUÉ de js/subscription.mjs ──────────────
// Test-mirror : la source testée par Vitest est js/subscription.mjs.
// Toute modif ici DOIT être répercutée là-bas ET dans
// supabase/functions/prepare-module-change/index.ts (canChangeModuleServer).
// Référence task #58.
//
// Args :
//   userData : { date_debut_abonnement: string | null, last_module_change: string | null }
//   now      : Date (injectable pour tests déterministes)
//
// Retourne null si OK (autorisé), sinon { reason, next_change_date? }.
// Logique : grace period 7j post-souscription initiale + lock 30j entre changements.
// Le caller (subscribePaymentLink, C3) n'appelle canChangeModule QUE si modules
// changent ET plan inchangé (cf. Q3 task #58).
// ────────────────────────────────────────────────────────────────────
function canChangeModule(userData, now) {
  // Première souscription : pas de date_debut → toujours OK.
  if (!userData.date_debut_abonnement) return null;

  const debut = new Date(userData.date_debut_abonnement).getTime();
  const nowMs = now.getTime();
  const sevenDaysMs = 7 * 86400 * 1000;
  // Grace period 7j post-souscription initiale : changement libre.
  if (nowMs - debut <= sevenDaysMs) return null;

  // Hors grace period : jamais changé → OK.
  if (!userData.last_module_change) return null;

  const lastChange = new Date(userData.last_module_change).getTime();
  const thirtyDaysMs = 30 * 86400 * 1000;
  if (nowMs - lastChange >= thirtyDaysMs) return null;

  // Lock actif : calcule la prochaine date possible.
  return {
    reason: 'locked',
    next_change_date: new Date(lastChange + thirtyDaysMs).toISOString(),
  };
}

// applyReadOnlyUI — applique le gating visuel sur les 6 boutons cibles (task #57).
// level : 'full' | 'readonly' | 'blocked' | 'loading'.
//
// IMPORTANT — DOM dynamique : applyReadOnlyUI doit être appelée à plusieurs
// endroits car certains boutons sont re-créés dynamiquement par innerHTML :
//   1. checkAccessStatus() (en fin de chaque branche)
//   2. renderPatientList() (re-création des boutons "Nouveau bilan Sport/Posturo"
//      à chaque modif patient)
// Si d'autres render functions sont ajoutées plus tard qui régénèrent des boutons
// cibles, hooker applyReadOnlyUI() à leur fin également.
//
// Cibles (6) :
//   - "+ Nouveau patient" (index.html statique, onclick=openNewPatientModal)
//   - Boutons "Initial/Contrôle" bilan sport (dynamiques, onclick=creerBilanSport)
//   - Boutons "Initial/Contrôle" bilan posturo (dynamiques, onclick=creerBilanPosturo)
//   - "Imprimer / PDF" rapport posturo (index.html statique, onclick=printRapportPosturo)
//   - "Imprimer / PDF" rapport sport (index.html statique, onclick=printReport)
//   - "Imprimer" bilan clinique (index.html statique, onclick=printBilan)
//
// La sélection par attribut onclick fonctionne pour le HTML statique ET le HTML
// rendu dynamiquement par innerHTML (l'attribut onclick est inline dans les deux cas).
function applyReadOnlyUI(level) {
  const blocked = level === 'readonly' || level === 'blocked';
  const selectors = [
    '[onclick*="openNewPatientModal"]',
    '[onclick*="creerBilanSport"]',
    '[onclick*="creerBilanPosturo"]',
    '[onclick*="printRapportPosturo"]',
    '[onclick*="printReport"]',
    '[onclick*="printBilan"]',
  ];
  const buttons = document.querySelectorAll(selectors.join(','));
  buttons.forEach(btn => {
    if (blocked) {
      btn.classList.add('btn-disabled');
      btn.setAttribute('disabled', 'true');
      btn.setAttribute('title', "Reprenez votre abonnement pour activer cette fonctionnalité");
    } else {
      btn.classList.remove('btn-disabled');
      btn.removeAttribute('disabled');
      btn.removeAttribute('title');
    }
  });
}

// showAccessRestrictedModal — modale affichée quand un utilisateur readonly ou
// blocked tente une action gatée (création patient/bilan, export PDF).
// reason : 'create_patient' | 'create_bilan' | 'export_pdf'.
// Pattern de création runtime cohérent avec openNewPatientModal :
// le modal est créé une fois et réutilisé. Z-index 10001 pour passer au-dessus
// du modal Mon Compte (10000) et de l'overlay blocked (9998).
function showAccessRestrictedModal(reason) {
  const labels = {
    create_patient: 'Création de patient',
    create_bilan: 'Création de bilan',
    export_pdf: 'Export PDF',
  };
  const label = labels[reason] || 'Cette fonctionnalité';

  let modal = document.getElementById('modal-access-restricted');
  if (!modal) {
    modal = document.createElement('div');
    modal.id = 'modal-access-restricted';
    modal.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.7);z-index:10001;display:none;align-items:center;justify-content:center;padding:16px;box-sizing:border-box;';
    document.body.appendChild(modal);
    // Clic sur le backdrop = fermeture (cohérent avec les autres modales du code).
    // C'est OK ici : la modale est ponctuelle (déclenchée par une action utilisateur),
    // pas persistante comme le bandeau readonly ou l'overlay blocked.
    modal.addEventListener('click', e => { if (e.target === modal) modal.style.display = 'none'; });
  }
  // Sécurité : reason doit toujours être une string constante littérale du code,
  // jamais user-controlled — ${label} est rendu via innerHTML.
  modal.innerHTML = `
    <div style="background:var(--card);border-radius:14px;padding:28px;max-width:440px;width:100%;text-align:center;">
      <div style="font-size:38px;margin-bottom:14px;">🔒</div>
      <div style="font-size:17px;font-weight:700;color:var(--fg);margin-bottom:8px;">
        Fonctionnalité réservée aux abonnés actifs
      </div>
      <div style="font-size:13px;color:var(--mut);margin-bottom:22px;line-height:1.5;">
        ${label} indisponible. Reprenez votre abonnement pour réactiver cette fonctionnalité.
      </div>
      <div style="display:flex;gap:10px;justify-content:center;">
        <button onclick="document.getElementById('modal-access-restricted').style.display='none'" style="background:none;border:1px solid var(--bord);color:var(--mut);padding:10px 20px;border-radius:8px;font-size:13px;cursor:pointer;">
          Fermer
        </button>
        <button onclick="document.getElementById('modal-access-restricted').style.display='none';showSubscribeModal()" style="background:var(--blue);color:#fff;border:none;padding:10px 22px;border-radius:8px;font-size:13px;font-weight:700;cursor:pointer;">
          Reprendre l'abonnement
        </button>
      </div>
    </div>`;
  modal.style.display = 'flex';
}

// ═══════════════════════════════════════════════════════════════════
// Wizard subscribe modal (task #58)
// ═══════════════════════════════════════════════════════════════════
// Flow 2-vues pour la souscription/changement de formule depuis la PWA :
//   Vue 1 (#ms-view-cards) : cartes des 5 plans + toggle Mensuel/Annuel.
//   Vue 2 (#ms-view-modules) : 3 checkboxes pour le plan sélectionné +
//                              bouton Confirmer → subscribePaymentLink.
//
// Découplage avec le flow landing public : ici le user est authentifié, les
// modules sont stockés en pending_* via prepare-module-change Edge Function,
// puis appliqués par stripe-webhook au retour signé Stripe.
//
// Logique anti-abus (Q3 task #58) :
//   Plan différent  → CHANGE LIBRE (transaction commerciale légitime)
//   Plan identique + modules différents → check canChangeModule (lock 30j)
//   Plan identique + modules identiques → bouton désactivé (no-op)

// Mapping prix (test-mirror du landing pricing index.html lignes 113-117).
// Source de vérité = Stripe Dashboard + landing public. À synchroniser
// quand un prix change dans le dashboard.
const MS_PLAN_NAMES = ['Essentiel', 'Sport', 'Duo', 'Duo Sport', 'Intégral'];
const MS_PRICES_M  = [30, 40, 50, 60, 70];      // €/mois
const MS_PRICES_A  = [300, 400, 500, 600, 700]; // €/an (mensuel × 10, 2 mois offerts)
const MS_DESCR     = [
  '1 module au choix',
  'Podo sport + analyse cinématique',
  'Postural + Podopédiatrie',
  'Podo Sport + Postural ou Podopédiatrie',
  'Les 3 modules complets',
];

// Mapping plan → modules (test-mirror de PLAN_MODULES de js/subscription.mjs).
// Toute modif DOIT être répercutée là-bas (et dans prepare-module-change
// Edge Function). Référence task #58.
const MS_PLAN_MODULES = [
  { required: [],                                      choose: { from: ['postural', 'podopedia'], count: 1 } },
  { required: ['podo_sport'],                          choose: null },
  { required: ['postural', 'podopedia'],               choose: null },
  { required: ['podo_sport'],                          choose: { from: ['postural', 'podopedia'], count: 1 } },
  { required: ['postural', 'podopedia', 'podo_sport'], choose: null },
];

// État local wizard — préfixe _ms cohérent avec _userModules, _accessLevel.
let _msSelectedPlanIdx = null;  // 0-4 ou null si on est en vue 1 (pas encore choisi)
let _msSelectedModules = [];    // array canonique ['postural', ...]
let _msIsAnnuel = true;         // Annuel par défaut (Q2=b)

// ─── Helpers wizard — Vue 1 (cards) ────────────────────────────────

function showSubscribeModal() {
  // Reset état local pour ne pas hériter d'une session précédente.
  _msSelectedPlanIdx = null;
  _msSelectedModules = [];
  // Hide vue 2 + show vue 1.
  msShowCardsView();
  // Close button conditionnel : non-dismissible si accessLevel === 'blocked'.
  // Cf. C6 — backdrop click logic appliquée aussi.
  const closeBtn = document.getElementById('ms-close');
  if (closeBtn) {
    closeBtn.style.display = window._accessLevel === 'blocked' ? 'none' : 'inline-block';
  }
  // Reset bandeau d'erreur d'éventuel call précédent.
  const errEl = document.getElementById('ms-err');
  if (errEl) errEl.style.display = 'none';
  // Re-render cards selon état toggle + licence_payee actuel.
  msRenderCards();
  // Affiche le modal + (re-)wire le backdrop handler (C6).
  // Pattern défensif : on stocke le handler sur modal._backdropHandler pour
  // pouvoir le retirer/réenregistrer au prochain show (le DOM persiste entre
  // open/close — la modale est statique dans index.html, pas re-créée).
  // Ferme uniquement si :
  //   - le click vise le backdrop (e.target === modal, pas un enfant interne)
  //   - ET l'accessLevel n'est pas 'blocked' (modal non-dismissible si bloqué,
  //     cohérent avec closeSubscribeModal qui refuse aussi dans ce cas).
  const modal = document.getElementById('modal-subscribe');
  if (modal) {
    if (modal._backdropHandler) modal.removeEventListener('click', modal._backdropHandler);
    modal._backdropHandler = (e) => {
      if (e.target === modal && window._accessLevel !== 'blocked') {
        modal.style.display = 'none';
      }
    };
    modal.addEventListener('click', modal._backdropHandler);
    modal.style.display = 'flex';
  }
}

function closeSubscribeModal() {
  // Refuse de fermer si user en accès bloqué (cf. C6).
  if (window._accessLevel === 'blocked') return;
  const modal = document.getElementById('modal-subscribe');
  if (modal) modal.style.display = 'none';
}

function msShowCardsView() {
  document.getElementById('ms-view-cards').style.display = '';
  document.getElementById('ms-view-modules').style.display = 'none';
  document.getElementById('ms-title').textContent = 'Choisir une formule';
}

function msToggleAnnuel() {
  _msIsAnnuel = !_msIsAnnuel;
  const tog = document.getElementById('ms-tog');
  const lblM = document.getElementById('ms-lbl-m');
  const lblA = document.getElementById('ms-lbl-a');
  if (_msIsAnnuel) {
    tog?.classList.add('ann');
    lblM?.classList.remove('on');
    lblA?.classList.add('on');
  } else {
    tog?.classList.remove('ann');
    lblM?.classList.add('on');
    lblA?.classList.remove('on');
  }
  msRenderCards();
}

function msRenderCards() {
  const el = document.getElementById('ms-cards');
  if (!el) return;
  // Détecter la formule actuelle pour highlight + badge "Votre formule".
  const currentFormule = pwaUser?.user_data?.formule;
  const currentPlanIdx = (typeof currentFormule === 'string' && currentFormule.startsWith('formule_'))
    ? parseInt(currentFormule.replace('formule_', ''), 10) - 1
    : null;
  // Badge licence-aware (Q2) : si licence déjà payée, on remplace la mention
  // "+ 299€ licence" par un badge vert "✓ Vous avez déjà la licence" — évite
  // de suggérer au user qu'il va re-payer la licence. Cohérent avec la logique
  // Edge Function paymentLinkFor qui sélectionne sansLicence si hasLicence.
  const hasLicence = pwaUser?.user_data?.licence_payee === true;
  const licenceLine = hasLicence
    ? '<div style="font-size:10px;color:#2dd4bf;font-weight:600;margin-top:4px;">✓ Vous avez déjà la licence</div>'
    : '<div style="font-size:10px;color:rgba(45,212,191,0.7);margin-top:4px;">+ 299€ licence & mises à jour</div>';

  el.innerHTML = MS_PLAN_NAMES.map((name, idx) => {
    const price = _msIsAnnuel ? MS_PRICES_A[idx] : MS_PRICES_M[idx];
    const period = _msIsAnnuel ? '/ an' : '/ mois';
    const isCurrent = idx === currentPlanIdx;
    const cardBorder = isCurrent ? '2px solid #2dd4bf' : '1px solid var(--bord)';
    const currentBadge = isCurrent
      ? '<div style="font-size:10px;color:#2dd4bf;font-weight:700;margin-bottom:6px;">VOTRE FORMULE ACTUELLE</div>'
      : '';
    return `
      <div style="background:var(--card);border-radius:12px;padding:18px;border:${cardBorder};">
        ${currentBadge}
        <div style="font-size:15px;font-weight:700;color:#fff;">${_escHtml(name)}</div>
        <div style="font-size:22px;font-weight:700;color:#fff;margin-top:8px;">${price}€ <span style="font-size:12px;font-weight:400;color:var(--mut);">${period}</span></div>
        ${licenceLine}
        <div style="font-size:12px;color:var(--mut);margin-top:10px;">${_escHtml(MS_DESCR[idx])}</div>
        <button onclick="msSelectPlan(${idx})" class="btn btn-blue" style="width:100%;margin-top:14px;font-size:13px;">Choisir</button>
      </div>`;
  }).join('');
}

// ─── Helpers wizard — Vue 2 (modules) ──────────────────────────────

function msSelectPlan(idx) {
  if (!Number.isInteger(idx) || idx < 0 || idx > 4) return;
  _msSelectedPlanIdx = idx;
  // Présélection : modules par défaut (required + premiers choose.count).
  const plan = MS_PLAN_MODULES[idx];
  const fromChoose = plan.choose ? plan.choose.from.slice(0, plan.choose.count) : [];
  _msSelectedModules = [...plan.required, ...fromChoose];
  msShowModulesView();
}

function msShowModulesView() {
  document.getElementById('ms-view-cards').style.display = 'none';
  document.getElementById('ms-view-modules').style.display = '';
  document.getElementById('ms-title').textContent = 'Choisir vos modules';
  const subtitle = document.getElementById('ms-modules-subtitle');
  if (subtitle && _msSelectedPlanIdx !== null) {
    subtitle.textContent = MS_PLAN_NAMES[_msSelectedPlanIdx] + ' — sélectionnez vos modules.';
  }
  const errEl = document.getElementById('ms-err');
  if (errEl) errEl.style.display = 'none';
  msRenderModules();
  msUpdateConfirmButton();
}

function msRenderModules() {
  const el = document.getElementById('ms-modules-list');
  if (!el || _msSelectedPlanIdx === null) return;
  const plan = MS_PLAN_MODULES[_msSelectedPlanIdx];
  // Afficher les 3 modules canoniques pour cohérence visuelle, avec état :
  //   - required → coché + disabled (verrouillé par le plan)
  //   - choose.from → cochable, contrainte count vérifiée à l'update
  //   - autres → disabled + opacity réduite ("non disponible dans ce plan")
  const modules = [
    { id: 'postural',   label: 'Postural' },
    { id: 'podopedia',  label: 'Podopédiatrie', suffix: ' (en développement)' },
    { id: 'podo_sport', label: 'Sport' },
  ];
  el.innerHTML = modules.map(m => {
    const isRequired = plan.required.includes(m.id);
    const isInChoose = plan.choose ? plan.choose.from.includes(m.id) : false;
    const isApplicable = isRequired || isInChoose;
    const isChecked = _msSelectedModules.includes(m.id);
    const disabled = isRequired || !isApplicable;
    const opacity = isApplicable ? '1' : '0.4';
    const note = isRequired
      ? ' <span style="font-size:10px;color:var(--mut);">(inclus dans le plan)</span>'
      : (isInChoose
          ? ` <span style="font-size:10px;color:var(--mut);">(au choix : ${plan.choose.count})</span>`
          : ' <span style="font-size:10px;color:var(--mut);">(non disponible dans ce plan)</span>');
    const suffix = m.suffix ? `<span style="font-size:10px;color:var(--mut);">${_escHtml(m.suffix)}</span>` : '';
    return `
      <label style="font-size:13px;display:flex;align-items:center;gap:10px;padding:10px 12px;background:var(--card);border:1px solid var(--bord);border-radius:8px;cursor:${disabled ? 'not-allowed' : 'pointer'};opacity:${opacity};">
        <input type="checkbox" id="ms-mod-${m.id}" ${isChecked ? 'checked' : ''} ${disabled ? 'disabled' : ''} onchange="msToggleModule('${m.id}')"/>
        ${_escHtml(m.label)}${suffix}${note}
      </label>`;
  }).join('');
}

function msToggleModule(name) {
  if (_msSelectedModules.includes(name)) {
    _msSelectedModules = _msSelectedModules.filter(m => m !== name);
  } else {
    _msSelectedModules = [..._msSelectedModules, name];
  }
  msUpdateConfirmButton();
}

// msUpdateConfirmButton — applique la logique anti-abus Q3 (task #58).
//
//   Cas A : plan ≠ plan actuel
//           → bouton activé si modules valides pour le plan (NO lock check).
//             Changement de plan = transaction commerciale légitime.
//   Cas B : plan = plan actuel + modules ≠
//           → bouton activé si modules valides ET canChangeModule()===null.
//             Sinon disabled + affichage du lock + next_date dans #ms-err.
//   Cas C : plan = plan actuel + modules =
//           → bouton disabled + message info "Aucun changement" dans #ms-err.
function msUpdateConfirmButton() {
  const btn = document.getElementById('ms-confirm-btn');
  const errEl = document.getElementById('ms-err');
  if (!btn || _msSelectedPlanIdx === null) return;

  // 1. Validation modules vs plan (test-mirror PLAN_MODULES)
  if (!msIsValidModulesForPlan(_msSelectedPlanIdx, _msSelectedModules)) {
    btn.disabled = true;
    if (errEl) {
      errEl.style.display = 'block';
      errEl.style.background = 'rgba(231,76,60,0.1)';
      errEl.style.color = '#e74c3c';
      errEl.textContent = 'Sélection incomplète ou invalide pour ce plan.';
    }
    return;
  }

  // 2. Détection changement plan vs actuel
  const currentFormule = pwaUser?.user_data?.formule;
  const currentPlanIdx = (typeof currentFormule === 'string' && currentFormule.startsWith('formule_'))
    ? parseInt(currentFormule.replace('formule_', ''), 10) - 1
    : null;
  const planChanged = currentPlanIdx === null || currentPlanIdx !== _msSelectedPlanIdx;

  // 3. Détection changement modules vs actuel
  const currentModules = Array.isArray(window._userModules) ? window._userModules : [];
  const sortedCur = [...currentModules].sort();
  const sortedNew = [..._msSelectedModules].sort();
  const modulesChanged = sortedCur.length !== sortedNew.length
    || sortedCur.some((m, i) => m !== sortedNew[i]);

  // Cas C : no-op
  if (!planChanged && !modulesChanged) {
    btn.disabled = true;
    if (errEl) {
      errEl.style.display = 'block';
      errEl.style.background = 'rgba(127,127,127,0.1)';
      errEl.style.color = 'var(--mut)';
      errEl.textContent = 'Aucun changement par rapport à votre formule actuelle.';
    }
    return;
  }

  // Cas A : plan changé → bouton activé sans lock check
  if (planChanged) {
    btn.disabled = false;
    if (errEl) errEl.style.display = 'none';
    return;
  }

  // Cas B : plan inchangé + modules changés → check lock anti-abus (Q3 brief)
  const lockCheck = canChangeModule(
    {
      date_debut_abonnement: pwaUser?.user_data?.date_debut_abonnement || null,
      last_module_change: pwaUser?.user_data?.last_module_change || null,
    },
    new Date()
  );
  if (lockCheck) {
    btn.disabled = true;
    if (errEl) {
      errEl.style.display = 'block';
      errEl.style.background = 'rgba(231,76,60,0.1)';
      errEl.style.color = '#e74c3c';
      const nextDate = new Date(lockCheck.next_change_date).toLocaleDateString('fr-FR', {
        day: 'numeric',
        month: 'long',
        year: 'numeric',
      });
      errEl.textContent = `Changement de modules non autorisé avant le ${nextDate} (lock 30j entre changements).`;
    }
    return;
  }

  btn.disabled = false;
  if (errEl) errEl.style.display = 'none';
}

// Mirror local de isValidModulesForPlan (js/subscription.mjs). Cf. duplication
// test-mirror documentée — toute modif DOIT être répercutée.
function msIsValidModulesForPlan(planIdx, modules) {
  const plan = MS_PLAN_MODULES[planIdx];
  if (!plan) return false;
  if (!plan.required.every(m => modules.includes(m))) return false;
  if (plan.choose) {
    const chosen = modules.filter(m => plan.choose.from.includes(m)).length;
    if (chosen !== plan.choose.count) return false;
  }
  return true;
}

// subscribePaymentLink — appel Edge Function prepare-module-change (task #58).
//
// Flow : check préalable → POST prepare-module-change → redirect Stripe.
//
// Retour post-Stripe (V1) : aucune logique custom. Au retour signé Stripe
// (checkout.session.completed), stripe-webhook applique les pending_modules.
// L'app reload → onPwaLoginSuccess → fetchUserDataAtLogin → checkAccessStatus
// s'enchaînent automatiquement. Pas de message "paiement reçu" pour V1 ;
// à ajouter en V2+ si besoin UX.
//
// Pas de loading state explicite : le user verra l'animation Stripe au
// window.location.href. Si retour de l'app pour cause d'échec (back
// browser), la modale reste ouverte avec le bouton réactivé (display:flex
// préservé).
async function subscribePaymentLink() {
  // 1. Validation préalable (défense en profondeur — le bouton devrait être
  //    disabled si invalide, mais on protège contre l'appel direct console).
  if (_msSelectedPlanIdx === null || !Array.isArray(_msSelectedModules)) {
    console.error('subscribePaymentLink: state local invalide', { _msSelectedPlanIdx, _msSelectedModules });
    return;
  }
  if (!msIsValidModulesForPlan(_msSelectedPlanIdx, _msSelectedModules)) {
    console.error('subscribePaymentLink: modules invalides pour plan', { _msSelectedPlanIdx, _msSelectedModules });
    return;
  }

  // 2. Lecture promo code (optionnel, vide string acceptée).
  const promoEl = document.getElementById('ms-promo');
  const promoCode = (promoEl?.value || '').trim();

  const errEl = document.getElementById('ms-err');
  const showGenericError = () => {
    if (!errEl) return;
    errEl.style.display = 'block';
    errEl.style.background = 'rgba(231,76,60,0.1)';
    errEl.style.color = '#e74c3c';
    errEl.textContent = 'Erreur lors de la préparation du paiement. Veuillez réessayer ou contacter le support.';
  };

  // 3. Appel Edge Function (authFetch ajoute Authorization Bearer JWT auto).
  try {
    const res = await authFetch(SUPA_URL + '/functions/v1/prepare-module-change', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        planIdx: _msSelectedPlanIdx,
        modules: _msSelectedModules,
        isAnnuel: _msIsAnnuel,
      }),
    });
    const data = await res.json().catch(() => ({}));

    // 4a. 200 OK — redirect Stripe avec append promo code si fourni.
    if (res.status === 200 && data.ok && typeof data.payment_link_url === 'string') {
      let url = data.payment_link_url;
      if (promoCode) {
        const sep = url.includes('?') ? '&' : '?';
        url = url + sep + 'prefilled_promo_code=' + encodeURIComponent(promoCode);
      }
      window.location.href = url;
      return;
    }

    // 4b. 409 locked — affichage du next_change_date formaté (Q5).
    if (res.status === 409 && data.error === 'locked' && data.next_change_date) {
      const nextDate = new Date(data.next_change_date).toLocaleDateString('fr-FR', {
        day: 'numeric',
        month: 'long',
        year: 'numeric',
      });
      if (errEl) {
        errEl.style.display = 'block';
        errEl.style.background = 'rgba(231,76,60,0.1)';
        errEl.style.color = '#e74c3c';
        errEl.textContent = `Changement de modules non autorisé avant le ${nextDate} (lock 30j entre changements).`;
      }
      return;
    }

    // 4c. Autres erreurs (400, 401, 500, …) — message générique + log.
    console.error('subscribePaymentLink: erreur Edge Function', { status: res.status, data });
    showGenericError();
  } catch (e) {
    // 4d. Erreur réseau (fetch reject, timeout, etc.).
    console.error('subscribePaymentLink: exception', e);
    showGenericError();
  }
}

// ─── Helpers DOM bandeau + overlay (task #57) ───────────────────────
// Utilisent les ID existants (#trial-banner, #trial-banner-text, #trial-expired-overlay).
// Renommage éventuel vers #access-* possible en PR future si la sémantique « trial »
// devient trop trompeuse — pas dans cette PR pour limiter le scope HTML.

function _hideAccessBanner() {
  const b = document.getElementById('trial-banner');
  if (b) b.style.display = 'none';
}

function _showAccessBanner({ text, background }) {
  const b = document.getElementById('trial-banner');
  const t = document.getElementById('trial-banner-text');
  if (b) {
    b.style.display = 'block';
    // Note : `if (background)` (vs `!== undefined`) pour que les falsy values (`''`,
    // `null`) préservent le style HTML inline. Permet aux callers de signifier "ne pas
    // toucher" en passant '' ou undefined indifféremment. Task #61.
    if (background) b.style.background = background;
  }
  if (t) t.textContent = text;
}

function _hideAccessOverlay() {
  const o = document.getElementById('trial-expired-overlay');
  if (o) o.style.display = 'none';
}

// ─── Sync error banner (task #38) ──────────────────────────────────────────
// Affiché par saveToSupabase() lorsque la sync DB échoue (path !ok ou catch).
// Caché automatiquement au prochain save success (via flag _syncErrorShown).
// Dismissible manuellement par bouton ✕ (cf. index.html #sync-error-banner).
function _showSyncErrorBanner(message) {
  const b = document.getElementById('sync-error-banner');
  const t = document.getElementById('sync-error-banner-text');
  if (b) b.style.display = 'block';
  if (t) t.textContent = message;
}

function _hideSyncErrorBanner() {
  const b = document.getElementById('sync-error-banner');
  if (b) b.style.display = 'none';
  _syncErrorShown = false;
}

// Mute le titre + le message internes de l'overlay selon la cause du blocage.
// Les 2 divs n'ont pas d'ID dans le HTML actuel — on les adresse par position
// (children[1]=titre, children[2]=message du wrapper). Fragile si la structure
// HTML change ; un commit ultérieur peut les passer en data-* attributes.
function _showAccessOverlay({ cause }) {
  const o = document.getElementById('trial-expired-overlay');
  if (!o) return;
  o.style.display = 'flex';
  const wrapper = o.firstElementChild;
  if (!wrapper || wrapper.children.length < 3) return;
  const titleEl = wrapper.children[1];
  const msgEl = wrapper.children[2];
  if (cause === 'trial_expired') {
    if (titleEl) titleEl.textContent = 'Votre essai est terminé';
    if (msgEl) msgEl.textContent = 'Votre essai gratuit de 14 jours est terminé. Choisissez une formule pour continuer.';
  } else if (cause === 'never_paid') {
    if (titleEl) titleEl.textContent = 'Bienvenue';
    if (msgEl) msgEl.textContent = 'Démarrez votre essai gratuit de 14 jours ou choisissez une formule.';
  }
}

async function pwaLogout() {
  if(!sessionStorage.getItem('skip_logout_confirm')) {
    if(!confirm('Se déconnecter ?')) return;
  }
  sessionStorage.removeItem('skip_logout_confirm');
  if(pwaUser?.token) {
    try { await supa.signOut(pwaUser.token); } catch(e) {}
  }
  clearPwaSession();
  pwaUser = null;
  patients = []; praticiens = []; currentPatient = null; bilanData = {};
  _dataLoaded = false;  // Task #64 — reset guard pour prochaine session
  renderPatientList();
  document.getElementById('biomeca-app').style.display = 'none';
  document.getElementById('pwa-login').style.display = 'flex';
  // Scroll vers tarifs si demandé
  if(sessionStorage.getItem('scroll_tarifs')) {
    sessionStorage.removeItem('scroll_tarifs');
    setTimeout(function() {
      var el = document.getElementById('lp-pricing-section');
      if(el) el.scrollIntoView({behavior:'smooth'});
    }, 300);
  }
  document.getElementById('pwa-email').value = '';
  document.getElementById('pwa-pwd').value = '';
  document.getElementById('pwa-login-btn').disabled = false;
  document.getElementById('pwa-login-btn').textContent = 'Se connecter';
  const mc = document.getElementById('modal-mon-compte');
  if(mc) mc.style.display = 'none';
  const tb = document.getElementById('trial-banner');
  if(tb) tb.style.display = 'none';
  const ov = document.getElementById('trial-expired-overlay');
  if(ov) ov.style.display = 'none';
  nav('pg-sport');
}

// ─── Init PWA ───
async function initPWA() {
  // Vérifier session existante
  const session = loadPwaSession();
  if(session.token && session.user) {
    try {
      const userData = await supa.getUser();
      if(userData.id) {
        const isAdmin = session.user.email?.toLowerCase() === 'sciopraxi@gmail.com';
        pwaUser = { ...session.user, token: session.token, isAdmin, user_metadata: session.user?.user_metadata || {} };
        await onPwaLoginSuccess();
        return;
      }
    } catch(e) {}
  }
  // Pas de session valide: afficher le login
  document.getElementById('pwa-login').style.display = 'flex';
  enumerateCameras('vcam-select');
  enumerateCameras('cam-select');
}

initPWA();





// ─── Service Worker ───
if ('serviceWorker' in navigator) {
  window.addEventListener('load', () => {
    navigator.serviceWorker
      .register('service-worker.js', { scope: './' })
      .then(reg => {
        if (reg.waiting) console.info('[SW] new version waiting');
        reg.addEventListener('updatefound', () => {
          const sw = reg.installing;
          sw && sw.addEventListener('statechange', () => {
            if (sw.state === 'installed' && navigator.serviceWorker.controller) {
              console.info('[SW] update available — refresh to apply');
            }
          });
        });
      })
      .catch(err => console.warn('[SW] registration failed:', err));
  });
}



