function cloneMarkers(type) {
  const tmpl = MARKER_TEMPLATES[type] || MARKER_TEMPLATES['mla'];
  return tmpl.map(m => ({...m, x:null, y:null}));
}

function getMkrsBySet(markers, targetSet) {
  // Retourne les 3 marqueurs d'un côté (set = 'D' ou 'G') ou tous si side=''
  if (!targetSet) return markers;
  return markers.filter(m => m.side === targetSet);
}

// ══════════════════════════════════════════════════════
// NAVIGATION
// ══════════════════════════════════════════════════════
function nav(id) {
  // #116 — Capture-avant-quitter : si on quitte un bilan vers une autre page,
  // capturer le DOM dans bilanData/bilanDataPosturo AVANT de le masquer. Sinon
  // la saisie texte non capturée est perdue au retour (loadBilan re-rend depuis
  // les données). saveBilanSilent / savePosturoBilan font un sweep DOM SYNCHRONE
  // en début d'exécution → la capture a lieu avant le masquage malgré l'async
  // (la partie sweep DOM s'exécute avant le 1er await, fire-and-forget OK).
  const _leavingPage = document.querySelector('.page.active');
  const _leavingId = _leavingPage ? _leavingPage.id : null;
  if (_leavingId && _leavingId !== id) {
    if (_leavingId === 'pg-bilan' && typeof saveBilanSilent === 'function') saveBilanSilent();
    else if (_leavingId === 'pg-bilan-posturo' && typeof savePosturoBilan === 'function') savePosturoBilan(true);
  }
  // Déplacer toutes les pages orphelines dans .main
  const mainEl = document.querySelector('.main');
  if(mainEl) {
    document.querySelectorAll('.page').forEach(pg => {
      if(pg.parentElement !== mainEl) mainEl.appendChild(pg);
    });
  }
  document.querySelectorAll('.page').forEach(p => {
    p.classList.remove('active');
    p.style.display = 'none';
  });
  document.querySelectorAll('.tnav button').forEach(b => b.classList.remove('act'));
  if(mainEl) mainEl.scrollTop = 0;
  window.scrollTo({top:0, behavior:'instant'});
  setTimeout(() => {
    if(mainEl) mainEl.scrollTop = 0;
    window.scrollTo({top:0, behavior:'instant'});
  }, 50);
  const pg = document.getElementById(id);
  if (pg) { pg.classList.add('active'); pg.style.display = 'block'; }
  const map = {
    'pg-patients':'tn-patients',
    'pg-praticiens':'tn-praticiens','pg-params':'tn-params',
    'pg-sport':'tn-patients','pg-posturo':'tn-patients'
  };
  if (map[id]) { const b=document.getElementById(map[id]); if(b) b.classList.add('act'); }
  if(id === 'pg-rapport') buildRapport();
  if(id === 'pg-patients') { renderPatientList(); populatePratSelect(); }
  if(id === 'pg-praticiens') renderPratList();
  if(id === 'pg-params') {
    renderParamsPratList();
    // #81 — rafraîchit le compteur Maintenance à l'ouverture de Paramètres
    if (typeof _runBackfillDryRun === 'function') _runBackfillDryRun();
    // #106-A — peuple la card seuils analyse posturale (valeurs actuelles ou défauts)
    if (typeof _renderPostureThresholdsPanel === 'function') _renderPostureThresholdsPanel();
  }
  if(id === 'pg-sport') {
    // Mettre à jour le sous-titre avec le patient courant
    const sub = document.getElementById('sport-sub');
    if(sub && currentPatient) sub.textContent = 'Patient : '+currentPatient.prenom+' '+currentPatient.nom+' · '+(currentPatient.sport||'—');
    // Mettre à jour info posturo aussi
    const pinfo = document.getElementById('posturo-patient-info');
    if(pinfo && currentPatient) pinfo.textContent = 'Patient : '+currentPatient.prenom+' '+currentPatient.nom;
  }
  if(id === 'pg-posturo') {
    const pinfo = document.getElementById('posturo-patient-info');
    if(pinfo && currentPatient) pinfo.textContent = 'Patient : '+currentPatient.prenom+' '+currentPatient.nom+' · '+(currentPatient.sport||'—');
  }
  if(id === 'pg-bilan-posturo') {
    injectBilanPosturoPage();
    // Forcer la visibilité après injection dynamique
    const pgPost = document.getElementById('pg-bilan-posturo');
    if(pgPost) {
      pgPost.classList.add('active');
      pgPost.style.height = 'auto';
      pgPost.style.visibility = 'visible';
      pgPost.style.overflow = 'visible';
    }
    showPosturoSection(0);
    setTimeout(loadPosturoBilan, 50);
  }
  if(id === 'pg-bilan') {
    setTimeout(() => {
      clearBilanFields();
      // 1. Initialiser les canvas morpho (taille + setupDrawCanvas)
      ['morpho-face','morpho-face2','morpho-profilG','morpho-profilD'].forEach(id => initMorphoCanvas(id));
      // 2. Charger les données du bilan
      setTimeout(() => {
        loadBilan();
        // 3. Initialiser canvas pieds APRÈS loadBilan (bilanData disponible)
        const pc = document.getElementById('pieds-canvas');
        if(pc) { drawPiedsTemplate(currentPatient?.bilanData?._pieds); }
      }, 200);
      // Injection micros de dictée par champ texte (Q-mic-1 b, #73 A1)
      if(typeof _injectSportMicButtons === 'function') setTimeout(_injectSportMicButtons, 250);
      // 4. Restaurer les dessins directement (pas via restoreCanvas)
      // #99 refactor — délégué à _drawMorphoCanvasesFromSource pour fidélité
      // byte-pour-byte avec le 2e call-site post-prefetch (.then() loadBilan).
      setTimeout(() => {
        _drawMorphoCanvasesFromSource(currentPatient?.bilanData);
        // pieds restaurés dans drawPiedsTemplate
      }, 500);
    }, 80);
  }
}

// ─── Admin: gestion utilisateurs via Edge Function admin-users (Task #56) ───
// L'ancienne clé admin a été retirée du client suite à l'incident #29 — elle
// vit désormais uniquement comme variable d'env côté Edge Function. Celle-ci
// vérifie côté serveur que l'appelant est l'admin (JWT email == ADMIN_EMAIL)
// avant d'exécuter list/setLicencePayee/setFormule/setDroits. Le bouton
// "Ouvrir Supabase Users" en haut de la page reste comme secours pour les
// actions hors scope (suspend, delete, invite, resetPassword — voir PR D').

// Cache module-level : les boutons "Modifier" passent un index, pas un objet,
// pour éviter de sérialiser le user dans onclick="..." (apostrophes, escaping).
let _adminUsersCache = [];

function _escHtml(s) {
  return String(s ?? '').replace(/[&<>"']/g, c =>
    ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c])
  );
}

async function renderParamsPratList() {
  const el = document.getElementById('params-prat-list');
  if (!el) return;
  el.innerHTML = '<div style="font-size:12px;color:var(--mut);padding:8px 0;">Chargement des utilisateurs…</div>';
  const res = await adminListUsers();
  if (!res || res.ok === false) {
    el.innerHTML = `<div style="font-size:12px;color:var(--red);padding:8px 0;">Erreur : ${_escHtml(res?.error || 'inconnue')}</div>`;
    return;
  }
  _adminUsersCache = Array.isArray(res.users) ? res.users : [];
  if (_adminUsersCache.length === 0) {
    el.innerHTML = '<div style="font-size:12px;color:var(--mut);padding:8px 0;">Aucun utilisateur.</div>';
    return;
  }
  el.innerHTML = _adminUsersCache.map((u, i) => _adminUserRowHTML(u, i)).join('');
}

function _adminUserRowHTML(u, idx) {
  const licenceBadge = u.licence_payee
    ? '<span style="color:#2a7a4e;font-weight:600;">✅ Licence</span>'
    : '<span style="color:#e74c3c;font-weight:600;">⚠️ Sans licence</span>';
  const formuleTxt = u.formule ? _escHtml(u.formule) : '<span style="color:var(--mut);">—</span>';
  // modules (task #58) : array depuis adminListUsers refactoré. Si vide,
  // fallback "—" plutôt que "all" pour ne pas mentir sur le périmètre réel.
  const modulesTxt = u.modules && u.modules.length
    ? u.modules.map(_escHtml).join(', ')
    : '<span style="color:var(--mut);">—</span>';
  const engagement = u.engagement ? ' · ' + _escHtml(u.engagement) : '';
  return `
    <div style="display:flex;align-items:center;gap:12px;padding:10px 12px;background:var(--card);border:1px solid var(--bord);border-radius:8px;margin-bottom:8px;">
      <div style="flex:1;min-width:0;">
        <div style="font-size:13px;font-weight:600;color:#fff;overflow:hidden;text-overflow:ellipsis;">${_escHtml(u.email)}</div>
        <div style="font-size:11px;color:var(--mut);margin-top:3px;">
          ${licenceBadge} · Formule : ${formuleTxt} · Modules : ${modulesTxt}${engagement}
        </div>
      </div>
      <button onclick="openEditUserModal(${idx})" class="btn" style="font-size:11px;padding:6px 12px;flex-shrink:0;">Modifier</button>
    </div>`;
}

function openEditUserModal(idx) {
  const u = _adminUsersCache[idx];
  if (!u) return;
  let modal = document.getElementById('modal-edit-user');
  if (!modal) {
    modal = document.createElement('div');
    modal.id = 'modal-edit-user';
    modal.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.7);z-index:9999;display:flex;align-items:center;justify-content:center;padding:16px;box-sizing:border-box;';
    document.body.appendChild(modal);
    modal.addEventListener('click', e => { if (e.target === modal) closeEditUserModal(); });
  }
  modal.innerHTML = `
    <div style="background:var(--card);border-radius:14px;padding:24px;width:100%;max-width:500px;max-height:90vh;overflow-y:auto;">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;">
        <div style="font-size:16px;font-weight:700;">Modifier l'utilisateur</div>
        <button onclick="closeEditUserModal()" style="background:none;border:none;font-size:20px;cursor:pointer;color:var(--mut);">✕</button>
      </div>
      <div style="font-size:13px;color:var(--mut);margin-bottom:18px;">${_escHtml(u.email)}</div>

      <div style="margin-bottom:14px;">
        <label style="font-size:12px;font-weight:600;display:flex;align-items:center;gap:8px;cursor:pointer;">
          <input type="checkbox" id="eu-licence" ${u.licence_payee ? 'checked' : ''}/>
          Licence activée
        </label>
        ${u.engagement ? `<div style="font-size:11px;color:var(--mut);margin-top:4px;margin-left:24px;">Engagement actuel : <strong>${_escHtml(u.engagement)}</strong>${u.date_debut_abonnement ? ` depuis ${_escHtml(new Date(u.date_debut_abonnement).toLocaleDateString('fr-FR'))}` : ''}</div>` : ''}
        <div style="font-size:11px;color:var(--mut);margin-top:4px;margin-left:24px;">Sur activation : engagement passe à <code>admin_gratuit</code> (distinct des paiements Stripe). Sur désactivation : engagement préservé.</div>
      </div>

      <div style="margin-bottom:14px;">
        <div style="font-size:12px;font-weight:600;margin-bottom:4px;">Formule</div>
        <select id="eu-formule" class="inp" style="width:100%;">
          <option value="">— inchangée —</option>
          <option value="formule_1" ${u.formule === 'formule_1' ? 'selected' : ''}>formule_1</option>
          <option value="formule_2" ${u.formule === 'formule_2' ? 'selected' : ''}>formule_2</option>
          <option value="formule_3" ${u.formule === 'formule_3' ? 'selected' : ''}>formule_3</option>
          <option value="formule_4" ${u.formule === 'formule_4' ? 'selected' : ''}>formule_4</option>
          <option value="formule_5" ${u.formule === 'formule_5' ? 'selected' : ''}>formule_5</option>
        </select>
      </div>

      <div style="margin-bottom:14px;">
        <div style="font-size:12px;font-weight:600;margin-bottom:6px;">Modules</div>
        <div style="display:flex;flex-direction:column;gap:6px;">
          <label style="font-size:12px;display:flex;align-items:center;gap:8px;cursor:pointer;">
            <input type="checkbox" id="eu-mod-postural" ${(u.modules||[]).includes('postural') ? 'checked' : ''}/>
            Postural
          </label>
          <label style="font-size:12px;display:flex;align-items:center;gap:8px;cursor:pointer;">
            <input type="checkbox" id="eu-mod-podopedia" ${(u.modules||[]).includes('podopedia') ? 'checked' : ''}/>
            Podopédiatrie <span style="font-size:10px;color:var(--mut);">(en développement)</span>
          </label>
          <label style="font-size:12px;display:flex;align-items:center;gap:8px;cursor:pointer;">
            <input type="checkbox" id="eu-mod-podo_sport" ${(u.modules||[]).includes('podo_sport') ? 'checked' : ''}/>
            Sport
          </label>
        </div>
        <div style="font-size:10px;color:var(--mut);margin-top:6px;">Override admin — pas de contrôle de cohérence avec la formule (responsabilité humaine).</div>
      </div>

      <div id="eu-err" style="display:none;color:var(--red);font-size:12px;margin-bottom:12px;padding:8px 10px;background:rgba(231,76,60,0.1);border-radius:6px;"></div>

      <div style="display:flex;gap:10px;justify-content:flex-end;">
        <button onclick="closeEditUserModal()" class="btn" style="font-size:12px;">Annuler</button>
        <button onclick="saveEditUser(${idx})" id="eu-save-btn" class="btn btn-blue" style="font-size:12px;">Enregistrer</button>
      </div>
    </div>`;
  modal.style.display = 'flex';
}

function closeEditUserModal() {
  const m = document.getElementById('modal-edit-user');
  if (m) m.style.display = 'none';
}

async function saveEditUser(idx) {
  const u = _adminUsersCache[idx];
  if (!u) return;
  const errEl = document.getElementById('eu-err');
  const btn = document.getElementById('eu-save-btn');
  errEl.style.display = 'none';
  btn.disabled = true; btn.textContent = 'Enregistrement…';

  const newLicence = document.getElementById('eu-licence').checked;
  const newFormule = document.getElementById('eu-formule').value;  // '' si inchangée

  // Lecture des 3 checkboxes modules (task #58). Ordre canonique
  // [postural, podopedia, podo_sport] pour comparaison stable.
  const newModules = [];
  if (document.getElementById('eu-mod-postural').checked) newModules.push('postural');
  if (document.getElementById('eu-mod-podopedia').checked) newModules.push('podopedia');
  if (document.getElementById('eu-mod-podo_sport').checked) newModules.push('podo_sport');

  // On n'appelle que ce qui a réellement changé. Les actions sont indépendantes
  // (colonnes différentes pour licence/formule, table différente pour modules)
  // donc Promise.all est safe — pas de course critique.
  const tasks = [];
  if (newLicence !== !!u.licence_payee) {
    tasks.push(adminSetLicencePayee(u.email, newLicence));
  }
  if (newFormule && newFormule !== (u.formule || '')) {
    tasks.push(adminSetFormule(u.email, newFormule));
  }
  // Comparaison set-equality : on trie les 2 arrays pour comparaison stable
  // (l'ordre dans u.modules vient du serveur, peut différer de l'ordre canonique).
  const currentModules = Array.isArray(u.modules) ? [...u.modules].sort() : [];
  const sortedNew = [...newModules].sort();
  const modulesChanged =
    currentModules.length !== sortedNew.length ||
    currentModules.some((m, i) => m !== sortedNew[i]);
  if (modulesChanged) {
    tasks.push(adminSetModules(u.id, newModules));
  }

  if (tasks.length === 0) {
    closeEditUserModal();
    btn.disabled = false; btn.textContent = 'Enregistrer';
    return;
  }

  const results = await Promise.all(tasks);
  const failed = results.filter(r => !r || r.ok === false);
  if (failed.length > 0) {
    errEl.textContent = 'Échec partiel : ' + failed.map(r => r.error || 'inconnu').join(' · ');
    errEl.style.display = 'block';
    btn.disabled = false; btn.textContent = 'Enregistrer';
    return;
  }

  closeEditUserModal();
  renderParamsPratList();
}

function switchCaptureMode(mode) {
  document.getElementById('mode-photo').style.display = mode==='photo'?'':'none';
  document.getElementById('mode-video').style.display = mode==='video'?'':'none';
  document.getElementById('sw-photo').className = mode==='photo'?'btn btn-blue':'btn';
  document.getElementById('sw-video').className = mode==='video'?'btn btn-blue':'btn';
}

async function launchTest(testId) {
  if (!currentPatient) { alert('Sélectionnez d\'abord un patient.'); nav('pg-patients'); return; }
  const t = TESTS[testId]; if (!t) return;
  currentTestId = testId;
  testMode = t.mode;

  // Init marqueurs
  liveMarkers = cloneMarkers(t.markers);
  vidMarkers = cloneMarkers(t.markers);
  selectedMkrIdx = -1; isDragging = false;
  selectedVidMkrIdx = -1; isVidDragging = false;

  // Init photos - charger les données sauvegardées si elles existent
  const savedData = currentPatient?.mesures?.[testId];
  if(savedData && savedData.photos && savedData.photos.length) {
    photoSlots = savedData.photos.map((p,i) => ({
      label: p.label || (t.photoLabels[i]||'Photo '+(i+1)),
      side: p.side || (t.photoSides?.[i]||''),
      dataUrl: p.dataUrl || null,
      angle: p.angle !== undefined ? p.angle : null,
      angleD: p.angleD !== undefined ? p.angleD : null,
      angleG: p.angleG !== undefined ? p.angleG : null,
      path: p.path || null
    }));
    // Compléter si slots manquants
    while(photoSlots.length < t.photoLabels.length) {
      const i = photoSlots.length;
      photoSlots.push({label:t.photoLabels[i]||'Photo '+(i+1), side:t.photoSides?.[i]||'', dataUrl:null, angle:null, path:null});
    }
  } else {
    photoSlots = t.photoLabels.map((l,i) => ({
      label:l, side: t.photoSides?.[i]||'', dataUrl:null, angle:null, path:null
    }));
  }

  // Charger frames sauvegardées
  if(savedData && savedData.frames && savedData.frames.length) {
    capturedFrames = savedData.frames.map(f => ({
      time: f.time||0, dataUrl: f.dataUrl||null,
      angD: f.angD!==undefined?f.angD:null,
      angG: f.angG!==undefined?f.angG:null,
      markers: f.markers||[],
      path: f.path || null
    }));
  } else {
    capturedFrames = [];
  }
  selectedFrameIdx = -1;

  // Prefetch Storage paths → populate dataUrls en RAM (Task #53 PR B2).
  // Mutate photoSlots/capturedFrames entries en place AVANT les renders
  // (renderPhotoGrid/renderFrameStrip lisent .dataUrl pour les thumbnails).
  // On prefetch directement dans les globaux RAM plutôt que dans
  // currentPatient.mesures pour éviter de polluer la struct persistée si
  // l'utilisateur déclenche un archivage sans avoir d'abord re-sauvegardé.
  await prefetchSportPhotos({ photos: photoSlots, frames: capturedFrames });

  // Mise à jour UI
  document.getElementById('cap-name').textContent = t.name;
  document.getElementById('cap-note').textContent = t.note;
  document.getElementById('cap-mode-badge').textContent = t.mode==='video'?'Vidéo':'Photo';
  document.getElementById('cap-pt-badge').textContent = currentPatient.prenom+' '+currentPatient.nom;
  document.getElementById('cap-mkr-title').textContent = `Marqueurs (${liveMarkers.length})`;
  document.getElementById('mode-photo').style.display = (t.mode==='photo'||t.mode==='both')?'':'none';
  document.getElementById('mode-video').style.display = (t.mode==='video'||t.mode==='both')?'':'none';
  // Pour mode 'both': montrer onglets de switch
  const hasBoth = t.mode==='both';
  document.getElementById('mode-switch-row').style.display = hasBoth?'flex':'none';
  if(!hasBoth && t.mode==='video') {
    document.getElementById('mode-photo').style.display='none';
    document.getElementById('mode-video').style.display='';
  }

  renderMkrList();
  renderPhotoGrid();
  renderFrameStrip();
  updateResults();

  // Afficher les slots photos dans le mode vidéo si showPhotoSlots
  const vidSlotsEl = document.getElementById('vid-photo-slots');
  const vidGridEl = document.getElementById('vid-photo-grid');
  if(vidSlotsEl && vidGridEl) {
    if(t.showPhotoSlots && testMode === 'video') {
      vidSlotsEl.style.display = '';
      renderVidPhotoGrid();
    } else {
      vidSlotsEl.style.display = 'none';
    }
  }

  // Pré-remplir le sélecteur de caméra photo
  if(testMode === 'photo') {
    setTimeout(() => enumerateCameras('cam-select'), 300);
  }
  nav('pg-capture');
}

// ══════════════════════════════════════════════════════
// PATIENTS
// ══════════════════════════════════════════════════════

// Calcule en bytes la taille totale stockée par BioMéca dans localStorage.
// Utilise la propriété character.length × 2 (UTF-16 en JS) comme approximation.
function getBioMecaStorageBytes() {
  let total = 0;
  try {
    for (let i = 0; i < localStorage.length; i++) {
      const key = localStorage.key(i);
      if (key && key.startsWith('bm4-')) {
        const val = localStorage.getItem(key) || '';
        total += (key.length + val.length) * 2;
      }
    }
  } catch(e) {}
  return total;
}

// Quota typique Chrome/Edge ~10 Mo (limite réelle), Safari/Firefox 5 Mo. On aligne
// le threshold sur Chrome pour ne pas bloquer prématurément les utilisateurs principaux.
// Le catch QuotaExceededError reste le filet de sécurité ultime, qui prendra le relais
// sur Safari/Firefox quand le mur 5 Mo strict est atteint.
const STORAGE_QUOTA_BYTES = 10 * 1024 * 1024;
const STORAGE_WARNING_THRESHOLD = 0.80;
const STORAGE_CRITICAL_THRESHOLD = 0.95;

// État pour ne pas spammer l'utilisateur avec des alertes répétées
let _quotaWarningShown = false;

// #81 + Bug RAM-leak posturo — strip in-place les dataURLs déjà migrées (Path set)
// pour éviter qu'elles re-saturent le localStorage à chaque savePatients. Le pattern
// posturo prefetchPosturoPhotos écrit la dataURL réhydratée DIRECTEMENT dans
// currentPatient.bilanDataPosturo (objet persisté) ; savePosturoBilan fait ensuite
// Object.assign(d, photoStash) pour preserve display RAM. Sans strip à savePatients,
// tout savePatients() ultérieur (saveBilanSilent sport, navigation, …) écrirait
// les dataURLs en localStorage → bug 0.10 → 2.46 Mo observé E2E.
//
// Garantie : strip UNIQUEMENT si obj[k+'Path'] set ET obj[k] = dataURL. Une édition
// (cf 10 invalidations Path à mouseup/capture L10926-L10942/L13053/L13064/L13091/
// L8598-L8602/L8905-L8910) a Path absent → jamais strippée → migration ultérieure
// uploadera proprement. Couverture exhaustive : bilanData courant + bilanDataPosturo
// courant + mesures (photos+frames) + archives bilansSport (bilanData + mesures)
// + archives bilansPosturo.
function _stripDataURLsForPersist(patientsArr) {
  const stash = []; // [{ obj, key, dataUrl }]
  const stripObjFlat = (obj, keysList) => {
    if (!obj) return;
    for (const k of keysList) {
      if (obj[k + 'Path'] && typeof obj[k] === 'string' && obj[k].startsWith('data:')) {
        stash.push({ obj, key: k, dataUrl: obj[k] });
        delete obj[k];
      }
    }
  };
  const stripMesures = (mesures) => {
    if (!mesures) return;
    for (const tid in mesures) {
      if (tid.startsWith('_')) continue;
      const t = mesures[tid];
      for (const arr of [t?.photos, t?.frames]) {
        if (!Array.isArray(arr)) continue;
        for (const entry of arr) {
          if (entry && entry.path && typeof entry.dataUrl === 'string' && entry.dataUrl.startsWith('data:')) {
            stash.push({ obj: entry, key: 'dataUrl', dataUrl: entry.dataUrl });
            delete entry.dataUrl;
          }
        }
      }
    }
  };
  // #85 Bug RAM-leak neuro4 — purge DÉFINITIVE des clés image qui ont pollué
  // bilanDataPosturo.neuro4 (et archives) via l'ancien Object.assign(d.neuro4,
  // bilanData) L13042. Aucun call-site légitime ne lit ces clés depuis neuro4
  // (les readers L13307/L13464 filtrent boolean). Donc pas de stash/restore :
  // c'est de la donnée à éliminer définitivement, RAM ET persisté. La pollution
  // existante se résorbe au prochain savePatients.
  const purgeImagesFromNeuro4 = (obj) => {
    if (!obj || !obj.neuro4) return;
    for (const k of SPORT_BILAN_PHOTO_KEYS) {
      delete obj.neuro4[k];
      delete obj.neuro4[k + 'Path'];
    }
    for (const k of POSTURO_PHOTO_KEYS) {
      delete obj.neuro4[k];
      delete obj.neuro4[k + 'Path'];
    }
  };
  for (const p of patientsArr) {
    stripObjFlat(p.bilanData, SPORT_BILAN_PHOTO_KEYS);
    stripObjFlat(p.bilanDataPosturo, POSTURO_PHOTO_KEYS);
    purgeImagesFromNeuro4(p.bilanDataPosturo);
    stripMesures(p.mesures);
    if (Array.isArray(p.bilansSport)) for (const arch of p.bilansSport) {
      stripObjFlat(arch.bilanData, SPORT_BILAN_PHOTO_KEYS);
      stripMesures(arch.mesures);
    }
    if (Array.isArray(p.bilansPosturo)) for (const arch of p.bilansPosturo) {
      stripObjFlat(arch.bilanDataPosturo, POSTURO_PHOTO_KEYS);
      purgeImagesFromNeuro4(arch.bilanDataPosturo);
    }
  }
  return stash;
}

// #114-1a — Compte des « unités de travail » comparables entre deux snapshots
// patients[] : nombre de patients + total bilans sport + total bilans posturo
// + markers posturaux placés + photos posturales (dataURL inline ou Path).
// Utilisé par le reconcile fallback de saveToSupabase pour décider si le cloud
// est PLUS RICHE que la mémoire locale (donc à ne pas écraser). Métriques
// volontairement insensibles aux clés méta (_bilanId, etc.) qui ne représentent
// pas du travail clinique.
// #117-incident — Compte aussi les unités (markers + photos) des bilans
// ARCHIVÉS, pas seulement du bilan courant. Sinon archiver (finalize) ou
// créer un Contrôle (qui copie + reset le courant) déplace le travail
// clinique du courant vers une archive, comptabilisé seulement comme +1
// (l'archive) tandis que les markers/photos du courant disparaissent du
// total → faux positif « réduction » de la garde de richesse. Helper
// countBd factorisé pour appliquer la même règle au courant ET à chaque
// archive de manière symétrique.
function _countDataUnits(arr) {
  if (!Array.isArray(arr)) return 0;
  const countBd = (bd) => {
    if (!bd) return 0;
    let c = 0;
    const pa = bd._postureAnalysis || {};
    for (const vk in pa) c += (pa[vk]?.markers?.filter(m => m && m.nx != null).length) || 0;
    ['Face','Dos','ProfilG','ProfilD'].forEach(v => { if (bd['_posture'+v] || bd['_posture'+v+'Path']) c += 1; });
    return c;
  };
  let n = arr.length;
  for (const p of arr) {
    n += (p.bilansSport?.length || 0) + (p.bilansPosturo?.length || 0);
    n += countBd(p.bilanData) + countBd(p.bilanDataPosturo);
    (p.bilansSport || []).forEach(b => { n += countBd(b.bilanData); });
    (p.bilansPosturo || []).forEach(b => { n += countBd(b.bilanDataPosturo); });
  }
  return n;
}

function _restoreDataURLsAfterPersist(stash) {
  for (const { obj, key, dataUrl } of stash) {
    obj[key] = dataUrl;
  }
}

function savePatients() {
  // #81 + Bug RAM-leak — strip in-place AVANT toute sérialisation. try/finally
  // GARANTIT la restauration RAM sur TOUS les chemins de sortie (return false
  // critique threshold, return false quota, throw, return normal). RAM continue
  // d'afficher les dataURLs pour les renderers ; localStorage est propre.
  const _stripStash = _stripDataURLsForPersist(patients);
  try {
  // #114-1b — Garde de richesse : refuse une chute brutale de données sans
  // confirmation explicite (filet anti-effacement façon Maeva). Compare la
  // mémoire à la dernière version localStorage (post-strip des deux côtés
  // → comparaison cohérente, sans inflation par les dataURLs présentes
  // seulement en RAM). Déclenche si on perd un patient entier OU >= 8 unités
  // de travail. return false → le try/finally restaure les dataURLs en RAM.
  try {
    const storedRaw = localStorage.getItem('bm4-patients');
    if (storedRaw) {
      const stored = JSON.parse(storedRaw);
      if (Array.isArray(stored)) {
        const storedUnits = _countDataUnits(stored);
        const newUnits = _countDataUnits(patients);
        const lostPatient = patients.length < stored.length;
        const bigDrop = (storedUnits - newUnits) >= 8;
        // #117-incident — Skip la garde si la réduction est VOLONTAIRE (drapeau
        // levé par le handler qui supprime). Sinon la pop-up devient du bruit
        // sur chaque suppression légitime.
        if ((lostPatient || bigDrop) && !_intentionalReduction) {
          const ok = confirm(
            '⚠️  SAUVEGARDE QUI RÉDUIT VOS DONNÉES\n\n' +
            'Cette sauvegarde supprimerait des données par rapport à la dernière version enregistrée\n' +
            '(' + stored.length + ' patient(s) / ' + storedUnits + ' éléments → ' + patients.length + ' / ' + newUnits + ').\n\n' +
            '➡️  Cliquez ANNULER pour PROTÉGER vos données (recommandé).\n' +
            'Ne cliquez OK QUE si vous venez VOLONTAIREMENT de supprimer un patient ou un bilan.'
          );
          if (!ok) return false; // abort — le finally restaure les dataURLs en RAM
        }
      }
    }
  } catch (e) { /* parse échoué → on ne bloque pas, save normal */ }
  const beforeBytes = getBioMecaStorageBytes();

  // Calcul de la taille future après sérialisation : seul bm4-patients change.
  // (savePatients() n'écrit que bm4-patients ; bm4-praticiens est géré par savePraticiens.)
  const futurePatientsBytes = JSON.stringify(patients).length * 2;
  const futureKeyBytes = 'bm4-patients'.length * 2;
  // Reconstituer la taille post-save totale du stockage BioMéca
  let otherKeysBytes = 0;
  try {
    for (let i = 0; i < localStorage.length; i++) {
      const key = localStorage.key(i);
      if (key && key.startsWith('bm4-') && key !== 'bm4-patients') {
        const val = localStorage.getItem(key) || '';
        otherKeysBytes += (key.length + val.length) * 2;
      }
    }
  } catch(e) {}
  const futureBytes = futurePatientsBytes + futureKeyBytes + otherKeysBytes;

  const ratio = beforeBytes / STORAGE_QUOTA_BYTES;
  const isReduction = futureBytes <= beforeBytes;

  // Seuil critique : on refuse SEULEMENT si on est au-dessus ET qu'on n'est pas en train de réduire.
  // Si l'opération réduit le stockage (suppression), on autorise toujours pour permettre le déblocage.
  if (ratio >= STORAGE_CRITICAL_THRESHOLD && !isReduction) {
    const used = (beforeBytes / 1024 / 1024).toFixed(1);
    alert(
      '⚠️ ESPACE DE STOCKAGE CRITIQUE\n\n' +
      'Vous utilisez ' + used + ' Mo sur 10 Mo disponibles dans le stockage local du navigateur.\n\n' +
      'Pour éviter toute perte de données :\n' +
      '• Supprimez d\'anciens bilans archivés (fiche patient → ✕ à côté du bilan)\n' +
      '• Ou supprimez d\'anciens patients de test (page Patients → ✕)\n\n' +
      'La sauvegarde de cette modification est ANNULÉE pour protéger vos données existantes. ' +
      'Une fois de l\'espace libéré, vos modifications en cours seront sauvegardées au prochain enregistrement.'
    );
    return false;
  }

  try {
    localStorage.setItem('bm4-patients', JSON.stringify(patients));
  } catch(e) {
    if (e && (e.name === 'QuotaExceededError' || e.code === 22 || (e.message && e.message.toLowerCase().includes('quota')))) {
      alert(
        '⚠️ ESPACE DE STOCKAGE PLEIN\n\n' +
        'La sauvegarde a échoué : la limite de 5 à 10 Mo selon le navigateur est atteinte.\n\n' +
        'Vos modifications en cours sont en mémoire mais NON sauvegardées sur cet appareil. ' +
        'NE FERMEZ PAS l\'onglet avant d\'avoir libéré de l\'espace :\n' +
        '• Supprimez d\'anciens bilans archivés\n' +
        '• Ou d\'anciens patients de test\n\n' +
        'Réessayez ensuite la sauvegarde.'
      );
      return false;
    }
    // Autre erreur inattendue — la propager pour qu'elle soit visible
    throw e;
  }

  // Seuil de warning : on alerte une seule fois mais on laisse la sauvegarde se faire.
  // Si on vient de réduire (isReduction), on n'affiche pas le warning même si encore au-dessus du seuil
  // — le but est de ne pas spammer l'utilisateur qui est en train de nettoyer son stockage.
  const afterBytes = getBioMecaStorageBytes();
  const afterRatio = afterBytes / STORAGE_QUOTA_BYTES;
  if (afterRatio >= STORAGE_WARNING_THRESHOLD && !_quotaWarningShown && !isReduction) {
    _quotaWarningShown = true;
    const used = (afterBytes / 1024 / 1024).toFixed(1);
    const pct = Math.round(afterRatio * 100);
    console.warn('BioMéca storage usage:', used + ' Mo (' + pct + '%)');
    alert(
      '⚠️ Espace de stockage à ' + pct + ' %\n\n' +
      'Vous utilisez ' + used + ' Mo sur 10 Mo disponibles. La sauvegarde s\'est bien effectuée, ' +
      'mais pensez à archiver ou supprimer d\'anciens bilans pour éviter une saturation prochaine.\n\n' +
      '(Cette alerte ne s\'affichera qu\'une fois par session.)'
    );
  }

  saveToSupabase();
  return true;
  } finally {
    // #81 + Bug RAM-leak — restauration RAM garantie sur TOUS les chemins de
    // sortie (return false critique, return false quota, throw, return normal).
    // Les renderers (img.src, canvas drawImage) continuent de trouver les
    // dataURLs en RAM. Persisté = propre, RAM = display continu.
    _restoreDataURLsAfterPersist(_stripStash);
  }
}

