function savePraticiens() {
  localStorage.setItem('bm4-praticiens', JSON.stringify(praticiens));
  saveToSupabase();
}

function createPraticien() {
  const nom = document.getElementById('pr-nom').value.trim();
  if (!nom) { alert('Nom obligatoire.'); return; }
  const pr = {
    id:Date.now(), nom,
    titre:document.getElementById('pr-titre').value,
    cabinet:document.getElementById('pr-cabinet').value,
    tel:document.getElementById('pr-tel').value,
    adresse:document.getElementById('pr-adresse').value,
    email:document.getElementById('pr-email').value,
  };
  praticiens.push(pr); savePraticiens();
  ['pr-nom','pr-titre','pr-cabinet','pr-tel','pr-adresse','pr-email'].forEach(id=>{document.getElementById(id).value='';});
  renderPratList(); populatePratSelect();
  alert(`✓ Praticien enregistré : ${pr.nom}`);
}

function deletePraticien(i) {
  if(!confirm('Supprimer ce praticien ?')) return;
  praticiens.splice(i,1); savePraticiens(); renderPratList(); populatePratSelect();
}




function createBilanInitial(patIdx) {
  const p = patients[patIdx];
  if(!p) return;
  selectPatient(p);
  p.bilanInitialDate = new Date().toLocaleDateString('fr-FR');
  savePatients();
  renderPatientList();
  nav('pg-sport');
}

function createBilanControle(patIdx) {
  const p = patients[patIdx];
  if(!p) return;
  // Sauvegarder l'état actuel du bilan comme historique
  if(!p.bilans) p.bilans = [];
  const num = p.bilans.length + 1;
  const bilan = {
    label: 'Bilan de contrôle ' + num,
    date: new Date().toLocaleDateString('fr-FR'),
    mesures: JSON.parse(JSON.stringify(p.mesures||{})),
    bilanData: JSON.parse(JSON.stringify(p.bilanData||{}))
  };
  p.bilans.push(bilan);
  // Réinitialiser les mesures pour le nouveau bilan
  p.mesures = {};
  p.bilanData = {};
  savePatients();
  selectPatient(p);
  renderPatientList();
  nav('pg-sport');
}

function loadBilanFromHistory(patIdx, bilanIdx) {
  const p = patients[patIdx];
  if(!p || !p.bilans || !p.bilans[bilanIdx]) return;
  const bilan = p.bilans[bilanIdx];
  selectPatient(p);
  currentPatient.mesures = bilan.mesures;
  currentPatient.bilanData = bilan.bilanData;
  nav('pg-rapport');
}

// ---- NOUVEAU SYSTÈME BILANS ----

// Abandonne le bilan sport en cours sans archiver. Utile pour annuler un bilan
// démarré par erreur ou vide. Confirme avec l'utilisateur si des données existent.
function abandonnerBilanSport(patIdx) {
  const p = patients[patIdx];
  if (!p) return;
  const hasMesures = p.mesures && Object.keys(p.mesures).length > 0;
  const hasBilanData = hasBilanDataContent(p.bilanData);
  let confirmMsg;
  if (hasMesures || hasBilanData) {
    const nbTests = hasMesures ? Object.keys(p.mesures).length : 0;
    const parts = [];
    if (nbTests > 0) parts.push(nbTests + ' test(s) saisi(s)');
    if (hasBilanData) parts.push('saisie clinique');
    const desc = parts.join(' + ');
    confirmMsg = 'Abandonner le bilan en cours ?\n\nVous allez perdre : ' + desc + '.\n\nCette action est irréversible.';
  } else {
    confirmMsg = 'Abandonner le bilan en cours ?\n\nLe bilan est actuellement vide (aucune donnée saisie). Cette action supprimera le bilan démarré.';
  }
  if (!confirm(confirmMsg)) {
    return;
  }
  p.mesures = {};
  p.bilanData = {};
  delete p.currentBilanSportSousType;
  currentOpenedBilanIdx = null;
  // #117-incident — Abandon VOLONTAIRE d'un bilan en cours → suppress la garde.
  _intentionalReduction = true;
  try { savePatients(); } finally { _intentionalReduction = false; }
  renderPatientList();
}

// Archive le bilan sport en cours (currentPatient.mesures) dans bilansSport[]
// sans démarrer un nouveau bilan. Reste sur la fiche patient.
function finalizeBilanSport(patIdx) {
  const p = patients[patIdx];
  if (!p) return;
  const hasMesures = p.mesures && Object.keys(p.mesures).length > 0;
  const hasBilanData = hasBilanDataContent(p.bilanData);
  if (!hasMesures && !hasBilanData) {
    alert('Aucun test ni saisie clinique n\'a été effectué dans le bilan en cours.');
    return;
  }
  if (!p.bilansSport) p.bilansSport = [];
  // Task [#71] — Numérotation Contrôle basée UNIQUEMENT sur les bilans Contrôle
  // déjà archivés (filter type === 'controle'), pas sur bilansSport.length qui
  // inclut l'Initial → bug "Sportif Contrôle 2" au lieu de "1" pour le 1er Contrôle.
  const num = p.bilansSport.filter((b) => b.type === 'controle').length + 1;
  const type = p.currentBilanSportSousType || 'initial';
  const label = type === 'initial' ? 'Sportif Initial' : 'Sportif Contrôle ' + num;
  p.bilansSport.push({
    label: label,
    type: type,
    date: new Date().toLocaleDateString('fr-FR'),
    mesures: JSON.parse(JSON.stringify(p.mesures)),
    bilanData: JSON.parse(JSON.stringify(p.bilanData || {}))
  });
  // Reset du bilan en cours
  p.mesures = {};
  p.bilanData = {};
  delete p.currentBilanSportSousType;
  currentOpenedBilanIdx = null;
  // #99 + Bug édition perdue — reset _userDirty pour les 5 canvas sport :
  // l'archive est figée, le nouveau bilan en cours est vide → clean.
  ['morpho-face','morpho-face2','morpho-profilG','morpho-profilD','pieds-canvas'].forEach(id => {
    const c = document.getElementById(id);
    if(c) c._userDirty = false;
  });
  savePatients();
  renderPatientList();
  alert('✓ Bilan "' + label + '" archivé avec succès.');
}

// Abandonne le bilan posturo en cours sans archiver. Mirror de abandonnerBilanSport.
function abandonnerBilanPosturo(patIdx) {
  const p = patients[patIdx];
  if (!p) return;
  const hasBilanPosturoData = hasBilanDataContent(p.bilanDataPosturo);
  let confirmMsg;
  if (hasBilanPosturoData) {
    confirmMsg = 'Abandonner le bilan postural en cours ?\n\nVous allez perdre : saisie clinique.\n\nCette action est irréversible.';
  } else {
    confirmMsg = 'Abandonner le bilan postural en cours ?\n\nLe bilan est actuellement vide (aucune donnée saisie). Cette action supprimera le bilan démarré.';
  }
  if (!confirm(confirmMsg)) return;
  p.bilanDataPosturo = {};
  delete p.currentBilanPosturoSousType;
  currentOpenedBilanPosturoIdx = null;
  // #117-incident — Abandon VOLONTAIRE d'un bilan posturo en cours → suppress la garde.
  _intentionalReduction = true;
  try { savePatients(); } finally { _intentionalReduction = false; }
  renderPatientList();
}

// Archive le bilan postural en cours dans bilansPosturo[] sans démarrer un nouveau bilan.
function finalizeBilanPosturo(patIdx) {
  const p = patients[patIdx];
  if (!p) return;
  const hasBilanPosturoData = hasBilanDataContent(p.bilanDataPosturo);
  if (!hasBilanPosturoData) {
    alert('Aucune saisie clinique n\'a été effectuée dans le bilan postural en cours.');
    return;
  }
  if (!p.bilansPosturo) p.bilansPosturo = [];
  // Label position-based : 0 archives → "Posturo Initial" (sans numéro),
  // ≥1 archives → "Posturo Contrôle N" (N = nombre d'archives existantes).
  const existingCount = p.bilansPosturo.length;
  const label = existingCount === 0 ? 'Posturo Initial' : 'Posturo Contrôle ' + existingCount;
  const archivedType = existingCount === 0 ? 'initial' : 'controle';
  p.bilansPosturo.push({
    label: label,
    type: archivedType,
    date: new Date().toLocaleDateString('fr-FR'),
    bilanDataPosturo: JSON.parse(JSON.stringify(p.bilanDataPosturo))
  });
  p.bilanDataPosturo = {};
  delete p.currentBilanPosturoSousType;
  currentOpenedBilanPosturoIdx = null;
  savePatients();
  renderPatientList();
  alert('✓ Bilan "' + label + '" archivé avec succès.');
}

function creerBilanSport(patIdx, type) {
  // Gating task #57 — bloque la création si pas full access.
  if (window._accessLevel && window._accessLevel !== 'full') {
    showAccessRestrictedModal('create_bilan');
    return;
  }
  const p = patients[patIdx];
  if(!p) return;
  // Sauvegarder bilan courant si données existantes ET bilan effectivement en cours
  // (sousType set). Task #69.4 — sans ce check sousType, les mesures résiduelles
  // d'une archive ouverte par ouvrirBilanSport déclencheraient un faux confirm
  // "bilan en cours" puis push doublon de l'archive. Parité avec creerBilanPosturo.
  if(p.currentBilanSportSousType && p.mesures && Object.keys(p.mesures).length > 0) {
    const nbTests = Object.keys(p.mesures).length;
    const confirmMsg = 'Vous avez un bilan en cours avec ' + nbTests + ' test(s) saisi(s).\n\n' +
      'Voulez-vous le finaliser et archiver maintenant, puis démarrer un nouveau bilan ?\n\n' +
      '• OK : finalise et archive le bilan en cours, puis démarre un nouveau bilan ' + (type === 'initial' ? 'initial' : 'de contrôle') + '.\n' +
      '• Annuler : retour à la fiche patient pour utiliser le bouton "Finaliser et archiver" du bilan en cours.';
    if (!confirm(confirmMsg)) {
      return;
    }
    if(!p.bilansSport) p.bilansSport = [];
    // Task [#71] — voir finalizeBilanSport L2812 pour la justification détaillée.
    const num = p.bilansSport.filter((b) => b.type === 'controle').length + 1;
    p.bilansSport.push({
      label: type === 'initial' ? 'Sportif Initial' : 'Sportif Contrôle ' + num,
      type: type,
      date: new Date().toLocaleDateString('fr-FR'),
      mesures: JSON.parse(JSON.stringify(p.mesures||{})),
      bilanData: JSON.parse(JSON.stringify(p.bilanData||{}))
    });
  }
  // Nouveau bilan vide
  p.mesures = {};
  p.bilanData = {};
  p.currentBilanSportSousType = type;
  // NE PAS toucher currentBilanPosturoSousType — laisse l'autre bilan en cours intact.
  savePatients();
  currentOpenedBilanIdx = null;
  selectPatient(p);
  nav('pg-sport');
}

function ouvrirBilanSport(patIdx, bilanIdx) {
  const p = patients[patIdx];
  if(!p) return;
  const bilan = p.bilansSport?.[bilanIdx];
  if(!bilan) {
    // Bilan courant
    currentOpenedBilanIdx = null;
    selectPatient(p);
    nav('pg-sport');
    return;
  }
  // Task #69 — Check data-loss AVANT selectPatient (qui aurait des side-effects
  // DOM via clearBilanFields/loadBilan). On utilise p.* (pas currentPatient.*)
  // pour ne pas dépendre du timing pre/post-selectPatient. Le warning ne
  // s'affiche QUE si l'écrasement causerait une perte réelle (data-driven).
  const hasMesures = p.mesures && Object.keys(p.mesures).length > 0;
  const hasBilanData = hasBilanDataContent(p.bilanData);
  // Task [#70] — check sousType en plus de mesures/bilanData : sinon le résidu
  // d'une archive précédemment ouverte (mesures écrasées par ouvrirBilanSport,
  // sousType deleted par #69.3) déclenche un faux confirm "perdre vos données
  // actuelles" alors qu'il s'agit en réalité des mesures de l'archive précédente.
  // Parité avec creerBilanSport #69.4 qui a déjà ce check.
  if (p.currentBilanSportSousType && (hasMesures || hasBilanData)) {
    if (!confirm('⚠️ Vous avez un bilan en cours non-archivé. Ouvrir cette archive perdra vos données actuelles.\n\nCliquez Annuler puis allez finaliser ou abandonner votre bilan en cours d\'abord.')) {
      return;
    }
  }
  selectPatient(p);
  currentPatient.mesures = JSON.parse(JSON.stringify(bilan.mesures||{}));
  currentPatient.bilanData = JSON.parse(JSON.stringify(bilan.bilanData||{}));
  // #117-incident — Resync IMMÉDIATE de la globale bilanData avec l'archive chargée,
  // sinon une sauvegarde déclenchée AVANT loadBilan (capture/import depuis pg-sport,
  // auto-save) écraserait currentPatient.bilanData par une globale périmée sans
  // _postureAnalysis → perte des points de posture.
  bilanData = JSON.parse(JSON.stringify(currentPatient.bilanData));
  currentOpenedBilanIdx = bilanIdx;
  currentOpenedBilanPosturoIdx = null;  // Task #69 bonus — symétrie cross-modal avec ouvrirBilanPosturo L3180
  // Task #69.3 — Reset flag "bilan en cours" sport pour éviter état hybride
  // corrompu (bandeau orange affichant un faux bilan en cours avec les mesures
  // de l'archive). Le user a explicitement consenti à perdre son bilan en cours
  // via le confirm() ci-dessus. Cohérent avec le pattern delete sousType utilisé
  // par abandonner/finalize/creer.
  delete p.currentBilanSportSousType;
  nav('pg-sport');
}

function creerBilanPosturo(patIdx, type) {
  // Gating task #57 — bloque la création si pas full access.
  if (window._accessLevel && window._accessLevel !== 'full') {
    showAccessRestrictedModal('create_bilan');
    return;
  }
  const p = patients[patIdx];
  if(!p) return;
  // Archiver UNIQUEMENT si in-progress (sousType set), pas si viewing-only.
  // Viewing-only = data chargée par ouvrirBilanPosturo SANS sousType set
  // → cliquer Initial/Contrôle ne doit PAS créer une archive fantôme.
  const isInProgress = p.currentBilanPosturoSousType != null;
  const hasData = p.bilanDataPosturo && Object.keys(p.bilanDataPosturo).length > 0;
  if(isInProgress && hasData) {
    const confirmMsg = 'Vous avez un bilan postural en cours.\n\n' +
      'Voulez-vous le finaliser et archiver maintenant, puis démarrer un nouveau bilan ?\n\n' +
      '• OK : finalise et archive le bilan en cours, puis démarre un nouveau bilan.\n' +
      '• Annuler : retour à la fiche patient pour utiliser le bouton "Finaliser et archiver" du bilan en cours.';
    if (!confirm(confirmMsg)) return;
    if(!p.bilansPosturo) p.bilansPosturo = [];
    // Label position-based : 0 archives → "Posturo Initial" (sans numéro),
    // ≥1 archives → "Posturo Contrôle N" (N = nombre d'archives existantes).
    const existingCount = p.bilansPosturo.length;
    const archiveLabel = existingCount === 0 ? 'Posturo Initial' : 'Posturo Contrôle ' + existingCount;
    const archiveType = existingCount === 0 ? 'initial' : 'controle';
    p.bilansPosturo.push({
      label: archiveLabel,
      type: archiveType,
      date: new Date().toLocaleDateString('fr-FR'),
      bilanDataPosturo: JSON.parse(JSON.stringify(p.bilanDataPosturo))
    });
  }
  // Reset état pour démarrer un nouveau bilan vide
  p.bilanDataPosturo = {};
  p.currentBilanPosturoSousType = type;
  // NE PAS toucher currentBilanSportSousType — laisse l'autre bilan en cours intact.
  savePatients();
  currentOpenedBilanPosturoIdx = null;
  selectPatient(p);
  nav('pg-bilan-posturo');
}

async function supprimerBilanSport(patIdx, bilanIdx) {
  const p = patients[patIdx];
  if(!p) return;
  const bilan = p.bilansSport?.[bilanIdx];
  if(!bilan) return;
  if(!confirm('Supprimer le bilan "' + bilan.label + '" du ' + bilan.date + ' ? Cette action est irréversible.')) return;
  // Cleanup Storage best-effort (Task #53 PR B2) — purge le dossier
  // {userId}/{patientId}/sport/{bilanId}/ qui contient toutes les photos
  // et frames du bilan, y compris les orphelins issus de remplacements.
  // Si l'opération échoue, on log un warning et on procède quand même au
  // splice : la suppression de l'archive est l'intention principale.
  // Les bilans très anciens (pré-B2) n'ont pas de _bilanId → cleanup
  // skip (aucun fichier Storage à purger pour eux).
  const bilanId = bilan.mesures?._bilanId;
  if(pwaUser?.id && bilanId) {
    const r = await deleteSportBilanFolder(pwaUser.id, p.id, bilanId);
    if(!r.ok) console.warn('[supprimerBilanSport] Storage cleanup failed:', r.error);
  }
  p.bilansSport.splice(bilanIdx, 1);
  // #117-incident — Suppression VOLONTAIRE d'une archive sport → suppress la garde.
  _intentionalReduction = true;
  try { savePatients(); } finally { _intentionalReduction = false; }
  renderPatientList();
}

function supprimerBilanPosturo(patIdx, bilanIdx) {
  const p = patients[patIdx];
  if(!p) return;
  const bilan = p.bilansPosturo?.[bilanIdx];
  if(!bilan) return;
  if(!confirm('Supprimer le bilan "' + bilan.label + '" du ' + bilan.date + ' ? Cette action est irréversible.')) return;
  p.bilansPosturo.splice(bilanIdx, 1);
  // #117-incident — Suppression VOLONTAIRE d'une archive posturo → suppress la garde.
  _intentionalReduction = true;
  try { savePatients(); } finally { _intentionalReduction = false; }
  renderPatientList();
}

// Clés photo du bilan posturo (Task #51 PR B1). Pour chaque clé `_xxx`,
// on persiste `_xxxPath` en DB ; la dataUrl correspondante (`_xxx`) reste
// en RAM le temps de l'édition mais n'est jamais sauvegardée.
// #85 Phase 1 — extension : 4 captures Analyse posturale (face/dos/profilG/profilD).
// savePosturoBilan est déjà async + appelle migratePosturoPhotos → migration auto.
const POSTURO_PHOTO_KEYS = [
  '_empreinte', '_bodyCanvas', '_feetDrawings', '_feetComposite',
  '_postureFace', '_postureDos', '_postureProfilG', '_postureProfilD'
];

// Pour chaque clé photo : si seul le path est présent en DB, on récupère
// la dataUrl depuis Storage et on la réinjecte dans `d[key]` pour que les
// renderers (img.src, canvas drawImage) trouvent ce qu'ils attendent.
// Échec silencieux (warning console) — l'UI affichera un placeholder vide
// pour la photo manquante, ce qui est acceptable.
async function prefetchPosturoPhotos(d) {
  if (!d) return;
  // #85 Fix race boot — refresh préventif si JWT proche de l'expiration.
  await ensureSession();
  await Promise.all(POSTURO_PHOTO_KEYS.map(async k => {
    const pathKey = k + 'Path';
    if (!d[pathKey] || d[k]) return;
    const r = await prefetchPhotoToDataUrl(d[pathKey]);
    if (r.ok) d[k] = r.dataUrl;
    else console.warn('[posturo] prefetch fail', pathKey, '→', r.error);
  }));
}

// Migration lazy des photos posturo vers Storage. Pour chaque clé `_xxx`
// qui contient encore une dataUrl, upload vers patient-media et remplace
// par `_xxxPath` (côté `d`). Les dataUrls réussies sont SUPPRIMÉES de `d`
// par migratePhotoEntry ; en cas d'échec, la dataUrl reste pour retry au
// prochain save (lazy retry). Retourne un stash des dataUrls initiales,
// pour que le caller puisse les restaurer en RAM après savePatients().
async function migratePosturoPhotos(d, patientId, bilanId) {
  // #85 Fix race boot — refresh préventif avant les uploads Storage.
  await ensureSession();
  const stash = {};
  for (const k of POSTURO_PHOTO_KEYS) {
    if (d[k] && typeof d[k] === 'string' && d[k].startsWith('data:')) {
      stash[k] = d[k];
    }
  }
  if (Object.keys(stash).length === 0) return stash;
  const pathArgs = { userId: pwaUser?.id, patientId, type: 'posturo', bilanId };
  const results = await Promise.all(
    POSTURO_PHOTO_KEYS.map(k => migratePhotoEntry(d, k, pathArgs))
  );
  results.forEach((r, i) => {
    if (!r.ok) console.warn('[posturo] migrate fail', POSTURO_PHOTO_KEYS[i], '→', r.error);
  });
  // Cleanup explicite — couvre le cas "double save sans reload" : à la 2e save,
  // d[k+'Path'] est déjà set (de la save #1) ET d[k] contient encore la dataUrl
  // restaurée du stash post-save #1. migratePhotoEntry retourne migrated:false
  // (no-op, path déjà set), mais sans ce delete la dataUrl serait re-persistée.
  // Le stash capturé en début de fonction garantit la restauration RAM par le caller.
  for (const k of POSTURO_PHOTO_KEYS) {
    if (d[k + 'Path'] && typeof d[k] === 'string' && d[k].startsWith('data:')) {
      delete d[k];
    }
  }
  return stash;
}

// ───────────────────────────────────────────────────────────────────
// Helpers Storage — bilan sport (Task #53 PR B2)
// ───────────────────────────────────────────────────────────────────
// Les photos sport sont stockées dans des arrays d'objets :
//   mesures[testId].photos[i] = { label, side, dataUrl, angle, angleD, angleG, path }
//   mesures[testId].frames[i] = { time, angD, angG, dataUrl, markers, path }
//
// Lifecycle de `path` (différent de posturo qui utilise des clés parallèles `_xxxPath`) :
//   - vide initial          → { dataUrl: null, path: null }
//   - après upload utilisateur → { dataUrl: 'data:...', path: null } (migration uploadera)
//   - après save+migration    → { dataUrl: <stash RAM>, path: 'storage_path' }
//   - après prefetch reopen   → { dataUrl: <fetched>, path: 'storage_path' }
//   - après remplacement      → { dataUrl: 'new data:...', path: null } ← caller efface .path
//                                 → migration ré-uploade, nouveau path, ancien fichier orphan
//
// Pour chaque entry avec path mais sans dataUrl, prefetch via Storage et
// repopule dataUrl en RAM (compat avec le pattern <img src="data:..."> existant).
async function prefetchSportPhotos(mesuresEntry) {
  if (!mesuresEntry) return;
  const photoArr = mesuresEntry.photos || [];
  const frameArr = mesuresEntry.frames || [];
  await Promise.all([...photoArr, ...frameArr].map(async entry => {
    if (!entry || !entry.path || entry.dataUrl) return;
    const r = await prefetchPhotoToDataUrl(entry.path);
    if (r.ok) entry.dataUrl = r.dataUrl;
    else console.warn('[sport] prefetch fail', entry.path, '→', r.error);
  }));
}

// Fix rapport-sport-test-photos — prefetch des dataURLs de TOUS les tests
// de p.mesures (pas seulement le test en cours d'édition). Couvre le flux
// « PWA reload → ouvrir patient → générer rapport SANS rouvrir aucun test » :
// sans ce prefetch, les entries n'ont que .path (post-strip persistence),
// buildPrintPhotos filtre `ph?.dataUrl ?…` → aucune image rendue.
// Itération par testId (skip clés `_*` comme `_bilanId`). Chaque test est
// délégué à prefetchSportPhotos existante (réutilisation, pas de duplication).
// Fallback gracieux : si un fetch Storage échoue, l'entry reste sans dataURL
// → image absente mais pas de crash (cf comportement existant).
async function _prefetchAllSportMesuresPhotos(mesures) {
  if (!mesures) return;
  const promises = [];
  for (const tid in mesures) {
    if (tid.startsWith('_')) continue; // skip _bilanId et autres méta
    const entry = mesures[tid];
    if (entry) promises.push(prefetchSportPhotos(entry));
  }
  await Promise.all(promises);
}

// Migre les photos/frames d'un mesuresEntry vers Storage. Stash les dataUrls
// upfront (pour restauration RAM via restoreSportPhotosStash après save) ;
// upload uniquement les entries `dataUrl set + path null` (replacements et
// premières captures) ; cleanup en fin pour les entries `dataUrl set + path set`
// (cas "reopen+save sans modif" — dataUrl restée de la save précédente via stash).
async function migrateSportPhotos(mesuresEntry, patientId, bilanId, testId) {
  const stash = [];
  const photoArr = mesuresEntry.photos || [];
  const frameArr = mesuresEntry.frames || [];

  [...photoArr, ...frameArr].forEach(entry => {
    if (entry && typeof entry.dataUrl === 'string' && entry.dataUrl.startsWith('data:')) {
      stash.push({ entry, dataUrl: entry.dataUrl });
    }
  });
  if (stash.length === 0) return stash;

  const userId = pwaUser?.id;
  if (!userId || !patientId || !bilanId || !testId) {
    console.warn('[sport] migrate skipped — pathArgs incomplets', { userId, patientId, bilanId, testId });
    return stash;
  }

  // Upload des entries sans path. Les entries `path set + dataUrl set`
  // sont skip ici (migration no-op) et nettoyées par le cleanup en bas.
  const tasks = [];
  const enqueueUpload = (entry, idx, kind) => {
    if (entry.path) return;
    if (typeof entry.dataUrl !== 'string' || !entry.dataUrl.startsWith('data:')) return;
    tasks.push((async () => {
      const mimeMatch = entry.dataUrl.match(/data:image\/([a-zA-Z0-9+.-]+)/);
      const subtype = mimeMatch ? mimeMatch[1].toLowerCase() : 'bin';
      const ext = subtype === 'jpeg' ? 'jpg' : subtype;
      const filename = `${testId}/${kind}_${idx}_${Date.now()}.${ext}`;
      const path = buildPhotoPath(userId, patientId, 'sport', bilanId, filename);
      const up = await uploadPhotoBase64(entry.dataUrl, path);
      if (up.ok) {
        entry.path = up.path;
        delete entry.dataUrl;
      } else {
        console.warn('[sport] migrate fail', kind, idx, '→', up.error);
      }
    })());
  };
  photoArr.forEach((e, i) => enqueueUpload(e, i, 'photoSlot'));
  frameArr.forEach((e, i) => enqueueUpload(e, i, 'frame'));
  await Promise.all(tasks);

  // Cleanup : path set + dataUrl encore présent (cas "reopen+save sans modif"
  // — dataUrl est la copie stash restaurée de la save précédente). Le stash
  // capturé en début garantit la restauration RAM par le caller via
  // restoreSportPhotosStash() après savePatients().
  [...photoArr, ...frameArr].forEach(entry => {
    if (entry?.path && typeof entry.dataUrl === 'string' && entry.dataUrl.startsWith('data:')) {
      delete entry.dataUrl;
    }
  });

  return stash;
}

// Restaure les dataUrls retirées par migrateSportPhotos. Appelé après
// savePatients() pour préserver l'affichage <img>/canvas en RAM sans re-fetch.
function restoreSportPhotosStash(stash) {
  stash.forEach(({ entry, dataUrl }) => {
    if (!entry.dataUrl) entry.dataUrl = dataUrl;
  });
}

// #85 Phase 1 + #99 — clés photo bilanData sport migrées vers Storage.
//   - 4 captures Analyse posturale (JPEG 0.88 1080p) ajoutées en #85.
//   - 5 overlay dessins legacy (4 morpho + pieds, PNG transparent) ajoutés en #99.
// Pipeline préserve le MIME : PNG → upload image/png → refetch image/png → dataURL
// PNG transparente intacte (cf storage.js dataUrlToBlob L29-40 + FileReader L196-212).
// Pattern miroir POSTURO_PHOTO_KEYS : `_xxx` = dataUrl RAM, `_xxxPath` = path Storage.
const SPORT_BILAN_PHOTO_KEYS = [
  // #85 captures Analyse posturale
  '_postureFace', '_postureDos', '_postureProfilG', '_postureProfilD',
  // #99 overlay dessins legacy (PNG transparent — calques superposés à la photo)
  '_morpho_face', '_morpho_face2', '_morpho_profilG', '_morpho_profilD', '_pieds'
];

// Miroir prefetchPosturoPhotos L3143 — restaure dataUrl RAM depuis path Storage
// à l'ouverture du bilan sport. Échec silencieux par clé (console.warn) → l'UI
// affichera une cellule vide pour la photo manquante, acceptable.
async function prefetchSportBilanDataPhotos(bd) {
  if (!bd) return;
  // #85 Fix boot — js/storage.js chargé APRÈS js/biomeca.js dans index.html L2680-2681,
  // donc prefetchPhotoToDataUrl peut être undefined au 1er loadBilan top-level (boot).
  // Skip gracieux : les loadBilan ultérieurs (post-boot via navigation utilisateur)
  // bénéficieront du prefetch puisque storage.js sera chargé.
  if (typeof prefetchPhotoToDataUrl !== 'function') return;
  // #85 Fix race boot — refresh préventif si JWT proche de l'expiration.
  await ensureSession();
  await Promise.all(SPORT_BILAN_PHOTO_KEYS.map(async k => {
    const pathKey = k + 'Path';
    if (!bd[pathKey] || bd[k]) return;
    const r = await prefetchPhotoToDataUrl(bd[pathKey]);
    if (r.ok) bd[k] = r.dataUrl;
    else console.warn('[sport-bd] prefetch fail', pathKey, '→', r.error);
  }));
}

// Miroir migratePosturoPhotos L3160 — upload dataUrl → Storage, set path, delete
// dataUrl. Stash retourné pour restauration RAM post-savePatients (preserve display
// sans re-fetch). Type Storage = 'sport' (vs 'posturo' côté posturo).
async function migrateSportBilanDataPhotos(bd, patientId, bilanId) {
  // #85 Fix boot — garde défensive miroir prefetchSportBilanDataPhotos. Théoriquement
  // saveBilan/saveBilanSilent ne sont pas dans le boot top-level, mais protection
  // cohérente. Retour stash vide → restoreSportBilanDataPhotosStash no-op safe.
  if (typeof migratePhotoEntry !== 'function') return {};
  // #85 Fix race boot — refresh préventif avant les uploads Storage.
  await ensureSession();
  const stash = {};
  for (const k of SPORT_BILAN_PHOTO_KEYS) {
    if (bd[k] && typeof bd[k] === 'string' && bd[k].startsWith('data:')) {
      stash[k] = bd[k];
    }
  }
  if (Object.keys(stash).length === 0) return stash;
  const pathArgs = { userId: pwaUser?.id, patientId, type: 'sport', bilanId };
  const results = await Promise.all(
    SPORT_BILAN_PHOTO_KEYS.map(k => migratePhotoEntry(bd, k, pathArgs))
  );
  results.forEach((r, i) => {
    if (!r.ok) console.warn('[sport-bd] migrate fail', SPORT_BILAN_PHOTO_KEYS[i], '→', r.error);
  });
  // Cleanup miroir migratePosturoPhotos L3180-3184 (cas "double save sans reload").
  for (const k of SPORT_BILAN_PHOTO_KEYS) {
    if (bd[k + 'Path'] && typeof bd[k] === 'string' && bd[k].startsWith('data:')) {
      delete bd[k];
    }
  }
  return stash;
}

// Restaure les dataUrls retirées par migrateSportBilanDataPhotos. Appelé après
// savePatients() pour preserve display RAM.
function restoreSportBilanDataPhotosStash(bd, stash) {
  for (const k in stash) {
    if (!bd[k]) bd[k] = stash[k];
  }
}

// ══════════════════════════════════════════════════════
// #81 BACKFILL — migration one-shot des dataURLs historiques vers Storage
// ══════════════════════════════════════════════════════
// Couverture exhaustive du state patient :
//   (a) p.bilanData courant — 9 clés SPORT_BILAN_PHOTO_KEYS
//   (b) p.bilanDataPosturo courant — 8 clés POSTURO_PHOTO_KEYS
//   (c) p.mesures[testId].photos[] + frames[] — chaque .dataUrl
//   (d) p.bilansSport[i].bilanData + .mesures (archives)
//   (e) p.bilansPosturo[i].bilanDataPosturo (archives)
// Idempotent (migratePhotoEntry skip si Path déjà set), fail-safe (jamais de
// delete sans upload OK, cf storage.js L243-245), un seul savePatients final.

function _isDataURL(v) {
  return typeof v === 'string' && v.startsWith('data:');
}

// Compte les dataURLs persistées pour un patient sans rien muter.
// Fonction pure (sauf accès à SPORT_BILAN_PHOTO_KEYS / POSTURO_PHOTO_KEYS).
function _countDataURLsInPatient(p) {
  if (!p) return 0;
  let count = 0;
  // (a) bilanData courant
  if (p.bilanData) for (const k of SPORT_BILAN_PHOTO_KEYS) {
    if (_isDataURL(p.bilanData[k])) count++;
  }
  // (b) bilanDataPosturo courant
  if (p.bilanDataPosturo) for (const k of POSTURO_PHOTO_KEYS) {
    if (_isDataURL(p.bilanDataPosturo[k])) count++;
  }
  // (c) mesures courantes
  if (p.mesures) for (const tid in p.mesures) {
    if (tid.startsWith('_')) continue; // skip _bilanId etc.
    const t = p.mesures[tid];
    if (Array.isArray(t?.photos)) count += t.photos.filter(e => e && _isDataURL(e.dataUrl)).length;
    if (Array.isArray(t?.frames)) count += t.frames.filter(e => e && _isDataURL(e.dataUrl)).length;
  }
  // (d) bilansSport archives
  if (Array.isArray(p.bilansSport)) for (const arch of p.bilansSport) {
    if (arch.bilanData) for (const k of SPORT_BILAN_PHOTO_KEYS) {
      if (_isDataURL(arch.bilanData[k])) count++;
    }
    if (arch.mesures) for (const tid in arch.mesures) {
      if (tid.startsWith('_')) continue;
      const t = arch.mesures[tid];
      if (Array.isArray(t?.photos)) count += t.photos.filter(e => e && _isDataURL(e.dataUrl)).length;
      if (Array.isArray(t?.frames)) count += t.frames.filter(e => e && _isDataURL(e.dataUrl)).length;
    }
  }
  // (e) bilansPosturo archives
  if (Array.isArray(p.bilansPosturo)) for (const arch of p.bilansPosturo) {
    if (arch.bilanDataPosturo) for (const k of POSTURO_PHOTO_KEYS) {
      if (_isDataURL(arch.bilanDataPosturo[k])) count++;
    }
  }
  return count;
}

// Compte sans rien muter. Retourne { totals: [{id, name, count}], grand }.
function _dryRunBackfill() {
  const totals = (Array.isArray(patients) ? patients : [])
    .map(p => ({
      id: p?.id || '?',
      name: ((p?.prenom || '?') + ' ' + (p?.nom || '?')).trim() || '(sans nom)',
      count: _countDataURLsInPatient(p)
    }))
    .filter(t => t.count > 0)
    .sort((a, b) => b.count - a.count);
  const grand = totals.reduce((s, t) => s + t.count, 0);
  console.log('[#81 dry-run] Total dataURLs à migrer : ' + grand + ' (' + totals.length + ' patients)');
  if (totals.length > 0) console.table(totals);
  return { totals, grand };
}

// Migration effective. ⚠ NE PAS APPELER tant que la validation Joel n'est pas
// reçue (Palier 3 dry-run only). UN SEUL savePatients final.
async function _executeBackfill({ onProgress } = {}) {
  await ensureSession();
  let migrated = 0, failed = 0, patientsTraités = 0;

  // Helper : itère un objet mesures (courant ou archivé) et migre chaque test.
  async function _backfillMesuresEntry(mesures, bilanId, patientId) {
    if (!mesures) return;
    if (!mesures._bilanId) mesures._bilanId = bilanId;
    for (const tid in mesures) {
      if (tid.startsWith('_')) continue;
      try {
        await migrateSportPhotos(mesures[tid], patientId, mesures._bilanId, tid);
        migrated++;
      } catch (e) {
        failed++;
        console.warn('[#81] migrate mesures fail (' + tid + ') :', e);
      }
    }
  }

  for (const p of (Array.isArray(patients) ? patients : [])) {
    if (!p?.id) continue;
    // (a) + (c) bilan sport en cours
    if (!p.mesures) p.mesures = {};
    if (!p.mesures._bilanId) p.mesures._bilanId = crypto.randomUUID();
    if (p.bilanData) {
      try {
        await migrateSportBilanDataPhotos(p.bilanData, p.id, p.mesures._bilanId);
        migrated++;
      } catch (e) {
        failed++;
        console.warn('[#81] sport-bd courant fail :', e);
      }
    }
    await _backfillMesuresEntry(p.mesures, p.mesures._bilanId, p.id);

    // (b) bilan posturo en cours
    if (p.bilanDataPosturo) {
      if (!p.bilanDataPosturo.id) p.bilanDataPosturo.id = crypto.randomUUID();
      try {
        await migratePosturoPhotos(p.bilanDataPosturo, p.id, p.bilanDataPosturo.id);
        migrated++;
      } catch (e) {
        failed++;
        console.warn('[#81] posturo-bd courant fail :', e);
      }
    }

    // (d) archives sport
    for (const arch of (p.bilansSport || [])) {
      if (!arch._bilanId) arch._bilanId = crypto.randomUUID();
      if (arch.bilanData) {
        try {
          await migrateSportBilanDataPhotos(arch.bilanData, p.id, arch._bilanId);
          migrated++;
        } catch (e) {
          failed++;
          console.warn('[#81] archive sport-bd fail :', e);
        }
      }
      await _backfillMesuresEntry(arch.mesures, arch._bilanId, p.id);
    }

    // (e) archives posturo
    for (const arch of (p.bilansPosturo || [])) {
      if (arch.bilanDataPosturo) {
        if (!arch.bilanDataPosturo.id) arch.bilanDataPosturo.id = crypto.randomUUID();
        try {
          await migratePosturoPhotos(arch.bilanDataPosturo, p.id, arch.bilanDataPosturo.id);
          migrated++;
        } catch (e) {
          failed++;
          console.warn('[#81] archive posturo-bd fail :', e);
        }
      }
    }

    patientsTraités++;
    if (onProgress) onProgress({
      patientId: p.id,
      patientName: ((p.prenom || '?') + ' ' + (p.nom || '?')).trim(),
      patientsTraités,
      migrated,
      failed
    });
  }

  // UN SEUL savePatients final → libère le localStorage en un coup.
  savePatients();
  return { migrated, failed, patientsTraités };
}

// ─── UI Maintenance dans Paramètres ───

function _openBackfillLockModal() {
  const modal = document.getElementById('backfill-lock-modal');
  if (modal) modal.style.display = 'flex';
}

function _closeBackfillLockModal() {
  const modal = document.getElementById('backfill-lock-modal');
  if (modal) modal.style.display = 'none';
}

function _runBackfillDryRun() {
  if (!Array.isArray(patients)) return;
  const { totals, grand } = _dryRunBackfill();
  const countEl = document.getElementById('backfill-count-display');
  if (countEl) {
    if (grand === 0) {
      countEl.textContent = '✓ Aucune migration nécessaire (0 dataURL en localStorage).';
      countEl.style.color = '#2a7a4e';
    } else {
      countEl.textContent = grand + ' dataURL' + (grand > 1 ? 's' : '') + ' détectée' +
        (grand > 1 ? 's' : '') + ' dans ' + totals.length + ' patient' + (totals.length > 1 ? 's' : '');
      countEl.style.color = '#c0392b';
    }
  }
  const detailsEl = document.getElementById('backfill-details');
  if (detailsEl) {
    detailsEl.innerHTML = totals.length === 0
      ? ''
      : '<details style="margin-top:8px;"><summary style="cursor:pointer;font-size:11px;color:var(--mut);">Détail par patient</summary><ul style="font-size:11px;color:var(--mut);margin-top:6px;">' +
        totals.map(t => '<li>' + t.name + ' : ' + t.count + ' image' + (t.count > 1 ? 's' : '') + '</li>').join('') +
        '</ul></details>';
  }
}

async function _runBackfillExecution() {
  if (!confirm("⚠️ Lancer la migration de toutes les dataURLs vers Supabase Storage ?\n\nCette opération peut prendre plusieurs minutes selon le volume. Ne fermez pas l'application pendant l'exécution.")) return;
  _openBackfillLockModal();
  try {
    const progressEl = document.getElementById('backfill-progress');
    const result = await _executeBackfill({
      onProgress: ({ patientName, patientsTraités, migrated, failed }) => {
        if (progressEl) {
          progressEl.textContent = 'Patient #' + patientsTraités + ' : ' + patientName +
            ' · ' + migrated + ' migrations · ' + failed + ' échecs';
        }
      }
    });
    alert('✓ Migration terminée.\n\n' +
      result.patientsTraités + ' patient(s) traité(s).\n' +
      result.migrated + ' upload(s) réussi(s).\n' +
      result.failed + ' échec(s).\n\n' +
      'Le localStorage est libéré.');
    _runBackfillDryRun(); // recompte pour montrer le nouveau total
  } catch (e) {
    alert('Erreur pendant la migration : ' + (e?.message || e));
    console.error('[#81] executeBackfill exception :', e);
  } finally {
    _closeBackfillLockModal();
  }
}

// #99 Tracé commun des 4 canvas overlay morpho (PNG transparent) depuis un objet
// source. Extraction du bloc historique nav L2013-2034 pour zéro duplication +
// fidélité byte-pour-byte garantie entre les 2 call-sites (nav setTimeout 500ms
// pré-prefetch + .then() post-prefetch de prefetchSportBilanDataPhotos #99).
//
// Source paramétrée :
//   - chaîne nav setTimeout → currentPatient?.bilanData (état persisté, dataURLs
//     présentes pour bilans non-migrés legacy)
//   - .then() post-prefetch  → bilanData global (réhydraté par prefetch Storage
//     pour bilans post-migration où currentPatient.bilanData ne contient que Path)
//
// Function declaration → hoistée (insensible à l'ordre). Idempotent : drawImage
// est non-cumulatif, redraw même image = no-op visible. Donc 2e call-site n'altère
// pas le rendu du 1er si bilan non-migré.
// #99 + Bug édition perdue (gating _restoreReady) — overlay visuel posé sur le
// parent du canvas pendant la fenêtre de restauration async. Affiché seulement
// si la restauration dépasse ~150 ms (sinon flash gênant pour les bilans légers).
// pointer-events:none → n'intercepte pas le clic user (sécurité belt-and-suspenders ;
// le vrai blocage est dans setupDrawCanvas mousedown via guard _restoreReady).
function _showRestoreOverlay(canvas) {
  if (!canvas || canvas._restoreReady) return;
  const parent = canvas.parentElement;
  if (!parent) return;
  let overlay = parent.querySelector('.restore-loading-overlay');
  if (!overlay) {
    // Le parent doit être en position:relative pour que l'overlay s'aligne dessus.
    const cs = getComputedStyle(parent);
    if (cs.position === 'static') parent.style.position = 'relative';
    overlay = document.createElement('div');
    overlay.className = 'restore-loading-overlay';
    overlay.style.cssText = 'position:absolute;top:0;left:0;right:0;bottom:0;background:rgba(255,255,255,0.85);display:flex;align-items:center;justify-content:center;font-size:11px;color:#666;font-weight:600;pointer-events:none;z-index:10;border-radius:4px;';
    overlay.textContent = '⏳ Chargement du dessin…';
    parent.appendChild(overlay);
  }
  overlay.style.display = '';
}

function _hideRestoreOverlay(canvas) {
  if (!canvas) return;
  const parent = canvas.parentElement;
  if (!parent) return;
  const overlay = parent.querySelector('.restore-loading-overlay');
  if (overlay) overlay.style.display = 'none';
}

// Affiche l'overlay seulement après 150 ms (évite le flash pour les restorations
// rapides bilan vierge / dataURL inline déjà en RAM). Re-check _restoreReady au
// moment d'afficher : si déjà ready, no-op.
function _showRestoreOverlayDeferred(canvas) {
  setTimeout(() => {
    if (canvas && canvas._restoreReady === false) _showRestoreOverlay(canvas);
  }, 150);
}

// #99 + Bug édition perdue (gating _restoreReady) — `posesReadyFlag`:
//   - false (par défaut) : 1ère passe (chaîne nav setTimeout 500ms), source peut
//     être vide (currentPatient.bilanData pour bilan migré sans dataURL en RAM).
//     Ne touche pas le flag — la 2e passe via .then() prefetch s'en chargera
//     après réhydratation. Évite d'ouvrir le gate avant que la restauration
//     déterministe (Image.onload) ait effectivement peint.
//   - true : 2e passe via _restoreSportMorphoPiedsFromBilanData dans .then().
//     Pose `_restoreReady=true` déterministe dans img.onload (après drawImage).
//     Pour les canvas sans source[key] (rien à dessiner), pose ready immédiat.
//     img.onerror débloque aussi (sinon canvas figé en cas de dataURL corrompue).
function _drawMorphoCanvasesFromSource(source, posesReadyFlag) {
  if (!source) return;
  const pairs = [
    ['morpho-face',    '_morpho_face'],
    ['morpho-face2',   '_morpho_face2'],
    ['morpho-profilG', '_morpho_profilG'],
    ['morpho-profilD', '_morpho_profilD']
  ];
  pairs.forEach(([canvasId, key]) => {
    const cvs = document.getElementById(canvasId);
    if (!cvs || cvs.width === 0) return;
    if (!source[key]) {
      // Rien à restaurer pour ce canvas : ouverture immédiate du gate si on est
      // dans la passe finale. Sinon, on laisse au caller / 2e passe le soin.
      if (posesReadyFlag) {
        cvs._restoreReady = true;
        _hideRestoreOverlay(cvs);
      }
      return;
    }
    const img = new Image();
    img.onload = () => {
      const dpr = window.devicePixelRatio || 1;
      cvs.getContext('2d').drawImage(img, 0, 0, cvs.width / dpr, cvs.height / dpr);
      // Fix #94 auto-réparation — efface fond noir éventuel des bilans
      // corrompus pré-fix (saveBilanSilent JPEG sur canvas morpho overlay
      // transparent). Idempotent sur PNG transparent propre.
      _stripBackgroundFromRestore(cvs);
      if (posesReadyFlag) {
        cvs._restoreReady = true;
        _hideRestoreOverlay(cvs);
      }
    };
    img.onerror = () => {
      if (posesReadyFlag) {
        cvs._restoreReady = true;
        _hideRestoreOverlay(cvs);
      }
    };
    img.src = source[key];
  });
}

// #99 Restauration différée des canvas morpho/pieds depuis bilanData global
// (post-prefetch Storage). Appelée dans le .then() de prefetchSportBilanDataPhotos
// pour traiter le cas où les 5 clés _morpho_*/_pieds ont été remplacées par des
// Path (migration #99) : la chaîne nav setTimeout 500ms lit currentPatient.bilanData
// au reload et trouve les Path (pas les dataURLs), donc rien ne se dessine. Une
// fois le prefetch terminé, bilanData global contient les dataURLs réhydratées →
// redraw réussit. Pour les bilans non-migrés (legacy), le rendu nav setTimeout
// fonctionne ET ce 2e rendu est idempotent (cf comm _drawMorphoCanvasesFromSource).
function _restoreSportMorphoPiedsFromBilanData() {
  // Fix racine (symétrisation pattern posturo) : lire currentPatient.bilanData,
  // l'objet où le prefetch a réhydraté les dataURLs. Le bilanData global est une
  // copie défensive (JSON.parse(stringify(...))) qui ne reçoit plus les dataURLs
  // une fois le prefetch redirigé vers currentPatient.bilanData. Lire le global
  // ici ferait lire les Path-only → drawPiedsTemplate(undefined) → canvas vidé.
  const src = currentPatient?.bilanData;
  if (!src) return;
  // #99 + gating _restoreReady : 2e passe (post-prefetch), posesReadyFlag=true.
  // _drawMorphoCanvasesFromSource pose `_restoreReady=true` déterministiquement
  // dans img.onload de chaque canvas qui a une dataURL, ou immédiatement pour
  // les canvas sans dataURL (rien à restaurer).
  _drawMorphoCanvasesFromSource(src, true);
  if (src._pieds && typeof drawPiedsTemplate === 'function') {
    // Callback onReady passé à drawPiedsTemplate → pose `_restoreReady=true`
    // dans saved.onload après le drawImage déterministe.
    drawPiedsTemplate(src._pieds, () => {
      const pc = document.getElementById('pieds-canvas');
      if (pc) {
        pc._restoreReady = true;
        _hideRestoreOverlay(pc);
      }
    });
  } else {
    // Pas de _pieds à restaurer → ouverture immédiate du gate pour ce canvas.
    const pc = document.getElementById('pieds-canvas');
    if (pc) {
      pc._restoreReady = true;
      _hideRestoreOverlay(pc);
    }
  }
}

async function ouvrirBilanPosturo(patIdx, bilanIdx) {
  const p = patients[patIdx];
  if(!p) return;
  const bilan = p.bilansPosturo?.[bilanIdx];
  if(!bilan) {
    // Bilan courant
    currentOpenedBilanPosturoIdx = null;
    selectPatient(p);
    await prefetchPosturoPhotos(currentPatient?.bilanDataPosturo);
    nav('pg-bilan-posturo');
    return;
  }
  // Task #69 — Check data-loss AVANT selectPatient (mirror posturo de
  // ouvrirBilanSport). Posturo a 1 seul champ data (bilanDataPosturo).
  const hasBilanPosturoData = hasBilanDataContent(p.bilanDataPosturo);
  // Task [#70] — check sousType posturo (mirror sport). Parité avec
  // creerBilanPosturo qui a déjà isInProgress = currentBilanPosturoSousType != null.
  if (p.currentBilanPosturoSousType && hasBilanPosturoData) {
    if (!confirm('⚠️ Vous avez un bilan en cours non-archivé. Ouvrir cette archive perdra vos données actuelles.\n\nCliquez Annuler puis allez finaliser ou abandonner votre bilan en cours d\'abord.')) {
      return;
    }
  }
  selectPatient(p);
  currentPatient.bilanDataPosturo = JSON.parse(JSON.stringify(bilan.bilanDataPosturo||{}));
  currentOpenedBilanIdx = null;
  currentOpenedBilanPosturoIdx = bilanIdx;
  // Task #69.3 — Reset flag "bilan en cours" posturo (mirror sport). Cohérent
  // avec le pattern delete sousType utilisé par abandonner/finalize/creer.
  delete p.currentBilanPosturoSousType;
  // Réinitialiser le canvas pour forcer recalcul taille
  const oldCanvas = document.getElementById('posturo-body-canvas');
  if(oldCanvas) { oldCanvas.width = 0; oldCanvas.height = 0; oldCanvas._baseSnapshot = null; oldCanvas._history = []; }
  await prefetchPosturoPhotos(currentPatient.bilanDataPosturo);
  nav('pg-bilan-posturo');
  setTimeout(() => {
    loadPosturoBilan();
    showPosturoSection(0);
  }, 300);
  // Restauration neuro4 après recréation du DOM section 4
  setTimeout(() => {
    const dn = currentPatient?.bilanDataPosturo?.neuro4;
    if(!dn) return;
    Object.entries(dn).forEach(([key, val]) => {
      document.querySelectorAll('input[type="checkbox"]').forEach(cb => {
        const onch = cb.getAttribute('onchange') || '';
        if(onch.includes("'"+key+"'")) cb.checked = !!val;
      });
      if(typeof val === 'string' && val !== '') {
        document.querySelectorAll('input[type="radio"]').forEach(r => {
          const onch = r.getAttribute('onchange') || '';
          if(onch.includes("'"+key+"'") && r.value === val) r.checked = true;
        });
      }
    });
  }, 800);
}
function renderPratList() {
  const el = document.getElementById('prat-list-el');
  if (!praticiens.length) { el.innerHTML='<div style="font-size:12px;color:var(--mut);padding:8px 0;">Aucun praticien.</div>'; return; }
  el.innerHTML = praticiens.map((pr,i) => `
    <div class="prat-row">
      <div style="flex:1;"><div style="font-size:12px;font-weight:500;">${pr.nom}</div>
      <div style="font-size:10px;color:var(--mut);">${pr.titre||''}${pr.cabinet?' · '+pr.cabinet:''}${pr.adresse?' · '+pr.adresse:''}</div></div>
      <button class="btn" style="font-size:11px;" onclick="editPraticien(${i})">✏️</button>
      <button class="btn" style="color:var(--red);font-size:11px;" onclick="deletePraticien(${i})">✕</button>
    </div>`).join('');
}

function editPraticien(i) {
  const pr = praticiens[i];
  if(!pr) return;
  // Remplir le formulaire avec les données existantes
  document.getElementById('pr-nom').value = pr.nom || '';
  document.getElementById('pr-titre').value = pr.titre || '';
  document.getElementById('pr-cabinet').value = pr.cabinet || '';
  document.getElementById('pr-tel').value = pr.tel || '';
  document.getElementById('pr-adresse').value = pr.adresse || '';
  document.getElementById('pr-email').value = pr.email || '';
  // Changer le bouton en mode édition
  const btn = document.querySelector('#pg-praticiens button[onclick*="createPraticien"]');
  if(btn) {
    btn.textContent = '✓ Modifier le praticien';
    btn.onclick = () => saveEditPraticien(i);
  }
  // Scroller vers le formulaire
  // Garde-fou : scrollIntoView seulement si l'élément existe (évite TypeError si DOM modifié).
  const firstField = document.getElementById('pr-nom');
  if(firstField) firstField.scrollIntoView({behavior:'smooth', block:'start'});
}

function saveEditPraticien(i) {
  const pr = praticiens[i];
  if(!pr) return;
  pr.nom = document.getElementById('pr-nom').value.trim();
  pr.titre = document.getElementById('pr-titre').value.trim();
  pr.cabinet = document.getElementById('pr-cabinet').value.trim();
  pr.tel = document.getElementById('pr-tel').value.trim();
  pr.adresse = document.getElementById('pr-adresse').value.trim();
  pr.email = document.getElementById('pr-email').value.trim();
  savePatients();
  renderPratList();
  // Remettre le bouton en mode création
  const btn = document.querySelector('#pg-praticiens button[onclick*="saveEditPraticien"]');
  if(btn) { btn.textContent = '✓ Enregistrer le praticien'; btn.onclick = createPraticien; }
  ['pr-nom','pr-titre','pr-cabinet','pr-tel','pr-adresse','pr-email'].forEach(id => {
    const el = document.getElementById(id); if(el) el.value = '';
  });
}

function populatePratSelect() {
  const sel = document.getElementById('np-prat');
  if (!sel) return;
  sel.innerHTML = '<option value="">— Choisir —</option>' +
    praticiens.map(pr => `<option value="${pr.id}">${pr.nom}</option>`).join('');
}

// ══════════════════════════════════════════════════════
// RENDU MARQUEURS
// ══════════════════════════════════════════════════════
function renderMkrList() {
  const markers = testMode==='video' ? vidMarkers : liveMarkers;
  const selIdx = testMode==='video' ? selectedVidMkrIdx : selectedMkrIdx;
  document.getElementById('cap-mkr-list').innerHTML = markers.map((m,i) => `
    <div class="mkr-item ${selIdx===i?'sel':''}" onclick="selectMkr(${i})">
      <div class="mkr-dot" style="background:${m.color};"></div>
      ${m.side?`<span class="mkr-side ${m.side}">${m.side}</span>`:''}
      <span style="flex:1;font-size:11px;font-weight:500;">${m.name}</span>
      <span style="font-size:9px;color:var(--dim);font-family:var(--fm);">${m.x!==null?`${Math.round(m.x)},${Math.round(m.y)}`:'—'}</span>
      <span>${m.x!==null?'<span class="badge bg">✓</span>':'<span class="badge bd">—</span>'}</span>
      ${m.x!==null?`<button onclick="event.stopPropagation();clearMkr(${i})" style="border:none;background:none;cursor:pointer;color:var(--red);font-size:11px;">✕</button>`:''}
    </div>`).join('');
}

function selectMkr(i) {
  if (testMode==='video') selectedVidMkrIdx=i; else selectedMkrIdx=i;
  renderMkrList();
}
function clearMkr(i) {
  if (testMode==='video') { vidMarkers[i].x=null; vidMarkers[i].y=null; }
  else { liveMarkers[i].x=null; liveMarkers[i].y=null; }
  renderMkrList(); updateResults();
}
function resetAllMarkers() {
  const t=TESTS[currentTestId]; if(!t) return;
  liveMarkers=cloneMarkers(t.markers); selectedMkrIdx=-1; isDragging=false;
  vidMarkers=cloneMarkers(t.markers); selectedVidMkrIdx=-1; isVidDragging=false;
  renderMkrList(); updateResults();
}

// ══════════════════════════════════════════════════════
// PHOTO GRID
// ══════════════════════════════════════════════════════
function renderVidPhotoGrid() {
  const t = TESTS[currentTestId]; if(!t || !t.showPhotoSlots) return;
  const el = document.getElementById('vid-photo-grid'); if(!el) return;

  if(t.kfppaPhotos || t.mobiliteAP) {
    let html = '<div style="display:flex;flex-direction:column;gap:8px;">';
    photoSlots.forEach((slot, i) => { html += vidPhotoSlotHTML(slot, i); });
    html += '</div>';
    el.innerHTML = html;
    return;
  }
  if(t.mlaTest) {
    // MLA : 2 colonnes (pied D et pied G)
    const slotsD=photoSlots.map((s,i)=>({...s,idx:i})).filter(s=>s.side==='D');
    const slotsG=photoSlots.map((s,i)=>({...s,idx:i})).filter(s=>s.side==='G');
    let html='<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;">';
    html+='<div><div style="font-size:10px;font-weight:700;color:#4a9eff;margin-bottom:5px;">🦶 Pied Droit</div><div style="display:flex;flex-direction:column;gap:5px;">';
    slotsD.forEach(slot=>{ html+=vidPhotoSlotHTML(slot,slot.idx); });
    html+='</div></div>';
    html+='<div><div style="font-size:10px;font-weight:700;color:#3ecf72;margin-bottom:5px;">🦶 Pied Gauche</div><div style="display:flex;flex-direction:column;gap:5px;">';
    slotsG.forEach(slot=>{ html+=vidPhotoSlotHTML(slot,slot.idx); });
    html+='</div></div></div>';
    el.innerHTML=html;
    return;
  }

  const slotsG = photoSlots.map((s,i)=>({...s,idx:i})).filter(s=>s.side==='G');
  const slotsD = photoSlots.map((s,i)=>({...s,idx:i})).filter(s=>s.side==='D');
  let html = '<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;">';
  html += '<div><div style="font-size:10px;font-weight:700;color:var(--green);margin-bottom:5px;">🦵 Pied Gauche</div><div style="display:flex;flex-direction:column;gap:5px;">';
  slotsG.forEach(slot => { html += vidPhotoSlotHTML(slot, slot.idx); });
  html += '</div></div>';
  html += '<div><div style="font-size:10px;font-weight:700;color:var(--blue);margin-bottom:5px;">🦵 Pied Droit</div><div style="display:flex;flex-direction:column;gap:5px;">';
  slotsD.forEach(slot => { html += vidPhotoSlotHTML(slot, slot.idx); });
  html += '</div></div></div>';
  el.innerHTML = html;
}


function vidPhotoSlotHTML(slot, idx) {
  if(slot.dataUrl) {
    return '<div style="position:relative;background:var(--surf);border:1px solid var(--bord);border-radius:var(--rs);overflow:hidden;">'
      + '<img src="'+slot.dataUrl+'" style="width:100%;aspect-ratio:4/3;object-fit:cover;display:block;"/>'
      + (slot.angle !== null ? '<span style="position:absolute;top:3px;left:3px;background:rgba(0,0,0,.8);border:1px solid #FFD700;border-radius:2px;font-size:10px;font-weight:700;color:#FFD700;padding:1px 4px;font-family:var(--fm);">'+slot.angle.toFixed(1)+'°</span>' : '')
      + '<button onclick="deletePhotoSlot('+idx+');renderVidPhotoGrid();" style="position:absolute;top:3px;right:3px;background:rgba(200,30,30,.85);border:none;border-radius:2px;color:#fff;cursor:pointer;padding:0 4px;font-size:10px;">✕</button>'
      + '<span style="position:absolute;bottom:0;left:0;right:0;background:rgba(0,0,0,.7);font-size:9px;color:#fff;padding:2px 4px;">'+slot.label+'</span>'
      + '</div>';
  }
  return '<div style="background:var(--surf);border:1px dashed var(--bord);border-radius:var(--rs);aspect-ratio:4/3;display:flex;flex-direction:column;align-items:center;justify-content:center;cursor:pointer;" onclick="captureVidPhotoSlot('+idx+')">'
    + '<span style="font-size:16px;">📷</span>'
    + '<span style="font-size:9px;color:var(--mut);margin-top:3px;text-align:center;padding:0 4px;">'+slot.label+'</span>'
    + '</div>';
}

function captureVidPhotoSlot(slotIdx) {
  const player = document.getElementById('vid-el');
  const vcanvas = document.getElementById('vid-canvas');
  if(!player || !vcanvas) { alert('Activez la caméra ou importez une vidéo.'); return; }
  const t = TESTS[currentTestId];
  const view = t?.view || 'dos';
  const slot = photoSlots[slotIdx];
  const side = slot?.side || '';

  // Filtrer les marqueurs selon le côté du slot
  // Pour MLA : pas de filtrage (tous les marqueurs sont sans side)
  let markersForPhoto = vidMarkers;
  if(side && t?.markers !== 'mla') {
    markersForPhoto = vidMarkers.filter(m => m.side === side);
  }

  const tmp = document.createElement('canvas');
  tmp.width = vcanvas.width; tmp.height = vcanvas.height;
  const ctx = tmp.getContext('2d');
  ctx.drawImage(player, 0, 0, vcanvas.width, vcanvas.height);
  drawOverlay(ctx, tmp, markersForPhoto, -1, view);
  const dataUrl = tmp.toDataURL('image/jpeg', 0.88);

  // Calculer l'angle selon le côté
  const rawAng = calcAngle3(markersForPhoto);
  // MLA : angle brut (pas de correction)
  // KFPPA : stocker incl (180-rawAng) sans signe latéral (signe appliqué à l'affichage)
  const mlaType = t?.markers==='mla' ? 'mla' : (t?.markers==='genou-bi' ? 'kfppa' : (t?.type||''));
  const corrAng = computeCorrectedAngle(rawAng, side, view, mlaType, markersForPhoto);
  photoSlots[slotIdx].dataUrl = dataUrl;
  photoSlots[slotIdx].angle = corrAng;
  photoSlots[slotIdx].path = null; // remplacement → migration ré-uploadera (B2)

  // Mobilité AP : stocker angles D et G séparément
  if(t?.mobiliteAP) {
    const mkrD = vidMarkers.filter(m=>m.side==='D');
    const mkrG = vidMarkers.filter(m=>m.side==='G');
    // Signe anatomique réel : Inv=+ Ev=- selon direction du calca
    // Pied D: pointe droite=Inv(+), pointe gauche=Ev(-)
    // Pied G: pointe gauche=Inv(+), pointe droite=Ev(-)
    photoSlots[slotIdx].angleD = computeCorrectedAngle(calcAngle3(mkrD),'D',view,t?.type||'',mkrD);
    photoSlots[slotIdx].angleG = computeCorrectedAngle(calcAngle3(mkrG),'G',view,t?.type||'',mkrG);
  }

  // KFPPA photo bipodale : calculer angleD et angleG séparément
  if(t?.kfppaPhotos && !side) {
    // Bipodal KFPPA : stocker angle brut (rawAng) côté D et G
    const mkrD = vidMarkers.filter(m=>m.side==='D');
    const mkrG = vidMarkers.filter(m=>m.side==='G');
    photoSlots[slotIdx].angleD = computeCorrectedAngle(calcAngle3(mkrD),'D',view,'kfppa',mkrD);
    photoSlots[slotIdx].angleG = computeCorrectedAngle(calcAngle3(mkrG),'G',view,'kfppa',mkrG);
  }

  renderVidPhotoGrid();
  updateResults();
}

function renderPhotoGrid() {
  const t = TESTS[currentTestId]; if(!t) return;
  const el = document.getElementById('photo-grid-container');
  // Grouper par côté
  const hasSides = photoSlots.some(s=>s.side);
  if (hasSides) {
    // Grouper D vs G
    const sidesOrder = [...new Set(t.photoSides.filter(s=>s))];
    let html = '';
    sidesOrder.forEach(side => {
      const slots = photoSlots.map((s,i)=>({...s,idx:i})).filter(s=>s.side===side);
      html += `<div class="photo-section">
        <div class="photo-section-title">
          <span class="side-label ${side==='D'?'side-D':'side-G'}">Pied ${side}</span>
        </div>
        <div class="photo-row">${slots.map(slot=>photoSlotHTML(slot,slot.idx)).join('')}</div>
      </div>`;
    });
    el.innerHTML = html;
  } else {
    el.innerHTML = `<div class="photo-row">${photoSlots.map((s,i)=>photoSlotHTML(s,i)).join('')}</div>`;
  }
}

function photoSlotHTML(slot, idx) {
  if (slot.dataUrl) {
    const clrAng = slot.angle!==null ? getAngleColor(slot.angle) : '#FFD700';
    return `<div class="photo-slot has-photo">
      <img src="${slot.dataUrl}"/>
      <button class="ph-del" onclick="deletePhotoSlot(${idx})">✕</button>
      ${slot.angle!==null?`<span class="ph-angle" style="color:${clrAng};border-color:${clrAng};">${slot.angle.toFixed(1)}°</span>`:''}
      <span class="ph-label">${slot.label}</span>
    </div>`;
  }
  return `<div class="photo-slot" onclick="capturePhotoSlot(${idx})">
    <span class="ph-icon">📷</span>
    <span class="ph-lbl-empty">${slot.label}</span>
  </div>`;
}

function deletePhotoSlot(i) {
  photoSlots[i].dataUrl=null; photoSlots[i].angle=null; photoSlots[i].path=null;
  renderPhotoGrid(); updateResults();
}

function resetPhotoSlots() {
  const t=TESTS[currentTestId]; if(!t) return;
  photoSlots=t.photoLabels.map((l,i)=>({label:l,side:t.photoSides[i]||'',dataUrl:null,angle:null,path:null}));
  renderPhotoGrid(); updateResults();
}

// Capturer la photo courante et l'assigner au slot
function capturePhotoSlot(slotIdx) {
  const canvas = document.getElementById('ph-canvas');
  if (!camStream) { alert('Activez la caméra.'); return; }
  const t = TESTS[currentTestId];
  const view = t?.view || 'face';
  const slot = photoSlots[slotIdx];
  const side = slot.side || '';
  const markersForPhoto = side ? liveMarkers.filter(m=>m.side===side) : liveMarkers;
  const tmp = document.createElement('canvas');
  tmp.width = canvas.width; tmp.height = canvas.height;
  const ctx = tmp.getContext('2d');
  ctx.drawImage(canvas, 0, 0);
  drawOverlay(ctx, tmp, markersForPhoto, -1, view);
  const dataUrl = tmp.toDataURL('image/jpeg', 0.88);
  const rawAng = calcAngle3(markersForPhoto);
  // MLA : angle brut (pas de correction)
  // KFPPA : stocker incl (180-rawAng) sans signe latéral (signe appliqué à l'affichage)
  const mlaType = t?.markers==='mla' ? 'mla' : (t?.markers==='genou-bi' ? 'kfppa' : (t?.type||''));
  const corrAng = computeCorrectedAngle(rawAng, side, view, mlaType, markersForPhoto);
  photoSlots[slotIdx].dataUrl = dataUrl;
  photoSlots[slotIdx].angle = corrAng;
  photoSlots[slotIdx].path = null; // remplacement → migration ré-uploadera (B2)
  if(t && t.mobiliteAP) {
    const mkrD = liveMarkers.filter(m=>m.side==='D');
    const mkrG = liveMarkers.filter(m=>m.side==='G');
    photoSlots[slotIdx].angleD = computeCorrectedAngle(calcAngle3(mkrD),'D',view,t.type||'',mkrD);
    photoSlots[slotIdx].angleG = computeCorrectedAngle(calcAngle3(mkrG),'G',view,t.type||'',mkrG);
  }
  renderPhotoGrid(); updateResults();
}

// ══════════════════════════════════════════════════════
// CAMÉRA LIVE (mode photo)
// ══════════════════════════════════════════════════════
async function toggleCam() {
  if (camStream) { stopCam(); return; }
  try {
    const selCam = document.getElementById('cam-select')?.value;
    camStream = await navigator.mediaDevices.getUserMedia(selCam
      ? {video:{deviceId:{exact:selCam},width:{ideal:1280},height:{ideal:720}},audio:false}
      : {video:{facingMode:'environment',width:{ideal:1280},height:{ideal:720}},audio:false});
    const canvas = document.getElementById('ph-canvas');
    const wrap = document.getElementById('ph-wrap');
    const vEl = document.createElement('video');
    vEl.srcObject=camStream; vEl.autoplay=true; vEl.playsInline=true;
    vEl.onloadedmetadata = () => {
      canvas.width=vEl.videoWidth||640; canvas.height=vEl.videoHeight||360;
      wrap.style.minHeight='auto';
      document.getElementById('ph-info').textContent=`${canvas.width}×${canvas.height}`;
      document.getElementById('btn-auto').style.display='';
      document.getElementById('btn-redetect').style.display='';
      document.getElementById('cam-st').textContent='Active'; document.getElementById('cam-st').className='badge bg';
      document.getElementById('btn-cam').textContent='⏹ Arrêter'; document.getElementById('btn-cam').className='btn btn-red';
      setupPhotoCanvas(vEl, canvas);
      startLiveDraw(vEl, canvas);
      // Démarrer auto-détection
      autoLive = true;
      document.getElementById('btn-auto').textContent='Auto : ON';
      document.getElementById('btn-auto').className='btn btn-green';
    };
  } catch(e) {
    document.getElementById('ph-info').textContent='⚠ Accès caméra refusé';
    document.getElementById('cam-st').textContent='Erreur'; document.getElementById('cam-st').className='badge br';
  }
}

function stopCam() {
  if(camStream) camStream.getTracks().forEach(t=>t.stop()); camStream=null;
  if(animId) cancelAnimationFrame(animId); animId=null;
  document.getElementById('btn-cam').textContent='Activer caméra'; document.getElementById('btn-cam').className='btn btn-green';
  document.getElementById('btn-auto').style.display='none';
  document.getElementById('cam-st').textContent='Inactive'; document.getElementById('cam-st').className='badge bd';
  autoLive = false;
}

function setupPhotoCanvas(vid, canvas) {
  canvas.onmousedown = e => {
    const {x,y} = canvasXY(e, canvas);
    const hit = findMarkerAt(x, y, liveMarkers, canvas.width);
    if (hit >= 0) { selectedMkrIdx=hit; isDragging=true; renderMkrList(); return; }
    // Placer le marqueur sélectionné ou le suivant libre
    const idx = selectedMkrIdx>=0 ? selectedMkrIdx : liveMarkers.findIndex(m=>m.x===null);
    if (idx>=0 && idx<liveMarkers.length) {
      liveMarkers[idx].x=x; liveMarkers[idx].y=y;
      const next = liveMarkers.findIndex((m,i)=>i>idx&&m.x===null);
      selectedMkrIdx = next>=0?next:-1;
      renderMkrList(); updateResults();
    }
  };
  canvas.onmousemove = e => {
    if (!isDragging || selectedMkrIdx<0) return;
    const {x,y}=canvasXY(e,canvas);
    liveMarkers[selectedMkrIdx].x=x; liveMarkers[selectedMkrIdx].y=y;
    renderMkrList(); updateResults();
  };
  canvas.onmouseup = () => isDragging=false;
  canvas.ontouchstart = e=>{e.preventDefault();const t=e.touches[0];canvas.onmousedown({clientX:t.clientX,clientY:t.clientY});};
  canvas.ontouchmove = e=>{e.preventDefault();const t=e.touches[0];canvas.onmousemove({clientX:t.clientX,clientY:t.clientY});};
  canvas.ontouchend = ()=>canvas.onmouseup();
}

function startLiveDraw(vid, canvas) {
  const ctx = canvas.getContext('2d');
  const view = TESTS[currentTestId]?.view || 'face';
  function draw() {
    animId = requestAnimationFrame(draw);
    ctx.drawImage(vid, 0, 0, canvas.width, canvas.height);
    if (autoLive) {
      detectMarkersAuto(ctx, canvas, liveMarkers, view, ()=>{ renderMkrList(); updateResults(); });
    }
    drawOverlay(ctx, canvas, liveMarkers, selectedMkrIdx, view);
    updateAngleOverlay('ph-angles', liveMarkers, view);
    updateResults();
  }
  draw();
}

function toggleAutoLive() {
  autoLive=!autoLive;
  document.getElementById('btn-auto').textContent='Auto : '+(autoLive?'ON':'OFF');
  document.getElementById('btn-auto').className=autoLive?'btn btn-green':'btn';
}

function redetectMarkers() {
  // Réinitialiser les positions et relancer la détection blob sur tous les marqueurs
  liveMarkers.forEach(m => { m.x=null; m.y=null; });
  const canvas = document.getElementById('ph-canvas');
  if(!canvas) return;
  const ctx = canvas.getContext('2d');
  const view = TESTS[currentTestId]?.view || 'face';
  // Forcer la détection blob (pas le placement fixe) en passant markers avec x=null
  detectMarkersAuto(ctx, canvas, liveMarkers, view, ()=>{ renderMkrList(); updateResults(); });
}

// ══════════════════════════════════════════════════════
// CAMÉRA VIDÉO
// ══════════════════════════════════════════════════════

async function enumerateCameras(selectId) {
  try {
    // Demander permission d'abord pour avoir les labels
    await navigator.mediaDevices.getUserMedia({video:true}).then(s=>s.getTracks().forEach(t=>t.stop())).catch(()=>{});
    const devices = await navigator.mediaDevices.enumerateDevices();
    const cameras = devices.filter(d => d.kind === 'videoinput');
    const sel = document.getElementById(selectId);
    if (!sel) return;
    const current = sel.value;
    sel.innerHTML = cameras.map((d, i) => {
      // Nettoyer le label : enlever les infos techniques
      let label = d.label || ('Caméra ' + (i+1));
      if(label.includes('(')) label = label.split('(')[0].trim();
      if(label.length > 30) label = label.substring(0, 30) + '…';
      return `<option value="${d.deviceId}">${label}</option>`;
    }).join('');
    if (current && cameras.find(d=>d.deviceId===current)) sel.value = current;
    // Si un stream est actif, sélectionner la caméra actuellement utilisée
    if(vidStream) {
      const activeTrack = vidStream.getVideoTracks()[0];
      if(activeTrack) {
        const settings = activeTrack.getSettings();
        if(settings.deviceId) {
          const opt = sel.querySelector(`option[value="${settings.deviceId}"]`);
          if(opt) sel.value = settings.deviceId;
        }
      }
    }
  } catch(e) { console.warn('enumerateCameras:', e); }
}

async function toggleVCam() {
  if(vidStream) { stopVCam(); return; }
  try {
    const selCam = document.getElementById('vcam-select')?.value;
    const constraints = {
      audio: false,
      video: selCam
        ? {deviceId:{exact:selCam}, width:{ideal:1280}, height:{ideal:720}}
        : {facingMode:'environment', width:{ideal:1280}, height:{ideal:720}}
    };
    vidStream=await navigator.mediaDevices.getUserMedia(constraints);
    const player=document.getElementById('vid-el');
    const vcanvas=document.getElementById('vid-canvas');
    player.srcObject=vidStream; player.play();
    player.onloadedmetadata=()=>{
      vcanvas.width=player.videoWidth||640; vcanvas.height=player.videoHeight||360;
      document.getElementById('vid-info').textContent=`Live ${vcanvas.width}×${vcanvas.height}`;
      document.getElementById('btn-vrec').style.display='';
      document.getElementById('btn-vauto').style.display='';
      document.getElementById('vcam-st').textContent='Live'; document.getElementById('vcam-st').className='badge bg';
      document.getElementById('btn-vcam').textContent='⏹ Arrêter'; document.getElementById('btn-vcam').className='btn btn-red';
      vAutoDetect=true; document.getElementById('btn-vauto').textContent='Auto : ON'; document.getElementById('btn-vauto').className='btn btn-green';
      setupVidCanvas(player,vcanvas);
      // Mettre à jour le sélecteur avec les vraies caméras disponibles
      enumerateCameras('vcam-select');
    };
  } catch(e) { document.getElementById('vid-info').textContent='⚠ Accès caméra refusé : '+e.message; }
}

function stopVCam() {
  if(vidStream) vidStream.getTracks().forEach(t=>t.stop()); vidStream=null;
  document.getElementById('btn-vcam').textContent='Activer caméra'; document.getElementById('btn-vcam').className='btn btn-green';
  document.getElementById('btn-vrec').style.display='none'; document.getElementById('btn-vauto').style.display='none';
  document.getElementById('vcam-st').textContent='Inactive'; document.getElementById('vcam-st').className='badge bd';
}

function loadVidFile(input) {
  const file=input.files[0]; if(!file) return;
  const player=document.getElementById('vid-el');
  const vcanvas=document.getElementById('vid-canvas');
  player.srcObject=null; player.src=URL.createObjectURL(file);
  player.onloadedmetadata=()=>{
    vcanvas.width=player.videoWidth||640; vcanvas.height=player.videoHeight||360;
    document.getElementById('vid-info').textContent=`${player.videoWidth}×${player.videoHeight} · ${player.duration.toFixed(1)}s`;
    document.getElementById('btn-vauto').style.display='';
    vAutoDetect=true; document.getElementById('btn-vauto').textContent='Auto : ON'; document.getElementById('btn-vauto').className='btn btn-green';
    document.getElementById('vcam-st').textContent='Vidéo'; document.getElementById('vcam-st').className='badge bb';
    setupVidCanvas(player,vcanvas);
  };
}

// ══════════════════════════════════════════════════════
// #85 Phase 1 — ANALYSE POSTURALE : CAPTURE 4 VUES (sport + posturo)
// ══════════════════════════════════════════════════════
// Bloc partagé sport (ssec-1) + posturo (psec-1), paramétré par préfixe 'sp'/'po'.
// 1 stream caméra partagé pour les 4 vues, 4 captures distinctes via drawImage+toDataURL.
// Stockage dataUrl direct dans bilanData/bilanDataPosturo (clés _postureFace/Dos/ProfilG/ProfilD)
// → migration auto Storage côté posturo (POSTURO_PHOTO_KEYS étendu, savePosturoBilan async).
// Côté sport : Temps 2 brancher saveBilan async + migrateSportBilanDataPhotos.
// Format : JPEG 0.88, ideal 1920×1080 (fallback gracieux navigateur), facingMode:environment.
// #106-A — Seuils analyse posturale profil. Structure complète configurable :
//   - neutralite : zone de neutralité par mesure (mesures à zéro = neutre).
//   - courbures  : bornes basse (rectitude) et haute (hyper) par segment rachis,
//     sur la DÉVIATION (= 180 − calcAngle3).
// Chargée depuis localStorage clé bm4-posture-thresholds avec fallback défauts.
// Modifiable depuis Paramètres → « Seuils — analyse posturale (profil) ».
const POSTURE_THRESHOLDS_KEY = 'bm4-posture-thresholds';
const POSTURE_THRESHOLDS_DEFAULTS = {
  neutralite: {
    anteriorisation: 3, // Tête/Tronc/Cuisse/Jambe (segments d'orientation)
    cva: 2,             // ±2° autour de 50° (CVA référencée à 50°, pas à 0°)
    bassin: 3,
    hanche: 3,          // hanche articulaire ET flexionHanche (Tronc)
    genou: 3,           // genou centré 0 = neutre (flessum/récurvatum)
    epaule: 3,
  },
  courbures: {
    cervicale:  { rectitude: 10, hyper: 28 },
    thoracique: { rectitude: 12, hyper: 32 },
    lombaire:   { rectitude: 12, hyper: 35 },
  },
  // #108 Étape 3a — seuils face configurables. Tous en degrés sauf
  // `translation` en % (largeur d'appui). Repris des constantes inline étape 2
  // (SEUIL_TETE, SEUIL_EPAULES, etc. dans _renderFacePlacementResults et
  // _buildFaceConclusion → désormais lus depuis POSTURE_THRESHOLDS.face).
  face: {
    tete: 2,             // inclinaison / rotation / mandibule / inclinaison tronc
    epaules: 2,          // ligne épaules (asymétrie haut-bas)
    bassin: 2,           // bascule bassin (EIAS)
    translation: 3,      // % de la largeur d'appui (thorax / bassin)
    valgumVarum: 3,      // ° de déviation au genou
    // Angle de Fick / progression du pied — zone physiologique 15-25° de
    // rotation externe (le pied est NATURELLEMENT en rotation externe, pas
    // centré sur 0). < ouvertureMin = pied en fermeture ; > ouvertureMax =
    // pied en ouverture ; entre les deux = physiologique. Réglables /
    // calibrables si trop de faux « fermeture » sur une population donnée.
    ouvertureMin: 15,
    ouvertureMax: 25,
    lateralisation: 2,   // ° d'inclinaison latérale par étage (conclusion)
  },
  // #108 Dos étape 3a — seuils dos configurables. Promus depuis les constantes
  // inline de _renderDosPlacementResults / _buildDosConclusion / _computeDosAngles
  // (seuilSecondaire rachis). Tous en degrés sauf rachis/sillon/triangles en %
  // (% de la largeur d'épaules pour rachis et triangles, % de la largeur d'EIPS
  // pour sillon inter-fessier).
  dos: {
    tete: 2, epaules: 2, bassin: 2,   // ° — inclinaison/rotation tête ; ligne épaules + asymétrie scapulas ; bascule
    scapulaMin: 5, scapulaMax: 10,    // ° — bande physiologique orientation scapulaire (< min = rot. interne ; > max = rot. externe)
    scapulaAsym: 3,                   // ° — asymétrie orientation D−G
    rachis: 5,                        // % largeur d'épaules — offset par étage + seuil apex scoliose
    sillon: 3, triangles: 3,          // % — sillon inter-fessier ; triangles de la taille
    calcaneen: 3, axeJambier: 3,      // ° — angle calcanéen ; axe jambier
  },
  // #108 Étape 4 — couplage face+dos. Seuil utilisé par _buildCrossViewFindings
  // pour décider si une déviation antérieure (face) ou postérieure (dos) est
  // significative. Signes opposés → rotation antérieure du côté postérieur ;
  // même sens → translation / latéralisation du côté commun.
  crossView: {
    seuil: 3, // % de la largeur d'appui (face) ou de la largeur d'épaules (dos)
  },
};

// Loader fail-safe : merge profond avec les défauts pour tolérer un stockage
// partiel (ex. ajout d'un seuil dans une release future, ou JSON corrompu sur
// une seule clé). Renvoie toujours une structure valide.
function _loadPostureThresholds() {
  try {
    const raw = localStorage.getItem(POSTURE_THRESHOLDS_KEY);
    if (!raw) return JSON.parse(JSON.stringify(POSTURE_THRESHOLDS_DEFAULTS));
    const stored = JSON.parse(raw);
    return {
      neutralite: { ...POSTURE_THRESHOLDS_DEFAULTS.neutralite, ...(stored.neutralite || {}) },
      courbures: {
        cervicale:  { ...POSTURE_THRESHOLDS_DEFAULTS.courbures.cervicale,  ...(stored.courbures?.cervicale  || {}) },
        thoracique: { ...POSTURE_THRESHOLDS_DEFAULTS.courbures.thoracique, ...(stored.courbures?.thoracique || {}) },
        lombaire:   { ...POSTURE_THRESHOLDS_DEFAULTS.courbures.lombaire,   ...(stored.courbures?.lombaire   || {}) },
      },
      // #108 Étape 3a — merge profond face : tolère un stockage partiel
      // (utilisateurs qui ont déjà personnalisé leurs seuils profil avant la
      // release face → la section face manquera, on retombe sur les défauts).
      face: { ...POSTURE_THRESHOLDS_DEFAULTS.face, ...(stored.face || {}) },
      // #108 Dos étape 3a — merge profond dos, même contrat fail-safe que face.
      dos:  { ...POSTURE_THRESHOLDS_DEFAULTS.dos,  ...(stored.dos  || {}) },
      // #108 Étape 4 — merge profond couplage face+dos, idem fail-safe.
      crossView: { ...POSTURE_THRESHOLDS_DEFAULTS.crossView, ...(stored.crossView || {}) },
    };
  } catch (e) {
    console.warn('[#106] Seuils corrompus, fallback défauts :', e?.message);
    return JSON.parse(JSON.stringify(POSTURE_THRESHOLDS_DEFAULTS));
  }
}
let POSTURE_THRESHOLDS = _loadPostureThresholds();
function _savePostureThresholds() {
  try {
    localStorage.setItem(POSTURE_THRESHOLDS_KEY, JSON.stringify(POSTURE_THRESHOLDS));
  } catch (e) {
    console.warn('[#106] Échec sauvegarde seuils :', e?.message);
  }
}
function _resetPostureThresholds() {
  POSTURE_THRESHOLDS = JSON.parse(JSON.stringify(POSTURE_THRESHOLDS_DEFAULTS));
  try { localStorage.removeItem(POSTURE_THRESHOLDS_KEY); } catch (e) { /* noop */ }
}

// #106-A — Render du panneau Paramètres pour éditer les seuils. Appelé à
// l'ouverture de pg-params (nav L1995). Inputs number, save live sur oninput.
function _renderPostureThresholdsPanel() {
  const container = document.getElementById('params-posture-thresholds');
  if (!container) return;
  const T = POSTURE_THRESHOLDS;
  // Helper input numérique. `path` est l'argument dot-notation pour
  // _updatePostureThreshold (ex. 'neutralite.bassin' ou 'courbures.cervicale.hyper').
  // `unit` (par défaut '°') permet d'afficher '%' pour les seuils en pourcentage
  // (ex. face.translation = % de la largeur d'appui).
  const num = (label, val, path, unit = '°') =>
    `<label style="display:flex;align-items:center;gap:8px;margin-bottom:5px;font-size:12px;">
      <span style="flex:1;color:#444;">${label}</span>
      <input type="number" value="${val}" min="0" step="0.5"
        onchange="_updatePostureThreshold('${path}', this.value)"
        style="width:64px;padding:3px 6px;border:1px solid #cbd5e0;border-radius:3px;font-size:12px;text-align:right;">
      <span style="color:#888;font-size:11px;">${unit}</span>
    </label>`;
  const subHdr = `font-weight:600;color:#0e1f38;margin-bottom:6px;font-size:11px;text-transform:uppercase;letter-spacing:0.3px;`;
  const courbHdr = `font-size:10px;color:#666;margin:6px 0 3px;`;
  container.innerHTML = `
    <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:14px;">
      <div>
        <div style="${subHdr}">Zone de neutralité (±°)</div>
        ${num('Antériorisation (Tête/Tronc/Cuisse/Jambe)', T.neutralite.anteriorisation, 'neutralite.anteriorisation')}
        ${num('CVA (autour de 50°)',                       T.neutralite.cva,             'neutralite.cva')}
        ${num('Bassin',                                    T.neutralite.bassin,          'neutralite.bassin')}
        ${num('Hanche',                                    T.neutralite.hanche,          'neutralite.hanche')}
        ${num('Genou (flessum/récurvatum)',                T.neutralite.genou,           'neutralite.genou')}
        ${num('Épaule',                                    T.neutralite.epaule,          'neutralite.epaule')}
      </div>
      <div>
        <div style="${subHdr}">Courbures rachidiennes (déviation, °)</div>
        <div style="${courbHdr}">Cervicale</div>
        ${num('Rectitude si déviation &lt;',              T.courbures.cervicale.rectitude,  'courbures.cervicale.rectitude')}
        ${num('Hyperlordose si déviation &gt;',           T.courbures.cervicale.hyper,      'courbures.cervicale.hyper')}
        <div style="${courbHdr}">Thoracique</div>
        ${num('Rectitude si déviation &lt;',              T.courbures.thoracique.rectitude, 'courbures.thoracique.rectitude')}
        ${num('Hypercyphose si déviation &gt;',           T.courbures.thoracique.hyper,     'courbures.thoracique.hyper')}
        <div style="${courbHdr}">Lombaire</div>
        ${num('Rectitude si déviation &lt;',              T.courbures.lombaire.rectitude,   'courbures.lombaire.rectitude')}
        ${num('Hyperlordose si déviation &gt;',           T.courbures.lombaire.hyper,       'courbures.lombaire.hyper')}
      </div>
      <div>
        <div style="${subHdr}">Seuils — analyse face</div>
        ${num('Tête (inclinaison / rotation / mandibule)', T.face.tete,           'face.tete')}
        ${num('Ligne épaules (asymétrie)',                 T.face.epaules,        'face.epaules')}
        ${num('Bascule du bassin (EIAS)',                  T.face.bassin,         'face.bassin')}
        ${num('Translation latérale (% largeur d\'appui)', T.face.translation,    'face.translation', '%')}
        ${num('Valgum / Varum du genou',                   T.face.valgumVarum,    'face.valgumVarum')}
        ${num('Pied — fermeture si <',                     T.face.ouvertureMin,   'face.ouvertureMin')}
        ${num('Pied — ouverture si >',                     T.face.ouvertureMax,   'face.ouvertureMax')}
        ${num('Latéralisation par étage (conclusion)',     T.face.lateralisation, 'face.lateralisation')}
      </div>
      <div>
        <div style="${subHdr}">Seuils — analyse dos</div>
        ${num('Tête (inclinaison / rotation)',             T.dos.tete,         'dos.tete')}
        ${num('Ligne épaules + asymétrie scapulas',        T.dos.epaules,      'dos.epaules')}
        ${num('Bascule du bassin (EIPS)',                  T.dos.bassin,       'dos.bassin')}
        ${num('Scapula — rot. interne si <',               T.dos.scapulaMin,   'dos.scapulaMin')}
        ${num('Scapula — rot. externe si >',               T.dos.scapulaMax,   'dos.scapulaMax')}
        ${num('Asymétrie orientation scapulaire (D−G)',    T.dos.scapulaAsym,  'dos.scapulaAsym')}
        ${num('Rachis — offset par étage + apex (% largeur épaules)', T.dos.rachis,    'dos.rachis',    '%')}
        ${num('Sillon inter-fessier (% largeur EIPS)',     T.dos.sillon,       'dos.sillon',    '%')}
        ${num('Triangles de la taille (% largeur épaules)', T.dos.triangles,   'dos.triangles', '%')}
        ${num('Angle calcanéen',                           T.dos.calcaneen,    'dos.calcaneen')}
        ${num('Axe jambier',                               T.dos.axeJambier,   'dos.axeJambier')}
      </div>
      <div>
        <div style="${subHdr}">Seuils — couplage face+dos</div>
        ${num('Rotation antérieure / Translation (% largeur)', T.crossView.seuil, 'crossView.seuil', '%')}
      </div>
    </div>
    <div style="margin-top:12px;">
      <button onclick="_resetPostureThresholdsAndRefresh()" class="btn" style="background:#888;color:#fff;font-size:11px;padding:6px 14px;">↺ Réinitialiser les valeurs par défaut</button>
    </div>`;
}

// Met à jour un seuil par dot-path (ex. 'neutralite.bassin' ou
// 'courbures.cervicale.hyper') et persiste immédiatement en localStorage.
// Garde-fou courbures : rectitude STRICTEMENT < hyper sur chaque segment, sinon
// la bande « normes » devient incohérente (vide ou ambiguë). Si la saisie casse
// l'invariant, on refuse + re-render → l'input revient à la valeur valide.
function _updatePostureThreshold(path, value) {
  const n = parseFloat(value);
  if (isNaN(n) || n < 0) return;
  const parts = path.split('.');
  if (parts[0] === 'courbures' && parts.length === 3) {
    const sibling = POSTURE_THRESHOLDS.courbures?.[parts[1]];
    if (sibling) {
      const key = parts[2];
      if (key === 'rectitude' && n >= sibling.hyper) { _renderPostureThresholdsPanel(); return; }
      if (key === 'hyper'     && n <= sibling.rectitude) { _renderPostureThresholdsPanel(); return; }
    }
  }
  const lastKey = parts.pop();
  let target = POSTURE_THRESHOLDS;
  for (const p of parts) {
    if (!target[p]) return;
    target = target[p];
  }
  target[lastKey] = n;
  _savePostureThresholds();
}

// Reset + re-render du panneau pour réafficher les valeurs par défaut dans les inputs.
function _resetPostureThresholdsAndRefresh() {
  _resetPostureThresholds();
  _renderPostureThresholdsPanel();
}

// #85-P2a — ratio largeur/hauteur du cadre de capture posturale (portrait).
// Tunable : 3/4 conservateur (couvre patient debout plein corps avec marge
// latérale confortable) ; 9/16 plus serré (mobile-like, recadre davantage).
// Utilisé à la fois pour aspect-ratio du preview vidéo ET pour le crop centré
// au moment du capture → ce que le praticien voit = ce qui est stocké.
const POSTURE_CAPTURE_ASPECT = 3/4;
const POSTURE_VIEWS = [
  { key: 'face',    label: 'Face'     },
  { key: 'dos',     label: 'Dos'      },
  { key: 'profilG', label: 'Profil G' },
  { key: 'profilD', label: 'Profil D' }
];
const _postureStreams = { sp: null, po: null };

// Renvoie l'objet bilanData (sport) ou bilanDataPosturo (posturo) selon prefix.
// Pendant l'édition : ces objets sont en RAM dans currentPatient (sport) ou
// la variable d (posturo). Si non disponibles (pas de patient sélectionné),
// retourne null → la capture est skip silencieuse.
function _getPostureBilanData(prefix) {
  if (prefix === 'sp') return (typeof bilanData !== 'undefined' && bilanData) ? bilanData : null;
  if (prefix === 'po') return currentPatient?.bilanDataPosturo || null;
  return null;
}

// Builder HTML partagé — retourne le markup du bloc (à interpoler dans template
// posturo OU injecter dans #sp-posture-capture-container au boot sport).
function _buildPostureCaptureBlockHTML(prefix) {
  const slotsHTML = POSTURE_VIEWS.map(v =>
    `<div class="pc-slot" id="${prefix}-pc-slot-${v.key}" style="flex:1;min-width:140px;background:#f8f9fa;border:1px dashed #cbd5e0;border-radius:6px;padding:8px;text-align:center;min-height:120px;display:flex;flex-direction:column;align-items:center;justify-content:center;">
       <div style="font-size:10px;color:#666;margin-bottom:6px;font-weight:600;">${v.label}</div>
       <button class="btn" onclick="capturePostureView('${prefix}','${v.key}')" style="font-size:11px;background:#0e1f38;color:#fff;padding:6px 12px;">📷 Capturer</button>
     </div>`
  ).join('');
  return `<div class="card" style="margin-bottom:12px;border:1px solid #cbd5e0;border-radius:8px;padding:12px;background:#fff;">
    <div style="font-weight:700;color:#0e1f38;font-size:13px;margin-bottom:8px;">📸 Analyse posturale — captures 4 vues</div>
    <div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center;margin-bottom:8px;">
      <select id="${prefix}-pc-camera-select" onchange="_switchPostureCam('${prefix}')" style="font-size:11px;padding:4px 8px;border:1px solid #cbd5e0;border-radius:4px;min-width:160px;">
        <option value="">— Caméra —</option>
      </select>
      <button class="btn" id="${prefix}-pc-cam-btn" onclick="_togglePostureCam('${prefix}')" style="font-size:11px;background:#2a7a4e;color:#fff;padding:5px 12px;">▶ Activer caméra</button>
      <button class="btn" id="${prefix}-pc-grid-btn" onclick="_togglePostureGrid('${prefix}')" title="Afficher/masquer la grille de cadrage" style="font-size:11px;background:#0e7490;color:#fff;padding:5px 10px;">▦ Grille</button>
      <span id="${prefix}-pc-cam-status" class="badge bd" style="font-size:10px;">Inactive</span>
    </div>
    <div style="position:relative;background:#000;border-radius:6px;overflow:hidden;margin:0 auto 8px;max-width:240px;aspect-ratio:${POSTURE_CAPTURE_ASPECT};">
      <video id="${prefix}-pc-video" playsinline autoplay muted style="width:100%;height:100%;object-fit:cover;display:block;"></video>
      <!--
        #85-2c-grid — overlay SVG d'aide au cadrage. Élément DOM séparé du <video>
        → capturePostureView (drawImage(video, …) L4954) capture le FRAME VIDÉO
        natif, jamais l'overlay. La grille reste donc UI-only, jamais persistée.
        viewBox 0 0 100 100 + preserveAspectRatio="none" : la grille s'étire pour
        coller au conteneur portrait (3/4) → coordonnées en pourcentage.
        Grille 4 colonnes × 6 lignes (cf brief #85-2c-grid) :
          - 3 verticales à 25/50/75 % (centrale plus marquée)
          - 5 horizontales à 16.67/33.33/50/66.67/83.33 % (centrale plus marquée)
        Les centrales (50 % H/V) servent de repère croisé pour centrer le sujet.
        Les autres horizontales aident à aligner sol/mur et mur/plafond.
        Default display:none — affichée automatiquement par _togglePostureCam
        à l'activation caméra ; le bouton ▦ Grille toggle manuellement.
      -->
      <svg id="${prefix}-pc-grid" viewBox="0 0 100 100" preserveAspectRatio="none" style="position:absolute;inset:0;width:100%;height:100%;pointer-events:none;display:none;">
        <line x1="25" y1="0" x2="25" y2="100" stroke="#67e8f9" stroke-width="0.25" opacity="0.4"/>
        <line x1="75" y1="0" x2="75" y2="100" stroke="#67e8f9" stroke-width="0.25" opacity="0.4"/>
        <line x1="0" y1="16.67" x2="100" y2="16.67" stroke="#67e8f9" stroke-width="0.25" opacity="0.4"/>
        <line x1="0" y1="33.33" x2="100" y2="33.33" stroke="#67e8f9" stroke-width="0.25" opacity="0.4"/>
        <line x1="0" y1="66.67" x2="100" y2="66.67" stroke="#67e8f9" stroke-width="0.25" opacity="0.4"/>
        <line x1="0" y1="83.33" x2="100" y2="83.33" stroke="#67e8f9" stroke-width="0.25" opacity="0.4"/>
        <line x1="50" y1="0" x2="50" y2="100" stroke="#ffffff" stroke-width="0.4" opacity="0.6"/>
        <line x1="0" y1="50" x2="100" y2="50" stroke="#ffffff" stroke-width="0.4" opacity="0.6"/>
      </svg>
    </div>
    <div style="display:flex;gap:6px;flex-wrap:wrap;">${slotsHTML}</div>
  </div>`;
}

// Met à jour 1 cellule (vide → miniature → ré-capture). Lit la dataUrl depuis
// bilanData/bilanDataPosturo (clé `_posture<View>`). Idempotent (re-render OK).
function _renderPostureSlot(prefix, viewKey) {
  const slot = document.getElementById(`${prefix}-pc-slot-${viewKey}`);
  if (!slot) return;
  const view = POSTURE_VIEWS.find(v => v.key === viewKey);
  if (!view) return;
  const bd = _getPostureBilanData(prefix);
  const key = '_posture' + viewKey.charAt(0).toUpperCase() + viewKey.slice(1);
  const dataUrl = bd?.[key];
  // #85-2b + #108 — bouton 🎯 placement points sur profil G/D (14 pts), face
  // (25 pts), dos (28 pts). Badge "✓ N/total placés" indique l'avancement.
  // Total dérivé du template via _posturePointsTotal.
  const isProfil = viewKey === 'profilG' || viewKey === 'profilD';
  const isFace = viewKey === 'face';
  const isDos = viewKey === 'dos';
  const hasPlacement = isProfil || isFace || isDos;
  const totalPoints = _posturePointsTotal(viewKey);
  const markerCount = hasPlacement ? _countPostureMarkers(bd, viewKey) : 0;
  const placementBtn = (dataUrl && hasPlacement)
    ? `<button class="btn" onclick="openPosturePlacementModal('${prefix}','${viewKey}')" title="Placer les ${totalPoints} points anatomiques" style="font-size:9px;padding:2px 6px;background:#7c3aed;color:#fff;">🎯</button>`
    : '';
  const placementBadge = (markerCount > 0)
    ? `<div style="font-size:9px;color:#10b981;font-weight:600;margin-top:2px;">✓ ${markerCount}/${totalPoints} placés</div>`
    : '';
  // #85-2c-import — input file caché + bouton/label cliquable. Pattern label-for-input
  // pour éviter un onclick programmatique (compat iOS Safari : trigger click sur
  // input file depuis onclick peut être bloqué hors gesture utilisateur).
  // L'ID inclut le préfixe + viewKey pour unicité (4 slots × sp/po possible).
  const importInputId = `${prefix}-pc-import-${viewKey}`;
  // #85-2c-import — accept inclut explicitement .heic/.heif (iOS) : MIME image/*
  // matche image/heic|heif mais certains pickers se basent sur l'extension.
  const importInput = `<input type="file" accept="image/*,.heic,.heif" id="${importInputId}" onchange="importPostureView('${prefix}','${viewKey}',this)" style="display:none;">`;
  if (dataUrl) {
    slot.innerHTML = `<div style="font-size:10px;color:#666;margin-bottom:4px;font-weight:600;">${view.label}</div>
      <img src="${dataUrl}" style="max-width:100%;max-height:90px;border-radius:4px;display:block;margin:0 auto 4px;"/>
      <div style="display:flex;gap:4px;justify-content:center;flex-wrap:wrap;">
        <button class="btn" onclick="capturePostureView('${prefix}','${viewKey}')" title="Re-capturer depuis la caméra" style="font-size:9px;padding:2px 6px;background:#0e1f38;color:#fff;">↻</button>
        <label for="${importInputId}" title="Importer une image" style="font-size:9px;padding:2px 6px;background:#0e7490;color:#fff;border-radius:3px;cursor:pointer;display:inline-block;line-height:1.4;">⬆</label>
        ${placementBtn}
        <button class="btn" onclick="deletePostureView('${prefix}','${viewKey}')" title="Supprimer" style="font-size:9px;padding:2px 6px;background:#c0392b;color:#fff;">✕</button>
      </div>
      ${importInput}
      ${placementBadge}`;
    slot.style.borderStyle = 'solid';
    slot.style.background = '#fff';
  } else {
    slot.innerHTML = `<div style="font-size:10px;color:#666;margin-bottom:6px;font-weight:600;">${view.label}</div>
      <div style="display:flex;flex-direction:column;gap:4px;align-items:center;">
        <button class="btn" onclick="capturePostureView('${prefix}','${viewKey}')" style="font-size:11px;background:#0e1f38;color:#fff;padding:6px 12px;">📷 Capturer</button>
        <label for="${importInputId}" title="Importer une image (limite ultra grand-angle iOS)" style="font-size:11px;background:#0e7490;color:#fff;padding:6px 12px;border-radius:3px;cursor:pointer;display:inline-block;">⬆ Importer</label>
      </div>
      ${importInput}`;
    slot.style.borderStyle = 'dashed';
    slot.style.background = '#f8f9fa';
  }
}

function _renderAllPostureSlots(prefix) {
  POSTURE_VIEWS.forEach(v => _renderPostureSlot(prefix, v.key));
}

// ══════════════════════════════════════════════════════
// #85-2b — Moteur de placement des 14 points posture (vue profil).
// ══════════════════════════════════════════════════════
// Pattern : réutilise canvasXY (L4823) / findMarkerAt (L4828) pour le hit-test
// et la conversion clic→pixels canvas, exactement comme setupPhotoCanvas
// (L4334-4358) le fait pour les mesures sport. Différences :
//   - PAS de flux vidéo : un seul drawImage(img,0,0) au load, puis redraw
//     image+points à chaque interaction (jamais de requestAnimationFrame).
//   - PAS de segments ni d'arc d'angle : _drawMarkersOnly se limite aux points
//     colorés + labels (périmètre #85-2b = placement, pas de calculs).
//   - Coords stockées NORMALISÉES nx/ny ∈ [0,1] (cf _validatePosturePlacement) :
//     indépendantes de la résolution photo / taille d'affichage / device DPR.
// État modal : variables module-level (miroir liveMarkers/selectedMkrIdx/isDragging
// pour mesures sport L1689). Reset systématique dans _cancelPosturePlacement.

let _postureModalMarkers = [];
let _postureModalSelIdx = -1;
let _postureModalDragging = false;
let _postureModalCanvas = null;
let _postureModalImg = null;
let _postureModalCtx = null;
// #85-2c-angles — calibration optionnelle de l'horizontale du sol.
// _postureCalibration : { p1:{x,y}, p2:{x,y} } | null (pixels canvas absolus).
// _postureCalibrationMode : true → les clics canvas placent les 2 points de
// calibration au lieu des markers. Auto-exit après placement du p2.
let _postureCalibration = null;
let _postureCalibrationMode = false;
// #106-Final — Identité prefix/viewKey de la modale (utilisé par le panneau
// pour relire _postureAnalysis depuis bd et alimenter les <select> courbures
// avec curveInterp sauvegardé ou auto-mapping).
let _postureModalPrefix = null;
let _postureModalViewKey = null;

// Compte les markers placés (nx/ny non nuls) pour la vue donnée.
// Utilisé par le badge "✓ N/14 placés" dans _renderPostureSlot.
function _countPostureMarkers(bd, viewKey) {
  const markers = bd?._postureAnalysis?.[viewKey]?.markers || [];
  return markers.filter(m => m.nx != null && m.ny != null).length;
}

// #108 — résolution du template MARKER_TEMPLATES par viewKey.
// face → 25 pts ; dos → 28 pts ; profilG/profilD → 14 pts.
function _postureTemplateName(viewKey) {
  if (viewKey === 'face') return 'posture-face';
  if (viewKey === 'dos')  return 'posture-dos';
  return 'posture-profil';
}
function _posturePointsTotal(viewKey) {
  return (MARKER_TEMPLATES[_postureTemplateName(viewKey)] || []).length;
}

// #85-2c-angles — calcul des 4 angles posturaux + global.
// Renvoie { tragus, acromion, trochanter, genou, global } en degrés signés :
//   + = antérieur (vers le regard) / − = postérieur. null si point ou cheville manque.
// `markers` = liste des 14 points (x/y en pixels canvas, ou null).
// `calibration` = { p1:{x,y}, p2:{x,y} } | null (pixels canvas absolus).
//
// Définition du repère :
//   - plumb_up = vecteur "haut" du fil à plomb. Si calibration : perpendiculaire
//     à (p2−p1) orientée vers le haut (Y négatif dans repère canvas). Sinon :
//     (0,−1) = verticale-image.
//   - anterior_dir = composante horizontale de (Tragus − C7). Le tragus est
//     antérieur au rachis cervical → le sens s'auto-corrige selon que le sujet
//     regarde à droite ou à gauche de l'image (robuste profil G ET profil D,
//     pas de hardcoding par viewKey). Fallback : (Acromion − Base sacrum).
//     Si rien d'exploitable : +x avec console.warn.
//
// Pour chaque landmark L : vec = L − cheville ; angle = atan2(projAnt, projUp)
// où projAnt = vec · anterior_dir et projUp = vec · plumb_up. atan2 garantit
// que le signe sort directement antérieur/postérieur sans branche conditionnelle.
function _computePostureAngles(markers, calibration) {
  const byName = Object.fromEntries(markers.map(m => [m.name, m]));
  const cheville = byName['Réf. cheville'];
  const targets = {
    tragus:     byName['Tragus'],
    acromion:   byName['Acromion'],
    trochanter: byName['Grand trochanter'],
    genou:      byName['Genou (milieu lat.)'],
  };
  const isPlaced = m => m && m.x !== null && m.y !== null;
  // 1. plumb_up — calculé EN PREMIER : anterior_dir s'en dérive (perpendiculaire).
  // Sans calibration → verticale-image (0,-1). Avec calibration → perpendiculaire
  // à (p2−p1) orientée vers le haut (Y<0 dans repère canvas).
  let plumbUp;
  if (calibration && calibration.p1 && calibration.p2) {
    const dx = calibration.p2.x - calibration.p1.x;
    const dy = calibration.p2.y - calibration.p1.y;
    const len = Math.hypot(dx, dy);
    if (len > 0) {
      // Deux perpendiculaires possibles : (−dy, dx) et (dy, −dx). Choisir celle
      // qui pointe vers le haut en repère canvas (Y < 0).
      let perp = { x: -dy / len, y: dx / len };
      if (perp.y > 0) perp = { x: -perp.x, y: -perp.y };
      plumbUp = perp;
    } else {
      plumbUp = { x: 0, y: -1 };
    }
  } else {
    plumbUp = { x: 0, y: -1 };
  }
  // 2. anterior_dir — PERPENDICULAIRE à plumb_up, orientée par la géométrie
  // (signe de (tragus−C7)·perp, fallback acromion−sacrum). Bug corrigé du
  // hardcoded horizontal {x:±1,y:0} : invalide dès que la calibration sol incline
  // le plumb_up. En verticale-image (plumb=(0,-1)) → perp=(1,0), même résultat
  // que l'ancien code (rétro-compat numérique). En calibration tiltée → l'antérieur
  // s'aligne parallèlement au sol physique, comme attendu cliniquement.
  const perp = { x: -plumbUp.y, y: plumbUp.x };  // rotation 90° de plumbUp
  const dot = (a, b) => a.x * b.x + a.y * b.y;
  let anteriorDir = null;
  const tragus = byName['Tragus'], c7 = byName['C7'];
  if (isPlaced(tragus) && isPlaced(c7)) {
    const diff = { x: tragus.x - c7.x, y: tragus.y - c7.y };
    const s = Math.sign(dot(diff, perp));
    if (s !== 0) anteriorDir = { x: perp.x * s, y: perp.y * s };
  }
  if (!anteriorDir) {
    const acr = byName['Acromion'], sac = byName['Base sacrum'];
    if (isPlaced(acr) && isPlaced(sac)) {
      const diff = { x: acr.x - sac.x, y: acr.y - sac.y };
      const s = Math.sign(dot(diff, perp));
      if (s !== 0) anteriorDir = { x: perp.x * s, y: perp.y * s };
    }
  }
  if (!anteriorDir) {
    anteriorDir = { x: perp.x, y: perp.y };  // fallback +perp (arbitraire)
    if (isPlaced(cheville) && Object.values(targets).every(isPlaced)) {
      console.warn('[#85-2c-angles] anterior_dir non dérivable (Tragus/C7 ou Acromion/Base sacrum manquants ou colinéaires au plumb) — fallback +perp');
    }
  }
  // 3. angles — chaque champ null si point requis manque. Out pré-initialisé à
  // null pour TOUS les champs (les groupes courbures/CVA/bassin/épaules ne
  // dépendent PAS de la cheville → toujours calculés si leurs points propres
  // sont placés). Global antériorisation = moyenne stricte des 4 (null si une
  // seule manque, pour éviter résultat partiel trompeur cliniquement).
  const out = {
    // Antériorisation (vs fil à plomb) — besoin de cheville.
    tragus: null, acromion: null, trochanter: null, genou: null, global: null,
    // Courbures rachidiennes — calcAngle3 sur triplets (base, apex, sommet).
    cervicale: null,  deviationCervicale: null,
    thoracique: null, deviationThoracique: null,
    lombaire: null,   deviationLombaire: null,
    // Tête / Bassin / Tronc (hanche) / Genou / Épaules — voir blocs dédiés.
    cva: null, bassin: null, genouFlexion: null, epaules: null, flexionHanche: null,
    // #85-2d-segments — orientations de segments + angle articulaire de hanche.
    // cuisse = orientation segment (genou→trochHip) vs verticale au genou.
    // hanche = angle ARTICULAIRE au trochanter (calcAngle3 genou-trochHip-acromion),
    // distinct de flexionHanche (= orientation du Tronc vs verticale). Garder les deux.
    cuisse: null, hanche: null,
  };
  // 3a. Antériorisation — besoin cheville + ≥1 cible.
  if (isPlaced(cheville)) {
    let sum = 0, count = 0;
    for (const [key, L] of Object.entries(targets)) {
      if (!isPlaced(L)) continue;
      const vec = { x: L.x - cheville.x, y: L.y - cheville.y };
      const projAnt = vec.x * anteriorDir.x + vec.y * anteriorDir.y;
      const projUp  = vec.x * plumbUp.x     + vec.y * plumbUp.y;
      const angleDeg = Math.atan2(projAnt, projUp) * 180 / Math.PI;
      out[key] = angleDeg;
      sum += angleDeg; count++;
    }
    if (count === 4) out.global = sum / count;
  }
  // 3b. Courbures — réutilise calcAngle3 (L5024) qui filtre les non-placés et
  // calcule l'angle au point milieu (= apex). Renvoie 0-180° (180 = droite).
  // Déviation = 180 − angle = magnitude de la courbure.
  const apexC = byName['Apex cervical'], baseCrane = byName['Base crâne'];
  if (isPlaced(c7) && isPlaced(apexC) && isPlaced(baseCrane)) {
    out.cervicale = calcAngle3([c7, apexC, baseCrane]);
    if (out.cervicale !== null) out.deviationCervicale = 180 - out.cervicale;
  }
  const apexT = byName['Apex thoracique'], t12 = byName['T12'];
  if (isPlaced(c7) && isPlaced(apexT) && isPlaced(t12)) {
    out.thoracique = calcAngle3([c7, apexT, t12]);
    if (out.thoracique !== null) out.deviationThoracique = 180 - out.thoracique;
  }
  const apexL = byName['Apex lombaire'], sacrum = byName['Base sacrum'];
  if (isPlaced(t12) && isPlaced(apexL) && isPlaced(sacrum)) {
    out.lombaire = calcAngle3([t12, apexL, sacrum]);
    if (out.lombaire !== null) out.deviationLombaire = 180 - out.lombaire;
  }
  // 3c. CVA (Cranio-Vertebral Angle) — angle de C7→Tragus avec l'horizontale
  // (= perp). Unsigned 0-90° (mesure clinique standard). Norme ~50° ; valeur
  // basse = tête en avant. La direction tête haut/bas est gérée par |projUp|
  // pour que le sujet regardant le haut OU le bas donne le même magnitude.
  if (isPlaced(c7) && isPlaced(tragus)) {
    const vec = { x: tragus.x - c7.x, y: tragus.y - c7.y };
    const projUp   = vec.x * plumbUp.x + vec.y * plumbUp.y;
    const projHorz = vec.x * perp.x    + vec.y * perp.y;
    out.cva = Math.atan2(Math.abs(projUp), Math.abs(projHorz)) * 180 / Math.PI;
  }
  // 3d. Bassin — ligne EIAS→EIPS vs horizontale, SIGNÉE.
  // Convention : vec = EIAS − EIPS. + = EIAS sous EIPS (antéversion) ; − = EIAS
  // au-dessus (rétroversion). atan2(−projUp, projAnt) → + quand projUp < 0
  // (EIAS plus bas que EIPS dans repère canvas Y-down → projUp < 0 vs plumbUp).
  const eias = byName['EIAS'], eips = byName['EIPS'];
  if (isPlaced(eias) && isPlaced(eips)) {
    const vec = { x: eias.x - eips.x, y: eias.y - eips.y };
    const projUp  = vec.x * plumbUp.x     + vec.y * plumbUp.y;
    const projAnt = vec.x * anteriorDir.x + vec.y * anteriorDir.y;
    out.bassin = Math.atan2(-projUp, projAnt) * 180 / Math.PI;
  }
  // 3e. Genou flexion — calcAngle3 ([trochanter, genou, cheville]) = 0-180°
  // (180 = droite). Pour distinguer flessum (<180, genou antérieur de la ligne
  // trochanter-cheville) de récurvatum (>180, genou postérieur), on signe via
  // projection du genou sur la perpendiculaire à l'axe trochanter-cheville
  // orientée antérieur : kneeDev > 0 → genou antérieur → on garde raw
  // (<180 = flessum) ; kneeDev < 0 → genou postérieur → 360 − raw (>180 =
  // récurvatum). Neutral kneeDev=0 donne raw=180 → 180 quel que soit le signe.
  const troch = byName['Grand trochanter'], genouPt = byName['Genou (milieu lat.)'];
  if (isPlaced(troch) && isPlaced(genouPt) && isPlaced(cheville)) {
    const raw = calcAngle3([troch, genouPt, cheville]);
    if (raw !== null) {
      const axis = { x: cheville.x - troch.x, y: cheville.y - troch.y };
      let perpAxis = { x: -axis.y, y: axis.x };
      // Orienter vers antérieur via le signe du produit scalaire avec anteriorDir.
      const dotA = perpAxis.x * anteriorDir.x + perpAxis.y * anteriorDir.y;
      if (dotA < 0) { perpAxis = { x: -perpAxis.x, y: -perpAxis.y }; }
      const kneeRel = { x: genouPt.x - troch.x, y: genouPt.y - troch.y };
      const kneeDev = kneeRel.x * perpAxis.x + kneeRel.y * perpAxis.y;
      out.genouFlexion = kneeDev >= 0 ? raw : (360 - raw);
    }
  }
  // 3f. Flexion de hanche — angle entre le segment (Grand trochanter → Acromion)
  // et la VERTICALE au trochanter (= plumb_up). Apex = trochanter. atan2(projAnt,
  // projUp) donne signe naturel : + = acromion antérieur du trochanter (flexion
  // de hanche, tronc penché en avant) ; − = extension de hanche. Norme 0° =
  // tronc parfaitement vertical au-dessus du bassin. Réutilise plumbUp +
  // anteriorDir dérivés plus haut → cohérent avec calibration sol éventuelle.
  const acromion = byName['Acromion'];
  const trochHip = byName['Grand trochanter']; // alias dédié, indépendant de l'accès `troch` du bloc 3e
  if (isPlaced(trochHip) && isPlaced(acromion)) {
    const vec = { x: acromion.x - trochHip.x, y: acromion.y - trochHip.y };
    const projAnt = vec.x * anteriorDir.x + vec.y * anteriorDir.y;
    const projUp  = vec.x * plumbUp.x     + vec.y * plumbUp.y;
    out.flexionHanche = Math.atan2(projAnt, projUp) * 180 / Math.PI;
  }
  // 3g. Épaules — décalage horizontal signé de l'Acromion par rapport à l'axe
  // tronc (C7 → Base sacrum). atan2(décalage_perp, distance_le_long_axe).
  // + = enroulement antérieur (acromion en avant de l'axe tronc).
  if (isPlaced(c7) && isPlaced(sacrum) && isPlaced(acromion)) {
    const axis = { x: sacrum.x - c7.x, y: sacrum.y - c7.y };
    const axisLen = Math.hypot(axis.x, axis.y);
    if (axisLen > 0) {
      const axisU = { x: axis.x / axisLen, y: axis.y / axisLen };
      let perpU = { x: -axisU.y, y: axisU.x };
      const dotA = perpU.x * anteriorDir.x + perpU.y * anteriorDir.y;
      if (dotA < 0) { perpU = { x: -perpU.x, y: -perpU.y }; }
      const vec = { x: acromion.x - c7.x, y: acromion.y - c7.y };
      const along = vec.x * axisU.x + vec.y * axisU.y;
      const perpComp = vec.x * perpU.x + vec.y * perpU.y;
      out.epaules = Math.atan2(perpComp, along) * 180 / Math.PI;
    }
  }
  // 3h. Cuisse (orientation segment) — apex = genou ; vec genou→trochHip vs
  // verticale au genou. + = trochanter antérieur du genou (cuisse penchée en
  // avant) / − = postérieur. Norme 0° = cuisse parfaitement verticale.
  // genouPt et troch déjà définis (bloc 3e). Réutilise plumbUp + anteriorDir.
  if (isPlaced(genouPt) && isPlaced(troch)) {
    const vec = { x: troch.x - genouPt.x, y: troch.y - genouPt.y };
    const projAnt = vec.x * anteriorDir.x + vec.y * anteriorDir.y;
    const projUp  = vec.x * plumbUp.x     + vec.y * plumbUp.y;
    out.cuisse = Math.atan2(projAnt, projUp) * 180 / Math.PI;
  }
  // 3i. Hanche (angle ARTICULAIRE) — apex = grand trochanter ; triplet
  // (genou, trochHip, acromion). Distinct de flexionHanche (= orientation du
  // Tronc). raw = calcAngle3 0-180° (180 = aligné) ; mag = 180 − raw (0 = neutre).
  // Signe : perpendiculaire à l'axe cuisse (trochHip − genou) orientée antérieur
  // via anteriorDir. Si l'acromion (depuis trochanter) a une composante antérieure
  // sur cette perpendiculaire → flexion (+) ; sinon extension (−). Même logique
  // de désambiguïsation que le genou flessum/récurvatum.
  if (isPlaced(genouPt) && isPlaced(troch) && isPlaced(acromion)) {
    const raw = calcAngle3([genouPt, troch, acromion]);
    if (raw !== null) {
      const mag = 180 - raw;
      const axisCuisse = { x: troch.x - genouPt.x, y: troch.y - genouPt.y };
      let perpCuisse = { x: -axisCuisse.y, y: axisCuisse.x };
      const dotA = perpCuisse.x * anteriorDir.x + perpCuisse.y * anteriorDir.y;
      if (dotA < 0) { perpCuisse = { x: -perpCuisse.x, y: -perpCuisse.y }; }
      const vecAcromion = { x: acromion.x - troch.x, y: acromion.y - troch.y };
      const sideTrunk = vecAcromion.x * perpCuisse.x + vecAcromion.y * perpCuisse.y;
      out.hanche = sideTrunk >= 0 ? mag : -mag;
    }
  }
  return out;
}

// #108 Étape 2 — Calcul des 11 mesures faciales sur le modèle de
// _computePostureAngles. Repères :
//   - plumbUp = vertical-image (0,-1) sauf si calibration sol → perpendiculaire
//     à (p2−p1) orientée Y<0 en canvas (identique au profil).
//   - horiz   = perpendiculaire à plumbUp, orientation arbitraire jusqu'à
//     déduction du « côté patient-D » via _deducePatientRightDir.
//   - patientRightDir = unit horizontal pointing vers patient-D, déduit de
//     la 1re paire D/G placée (acromions → EIAS → poignets → yeux → chevilles).
//     Sans paire exploitable, fallback +horiz + console.warn.
// Convention de signe pour TOUTES les mesures latéralisées :
//   + = côté patient-D ; − = côté patient-G ; null si point requis manquant.
function _computeFaceAngles(markers, calibration) {
  const byName = Object.fromEntries(markers.map(m => [m.name, m]));
  const isPlaced = m => m && m.x !== null && m.y !== null;
  // 1. plumbUp + horiz (identique au profil) -----------------------------
  let plumbUp;
  if (calibration && calibration.p1 && calibration.p2) {
    const dx = calibration.p2.x - calibration.p1.x;
    const dy = calibration.p2.y - calibration.p1.y;
    const len = Math.hypot(dx, dy);
    if (len > 0) {
      let perp = { x: -dy / len, y: dx / len };
      if (perp.y > 0) perp = { x: -perp.x, y: -perp.y };
      plumbUp = perp;
    } else {
      plumbUp = { x: 0, y: -1 };
    }
  } else {
    plumbUp = { x: 0, y: -1 };
  }
  const horiz = { x: -plumbUp.y, y: plumbUp.x };
  // 2. patientRightDir — direction horizontale vers patient-D (côté droit du
  // patient = côté gauche de l'image quand patient face caméra). Auto-dérivée
  // via 1re paire D/G placée. Ordre de priorité : acromions, EIAS, poignets,
  // yeux, chevilles (les plus discriminants en haut de liste).
  const dot = (a, b) => a.x * b.x + a.y * b.y;
  const pairs = [
    [byName['Acromion D'], byName['Acromion G']],
    [byName['EIAS D'],     byName['EIAS G']],
    [byName['Poignet D'],  byName['Poignet G']],
    [byName['Œil D'],      byName['Œil G']],
    [byName['Cheville D'], byName['Cheville G']],
  ];
  let patientRightDir = null;
  for (const [D, G] of pairs) {
    if (!isPlaced(D) || !isPlaced(G)) continue;
    const v = { x: D.x - G.x, y: D.y - G.y };
    const proj = dot(v, horiz);
    if (Math.abs(proj) > 1e-9) {
      const sign = Math.sign(proj);
      patientRightDir = { x: horiz.x * sign, y: horiz.y * sign };
      break;
    }
  }
  if (!patientRightDir) {
    patientRightDir = { x: horiz.x, y: horiz.y };
  }
  // 3. Output skeleton — null partout par défaut ------------------------
  const out = {
    // Tête
    inclinaisonTete:    null,  // +D / -G (côté de l'œil le plus bas)
    rotationTete:       null,  // +D / -G ; null si classification ≠ rotation
    deviationMandibule: null,  // +D / -G ; null si classification ≠ mandibule
    nezTordu:           false, // boolean
    // Épaules / Bassin
    ligneEpaules:       null,  // +D / -G (épaule la plus haute)
    basculeBassin:      null,  // +D / -G (EIAS la plus haute)
    fermetureViscerale: null,  // 'D' | 'G' | null
    // Translations (% de la largeur d'appui)
    translationThorax:  null,
    translationBassin:  null,
    devNombril:         null, // % de la largeur d'appui ; + = à D (couplage face+dos)
    // Genoux
    valgumVarumD:       null,  // + valgum / - varum
    valgumVarumG:       null,
    // Pieds
    ouverturePasD:      null,  // + = rotation externe (pied ouvert)
    ouverturePasG:      null,
    // Tronc (Nombril → Fourchette) — diagnostic latéral
    inclinaisonTronc:   null,  // +D / -G
    // Inclinaisons inter-étages (centres bas→haut) pour la conclusion
    tiltCheGen:  null, // chevilles → milieu genoux
    tiltGenBas:  null, // genoux → milieu bassin
    tiltBasFla:  null, // bassin → milieu flancs
    tiltFlaEpa:  null, // flancs → milieu épaules
    tiltEpaTet:  null, // épaules → tête (Glabelle ou milieu yeux)
    // Mémorise patientRightDir signe (utile pour debug / tests) — non rendu.
    _patientRightDir: patientRightDir,
  };
  // 4. Mesures TÊTE -----------------------------------------------------
  const eyeD = byName['Œil D'], eyeG = byName['Œil G'];
  const glab = byName['Glabelle'], nez = byName['Bout du nez'], menton = byName['Pointe menton'];
  // 4a. inclinaisonTete = angle vec(eyeD - eyeG) vs horizontale, +D = D plus bas.
  if (isPlaced(eyeD) && isPlaced(eyeG)) {
    const vec = { x: eyeD.x - eyeG.x, y: eyeD.y - eyeG.y };
    const projUp    = dot(vec, plumbUp);
    const projRight = dot(vec, patientRightDir);
    if (Math.abs(projRight) > 1e-9) {
      // -projUp > 0 quand eyeD est plus bas que eyeG (= tête inclinée à D).
      out.inclinaisonTete = Math.atan2(-projUp, Math.abs(projRight)) * 180 / Math.PI;
    }
  }
  // 4b/4c. rotationTete (oreilles, hiérarchique) vs deviationMandibule / nezTordu
  // --------------------------------------------------------------------
  // headHoriz = direction œil D → œil G (axe inter-orbitaire, NON patientRight :
  // c'est le repère propre à la tête, qui suit son inclinaison). Sert d'axe de
  // projection à la fois pour les oreilles (rotation) et pour nez/menton.
  // Conversion ratio → angle (asin) : faceScale = bras de levier.
  // Signe : patient-D positif. headHoriz pointe nativement de D vers G ;
  // donc projections > 0 sur headHoriz = côté G en headHoriz → on flippe le
  // signe via flip = -sign(headHoriz · patientRightDir) pour que + = D.
  if (isPlaced(eyeD) && isPlaced(eyeG) && isPlaced(glab)) {
    const headHorizRaw = { x: eyeG.x - eyeD.x, y: eyeG.y - eyeD.y };
    const headHorizLen = Math.hypot(headHorizRaw.x, headHorizRaw.y);
    const headHoriz = headHorizLen > 0
      ? { x: headHorizRaw.x / headHorizLen, y: headHorizRaw.y / headHorizLen }
      : null;
    if (headHoriz) {
      const headRightProj = dot(headHoriz, patientRightDir);
      const flip = headRightProj > 0 ? 1 : -1;
      const toDeg = r => Math.asin(Math.max(-1, Math.min(1, r))) * 180 / Math.PI;
      // PRIORITÉ ROTATION = oreilles. dist(oreille, axe central par Glabelle ⊥
      // ligne des yeux) = |(oreille − Glabelle) · headHoriz| en valeur algébrique
      // signée (positive si oreille côté G headHoriz natif, négative côté D).
      // distD = projection signée de l'oreille D ; distG idem oreille G.
      // Asymétrie normalisée par l'écart inter-oreilles (distG − distD positif
      // par construction d'une tête de face normale ; si rotation à D, oreille D
      // se rapproche de l'axe et |distD| diminue relativement à |distG|).
      const oreilleD = byName['Oreille sup D'];
      const oreilleG = byName['Oreille sup G'];
      let rotationFromEars = null;
      if (isPlaced(oreilleD) && isPlaced(oreilleG)) {
        const projD = dot({ x: oreilleD.x - glab.x, y: oreilleD.y - glab.y }, headHoriz);
        const projG = dot({ x: oreilleG.x - glab.x, y: oreilleG.y - glab.y }, headHoriz);
        // En tête de face neutre : projD < 0 (D côté patient → côté gauche image,
        // soit projection négative sur headHoriz qui pointe vers G) et projG > 0.
        // Distances absolues à l'axe central :
        const distD = Math.abs(projD);
        const distG = Math.abs(projG);
        const sumDist = distD + distG;
        if (sumDist > 0) {
          // Asymétrie : + = oreille D plus proche de l'axe (distD < distG) ⇒
          // patient tourne la tête à D (l'oreille D recule, donc apparaît plus
          // près de la ligne médiane projetée). Règle : oreille la plus proche
          // de l'axe = côté de la rotation.
          // PAS de flip ici : distD et distG sont des distances absolues
          // rattachées aux points D/G (déjà en repère patient via leur nommage).
          // Appliquer flip inverserait le sens à tort. Le flip reste utilisé
          // plus bas pour les projections signées nez/menton sur headHoriz.
          const asym = (distG - distD) / sumDist;
          const sEars = 0.06;
          if (Math.abs(asym) > sEars) rotationFromEars = toDeg(asym);
        }
      }
      // Fallback nez/menton — sert UNIQUEMENT pour la rotation si une oreille
      // manque (ne pas tout bloquer). Si les 2 oreilles sont placées et donnent
      // un asym < seuil, on considère « oreilles symétriques » → on évalue
      // alors la branche mandibule/nez-tordu.
      const earsBothPlaced = isPlaced(oreilleD) && isPlaced(oreilleG);
      if (rotationFromEars !== null) {
        // HIÉRARCHIE : rotation oreilles dominante ⇒ on n'évalue PAS mandibule/
        // nez-tordu (mis à null/false). Cohérent cliniquement : une rotation
        // de tête déplace ensemble nez et menton, leur asymétrie n'a alors
        // plus de valeur diagnostique propre.
        out.rotationTete = rotationFromEars;
      } else if (isPlaced(menton)) {
        const faceScale = Math.hypot(menton.x - glab.x, menton.y - glab.y);
        if (faceScale > 0) {
          const devNezRaw = isPlaced(nez)
            ? (dot({ x: nez.x - glab.x, y: nez.y - glab.y }, headHoriz) / faceScale) * flip
            : null;
          const devMentonRaw =
            (dot({ x: menton.x - glab.x, y: menton.y - glab.y }, headHoriz) / faceScale) * flip;
          const s = 0.06;
          const nezOut    = devNezRaw    !== null && Math.abs(devNezRaw)    > s;
          const mentonOut = devMentonRaw !== null && Math.abs(devMentonRaw) > s;
          if (!earsBothPlaced && nezOut && mentonOut && Math.sign(devNezRaw) === Math.sign(devMentonRaw)) {
            // Fallback rotation via nez/menton (oreille(s) manquante(s)).
            out.rotationTete = toDeg((devNezRaw + devMentonRaw) / 2);
          } else if (!nezOut && mentonOut) {
            // Déviation mandibulaire pure.
            out.deviationMandibule = toDeg(devMentonRaw);
          } else if (nezOut && !mentonOut) {
            // Nez tordu : flag spécifique (ni rotation ni mandibule).
            out.nezTordu = true;
          }
          // Sinon (nez et menton neutres OU signes opposés) → tête droite.
        }
      }
    }
  }
  // 5. Mesures ÉPAULES / BASSIN ----------------------------------------
  const acrD = byName['Acromion D'], acrG = byName['Acromion G'];
  if (isPlaced(acrD) && isPlaced(acrG)) {
    const vec = { x: acrD.x - acrG.x, y: acrD.y - acrG.y };
    const projUp    = dot(vec, plumbUp);
    const projRight = dot(vec, patientRightDir);
    if (Math.abs(projRight) > 1e-9) {
      // +projUp > 0 quand acrD est plus haut → épaule D plus haute.
      out.ligneEpaules = Math.atan2(projUp, Math.abs(projRight)) * 180 / Math.PI;
    }
  }
  const eiasD = byName['EIAS D'], eiasG = byName['EIAS G'];
  if (isPlaced(eiasD) && isPlaced(eiasG)) {
    const vec = { x: eiasD.x - eiasG.x, y: eiasD.y - eiasG.y };
    const projUp    = dot(vec, plumbUp);
    const projRight = dot(vec, patientRightDir);
    if (Math.abs(projRight) > 1e-9) {
      out.basculeBassin = Math.atan2(projUp, Math.abs(projRight)) * 180 / Math.PI;
    }
  }
  // Fermeture viscérale : EIAS haute du côté X + acromion bas du côté X → fermeture X.
  // Seuils lus depuis POSTURE_THRESHOLDS.face (étape 3a) — cohérent avec
  // les seuils utilisés pour la bascule du bassin et la ligne épaules ailleurs.
  const seuilBascule = POSTURE_THRESHOLDS.face.bassin;
  const seuilEpaule  = POSTURE_THRESHOLDS.face.epaules;
  if (out.basculeBassin !== null && out.ligneEpaules !== null) {
    const eiasHigh   = out.basculeBassin >  seuilBascule ? 'D'
                     : out.basculeBassin < -seuilBascule ? 'G' : null;
    const acromionLow = out.ligneEpaules >  seuilEpaule  ? 'G'
                      : out.ligneEpaules < -seuilEpaule  ? 'D' : null;
    if (eiasHigh && eiasHigh === acromionLow) out.fermetureViscerale = eiasHigh;
  }
  // 6. Translations (% de la largeur d'appui = distance chevilles) -----
  const chD = byName['Cheville D'], chG = byName['Cheville G'];
  let cChevilles = null, stanceWidth = 0;
  if (isPlaced(chD) && isPlaced(chG)) {
    cChevilles = { x: (chD.x + chG.x) / 2, y: (chD.y + chG.y) / 2 };
    stanceWidth = Math.hypot(chD.x - chG.x, chD.y - chG.y);
  }
  const fourchette = byName['Fourchette sternale'];
  if (cChevilles && stanceWidth > 0 && isPlaced(fourchette)) {
    const v = { x: fourchette.x - cChevilles.x, y: fourchette.y - cChevilles.y };
    out.translationThorax = (dot(v, patientRightDir) / stanceWidth) * 100;
  }
  if (cChevilles && stanceWidth > 0 && isPlaced(eiasD) && isPlaced(eiasG)) {
    const cBassin = { x: (eiasD.x + eiasG.x) / 2, y: (eiasD.y + eiasG.y) / 2 };
    const v = { x: cBassin.x - cChevilles.x, y: cBassin.y - cChevilles.y };
    out.translationBassin = (dot(v, patientRightDir) / stanceWidth) * 100;
  }
  // #108 Étape 4 — devNombril : décalage horizontal signé du nombril vs le
  // plomb des chevilles, normalisé par la largeur d'appui. Réutilisé par
  // _buildCrossViewFindings comme proxy ANTÉRIEUR du bassin (couplage face+dos
  // : croisé avec dosAngles.rachisOffsets.L3 = proxy POSTÉRIEUR du bassin).
  const nombrilPt = byName['Nombril'];
  if (cChevilles && stanceWidth > 0 && isPlaced(nombrilPt)) {
    const v = { x: nombrilPt.x - cChevilles.x, y: nombrilPt.y - cChevilles.y };
    out.devNombril = (dot(v, patientRightDir) / stanceWidth) * 100; // + = à D
  }
  // 7. Valgum/Varum par jambe ------------------------------------------
  // calcAngle3([Tête fémorale, Genou, Cheville]) ; déviation mag = 180 − raw.
  // Signe : projection (Genou − TêteFém) sur la perpendiculaire à l'axe
  // TêteFém→Cheville orientée MÉDIALEMENT (vers le centre du corps).
  //   Jambe D : médial = -patientRightDir (vers G en image, vers le centre)
  //   Jambe G : médial = +patientRightDir
  // dev > 0 = genou côté médial = VALGUM (+) ; dev < 0 = côté latéral = VARUM (−).
  const computeValgumVarum = (femoral, genou, cheville, medialDir) => {
    if (!isPlaced(femoral) || !isPlaced(genou) || !isPlaced(cheville)) return null;
    const raw = calcAngle3([femoral, genou, cheville]);
    if (raw === null) return null;
    const mag = 180 - raw;
    const axis = { x: cheville.x - femoral.x, y: cheville.y - femoral.y };
    let perp = { x: -axis.y, y: axis.x };
    const dotM = dot(perp, medialDir);
    if (dotM < 0) perp = { x: -perp.x, y: -perp.y };
    const vec = { x: genou.x - femoral.x, y: genou.y - femoral.y };
    const dev = dot(vec, perp);
    return dev >= 0 ? mag : -mag;
  };
  const medD = { x: -patientRightDir.x, y: -patientRightDir.y };
  const medG = patientRightDir;
  out.valgumVarumD = computeValgumVarum(byName['Tête fémorale D'], byName['Genou D'], chD, medD);
  out.valgumVarumG = computeValgumVarum(byName['Tête fémorale G'], byName['Genou G'], chG, medG);
  // 8. Ouverture du pas par pied ---------------------------------------
  // Angle vec(orteil − cheville) vs verticale (plumbDown). + = pied tourné
  // vers l'extérieur (rotation externe). Latéral = patientRightDir pour pied D,
  // -patientRightDir pour pied G (sym. valgumVarum).
  const computeOuverturePas = (cheville, orteil, lateralDir) => {
    if (!isPlaced(cheville) || !isPlaced(orteil)) return null;
    const vec = { x: orteil.x - cheville.x, y: orteil.y - cheville.y };
    const projDown = -dot(vec, plumbUp);
    const projLat  = dot(vec, lateralDir);
    if (Math.abs(projDown) < 1e-9 && Math.abs(projLat) < 1e-9) return null;
    return Math.atan2(projLat, projDown) * 180 / Math.PI;
  };
  out.ouverturePasD = computeOuverturePas(chD, byName['2e orteil D'], patientRightDir);
  out.ouverturePasG = computeOuverturePas(chG, byName['2e orteil G'], { x: -patientRightDir.x, y: -patientRightDir.y });
  // 9. Inclinaison du tronc (Nombril → Fourchette) — déviation latérale.
  const nombril = byName['Nombril'];
  if (isPlaced(nombril) && isPlaced(fourchette)) {
    const vec = { x: fourchette.x - nombril.x, y: fourchette.y - nombril.y };
    const projUp    = dot(vec, plumbUp);
    const projRight = dot(vec, patientRightDir);
    if (Math.abs(projUp) > 1e-9 || Math.abs(projRight) > 1e-9) {
      // projUp > 0 (fourchette plus haute que nombril, normal) → tronc droit en
      // projUp et projRight donne l'angle d'inclinaison latérale.
      out.inclinaisonTronc = Math.atan2(projRight, projUp) * 180 / Math.PI;
    }
  }
  // 10. Centres bas → haut pour la conclusion latéralisée par étage.
  const cGenoux = (isPlaced(byName['Genou D']) && isPlaced(byName['Genou G']))
    ? { x: (byName['Genou D'].x + byName['Genou G'].x) / 2, y: (byName['Genou D'].y + byName['Genou G'].y) / 2 } : null;
  const cBassin = (isPlaced(eiasD) && isPlaced(eiasG))
    ? { x: (eiasD.x + eiasG.x) / 2, y: (eiasD.y + eiasG.y) / 2 } : null;
  const flcD = byName['Pli flanc D'], flcG = byName['Pli flanc G'];
  const cFlancs = (isPlaced(flcD) && isPlaced(flcG))
    ? { x: (flcD.x + flcG.x) / 2, y: (flcD.y + flcG.y) / 2 } : null;
  const cEpaules = (isPlaced(acrD) && isPlaced(acrG))
    ? { x: (acrD.x + acrG.x) / 2, y: (acrD.y + acrG.y) / 2 } : null;
  const cTete = isPlaced(glab) ? { x: glab.x, y: glab.y }
              : (isPlaced(eyeD) && isPlaced(eyeG))
                ? { x: (eyeD.x + eyeG.x) / 2, y: (eyeD.y + eyeG.y) / 2 } : null;
  // Inclinaison latérale d'un segment (lower → upper) : atan2(projRight, projUp).
  // + = upper côté patient-D / − = upper côté patient-G.
  const segmentTilt = (lower, upper) => {
    if (!lower || !upper) return null;
    const v = { x: upper.x - lower.x, y: upper.y - lower.y };
    const projUp    = dot(v, plumbUp);
    const projRight = dot(v, patientRightDir);
    if (Math.abs(projUp) < 1e-9 && Math.abs(projRight) < 1e-9) return null;
    return Math.atan2(projRight, projUp) * 180 / Math.PI;
  };
  out.tiltCheGen = segmentTilt(cChevilles, cGenoux);
  out.tiltGenBas = segmentTilt(cGenoux,    cBassin);
  out.tiltBasFla = segmentTilt(cBassin,    cFlancs);
  out.tiltFlaEpa = segmentTilt(cFlancs,    cEpaules);
  out.tiltEpaTet = segmentTilt(cEpaules,   cTete);
  return out;
}

// #108 Étape 2 — Conclusion latéralisée face. Identifie le segment le plus
// bas hors zone neutre comme origine de la latéralisation, puis ajoute en
// déviations distinctes l'inclinaison du tronc et de la tête. Seuils lus
// depuis POSTURE_THRESHOLDS.face (étape 3a). Joint par « · ». Vide si tout neutre.
function _buildFaceConclusion(angles) {
  if (!angles) return '';
  const Tf = POSTURE_THRESHOLDS.face;
  const seuilLat  = Tf.lateralisation; // ° d'inclinaison latérale par étage
  const seuilTete = Tf.tete;
  const sideLabel = v => v > 0 ? 'à D' : 'à G';
  const segments = [
    { val: angles.tiltCheGen, origin: 'des chevilles' },
    { val: angles.tiltGenBas, origin: 'des genoux'    },
    { val: angles.tiltBasFla, origin: 'du bassin'     },
    { val: angles.tiltFlaEpa, origin: 'des flancs'    },
    { val: angles.tiltEpaTet, origin: 'des épaules'   },
  ];
  const parts = [];
  // Segment le plus bas hors zone neutre = origine principale.
  const primary = segments.find(s => s.val !== null && !isNaN(s.val) && Math.abs(s.val) > seuilLat);
  if (primary) parts.push('Latéralisation à partir ' + primary.origin + ' (' + sideLabel(primary.val) + ')');
  // Déviations distinctes pour le tronc et la tête (au-delà du segment global).
  if (angles.inclinaisonTronc !== null && !isNaN(angles.inclinaisonTronc) && Math.abs(angles.inclinaisonTronc) > seuilTete) {
    parts.push('Tronc incliné ' + sideLabel(angles.inclinaisonTronc));
  }
  if (angles.inclinaisonTete !== null && !isNaN(angles.inclinaisonTete) && Math.abs(angles.inclinaisonTete) > seuilTete) {
    parts.push('Tête inclinée ' + sideLabel(angles.inclinaisonTete));
  }
  return parts.join(' · ');
}

// #108 Dos étape 2 — Mesures vue postérieure. Mêmes scaffolding (plumbUp /
// horiz / patientRightDir auto) et conventions de signe (+ = patient-D) que
// _computeFaceAngles, pour cohérence cross-vue. Reprend pour la tête / épaules
// / bassin les MÊMES formules + sens que la face (Œil ↔ Oreille, EIAS ↔ EIPS).
// Cœur : rachis = décalage horizontal de C7/TH6/TH12/L3 par rapport au plomb
// ancré au sacrum, exprimé en % de la largeur d'épaules. Identification de
// l'apex (offset max) et de la courbure secondaire opposée pour repérer une
// éventuelle scoliose en S.
function _computeDosAngles(markers, calibration) {
  const byName = Object.fromEntries(markers.map(m => [m.name, m]));
  const isPlaced = m => m && m.x !== null && m.y !== null;
  // 1. plumbUp + horiz (identique au profil/face) ------------------------
  let plumbUp;
  if (calibration && calibration.p1 && calibration.p2) {
    const dx = calibration.p2.x - calibration.p1.x;
    const dy = calibration.p2.y - calibration.p1.y;
    const len = Math.hypot(dx, dy);
    if (len > 0) {
      let perp = { x: -dy / len, y: dx / len };
      if (perp.y > 0) perp = { x: -perp.x, y: -perp.y };
      plumbUp = perp;
    } else {
      plumbUp = { x: 0, y: -1 };
    }
  } else {
    plumbUp = { x: 0, y: -1 };
  }
  const horiz = { x: -plumbUp.y, y: plumbUp.x };
  // 2. patientRightDir — vue dos : patient face caméra (de dos), patient-D
  // = côté DROIT de l'image. Convention inversée vs la face. La dérivation
  // automatique via paire D/G placée donne le bon signe quelle que soit la
  // vue (D - G donne le sens), donc la même heuristique fonctionne ici.
  // Ordre de priorité : acromions (les plus discriminants), EIPS, oreilles,
  // calcanéum inférieur (le plus bas, repère de stabilité).
  const dot = (a, b) => a.x * b.x + a.y * b.y;
  const pairs = [
    [byName['Acromion D'],            byName['Acromion G']],
    [byName['EIPS D'],                byName['EIPS G']],
    [byName['Oreille sup D'],         byName['Oreille sup G']],
    [byName['Calcanéum inférieur D'], byName['Calcanéum inférieur G']],
  ];
  let patientRightDir = null;
  for (const [D, G] of pairs) {
    if (!isPlaced(D) || !isPlaced(G)) continue;
    const v = { x: D.x - G.x, y: D.y - G.y };
    const proj = dot(v, horiz);
    if (Math.abs(proj) > 1e-9) {
      const sign = Math.sign(proj);
      patientRightDir = { x: horiz.x * sign, y: horiz.y * sign };
      break;
    }
  }
  if (!patientRightDir) {
    patientRightDir = { x: horiz.x, y: horiz.y };
  }
  // 3. Output skeleton -------------------------------------------------
  const out = {
    // Tête
    inclinaisonTete: null, // + = D plus bas (= inclinée à D), comme la face
    rotationTete:    null, // + = côté de la distance la plus grande (D si distD > distG)
    // Épaules / Scapulas
    ligneEpaules:      null, // + = D plus haute (idem face)
    basculeBassin:     null, // + = D plus haute (idem face, sur EIPS)
    asymetrieScapula:  null, // tilt pointe inf scapula D→G, + = D plus haute
    orientationScapulaD: null, // + = abduction / rotation externe
    orientationScapulaG: null,
    asymetrieOrientationScapula: null, // D − G ; + = D plus en rotation externe que G
    // Rachis
    rachisOffsets:    { C7: null, TH3: null, TH6: null, TH12: null, L3: null }, // % signés
    rachisApex:       null, // 'C7' | 'TH6' | 'TH12' | 'L3' | null
    rachisConvexite:  null, // 'D' | 'G' | null
    rachisRegion:     null, // 'cervicale' | 'thoracique' | 'thoraco-lombaire' | 'lombaire' | null
    rachisSecondaire: null, // { region, convexite, apex, offset } | null
    // Bassin
    sillonInterfessier: null, // + = à D
    trianglesTaille:    null, // + = D plus ouvert
    // Membre inférieur
    angleCalcaneenD: null, // + = valgus (talon en dehors)
    angleCalcaneenG: null,
    axeJambierD:     null, // déviation latérale axe pli poplité → mi-mollet → calc. sup
    axeJambierG:     null,
    _patientRightDir: patientRightDir,
  };
  // 4. Tête — inclinaison oreilles + rotation oreilles (axe Base crâne → C7)
  const orD = byName['Oreille sup D'], orG = byName['Oreille sup G'];
  // 4a. inclinaisonTete = tilt (OreilleD − OreilleG), + = D plus bas (cf face).
  if (isPlaced(orD) && isPlaced(orG)) {
    const vec = { x: orD.x - orG.x, y: orD.y - orG.y };
    const projUp    = dot(vec, plumbUp);
    const projRight = dot(vec, patientRightDir);
    if (Math.abs(projRight) > 1e-9) {
      out.inclinaisonTete = Math.atan2(-projUp, Math.abs(projRight)) * 180 / Math.PI;
    }
  }
  // 4b. rotationTete — axe médian = ligne Base du crâne → C7 (au lieu de
  // l'axe facial). distD/distG = distance perpendiculaire à cet axe.
  // asym = (distD − distG)/(distD + distG) — + = côté de la distance la
  // plus grande (= rotation vers ce côté, inverse de la face où l'oreille
  // la plus proche de l'axe donnait le sens). Pas de fallback nez/menton.
  const baseCrane = byName['Base du crâne'], c7 = byName['Épineuse C7'];
  if (isPlaced(orD) && isPlaced(orG) && isPlaced(baseCrane) && isPlaced(c7)) {
    const axis = { x: c7.x - baseCrane.x, y: c7.y - baseCrane.y };
    const axisLen = Math.hypot(axis.x, axis.y);
    if (axisLen > 0) {
      // Perpendiculaire à l'axe ; le signe est sans importance (on prend la
      // distance algébrique signée, puis valeur absolue pour distD/distG).
      const perpAxis = { x: -axis.y / axisLen, y: axis.x / axisLen };
      const projD = dot({ x: orD.x - baseCrane.x, y: orD.y - baseCrane.y }, perpAxis);
      const projG = dot({ x: orG.x - baseCrane.x, y: orG.y - baseCrane.y }, perpAxis);
      const distD = Math.abs(projD);
      const distG = Math.abs(projG);
      const sumDist = distD + distG;
      if (sumDist > 0) {
        const asym = (distD - distG) / sumDist;
        const sEars = 0.06;
        if (Math.abs(asym) > sEars) {
          out.rotationTete = Math.asin(Math.max(-1, Math.min(1, asym))) * 180 / Math.PI;
        }
      }
    }
  }
  // 5. Épaules / Bassin / Scapulas (tilts) ----------------------------
  const acrD = byName['Acromion D'], acrG = byName['Acromion G'];
  if (isPlaced(acrD) && isPlaced(acrG)) {
    const vec = { x: acrD.x - acrG.x, y: acrD.y - acrG.y };
    const projUp    = dot(vec, plumbUp);
    const projRight = dot(vec, patientRightDir);
    if (Math.abs(projRight) > 1e-9) {
      out.ligneEpaules = Math.atan2(projUp, Math.abs(projRight)) * 180 / Math.PI;
    }
  }
  const eipsD = byName['EIPS D'], eipsG = byName['EIPS G'];
  if (isPlaced(eipsD) && isPlaced(eipsG)) {
    const vec = { x: eipsD.x - eipsG.x, y: eipsD.y - eipsG.y };
    const projUp    = dot(vec, plumbUp);
    const projRight = dot(vec, patientRightDir);
    if (Math.abs(projRight) > 1e-9) {
      out.basculeBassin = Math.atan2(projUp, Math.abs(projRight)) * 180 / Math.PI;
    }
  }
  const scapInfD = byName['Pointe inférieure scapula D'];
  const scapInfG = byName['Pointe inférieure scapula G'];
  if (isPlaced(scapInfD) && isPlaced(scapInfG)) {
    const vec = { x: scapInfD.x - scapInfG.x, y: scapInfD.y - scapInfG.y };
    const projUp    = dot(vec, plumbUp);
    const projRight = dot(vec, patientRightDir);
    if (Math.abs(projRight) > 1e-9) {
      out.asymetrieScapula = Math.atan2(projUp, Math.abs(projRight)) * 180 / Math.PI;
    }
  }
  // 6. Orientation des scapulas (Sup médial → Pointe inf) -------------
  // + = abduction (pointe en dehors), − = adduction (pointe vers les épineuses).
  const orientationScapula = (supMed, pointeInf, lateralDir) => {
    if (!isPlaced(supMed) || !isPlaced(pointeInf)) return null;
    const vec = { x: pointeInf.x - supMed.x, y: pointeInf.y - supMed.y };
    const projDown = -dot(vec, plumbUp);
    const projLat  = dot(vec, lateralDir);
    if (Math.abs(projDown) < 1e-9 && Math.abs(projLat) < 1e-9) return null;
    return Math.atan2(projLat, projDown) * 180 / Math.PI;
  };
  out.orientationScapulaD = orientationScapula(
    byName['Angle supéro-médial scapula D'], scapInfD, patientRightDir);
  out.orientationScapulaG = orientationScapula(
    byName['Angle supéro-médial scapula G'], scapInfG, { x: -patientRightDir.x, y: -patientRightDir.y });
  // Asymétrie D − G : + = D plus en rotation externe que G ; G plus externe
  // que D donne une valeur négative. null si une des deux orientations manque.
  out.asymetrieOrientationScapula =
    (out.orientationScapulaD !== null && out.orientationScapulaG !== null)
      ? out.orientationScapulaD - out.orientationScapulaG : null;
  // 7. Rachis (cœur de la mesure) -------------------------------------
  // Pour chaque étage P : offset latéral = (P − sacrum)·patientRightDir,
  // normalisé en % de la largeur d'épaules. + = à D / − = à G.
  // Identification scoliose : apex = offset max, secondaire = max opposé.
  const sacrum = byName['Base du sacrum'];
  let shoulderW = 0;
  if (isPlaced(acrD) && isPlaced(acrG)) {
    shoulderW = Math.hypot(acrD.x - acrG.x, acrD.y - acrG.y);
  }
  if (isPlaced(sacrum) && shoulderW > 0) {
    const levels = [
      { key: 'C7',   m: c7 },
      { key: 'TH3',  m: byName['Épineuse TH3']  },
      { key: 'TH6',  m: byName['Épineuse TH6']  },
      { key: 'TH12', m: byName['Épineuse TH12'] },
      { key: 'L3',   m: byName['Épineuse L3']   },
    ];
    levels.forEach(lvl => {
      if (isPlaced(lvl.m)) {
        const v = { x: lvl.m.x - sacrum.x, y: lvl.m.y - sacrum.y };
        out.rachisOffsets[lvl.key] = (dot(v, patientRightDir) / shoulderW) * 100;
      }
    });
    // Apex = niveau au plus grand |offset|.
    const placedLvls = levels.filter(l => out.rachisOffsets[l.key] !== null);
    if (placedLvls.length > 0) {
      const REGION = { C7: 'cervicale', TH3: 'thoracique haute', TH6: 'thoracique', TH12: 'thoraco-lombaire', L3: 'lombaire' };
      let apexLvl = placedLvls[0];
      for (const l of placedLvls) {
        if (Math.abs(out.rachisOffsets[l.key]) > Math.abs(out.rachisOffsets[apexLvl.key])) apexLvl = l;
      }
      const apexOffset = out.rachisOffsets[apexLvl.key];
      out.rachisApex      = apexLvl.key;
      out.rachisConvexite = apexOffset > 0 ? 'D' : 'G';
      out.rachisRegion    = REGION[apexLvl.key];
      // Secondaire : parmi les autres étages, plus grand |offset| de signe
      // opposé ET au-dessus du seuil rachis configuré. Sinon null (courbure unique).
      // #108 Dos étape 3a — promu depuis constante locale vers POSTURE_THRESHOLDS.
      const seuilSecondaire = POSTURE_THRESHOLDS.dos.rachis;
      const opposites = placedLvls
        .filter(l => l.key !== apexLvl.key)
        .filter(l => Math.sign(out.rachisOffsets[l.key]) !== Math.sign(apexOffset))
        .filter(l => Math.abs(out.rachisOffsets[l.key]) > seuilSecondaire);
      if (opposites.length > 0) {
        let secLvl = opposites[0];
        for (const l of opposites) {
          if (Math.abs(out.rachisOffsets[l.key]) > Math.abs(out.rachisOffsets[secLvl.key])) secLvl = l;
        }
        out.rachisSecondaire = {
          apex:       secLvl.key,
          region:     REGION[secLvl.key],
          convexite:  out.rachisOffsets[secLvl.key] > 0 ? 'D' : 'G',
          offset:     out.rachisOffsets[secLvl.key],
        };
      }
    }
  }
  // 8. Bassin — sillon inter-fessier + triangles de la taille ---------
  const sommetPli = byName['Sommet du pli inter-fessier'];
  if (isPlaced(sommetPli) && isPlaced(sacrum) && isPlaced(eipsD) && isPlaced(eipsG)) {
    const eipsW = Math.hypot(eipsD.x - eipsG.x, eipsD.y - eipsG.y);
    if (eipsW > 0) {
      const v = { x: sommetPli.x - sacrum.x, y: sommetPli.y - sacrum.y };
      out.sillonInterfessier = (dot(v, patientRightDir) / eipsW) * 100;
    }
  }
  const coudeD = byName['Coude D'], coudeG = byName['Coude G'];
  const tailleD = byName['Pli de la taille D'], tailleG = byName['Pli de la taille G'];
  if (isPlaced(coudeD) && isPlaced(coudeG) && isPlaced(tailleD) && isPlaced(tailleG) && shoulderW > 0) {
    const distD = Math.hypot(coudeD.x - tailleD.x, coudeD.y - tailleD.y);
    const distG = Math.hypot(coudeG.x - tailleG.x, coudeG.y - tailleG.y);
    out.trianglesTaille = ((distD - distG) / shoulderW) * 100;
  }
  // 9. Membre inférieur — angle calcanéen + axe jambier --------------
  // angleCalcaneen : décalage latéral du calcanéum inf vs axe (mi-mollet →
  // calc. sup) dans le repère pied. + = valgus (talon en dehors), − = varus.
  const computeAngleCalcaneen = (miMollet, calcSup, calcInf, lateralDir) => {
    if (!isPlaced(miMollet) || !isPlaced(calcSup) || !isPlaced(calcInf)) return null;
    const uL = { x: calcSup.x - miMollet.x, y: calcSup.y - miMollet.y };
    const uLen = Math.hypot(uL.x, uL.y);
    if (uLen < 1e-9) return null;
    const uLn = { x: uL.x / uLen, y: uL.y / uLen };
    const vC = { x: calcInf.x - calcSup.x, y: calcInf.y - calcSup.y };
    const projAlong = dot(vC, uLn);
    const projLat   = dot(vC, lateralDir);
    if (Math.abs(projAlong) < 1e-9 && Math.abs(projLat) < 1e-9) return null;
    return Math.atan2(projLat, projAlong) * 180 / Math.PI;
  };
  out.angleCalcaneenD = computeAngleCalcaneen(
    byName['Mi-mollet D'], byName['Calcanéum supérieur D'], byName['Calcanéum inférieur D'],
    patientRightDir);
  out.angleCalcaneenG = computeAngleCalcaneen(
    byName['Mi-mollet G'], byName['Calcanéum supérieur G'], byName['Calcanéum inférieur G'],
    { x: -patientRightDir.x, y: -patientRightDir.y });
  // axeJambier : déviation latérale axe (pli poplité → mi-mollet) vs
  // (mi-mollet → calc. sup). « Genou D/G » du template = pli poplité (vue dos).
  const computeAxeJambier = (pliPoplite, miMollet, calcSup, lateralDir) => {
    if (!isPlaced(pliPoplite) || !isPlaced(miMollet) || !isPlaced(calcSup)) return null;
    const uL = { x: miMollet.x - pliPoplite.x, y: miMollet.y - pliPoplite.y };
    const uLen = Math.hypot(uL.x, uL.y);
    if (uLen < 1e-9) return null;
    const uLn = { x: uL.x / uLen, y: uL.y / uLen };
    const vC = { x: calcSup.x - miMollet.x, y: calcSup.y - miMollet.y };
    const projAlong = dot(vC, uLn);
    const projLat   = dot(vC, lateralDir);
    if (Math.abs(projAlong) < 1e-9 && Math.abs(projLat) < 1e-9) return null;
    return Math.atan2(projLat, projAlong) * 180 / Math.PI;
  };
  // Convention de signe axe jambier : + = jambe déviée vers patient-D, − = vers
  // patient-G. C'est une mesure en repère patient ABSOLU (le segment jambier
  // dans son ensemble penche vers un côté), pas relative au pied. Les deux
  // côtés utilisent donc le MÊME lateralDir (= -patientRightDir, choisi pour
  // que projLat > 0 corresponde au côté D). C'est différent de l'angle
  // calcanéen qui est relatif au pied (D/G opposés volontairement).
  const axeJambierLat = { x: -patientRightDir.x, y: -patientRightDir.y };
  out.axeJambierD = computeAxeJambier(
    byName['Genou D'], byName['Mi-mollet D'], byName['Calcanéum supérieur D'],
    axeJambierLat);
  out.axeJambierG = computeAxeJambier(
    byName['Genou G'], byName['Mi-mollet G'], byName['Calcanéum supérieur G'],
    axeJambierLat);
  return out;
}

// #108 Dos étape 2 — Conclusion scoliose. Seuil provisoire (à promouvoir
// en POSTURE_THRESHOLDS.dos à l'étape 3a). Si |offset apex| > seuilRachis →
// « Attitude scoliotique [région] à convexité [droite/gauche] (proposition) »
// + si rachisSecondaire → « · 2ᵉ courbure [région] convexité [D/G] ».
// Sinon → « Rachis aligné — pas de déviation marquée ».
function _buildDosConclusion(angles) {
  if (!angles) return '';
  // #108 Dos étape 3a — seuil rachis lu depuis POSTURE_THRESHOLDS.dos.rachis
  // (% de la largeur d'épaules). Promu depuis la constante locale étape 2.
  const seuilRachis = POSTURE_THRESHOLDS.dos.rachis;
  const sideWord = c => c === 'D' ? 'droite' : 'gauche';
  if (angles.rachisApex === null || angles.rachisRegion === null) return '';
  const apexOffset = angles.rachisOffsets[angles.rachisApex];
  if (apexOffset === null || isNaN(apexOffset)) return '';
  if (Math.abs(apexOffset) <= seuilRachis) {
    return 'Rachis aligné — pas de déviation marquée';
  }
  let phrase = 'Attitude scoliotique ' + angles.rachisRegion
             + ' à convexité ' + sideWord(angles.rachisConvexite)
             + ' (proposition)';
  if (angles.rachisSecondaire) {
    phrase += ' · 2ᵉ courbure ' + angles.rachisSecondaire.region
            + ' convexité ' + angles.rachisSecondaire.convexite;
  }
  return phrase;
}

// #108 Dos étape 3b — Findings dos (miroir _buildFaceFindings). Liste les
// mesures hors zone neutre + conclusion scoliose, format identique pour
// intégration dans la synthèse et le rapport :
//   { horsNormes: [{ mesure: 'Tête (inclinaison)', detail: 'inclinée à D' }, ...],
//     conclusion: 'Attitude scoliotique … (proposition)' | '' }
// Règle « hors-normes seulement » : on n'émet QUE si hors zone neutre (cf
// seuils Td.tete/.epaules/.bassin/.scapulaMin/Max/.scapulaAsym/.sillon/
// .triangles/.calcaneen/.axeJambier). null/NaN → skip silencieux (point non
// placé). La conclusion `Rachis aligné — pas de déviation marquée` est vidée
// pour permettre au caller d'afficher le fallback « dans les normes » global.
function _buildDosFindings(angles, thr) {
  thr = thr || POSTURE_THRESHOLDS;
  const Td = thr.dos;
  const empty = { horsNormes: [], conclusion: '' };
  if (!angles) return empty;
  const horsNormes = [];
  const push = (mesure, detail) => horsNormes.push({ mesure, detail });
  const sideD = (v, posTxt, negTxt) => v > 0 ? posTxt : negTxt;
  // Tête (inclinaison / rotation) — seuil unique Td.tete.
  if (angles.inclinaisonTete !== null && !isNaN(angles.inclinaisonTete) && Math.abs(angles.inclinaisonTete) > Td.tete) {
    push('Tête (inclinaison)', sideD(angles.inclinaisonTete, 'inclinée à D', 'inclinée à G'));
  }
  if (angles.rotationTete !== null && !isNaN(angles.rotationTete) && Math.abs(angles.rotationTete) > Td.tete) {
    push('Tête (rotation)', sideD(angles.rotationTete, 'rotation à D', 'rotation à G'));
  }
  // Ligne épaules / asymétrie scapulas (en hauteur) — seuil Td.epaules.
  if (angles.ligneEpaules !== null && !isNaN(angles.ligneEpaules) && Math.abs(angles.ligneEpaules) > Td.epaules) {
    push('Ligne épaules', sideD(angles.ligneEpaules, 'D plus haute', 'G plus haute'));
  }
  if (angles.asymetrieScapula !== null && !isNaN(angles.asymetrieScapula) && Math.abs(angles.asymetrieScapula) > Td.epaules) {
    push('Asymétrie scapulas (hauteur)', sideD(angles.asymetrieScapula, 'D plus haute', 'G plus haute'));
  }
  // Orientation scapulaire : bande physiologique [Td.scapulaMin, Td.scapulaMax].
  // Hors bande = libellé clinique (rot. interne sous min, rot. externe au-dessus
  // de max). Dans bande = neutre → skip (pas de finding).
  const scapulaBand = v => {
    if (v < Td.scapulaMin) return 'rotation interne (rétropulsion d\'épaule)';
    if (v > Td.scapulaMax) return 'rotation externe (enroulement antérieur d\'épaule)';
    return null;
  };
  if (angles.orientationScapulaD !== null && !isNaN(angles.orientationScapulaD)) {
    const dD = scapulaBand(angles.orientationScapulaD);
    if (dD) push('Scapula D', dD);
  }
  if (angles.orientationScapulaG !== null && !isNaN(angles.orientationScapulaG)) {
    const dG = scapulaBand(angles.orientationScapulaG);
    if (dG) push('Scapula G', dG);
  }
  // Asymétrie orientation scapulaire D − G — seuil Td.scapulaAsym.
  if (angles.asymetrieOrientationScapula !== null && !isNaN(angles.asymetrieOrientationScapula) && Math.abs(angles.asymetrieOrientationScapula) > Td.scapulaAsym) {
    push('Asymétrie orientation scapulaire', sideD(angles.asymetrieOrientationScapula, 'D plus externe', 'G plus externe'));
  }
  // Bassin — bascule (Td.bassin) + sillon (Td.sillon) + triangles (Td.triangles).
  if (angles.basculeBassin !== null && !isNaN(angles.basculeBassin) && Math.abs(angles.basculeBassin) > Td.bassin) {
    push('Bascule bassin', sideD(angles.basculeBassin, 'D plus haute', 'G plus haute'));
  }
  if (angles.sillonInterfessier !== null && !isNaN(angles.sillonInterfessier) && Math.abs(angles.sillonInterfessier) > Td.sillon) {
    push('Sillon inter-fessier', sideD(angles.sillonInterfessier, 'à D', 'à G'));
  }
  if (angles.trianglesTaille !== null && !isNaN(angles.trianglesTaille) && Math.abs(angles.trianglesTaille) > Td.triangles) {
    push('Triangles de la taille', sideD(angles.trianglesTaille, 'D plus ouvert', 'G plus ouvert'));
  }
  // Membre inférieur — calcanéen (Td.calcaneen) valgus/varus + axe jambier
  // (Td.axeJambier) dévié à D/G (repère absolu patient — voir _computeDosAngles).
  if (angles.angleCalcaneenD !== null && !isNaN(angles.angleCalcaneenD) && Math.abs(angles.angleCalcaneenD) > Td.calcaneen) {
    push('Calcanéum D', sideD(angles.angleCalcaneenD, 'valgus', 'varus'));
  }
  if (angles.angleCalcaneenG !== null && !isNaN(angles.angleCalcaneenG) && Math.abs(angles.angleCalcaneenG) > Td.calcaneen) {
    push('Calcanéum G', sideD(angles.angleCalcaneenG, 'valgus', 'varus'));
  }
  if (angles.axeJambierD !== null && !isNaN(angles.axeJambierD) && Math.abs(angles.axeJambierD) > Td.axeJambier) {
    push('Axe jambier D', sideD(angles.axeJambierD, 'dévié à D', 'dévié à G'));
  }
  if (angles.axeJambierG !== null && !isNaN(angles.axeJambierG) && Math.abs(angles.axeJambierG) > Td.axeJambier) {
    push('Axe jambier G', sideD(angles.axeJambierG, 'dévié à D', 'dévié à G'));
  }
  // Conclusion scoliose — vidée si « Rachis aligné » pour ne pas empêcher
  // le fallback « Posture dos dans les normes » côté caller.
  let conclusion = _buildDosConclusion(angles);
  if (conclusion.startsWith('Rachis aligné')) conclusion = '';
  return { horsNormes, conclusion };
}

// #108 Étape 4 — Couplage face+dos : détection de rotations antérieures et
// translations par ceinture (pelvienne / tronc / scapulaire). Principe : on
// croise un repère ANTÉRIEUR (face : devNombril, translationThorax) avec le
// repère POSTÉRIEUR correspondant (dos : rachisOffsets.L3/TH6/TH3/C7) au même
// étage. Les SIGNES OPPOSÉS révèlent une rotation autour de l'axe vertical
// (le côté du repère postérieur indique vers où la ceinture s'est tournée en
// avant) ; les SIGNES IDENTIQUES révèlent une translation/latéralisation pure
// (la ceinture entière est décalée du côté commun).
// Seuil POSTURE_THRESHOLDS.crossView.seuil applicable aux 2 valeurs : si l'une
// ou l'autre est sous le seuil, on n'émet rien (pas d'asymétrie significative).
// Retour : liste plate de chaînes prêtes à pousser dans items synthèse/rapport.
function _buildCrossViewFindings(faceAngles, dosAngles, thr) {
  thr = thr || POSTURE_THRESHOLDS;
  const seuil = thr.crossView.seuil;
  const avg2 = (a, b) => (a === null || b === null || isNaN(a) || isNaN(b)) ? null : (a + b) / 2;
  const beltFinding = (A, P, labelRot, labelTrans) => {
    if (A === null || P === null || isNaN(A) || isNaN(P)) return null;
    if (Math.abs(A) <= seuil || Math.abs(P) <= seuil) return null;
    const w = s => s > 0 ? 'droite' : 'gauche';
    // Sens opposés → rotation antérieure du côté POSTÉRIEUR (= signe de P).
    if (Math.sign(A) !== Math.sign(P)) return labelRot + ' ' + w(P);
    // Même sens → translation / latéralisation du côté commun.
    return labelTrans + ' ' + w(A);
  };
  const out = [];
  const f = (x) => { if (x) out.push(x); };
  // Ceinture pelvienne : Nombril (antérieur) vs L3 (postérieur).
  f(beltFinding(
    faceAngles.devNombril, dosAngles.rachisOffsets.L3,
    'Bassin en rotation antérieure', 'Translation du bassin à'));
  // Tronc : moyenne (Nombril, FourchetteSternale) antérieur vs moyenne (L3, TH6) postérieur.
  f(beltFinding(
    avg2(faceAngles.devNombril, faceAngles.translationThorax),
    avg2(dosAngles.rachisOffsets.L3, dosAngles.rachisOffsets.TH6),
    'Tronc en rotation antérieure', 'Latéralisation du tronc à'));
  // Ceinture scapulaire : FourchetteSternale (antérieur) vs moyenne (C7, TH3) postérieur.
  f(beltFinding(
    faceAngles.translationThorax,
    avg2(dosAngles.rachisOffsets.C7, dosAngles.rachisOffsets.TH3),
    'Ceinture scapulaire en rotation antérieure', 'Latéralisation de la ceinture scapulaire à'));
  return out;
}

// #108 Étape 3b — Findings face (miroir _buildPostureFindings). Liste les
// mesures hors zone neutre + conclusion latéralisée, format identique pour
// intégration dans la synthèse et le rapport :
//   { horsNormes: [{ mesure: 'Tête (inclinaison)', detail: 'inclinée à D' }, ...],
//     conclusion: 'Latéralisation à partir … · Tête inclinée à D' | '' }
// Règle « hors-normes seulement » : on n'émet QUE si hors zone neutre (cf
// seuils Tf.tete/.epaules/.bassin/.translation/.valgumVarum/.ouvertureMin/Max).
// null/NaN → skip silencieux (point non placé). Le caller décide du message
// « dans les normes » si horsNormes ET conclusion sont vides.
function _buildFaceFindings(angles, thr) {
  thr = thr || POSTURE_THRESHOLDS;
  const Tf = thr.face;
  const empty = { horsNormes: [], conclusion: '' };
  if (!angles) return empty;
  const horsNormes = [];
  const push = (mesure, detail) => horsNormes.push({ mesure, detail });
  const sideD = (v, posTxt, negTxt) => v > 0 ? posTxt : negTxt;
  // Tête (inclinaison / rotation / mandibule) — seuil unique Tf.tete.
  if (angles.inclinaisonTete !== null && !isNaN(angles.inclinaisonTete) && Math.abs(angles.inclinaisonTete) > Tf.tete) {
    push('Tête (inclinaison)', sideD(angles.inclinaisonTete, 'inclinée à D', 'inclinée à G'));
  }
  if (angles.rotationTete !== null && !isNaN(angles.rotationTete) && Math.abs(angles.rotationTete) > Tf.tete) {
    push('Tête (rotation)', sideD(angles.rotationTete, 'rotation à D', 'rotation à G'));
  }
  if (angles.deviationMandibule !== null && !isNaN(angles.deviationMandibule) && Math.abs(angles.deviationMandibule) > Tf.tete) {
    push('Mandibule', sideD(angles.deviationMandibule, 'déviation à D', 'déviation à G'));
  }
  if (angles.nezTordu === true) {
    push('Nez', 'désaxé sans rotation de tête (à vérifier)');
  }
  // Épaules / Bassin — seuils dédiés.
  if (angles.ligneEpaules !== null && !isNaN(angles.ligneEpaules) && Math.abs(angles.ligneEpaules) > Tf.epaules) {
    push('Ligne épaules', sideD(angles.ligneEpaules, 'D plus haute', 'G plus haute'));
  }
  if (angles.basculeBassin !== null && !isNaN(angles.basculeBassin) && Math.abs(angles.basculeBassin) > Tf.bassin) {
    push('Bascule bassin', sideD(angles.basculeBassin, 'D plus haute', 'G plus haute'));
  }
  // Fermeture viscérale = string 'D' | 'G' | null (déjà classifiée par _computeFaceAngles).
  if (angles.fermetureViscerale) {
    push('Fermeture viscérale', 'fermeture ' + angles.fermetureViscerale);
  }
  // Translations — seuil Tf.translation (en %).
  if (angles.translationThorax !== null && !isNaN(angles.translationThorax) && Math.abs(angles.translationThorax) > Tf.translation) {
    push('Translation thorax', sideD(angles.translationThorax, 'décalé à D', 'décalé à G'));
  }
  if (angles.translationBassin !== null && !isNaN(angles.translationBassin) && Math.abs(angles.translationBassin) > Tf.translation) {
    push('Translation bassin', sideD(angles.translationBassin, 'décalé à D', 'décalé à G'));
  }
  // Tronc (Nombril → Fourchette) — réutilise Tf.tete (inclinaison latérale).
  if (angles.inclinaisonTronc !== null && !isNaN(angles.inclinaisonTronc) && Math.abs(angles.inclinaisonTronc) > Tf.tete) {
    push('Tronc (inclinaison)', sideD(angles.inclinaisonTronc, 'incliné à D', 'incliné à G'));
  }
  // Genoux — Tf.valgumVarum. + = valgum / − = varum (sémantique _computeFaceAngles).
  if (angles.valgumVarumD !== null && !isNaN(angles.valgumVarumD) && Math.abs(angles.valgumVarumD) > Tf.valgumVarum) {
    push('Genou D', sideD(angles.valgumVarumD, 'valgum', 'varum'));
  }
  if (angles.valgumVarumG !== null && !isNaN(angles.valgumVarumG) && Math.abs(angles.valgumVarumG) > Tf.valgumVarum) {
    push('Genou G', sideD(angles.valgumVarumG, 'valgum', 'varum'));
  }
  // Pieds — bande physiologique [Tf.ouvertureMin, Tf.ouvertureMax] (angle de Fick).
  const ouvertureBand = v => {
    if (v < Tf.ouvertureMin) return 'en fermeture';
    if (v > Tf.ouvertureMax) return 'en ouverture';
    return null;
  };
  if (angles.ouverturePasD !== null && !isNaN(angles.ouverturePasD)) {
    const dD = ouvertureBand(angles.ouverturePasD);
    if (dD) push('Pied D', dD);
  }
  if (angles.ouverturePasG !== null && !isNaN(angles.ouverturePasG)) {
    const dG = ouvertureBand(angles.ouverturePasG);
    if (dG) push('Pied G', dG);
  }
  return { horsNormes, conclusion: _buildFaceConclusion(angles) };
}

// Calcule le vecteur plumb_up affichable (réutilisé pour le tracé du fil à plomb).
// Logique identique à _computePostureAngles (DRY évité car appelée dans la boucle
// de redraw — duplication contrôlée < 10 lignes pour éviter un getter dédié).
function _getPostureModalPlumbUp() {
  const cal = _postureCalibration;
  if (cal && cal.p1 && cal.p2) {
    const dx = cal.p2.x - cal.p1.x;
    const dy = cal.p2.y - cal.p1.y;
    const len = Math.hypot(dx, dy);
    if (len > 0) {
      let perp = { x: -dy / len, y: dx / len };
      if (perp.y > 0) perp = { x: -perp.x, y: -perp.y };
      return perp;
    }
  }
  return { x: 0, y: -1 };
}

// #106-A — Classification posturale : applique les seuils POSTURE_THRESHOLDS
// aux angles calculés pour produire une « proposition » de tendance par mesure.
// Retour : { cva, tronc, cuisse, jambe, bassin, hanche, genou, epaule,
//           cervicale, thoracique, lombaire } où chaque entrée est :
//   - null si la mesure n'est pas calculable (point requis manquant) ;
//   - { tendance: 'normes' }       si dans la zone de neutralité ;
//   - { tendance: 'hors-normes' }  si hors zone (mesures à zéro) ;
//   - { tendance: 'normes' | 'rectitude' | 'hyper', label: '<texte clinique>' }
//     pour les courbures (rectitude / normes / hyperlordose / hypercyphose).
// La signature accepte un thr custom pour permettre des tests unitaires sans
// dépendance au global mutable POSTURE_THRESHOLDS.
function _classifyPostureAngles(angles, thr) {
  thr = thr || POSTURE_THRESHOLDS;
  if (!angles) return {};
  const n = thr.neutralite;
  const out = {};
  // Mesure centrée sur 0, zone de neutralité ±seuil.
  const classifyNeutral = (val, seuil) => {
    if (val === null || isNaN(val)) return null;
    return { tendance: Math.abs(val) <= seuil ? 'normes' : 'hors-normes' };
  };
  // Courbure : déviation 180−angle. <rectitude → rectitude / [rectitude,hyper]
  // → normes / >hyper → hyper. Libellé hyper distinct cervicale/lombaire
  // (hyperlordose) vs thoracique (hypercyphose).
  const classifyCurvature = (dev, bands, hyperLabel) => {
    if (dev === null || isNaN(dev)) return null;
    if (dev < bands.rectitude) return { tendance: 'rectitude', label: 'rectitude / perte de courbure' };
    if (dev > bands.hyper)     return { tendance: 'hyper',     label: hyperLabel };
    return { tendance: 'normes', label: 'normes' };
  };
  // CVA : référencée à 50° (norme). Zone neutre = |cva−50| ≤ n.cva.
  if (angles.cva !== null && !isNaN(angles.cva)) {
    out.cva = { tendance: Math.abs(angles.cva - 50) <= n.cva ? 'normes' : 'hors-normes' };
  } else {
    out.cva = null;
  }
  // Segments d'orientation (Tronc, Cuisse, Jambe) — tous seuil n.anteriorisation.
  out.tronc  = classifyNeutral(angles.flexionHanche, n.anteriorisation);
  out.cuisse = classifyNeutral(angles.cuisse,        n.anteriorisation);
  // Jambe = angle d'antériorisation du genou depuis le fil à plomb à la cheville.
  out.jambe  = classifyNeutral(angles.genou,         n.anteriorisation);
  // Bassin / Hanche articulaire / Épaule.
  out.bassin = classifyNeutral(angles.bassin, n.bassin);
  out.hanche = classifyNeutral(angles.hanche, n.hanche);
  out.epaule = classifyNeutral(angles.epaules, n.epaule);
  // Genou flex/réc — utilise la valeur centrée (180−genouFlexion), comme l'affichage.
  const genouCentered = (angles.genouFlexion === null || isNaN(angles.genouFlexion))
    ? null : 180 - angles.genouFlexion;
  out.genou = classifyNeutral(genouCentered, n.genou);
  // Courbures rachidiennes (libellés cliniques par segment).
  out.cervicale  = classifyCurvature(angles.deviationCervicale,  thr.courbures.cervicale,  'hyperlordose');
  out.thoracique = classifyCurvature(angles.deviationThoracique, thr.courbures.thoracique, 'hypercyphose');
  out.lombaire   = classifyCurvature(angles.deviationLombaire,   thr.courbures.lombaire,   'hyperlordose');
  return out;
}

// #106-B — Construit la phrase de Conclusion (ordre bas→haut : jambe → cuisse
// → tronc → tête). Renvoie '' si tous les segments sont dans leur zone de
// neutralité. Source de vérité unique pour la modale ET la synthèse/rapport
// (évite la divergence si la logique évolue). CVA traité à part : référencée
// à 50° avec son seuil propre n.cva, pas à 0 comme les autres.
function _buildPostureConclusion(angles, thr) {
  thr = thr || POSTURE_THRESHOLDS;
  if (!angles) return '';
  const n = thr.neutralite;
  const parts = [];
  const addAnter = (val, origin) => {
    if (val === null || isNaN(val) || Math.abs(val) <= n.anteriorisation) return;
    parts.push((val > 0 ? 'Antériorisation' : 'Postériorisation') + ' à partir ' + origin);
  };
  addAnter(angles.genou,         'des chevilles'); // Jambe
  addAnter(angles.cuisse,        'des genoux');    // Cuisse
  addAnter(angles.flexionHanche, 'du bassin');     // Tronc
  if (angles.cva !== null && !isNaN(angles.cva)) {
    const delta = angles.cva - 50;
    if (Math.abs(delta) > n.cva) {
      parts.push((delta < 0 ? 'Antériorisation' : 'Postériorisation') + ' à partir des cervicales');
    }
  }
  return parts.join(' · ');
}

// #106-B — Liste des mesures hors-normes + conclusion, pour intégration dans
// la synthèse posturo et le rapport PDF. Format :
//   { horsNormes: [{ mesure: 'Tronc', detail: 'antérieur' }, ...],
//     conclusion: 'Antériorisation à partir du bassin · …' | '' }
// Le caller décide du marquage « dans les normes » si horsNormes + conclusion
// sont tous deux vides (cf brief : « Posture profil dans les normes — aucune
// tendance marquée »). Libellés cliniques alignés sur ceux affichés en modale.
function _buildPostureFindings(angles, thr, analysis) {
  thr = thr || POSTURE_THRESHOLDS;
  const empty = { horsNormes: [], conclusion: '' };
  if (!angles) return empty;
  const cls = _classifyPostureAngles(angles, thr);
  const horsNormes = [];
  const push = (mesure, detail) => horsNormes.push({ mesure, detail });
  // Tête (CVA) — libellé spécifique antépulsion/rétropulsion + dir antérieur/postérieur.
  if (cls.cva && cls.cva.tendance !== 'normes') {
    const delta = angles.cva - 50;
    push('Tête (CVA)', delta < 0
      ? 'antérieur (antépulsion de tête)'
      : 'postérieur (rétropulsion de tête)');
  }
  // Segments d'orientation (Tronc/Cuisse/Jambe) — antérieur/postérieur par signe.
  if (cls.tronc  && cls.tronc.tendance  !== 'normes') push('Tronc',  angles.flexionHanche > 0 ? 'antérieur' : 'postérieur');
  if (cls.cuisse && cls.cuisse.tendance !== 'normes') push('Cuisse', angles.cuisse        > 0 ? 'antérieur' : 'postérieur');
  if (cls.jambe  && cls.jambe.tendance  !== 'normes') push('Jambe',  angles.genou         > 0 ? 'antérieur' : 'postérieur');
  // Bassin / Hanche articulaire / Genou flex-réc / Épaule.
  if (cls.bassin && cls.bassin.tendance !== 'normes') push('Bassin', angles.bassin > 0 ? 'antéversion' : 'rétroversion');
  if (cls.hanche && cls.hanche.tendance !== 'normes') push('Hanche', angles.hanche > 0 ? 'flexion de hanche' : 'extension de hanche');
  if (cls.genou  && cls.genou.tendance  !== 'normes') {
    const genouCentered = 180 - angles.genouFlexion;
    push('Genou', genouCentered > 0 ? 'flessum' : 'récurvatum');
  }
  // Épaule : libellé clinique défini uniquement pour valeur positive (enroulement
  // antérieur). Valeurs négatives n'ont pas de terme conventionnel → on skip,
  // ne polluons pas la liste avec « hors-normes » sans libellé.
  if (cls.epaule && cls.epaule.tendance !== 'normes' && angles.epaules > 0) {
    push('Épaule', 'enroulement antérieur');
  }
  // #106-Final Volet 3e — Courbures : utilise l'interprétation du praticien
  // (curveInterp) si présente, sinon mapping auto depuis la tendance. Règle
  // « hors-normes seulement » : on affiche la courbure UNIQUEMENT si l'interp
  // n'est pas « Normale ». Format direct (« Hyperlordose »), sans « proposition ».
  ['cervicale', 'thoracique', 'lombaire'].forEach(courbure => {
    const interp = _resolveCurveInterp(analysis, cls, courbure);
    if (interp && interp !== 'Normale') {
      const label = courbure.charAt(0).toUpperCase() + courbure.slice(1);
      push(label, interp);
    }
  });
  return { horsNormes, conclusion: _buildPostureConclusion(angles, thr) };
}

// #106-B fix — Helper synthèse partagé (posturo + sport). Renvoie le tableau
// des sections « 📐 Analyse posturale — profil <gauche|droit> (propositions à
// valider) » pour chaque vue placée. Une section vide n'est PAS pushée (pas de
// vue analysée = pas de bruit). Appelé par genererSynthese (posturo, d = currentPatient.
// bilanDataPosturo) ET genererSyntheseSport (sport, d = bilanData global) — l'identité
// d'objet est différente mais la lecture _postureAnalysis y est symétrique :
// _validatePosturePlacement écrit dans bd via _getPostureBilanData(prefix), qui
// renvoie le MÊME objet (bilanData pour 'sp', currentPatient.bilanDataPosturo pour 'po').
// #106-Final Volet 3 — Interprétation courbures éditable par le praticien.
// Les options dépendent du segment : cervicale et lombaire sont lordoses
// normales → hyper = Hyperlordose ; thoracique est cyphose normale → hyper =
// Hypercyphose. L'option « Inversion » (rare : cyphose cervicale, lordose
// thoracique) n'est jamais proposée automatiquement, uniquement choisie par
// le praticien.
const POSTURE_COURBURE_OPTIONS = {
  cervicale:  ['Hyperlordose', 'Normale', 'Rectitude', 'Inversion'],
  thoracique: ['Hypercyphose', 'Normale', 'Rectitude', 'Inversion'],
  lombaire:   ['Hyperlordose', 'Normale', 'Rectitude', 'Inversion'],
};
const POSTURE_COURBURE_HYPER_LABEL = {
  cervicale:  'Hyperlordose',
  thoracique: 'Hypercyphose',
  lombaire:   'Hyperlordose',
};

// Mappe la tendance auto (cls[courbure].tendance) vers le label de l'option
// sélectionnée. null si la mesure n'est pas calculable (point manquant).
function _autoCurveInterp(cls, courbure) {
  if (!cls || !cls[courbure]) return null;
  const tendance = cls[courbure].tendance;
  if (tendance === 'hyper')      return POSTURE_COURBURE_HYPER_LABEL[courbure];
  if (tendance === 'rectitude')  return 'Rectitude';
  if (tendance === 'normes')     return 'Normale';
  return null;
}

// Résout l'interprétation courante : praticien (si curveInterp défini), sinon auto.
function _resolveCurveInterp(analysis, cls, courbure) {
  const saved = analysis?.curveInterp?.[courbure];
  if (saved) return saved;
  return _autoCurveInterp(cls, courbure);
}

// Handler onchange des 3 <select>. Mutation partielle (préserve markers/
// calibration/angles existants) + auto-save selon préfixe. Pattern miroir
// _onPostureCalibrationChange + _validatePosturePlacement save flow.
async function _onCurveInterpChange(prefix, viewKey, courbure, value) {
  const bd = _getPostureBilanData(prefix);
  if (!bd) return;
  if (!bd._postureAnalysis) bd._postureAnalysis = {};
  if (!bd._postureAnalysis[viewKey]) bd._postureAnalysis[viewKey] = {};
  if (!bd._postureAnalysis[viewKey].curveInterp) bd._postureAnalysis[viewKey].curveInterp = {};
  bd._postureAnalysis[viewKey].curveInterp[courbure] = value;
  try {
    if (prefix === 'sp' && typeof saveBilanSilent === 'function') {
      await saveBilanSilent();
    } else if (prefix === 'po' && typeof savePosturoBilan === 'function') {
      await savePosturoBilan(true);
    }
  } catch (e) {
    console.warn('[#106-Final] auto-save curveInterp posture échoué :', e?.message);
  }
}

function _buildPostureProfilSectionsSynthese(d) {
  const out = [];
  ['profilG', 'profilD'].forEach(function(viewKey) {
    const analysis = d && d._postureAnalysis && d._postureAnalysis[viewKey];
    if (!analysis || !analysis.angles) return;
    // #106-Final Volet 3e — _buildPostureFindings reçoit `analysis` pour pouvoir
    // appliquer curveInterp (interprétation praticien sur les courbures, qui
    // remplace la classification auto). Mesures non-courbures inchangées.
    const findings = _buildPostureFindings(analysis.angles, undefined, analysis);
    const items = [];
    findings.horsNormes.forEach(function(f) { items.push(f.mesure + ' : ' + f.detail); });
    if (findings.conclusion) items.push('Conclusion : ' + findings.conclusion);
    if (!items.length) items.push('Posture profil dans les normes — aucune tendance marquée');
    const side = viewKey === 'profilG' ? 'gauche' : 'droit';
    // #106-Final Volet 2 — titre nettoyé : plus de « (propositions à valider) ».
    out.push({
      titre: '📐 Analyse posturale — profil ' + side,
      items: items,
    });
  });
  // #108 Étape 3b — Bloc face (placement seul à étape 1, mesures étape 2,
  // findings étape 3b). Même schéma que profil : on lit les angles persistés
  // par _validatePosturePlacement, on bâtit la liste hors-normes + conclusion
  // via _buildFaceFindings, et on pousse une section unique. L'ordre cosmétique
  // (profil puis face) garde la cohérence visuelle « profil d'abord ».
  const fa = d && d._postureAnalysis && d._postureAnalysis.face;
  if (fa && fa.angles) {
    const ff = _buildFaceFindings(fa.angles);
    const items = [];
    ff.horsNormes.forEach(function(x) { items.push(x.mesure + ' : ' + x.detail); });
    if (ff.conclusion) items.push('Conclusion : ' + ff.conclusion);
    if (!items.length) items.push('Posture face dans les normes — aucune tendance marquée');
    out.push({
      titre: '📐 Analyse posturale — face',
      items: items,
    });
  }
  // #108 Dos étape 3b — Bloc dos (placement étape 1, mesures étape 2, seuils
  // configurables étape 3a, findings étape 3b). Même schéma que profil et face :
  // angles persistés par _validatePosturePlacement, hors-normes + conclusion
  // scoliose via _buildDosFindings. Ordre cosmétique : profil → face → dos.
  const da = d && d._postureAnalysis && d._postureAnalysis.dos;
  if (da && da.angles) {
    const df = _buildDosFindings(da.angles);
    const items = [];
    df.horsNormes.forEach(function(x) { items.push(x.mesure + ' : ' + x.detail); });
    if (df.conclusion) items.push('Conclusion : ' + df.conclusion);
    if (!items.length) items.push('Posture dos dans les normes — aucune tendance marquée');
    out.push({
      titre: '📐 Analyse posturale — dos',
      items: items,
    });
  }
  // #108 Étape 4 — Bloc couplage face+dos : rotations/translations par ceinture
  // (pelvienne, tronc, scapulaire). Apparaît UNIQUEMENT si les deux vues sont
  // placées (faceAngles ET dosAngles présents). Sinon impossible à raisonner.
  const fa2 = d && d._postureAnalysis && d._postureAnalysis.face;
  const da2 = d && d._postureAnalysis && d._postureAnalysis.dos;
  if (fa2 && fa2.angles && da2 && da2.angles) {
    const cv = _buildCrossViewFindings(fa2.angles, da2.angles);
    const items = cv.length
      ? cv.slice()
      : ['Pas de rotation ni de translation marquée (face + dos cohérents)'];
    out.push({
      titre: '📐 Analyse posturale — rotations (face + dos)',
      items: items,
    });
  }
  return out;
}

// #108 Étape 2 — Panneau résultats face. Reçoit les 11 mesures déjà calculées,
// les regroupe par étage anatomique. Sens latéralisé : libellé « (à D) » /
// « (à G) » en orange si hors seuil neutre, « (neutre) » en vert sinon.
// Pas de classification éditable à ce stade (étape 3 = POSTURE_THRESHOLDS.face
// configurable + selects), juste affichage des valeurs et de l'inclinaison.
// #109-A1 — Signature refactorée : retourne une string HTML au lieu d'écrire
// directement `panel.innerHTML`. Le dispatcher (`_renderPosturePlacementResults`)
// et l'helper unifié (`_buildPosturePanelHTML`) consomment la string.
function _renderFacePlacementResults(f) {
  // #108 Étape 3a — seuils lus depuis POSTURE_THRESHOLDS.face (configurables
  // depuis Paramètres). Les anciennes constantes inline (étape 2) ont été
  // promues dans POSTURE_THRESHOLDS_DEFAULTS.face.
  const Tf = POSTURE_THRESHOLDS.face;
  const SEUIL_TETE      = Tf.tete;        // ° pour inclinaison/rotation/mandibule
  const SEUIL_EPAULES   = Tf.epaules;
  const SEUIL_BASSIN    = Tf.bassin;
  const SEUIL_TRANSL    = Tf.translation; // % de la largeur d'appui
  const SEUIL_VALG_VAR  = Tf.valgumVarum; // ° de déviation au genou
  // Ouverture du pas = bande physiologique [OUV_MIN, OUV_MAX] non centrée sur 0
  // (angle de Fick : le pied est naturellement en rotation externe).
  const OUV_MIN         = Tf.ouvertureMin;
  const OUV_MAX         = Tf.ouvertureMax;
  const lblStyle = c => `color:${c};font-size:11px;margin-left:4px;`;
  const groupHdr = `font-weight:600;color:#0e1f38;margin-bottom:4px;font-size:10px;text-transform:uppercase;letter-spacing:0.4px;`;
  const lbl = `color:#64748b;`;
  const fmtDeg = v => (v === null || isNaN(v))
    ? `<span style="color:#94a3b8;">—</span>`
    : `<span style="color:${v > 0 ? '#3b82f6' : v < 0 ? '#dc2626' : '#0e1f38'};font-weight:700;">${v > 0 ? '+' : ''}${v.toFixed(1)}°</span>`;
  const fmtPct = v => (v === null || isNaN(v))
    ? `<span style="color:#94a3b8;">—</span>`
    : `<span style="color:${v > 0 ? '#3b82f6' : v < 0 ? '#dc2626' : '#0e1f38'};font-weight:700;">${v > 0 ? '+' : ''}${v.toFixed(1)} %</span>`;
  // Libellé de sens patient-D / patient-G avec zone neutre.
  const sideLbl = (v, seuil, posTxt, negTxt) => {
    if (v === null || isNaN(v)) return '';
    if (Math.abs(v) <= seuil) return `<span style="${lblStyle('#10b981')}">(neutre)</span>`;
    if (v > 0) return `<span style="${lblStyle('#ea580c')}">${posTxt}</span>`;
    return `<span style="${lblStyle('#ea580c')}">${negTxt}</span>`;
  };
  // Variants courts.
  const lblTeteIncl     = v => sideLbl(v, SEUIL_TETE, '(inclinée à D)', '(inclinée à G)');
  const lblRotation     = v => sideLbl(v, SEUIL_TETE, '(rotation à D)', '(rotation à G)');
  const lblMandibule    = v => sideLbl(v, SEUIL_TETE, '(déviation à D)', '(déviation à G)');
  const lblEpaules      = v => sideLbl(v, SEUIL_EPAULES, '(D plus haute)', '(G plus haute)');
  const lblBassin       = v => sideLbl(v, SEUIL_BASSIN, '(D plus haute)', '(G plus haute)');
  const lblTranslat     = v => sideLbl(v, SEUIL_TRANSL, '(décalé à D)', '(décalé à G)');
  const lblValgVar      = v => sideLbl(v, SEUIL_VALG_VAR, '(valgum)', '(varum)');
  // Ouverture du pas : classification en bande physiologique [OUV_MIN, OUV_MAX].
  // Hors bande = orange (fermé / ouvert) ; dans bande = vert (physiologique).
  // Le code couleur bleu(+)/rouge(−)/gris(null) de fmtDeg reste inchangé sur
  // la valeur numérique elle-même — seul le libellé entre parenthèses suit la bande.
  const lblOuverture = v => {
    if (v === null || isNaN(v)) return '';
    if (v < OUV_MIN) return `<span style="${lblStyle('#ea580c')}">(fermé)</span>`;
    if (v > OUV_MAX) return `<span style="${lblStyle('#ea580c')}">(ouvert)</span>`;
    return `<span style="${lblStyle('#10b981')}">(physiologique)</span>`;
  };
  const lblTroncIncl    = v => sideLbl(v, SEUIL_TETE, '(incliné à D)', '(incliné à G)');
  const fermLbl = f.fermetureViscerale
    ? `<span style="${lblStyle('#ea580c')}">(fermeture ${f.fermetureViscerale})</span>`
    : `<span style="${lblStyle('#10b981')}">(neutre)</span>`;
  const nezTorduAlert = f.nezTordu
    ? `<div style="margin-top:4px;padding:4px 6px;background:#fff7ed;border-left:3px solid #ea580c;font-size:11px;color:#9a3412;">⚠ Nez désaxé sans rotation de la tête (à vérifier cliniquement).</div>`
    : '';
  // Conclusion (latéralisation par étage).
  const conclusionText = _buildFaceConclusion(f) || 'Alignement global — pas de latéralisation marquée';
  return `
    <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:8px 14px;width:100%;font-size:12px;line-height:1.55;">
      <div>
        <div style="${groupHdr}">Tête</div>
        <div><span style="${lbl}">Inclinaison :</span> ${fmtDeg(f.inclinaisonTete)} ${lblTeteIncl(f.inclinaisonTete)}</div>
        <div><span style="${lbl}">Rotation :</span> ${fmtDeg(f.rotationTete)} ${lblRotation(f.rotationTete)}</div>
        <div><span style="${lbl}">Mandibule :</span> ${fmtDeg(f.deviationMandibule)} ${lblMandibule(f.deviationMandibule)}</div>
        ${nezTorduAlert}
      </div>
      <div>
        <div style="${groupHdr}">Épaules / Bassin</div>
        <div><span style="${lbl}">Ligne épaules :</span> ${fmtDeg(f.ligneEpaules)} ${lblEpaules(f.ligneEpaules)}</div>
        <div><span style="${lbl}">Bascule bassin :</span> ${fmtDeg(f.basculeBassin)} ${lblBassin(f.basculeBassin)}</div>
        <div><span style="${lbl}">Fermeture viscérale :</span> ${fermLbl}</div>
      </div>
      <div>
        <div style="${groupHdr}">Translations latérales</div>
        <div><span style="${lbl}">Thorax :</span> ${fmtPct(f.translationThorax)} ${lblTranslat(f.translationThorax)}</div>
        <div><span style="${lbl}">Bassin :</span> ${fmtPct(f.translationBassin)} ${lblTranslat(f.translationBassin)}</div>
        <div><span style="${lbl}">Tronc (Nombril→Fourchette) :</span> ${fmtDeg(f.inclinaisonTronc)} ${lblTroncIncl(f.inclinaisonTronc)}</div>
      </div>
      <div>
        <div style="${groupHdr}">Genoux / Pieds</div>
        <div><span style="${lbl}">Valgum/Varum D :</span> ${fmtDeg(f.valgumVarumD)} ${lblValgVar(f.valgumVarumD)}</div>
        <div><span style="${lbl}">Valgum/Varum G :</span> ${fmtDeg(f.valgumVarumG)} ${lblValgVar(f.valgumVarumG)}</div>
        <div><span style="${lbl}">Ouverture pas D :</span> ${fmtDeg(f.ouverturePasD)} ${lblOuverture(f.ouverturePasD)}</div>
        <div><span style="${lbl}">Ouverture pas G :</span> ${fmtDeg(f.ouverturePasG)} ${lblOuverture(f.ouverturePasG)}</div>
      </div>
      <div style="grid-column:1/-1;border-top:1px solid #cbd5e0;padding-top:5px;color:#0e1f38;line-height:1.45;">
        <span style="font-weight:700;">Conclusion :</span>
        <span>${conclusionText}</span>
      </div>
    </div>
  `;
}

// #108 Dos étape 2 — Panneau résultats dos. Même style que la face (mêmes
// codes couleur valeur, mêmes libellés vert (neutre) / orange (hors-zone)).
// Seuils inline provisoires — à promouvoir en POSTURE_THRESHOLDS.dos à
// l'étape 3a. Les 4 décalages rachis sont en % de la largeur d'épaules,
// avec un encart « Apex / Convexité » dérivé directement de l'angles.rachis*.
// #109-A1 — Même refactor que face : signature angles seul, retour string.
function _renderDosPlacementResults(d) {
  // #108 Dos étape 3a — seuils lus depuis POSTURE_THRESHOLDS.dos (configurables
  // depuis Paramètres). Mapping : tete→tete, ligne épaules + asymétrie scapulas
  // → epaules, bascule→bassin, orientation scapulaire → scapulaMin/scapulaMax,
  // asymétrie orientation → scapulaAsym, rachis→rachis, sillon→sillon,
  // triangles→triangles, calcaneen→calcaneen, axeJambier→axeJambier.
  const Td = POSTURE_THRESHOLDS.dos;
  const SEUIL_TETE      = Td.tete;
  const SEUIL_EPAULES   = Td.epaules;
  const SEUIL_BASSIN    = Td.bassin;
  // Orientation scapulaire = bande physiologique [SCAP_MIN, SCAP_MAX] non
  // centrée sur 0. < min = rotation interne / rétropulsion d'épaule ;
  // > max = rotation externe / enroulement antérieur d'épaule.
  const SCAP_MIN        = Td.scapulaMin;
  const SCAP_MAX        = Td.scapulaMax;
  const SEUIL_SCAP_ASYM = Td.scapulaAsym;
  const SEUIL_RACHIS    = Td.rachis;
  const SEUIL_SILLON    = Td.sillon;
  const SEUIL_TRIANGLES = Td.triangles;
  const SEUIL_CALC      = Td.calcaneen;
  const SEUIL_AXE_JAMB  = Td.axeJambier;
  const lblStyle = c => `color:${c};font-size:11px;margin-left:4px;`;
  const groupHdr = `font-weight:600;color:#0e1f38;margin-bottom:4px;font-size:10px;text-transform:uppercase;letter-spacing:0.4px;`;
  const lbl = `color:#64748b;`;
  const fmtDeg = v => (v === null || isNaN(v))
    ? `<span style="color:#94a3b8;">—</span>`
    : `<span style="color:${v > 0 ? '#3b82f6' : v < 0 ? '#dc2626' : '#0e1f38'};font-weight:700;">${v > 0 ? '+' : ''}${v.toFixed(1)}°</span>`;
  const fmtPct = v => (v === null || isNaN(v))
    ? `<span style="color:#94a3b8;">—</span>`
    : `<span style="color:${v > 0 ? '#3b82f6' : v < 0 ? '#dc2626' : '#0e1f38'};font-weight:700;">${v > 0 ? '+' : ''}${v.toFixed(1)} %</span>`;
  const sideLbl = (v, seuil, posTxt, negTxt) => {
    if (v === null || isNaN(v)) return '';
    if (Math.abs(v) <= seuil) return `<span style="${lblStyle('#10b981')}">(neutre)</span>`;
    if (v > 0) return `<span style="${lblStyle('#ea580c')}">${posTxt}</span>`;
    return `<span style="${lblStyle('#ea580c')}">${negTxt}</span>`;
  };
  const lblTeteIncl = v => sideLbl(v, SEUIL_TETE,    '(inclinée à D)', '(inclinée à G)');
  const lblRotation = v => sideLbl(v, SEUIL_TETE,    '(rotation à D)', '(rotation à G)');
  const lblEpaules  = v => sideLbl(v, SEUIL_EPAULES, '(D plus haute)', '(G plus haute)');
  const lblBassin   = v => sideLbl(v, SEUIL_BASSIN,  '(D plus haute)', '(G plus haute)');
  const lblScapAsym = v => sideLbl(v, SEUIL_EPAULES, '(D plus haute)', '(G plus haute)');
  // Orientation scapulaire : classification en bande physiologique [SCAP_MIN,
  // SCAP_MAX]. Hors bande = orange (rotation interne / externe avec libellé
  // clinique court) ; dans bande = vert (physiologique). Le code couleur de
  // fmtDeg sur la valeur numérique reste inchangé (bleu+/rouge−/gris null).
  const lblScapOri = v => {
    if (v === null || isNaN(v)) return '';
    if (v < SCAP_MIN) return `<span style="${lblStyle('#ea580c')}">(rotation interne — rétropulsion d'épaule)</span>`;
    if (v > SCAP_MAX) return `<span style="${lblStyle('#ea580c')}">(rotation externe — enroulement antérieur d'épaule)</span>`;
    return `<span style="${lblStyle('#10b981')}">(physiologique)</span>`;
  };
  // Asymétrie D − G de l'orientation scapulaire : + = D plus en rotation
  // externe que G (= D plus enroulée antérieurement). Seuil SEUIL_SCAP_ASYM.
  const lblScapAsymOri = v => sideLbl(v, SEUIL_SCAP_ASYM, '(D plus externe)', '(G plus externe)');
  const lblRachisOff = v => sideLbl(v, SEUIL_RACHIS, '(à D)',          '(à G)');
  const lblSillon    = v => sideLbl(v, SEUIL_SILLON, '(à D)',          '(à G)');
  const lblTriangles = v => sideLbl(v, SEUIL_TRIANGLES, '(D plus ouvert)', '(G plus ouvert)');
  const lblCalc      = v => sideLbl(v, SEUIL_CALC,   '(valgus)',       '(varus)');
  const lblAxeJamb   = v => sideLbl(v, SEUIL_AXE_JAMB, '(à D)',        '(à G)');
  // Apex / convexité — affichage dérivé, pas de libellé latéralisé classique.
  const apexBlock = d.rachisApex
    ? `<div style="${lbl}">Apex :</div>
       <div style="font-weight:700;color:#0e1f38;">${d.rachisRegion} (${d.rachisApex})
         <span style="color:#ea580c;font-weight:700;margin-left:4px;">→ convexité ${d.rachisConvexite}</span>
       </div>`
    : `<div style="${lbl}">Apex :</div><div style="color:#94a3b8;">—</div>`;
  const secBlock = d.rachisSecondaire
    ? `<div style="margin-top:3px;font-size:11px;color:#666;">2ᵉ courbure : ${d.rachisSecondaire.region} (${d.rachisSecondaire.apex}) → convexité ${d.rachisSecondaire.convexite}</div>`
    : '';
  const conclusionText = _buildDosConclusion(d) || 'Rachis aligné — pas de déviation marquée';
  return `
    <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:8px 14px;width:100%;font-size:12px;line-height:1.55;">
      <div>
        <div style="${groupHdr}">Tête</div>
        <div><span style="${lbl}">Inclinaison :</span> ${fmtDeg(d.inclinaisonTete)} ${lblTeteIncl(d.inclinaisonTete)}</div>
        <div><span style="${lbl}">Rotation :</span> ${fmtDeg(d.rotationTete)} ${lblRotation(d.rotationTete)}</div>
      </div>
      <div>
        <div style="${groupHdr}">Épaules / Scapulas</div>
        <div><span style="${lbl}">Ligne épaules :</span> ${fmtDeg(d.ligneEpaules)} ${lblEpaules(d.ligneEpaules)}</div>
        <div><span style="${lbl}">Asymétrie scapulas :</span> ${fmtDeg(d.asymetrieScapula)} ${lblScapAsym(d.asymetrieScapula)}</div>
        <div><span style="${lbl}">Orientation scapula D :</span> ${fmtDeg(d.orientationScapulaD)} ${lblScapOri(d.orientationScapulaD)}</div>
        <div><span style="${lbl}">Orientation scapula G :</span> ${fmtDeg(d.orientationScapulaG)} ${lblScapOri(d.orientationScapulaG)}</div>
        <div><span style="${lbl}">Asymétrie orientation scapulaire (D−G) :</span> ${fmtDeg(d.asymetrieOrientationScapula)} ${lblScapAsymOri(d.asymetrieOrientationScapula)}</div>
      </div>
      <div>
        <div style="${groupHdr}">Rachis</div>
        <div><span style="${lbl}">C7 :</span> ${fmtPct(d.rachisOffsets.C7)} ${lblRachisOff(d.rachisOffsets.C7)}</div>
        <div><span style="${lbl}">TH3 :</span> ${fmtPct(d.rachisOffsets.TH3)} ${lblRachisOff(d.rachisOffsets.TH3)}</div>
        <div><span style="${lbl}">TH6 :</span> ${fmtPct(d.rachisOffsets.TH6)} ${lblRachisOff(d.rachisOffsets.TH6)}</div>
        <div><span style="${lbl}">TH12 :</span> ${fmtPct(d.rachisOffsets.TH12)} ${lblRachisOff(d.rachisOffsets.TH12)}</div>
        <div><span style="${lbl}">L3 :</span> ${fmtPct(d.rachisOffsets.L3)} ${lblRachisOff(d.rachisOffsets.L3)}</div>
        <div style="margin-top:4px;padding-top:4px;border-top:1px dashed #e2e8f0;">
          ${apexBlock}
          ${secBlock}
        </div>
      </div>
      <div>
        <div style="${groupHdr}">Bassin</div>
        <div><span style="${lbl}">Bascule :</span> ${fmtDeg(d.basculeBassin)} ${lblBassin(d.basculeBassin)}</div>
        <div><span style="${lbl}">Sillon inter-fessier :</span> ${fmtPct(d.sillonInterfessier)} ${lblSillon(d.sillonInterfessier)}</div>
        <div><span style="${lbl}">Triangles de la taille :</span> ${fmtPct(d.trianglesTaille)} ${lblTriangles(d.trianglesTaille)}</div>
      </div>
      <div>
        <div style="${groupHdr}">Membre inférieur</div>
        <div><span style="${lbl}">Angle calcanéen D :</span> ${fmtDeg(d.angleCalcaneenD)} ${lblCalc(d.angleCalcaneenD)}</div>
        <div><span style="${lbl}">Angle calcanéen G :</span> ${fmtDeg(d.angleCalcaneenG)} ${lblCalc(d.angleCalcaneenG)}</div>
        <div><span style="${lbl}">Axe jambier D :</span> ${fmtDeg(d.axeJambierD)} ${lblAxeJamb(d.axeJambierD)}</div>
        <div><span style="${lbl}">Axe jambier G :</span> ${fmtDeg(d.axeJambierG)} ${lblAxeJamb(d.axeJambierG)}</div>
      </div>
      <div style="grid-column:1/-1;border-top:1px solid #cbd5e0;padding-top:5px;color:#0e1f38;line-height:1.45;">
        <span style="font-weight:700;">Conclusion :</span>
        <span>${conclusionText}</span>
      </div>
    </div>
  `;
}

// Panneau résultats sous le bandeau : 4 angles + global. Recalculé à chaque
// _redrawPostureModal (live durant drag) ET à chaque _renderPostureMarkerList
// (changement de sélection/placement). Vert si +, rouge si −, gris si null.
// #109-A1 — Dispatcher de panneau modal : route selon viewKey vers la fonction
// de rendu correspondante (face/dos/profilG/profilD), puis injecte la string
// HTML dans le DOM. Les 3 sous-fonctions retournent la string ; le dispatcher
// est l'unique site qui touche `panel.innerHTML` côté modale.
function _renderPosturePlacementResults() {
  const panel = document.getElementById('posture-placement-results');
  if (!panel) return;
  if (_postureModalViewKey === 'face') {
    const f = _computeFaceAngles(_postureModalMarkers, _postureCalibration);
    panel.innerHTML = _renderFacePlacementResults(f);
    return;
  }
  if (_postureModalViewKey === 'dos') {
    const dd = _computeDosAngles(_postureModalMarkers, _postureCalibration);
    panel.innerHTML = _renderDosPlacementResults(dd);
    return;
  }
  const a = _computePostureAngles(_postureModalMarkers, _postureCalibration);
  panel.innerHTML = _renderProfilPlacementResults(a);
}

// #109-A1 — Helper unifié pour rendre un panneau à partir d'un objet analysis
// persisté (`bd._postureAnalysis[viewKey]`). Réutilisable en rapport sans
// dépendre du contexte modale. Retourne '' si l'analyse ou ses angles manquent.
function _buildPosturePanelHTML(viewKey, analysis) {
  if (!analysis || !analysis.angles) return '';
  if (viewKey === 'face') return _renderFacePlacementResults(analysis.angles);
  if (viewKey === 'dos')  return _renderDosPlacementResults(analysis.angles);
  if (viewKey === 'profilG' || viewKey === 'profilD') return _renderProfilPlacementResults(analysis.angles);
  return '';
}

// #109-A1 — Construit une photo posturale annotée (PNG dataURL) à partir du
// dataURL de la photo brute + des markers normalisés persistés. Réutilise
// `_drawPosturePlumb` + `_drawMarkersOnly` (helpers partagés modale/rapport).
// Étapes :
//   1) Résout le dataURL : bd[_postureXxx] direct, ou prefetch depuis path Storage.
//   2) Lit `bd._postureAnalysis[viewKey]` ; sans markers placés → null (le
//      caller affichera la photo brute non annotée).
//   3) Charge l'image, downscale optionnel à `maxWidth` (#109-A2), draw sur canvas tmp.
//   4) Reconstruit des markers locaux : template (couleurs) + nx/ny denormalisés
//      sur les dimensions FINALES du canvas (les coords normalisées sont
//      indépendantes de la résolution, le scale est donc transparent).
//   5) Délègue le tracé aux helpers partagés, retourne le PNG.
// `maxWidth` (optionnel) — si fourni et W natif > maxWidth, l'image est downscalée
// proportionnellement (économie de poids pour les rapports). Les tailles de
// points / fil à plomb dérivent de W → restent proportionnelles.
// Retourne null si photo absente, markers non placés, ou erreur de chargement.
async function _buildAnnotatedPosturePhoto(viewKey, bd, maxWidth) {
  if (!bd || !viewKey) return null;
  const keyName = '_posture' + viewKey.charAt(0).toUpperCase() + viewKey.slice(1);
  let dataUrl = bd[keyName];
  if (!dataUrl) {
    const path = bd[keyName + 'Path'];
    if (path && typeof prefetchPhotoToDataUrl === 'function') {
      try {
        const r = await prefetchPhotoToDataUrl(path);
        if (r && r.ok && r.dataUrl) dataUrl = r.dataUrl;
      } catch (e) { /* silencieux : on retombe sur null si la photo brute manque */ }
    }
  }
  if (!dataUrl) return null;
  const analysis = bd._postureAnalysis && bd._postureAnalysis[viewKey];
  if (!analysis || !Array.isArray(analysis.markers)) return null;
  const placedCount = analysis.markers.filter(m => m.nx != null && m.ny != null).length;
  if (placedCount === 0) return null;
  // Charge l'image — Promise wrapper sur Image.onload pour await propre.
  let img;
  try {
    img = await new Promise((resolve, reject) => {
      const i = new Image();
      i.onload = () => resolve(i);
      i.onerror = () => reject(new Error('failed to load posture image'));
      i.src = dataUrl;
    });
  } catch (e) {
    console.warn('[#109-A1] _buildAnnotatedPosturePhoto — chargement image échoué :', e?.message);
    return null;
  }
  let W = img.naturalWidth, H = img.naturalHeight;
  if (W <= 0 || H <= 0) return null;
  // #109-A2 — downscale optionnel pour limiter le poids du PNG en rapport.
  if (maxWidth && W > maxWidth) {
    const scale = maxWidth / W;
    W = Math.round(W * scale);
    H = Math.round(H * scale);
  }
  const tmp = document.createElement('canvas');
  tmp.width = W; tmp.height = H;
  const ctx = tmp.getContext('2d');
  ctx.drawImage(img, 0, 0, W, H);
  // Reconstruit les markers locaux : on part du template (qui porte les couleurs
  // + side originaux) et on injecte les coords sauvegardées par NOM (résilient
  // au réordo / renommage futur, miroir openPosturePlacementModal L5786).
  const template = cloneMarkers(_postureTemplateName(viewKey));
  const savedByName = Object.fromEntries(analysis.markers.map(m => [m.name, m]));
  const localMarkers = template.map(t => {
    const s = savedByName[t.name];
    return {
      ...t,
      x: s && s.nx != null ? s.nx * W : null,
      y: s && s.ny != null ? s.ny * H : null,
    };
  });
  const savedCalib = analysis.calibration;
  const localCalib = (savedCalib && (savedCalib.p1 || savedCalib.p2)) ? {
    p1: savedCalib.p1 && savedCalib.p1.nx != null
      ? { x: savedCalib.p1.nx * W, y: savedCalib.p1.ny * H } : null,
    p2: savedCalib.p2 && savedCalib.p2.nx != null
      ? { x: savedCalib.p2.nx * W, y: savedCalib.p2.ny * H } : null,
  } : null;
  _drawPosturePlumb(ctx, W, H, localMarkers, localCalib, viewKey);
  // #109-B — Lignes de mesure 2 couleurs (rouge hors-norme / vert dans-norme).
  // Utilise les angles stockés dans `analysis` (sauvegardés lors de la
  // dernière édition modale → pas de recalcul nécessaire en rapport).
  _drawPostureLines(ctx, W, H, localMarkers, localCalib, viewKey, analysis.angles);
  _drawMarkersOnly(ctx, tmp, localMarkers, -1);
  return tmp.toDataURL('image/png');
}

// #109-A3 — Collecte les vues posturales annotées pour intégration en rapport.
// Pré-génère 4 vues max (profilG, profilD, face, dos) via Promise.all, filtre
// les non-null, enrichit chaque entrée du label affichable + de la string HTML
// du panneau de mesures (`_buildPosturePanelHTML`). Tolérant aux erreurs :
// try/catch interne → retourne [] si Promise.all échoue. Retourne aussi []
// si aucune vue n'a de photo + de markers placés.
async function _collectAnnotatedPostureViews(bd, maxWidth) {
  if (!bd) return [];
  const VIEW_LABELS = { profilG: 'Profil gauche', profilD: 'Profil droit', face: 'Face', dos: 'Dos' };
  const VIEW_ORDER = ['profilG', 'profilD', 'face', 'dos'];
  const annotatedViews = [];
  try {
    const results = await Promise.all(VIEW_ORDER.map(vk =>
      _buildAnnotatedPosturePhoto(vk, bd, maxWidth).then(dataUrl => ({ vk, dataUrl }))
    ));
    results.forEach(r => {
      if (r.dataUrl) {
        annotatedViews.push({
          viewKey:           r.vk,
          label:             VIEW_LABELS[r.vk],
          annotatedDataUrl:  r.dataUrl,
          panelHtml:         _buildPosturePanelHTML(r.vk, bd._postureAnalysis ? bd._postureAnalysis[r.vk] : null),
        });
      }
    });
  } catch (e) {
    console.warn('[#109-A3] _collectAnnotatedPostureViews échoué :', e?.message);
    return [];
  }
  return annotatedViews;
}

// #109-A3 — Construit la string HTML de la grille 2 colonnes des vues
// posturales annotées. Chaque cellule = label + photo annotée width:100% +
// panneau de mesures dessous. `break-inside:avoid` limite les coupures intra-
// cellule à l'impression. Retourne '' si entries vide → le caller peut faire
// un append direct sans tester la longueur séparément.
function _buildAnnotatedViewsGridHTML(entries) {
  if (!entries || entries.length === 0) return '';
  let html = '<div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;padding:10px 0;">';
  entries.forEach(function(entry) {
    html += '<div style="break-inside:avoid;page-break-inside:avoid;">';
    html += '<div style="font-size:10px;color:#9ca3af;margin-bottom:6px;text-transform:uppercase;letter-spacing:1px;text-align:center;font-weight:700;">'+entry.label+'</div>';
    html += '<img src="'+entry.annotatedDataUrl+'" style="width:100%;border-radius:4px;display:block;margin-bottom:8px;"/>';
    if (entry.panelHtml) html += '<div style="font-size:11px;line-height:1.4;color:#1f2937;">'+entry.panelHtml+'</div>';
    html += '</div>';
  });
  html += '</div>';
  return html;
}

// #109-A1 — Branche profil du dispatcher extraite : retourne le HTML du
// panneau profil à partir des angles uniquement. Lit `_postureModalPrefix`
// et `_postureModalViewKey` (module-level) pour câbler les selects courbures
// — en hors-modale (rapport), ces globales sont null et `renderCurveSelect`
// retourne '' silencieusement (panneau rendu sans selects, comportement OK).
function _renderProfilPlacementResults(a) {
  // #85-2d — fmt signé (bleu = +, rouge = −, gris = null) pour antériorisation/
  // bassin/épaules ; fmt unsigned pour CVA/courbures/genouFlexion (pas de signe
  // sémantique au niveau de la valeur brute — la classification viendra plus tard).
  const fmtSigned = v => (v === null || isNaN(v))
    ? `<span style="color:#94a3b8;">—</span>`
    : `<span style="color:${v > 0 ? '#3b82f6' : '#dc2626'};font-weight:700;">${v > 0 ? '+' : ''}${v.toFixed(1)}°</span>`;
  const fmtUnsigned = v => (v === null || isNaN(v))
    ? `<span style="color:#94a3b8;">—</span>`
    : `<span style="color:#0e1f38;font-weight:700;">${v.toFixed(1)}°</span>`;
  // Courbure : DÉVIATION seule (= 180−angle). 0° = rachis aligné, croissant avec
  // la courbure. Le libellé tendance (rectitude / norme / hyper) viendra à
  // l'étape classification.
  const fmtCurve = dev => dev === null || isNaN(dev)
    ? `<span style="color:#94a3b8;">—</span>`
    : `<span style="color:#0e1f38;font-weight:700;">${dev.toFixed(1)}°</span>`;
  // #106-Final Volet 2 — Factory de libellés cliniques. Couleurs harmonisées :
  // vert (#10b981) = mesure dans la zone de neutralité ; orange (#ea580c) =
  // hors zone. Le mot « (neutre) » est conservé comme indication clinique
  // mais avec la couleur verte signifiant « dans les normes ». Aucun mot
  // « proposition / normes / hors-normes ».
  const N = POSTURE_THRESHOLDS.neutralite;
  const _lblStyle = c => `color:${c};font-size:11px;margin-left:4px;`;
  const mkLbl = (threshold, posText, negText) => v => {
    if (v === null || isNaN(v)) return '';
    if (Math.abs(v) <= threshold) return `<span style="${_lblStyle('#10b981')}">(neutre)</span>`;
    if (v > 0) return `<span style="${_lblStyle('#ea580c')}">${posText}</span>`;
    return negText ? `<span style="${_lblStyle('#ea580c')}">${negText}</span>` : '';
  };
  const lblBassin     = mkLbl(N.bassin,          '(antéversion)',             '(rétroversion)');
  const lblGenouFR    = mkLbl(N.genou,           '(flessum)',                 '(récurvatum)');
  const lblEpaules    = mkLbl(N.epaule,          '(enroulement antérieur)',   null); // pas de libellé clinique défini pour < 0
  const lblHanche     = mkLbl(N.hanche,          '(flexion de hanche)',       '(extension de hanche)');
  const lblAnterPoint = mkLbl(N.anteriorisation, '(antérieur)',               '(postérieur)');
  // CVA référencée à 50°, seuil N.cva. Même schéma de couleurs.
  const lblCvaAnter = v => {
    if (v === null || isNaN(v)) return '';
    const delta = v - 50;
    if (Math.abs(delta) <= N.cva) return `<span style="${_lblStyle('#10b981')}">(neutre)</span>`;
    return delta < 0
      ? `<span style="${_lblStyle('#ea580c')}">(antérieur)</span>`
      : `<span style="${_lblStyle('#ea580c')}">(postérieur)</span>`;
  };
  const cls = _classifyPostureAngles(a);
  // #106-Final Volet 3 — Selects éditables pour les 3 courbures. Pré-sélection
  // depuis curveInterp sauvegardé (praticien), sinon mapping auto depuis tendance.
  // Lu via _postureModalPrefix/_postureModalViewKey (set à l'ouverture modale).
  const bdModal = _postureModalPrefix ? _getPostureBilanData(_postureModalPrefix) : null;
  const analysisModal = bdModal?._postureAnalysis?.[_postureModalViewKey];
  const _selectStyle = `font-size:11px;color:#0e1f38;border:1px solid #cbd5e0;border-radius:3px;padding:1px 4px;margin-left:4px;background:#fff;cursor:pointer;`;
  const renderCurveSelect = (courbure) => {
    if (!_postureModalPrefix || !_postureModalViewKey) return '';
    const current = _resolveCurveInterp(analysisModal, cls, courbure);
    const opts = POSTURE_COURBURE_OPTIONS[courbure].map(opt =>
      `<option value="${opt}" ${opt === current ? 'selected' : ''}>${opt}</option>`
    ).join('');
    return `<select id="posture-curve-interp-${courbure}" onchange="_onCurveInterpChange('${_postureModalPrefix}','${_postureModalViewKey}','${courbure}', this.value)" style="${_selectStyle}">${opts}</select>`;
  };
  const groupHdr = `font-weight:600;color:#0e1f38;margin-bottom:4px;font-size:10px;text-transform:uppercase;letter-spacing:0.4px;`;
  const lbl = `color:#64748b;`;
  // Genou centré 0 = neutre, dérivé de genouFlexion (180=neutre, <180=flessum, >180=récurvatum).
  // Stockage inchangé (sémantique calcAngle3 brut conservée pour le rapport futur).
  const genouCentered = (a.genouFlexion === null || isNaN(a.genouFlexion)) ? null : 180 - a.genouFlexion;
  // #85-2d-segments — Conclusion : phrase par segment hors zone neutre, jointe
  // par « · ». Ordre bas→haut (jambe → cuisse → tronc → tête) cohérent avec la
  // lecture clinique d'une chaîne posturale. Si tous neutres/null → message
  // d'alignement. CVA traité à part (référence 50°, pas 0).
  // #106-B — Conclusion extraite vers _buildPostureConclusion (source unique
  // partagée avec la synthèse + rapport). La fonction renvoie '' si tout est
  // aligné ; on ajoute ici le texte fallback spécifique à l'affichage modale.
  const conclusionText = _buildPostureConclusion(a)
    || 'Alignement global — pas de tendance antérieure/postérieure marquée';
  return `
    <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(210px,1fr));gap:8px 14px;width:100%;font-size:12px;line-height:1.55;">
      <div>
        <div style="${groupHdr}">Antériorisation / Postériorisation</div>
        <div><span style="${lbl}">Tête :</span> ${fmtUnsigned(a.cva)} ${lblCvaAnter(a.cva)}</div>
        <div><span style="${lbl}">Tronc :</span> ${fmtSigned(a.flexionHanche)} ${lblAnterPoint(a.flexionHanche)}</div>
        <div><span style="${lbl}">Cuisse :</span> ${fmtSigned(a.cuisse)} ${lblAnterPoint(a.cuisse)}</div>
        <div><span style="${lbl}">Jambe :</span> ${fmtSigned(a.genou)} ${lblAnterPoint(a.genou)}</div>
        <div style="margin-top:5px;padding-top:5px;border-top:1px solid #cbd5e0;color:#0e1f38;line-height:1.45;">
          <span style="color:#0e1f38;font-weight:700;">Conclusion :</span>
          <span style="color:#0e1f38;">${conclusionText}</span>
        </div>
      </div>
      <div>
        <div style="${groupHdr}">Courbures</div>
        <div><span style="${lbl}">Cervicale :</span> ${fmtCurve(a.deviationCervicale)} ${renderCurveSelect('cervicale')}</div>
        <div><span style="${lbl}">Thoracique :</span> ${fmtCurve(a.deviationThoracique)} ${renderCurveSelect('thoracique')}</div>
        <div><span style="${lbl}">Lombaire :</span> ${fmtCurve(a.deviationLombaire)} ${renderCurveSelect('lombaire')}</div>
      </div>
      <div>
        <div style="${groupHdr}">Bassin / Hanche / Genou</div>
        <div><span style="${lbl}">Hanche :</span> ${fmtSigned(a.hanche)} ${lblHanche(a.hanche)}</div>
        <div><span style="${lbl}">Bassin :</span> ${fmtSigned(a.bassin)} ${lblBassin(a.bassin)}</div>
        <div><span style="${lbl}">Genou :</span> ${fmtSigned(genouCentered)} ${lblGenouFR(genouCentered)}</div>
      </div>
      <div>
        <div style="${groupHdr}">Épaule</div>
        <div><span style="${lbl}">Épaule :</span> ${fmtSigned(a.epaules)} ${lblEpaules(a.epaules)}</div>
      </div>
    </div>
  `;
}

// Contrôle calibration sol dans le side-panel. Re-rendu à chaque _renderPostureMarkerList.
function _renderPostureCalibrationControl() {
  const el = document.getElementById('posture-calib-control');
  if (!el) return;
  const hasP1 = !!_postureCalibration?.p1;
  const hasP2 = !!_postureCalibration?.p2;
  const statusMsg = (hasP1 && hasP2)
    ? `✓ Calibrée (2 points)`
    : hasP1 ? `Place le 2e point…`
    : _postureCalibrationMode ? `Place le 1er point sur l'horizontale du sol`
    : `Optionnel : 2 points sur l'horizontale du sol`;
  const clearBtn = (hasP1 || hasP2)
    ? `<button onclick="_clearPostureCalibration()" style="font-size:9px;margin-left:6px;background:#dc2626;color:#fff;border:none;border-radius:3px;padding:2px 6px;cursor:pointer;">Effacer</button>`
    : '';
  el.innerHTML = `
    <div style="margin-bottom:8px;padding:6px 8px;background:${_postureCalibrationMode ? '#fff7ed' : '#fff'};border:1px solid ${_postureCalibrationMode ? '#f97316' : '#cbd5e0'};border-radius:4px;">
      <label style="display:flex;align-items:center;gap:6px;cursor:pointer;font-size:11px;">
        <input type="checkbox" ${_postureCalibrationMode ? 'checked' : ''} onclick="_togglePostureCalibrationMode()">
        <span style="font-weight:600;color:#0e1f38;">📐 Calibrer horizontale sol</span>
      </label>
      <div style="font-size:10px;color:#666;margin-top:3px;line-height:1.3;">${statusMsg}${clearBtn}</div>
    </div>`;
}

// Toggle du mode calibration. Quand on entre en mode, on ne reset PAS les points
// existants (l'utilisateur peut vouloir replacer p1 seul après inspection).
function _togglePostureCalibrationMode() {
  _postureCalibrationMode = !_postureCalibrationMode;
  _renderPostureMarkerList();
  _redrawPostureModal();
}

function _clearPostureCalibration() {
  _postureCalibration = null;
  _renderPostureMarkerList();
  _redrawPostureModal();
}

// Variante simplifiée de drawOverlay (L4944) : points + labels uniquement.
// Pas de drawSegmentRect, pas de calcAngle3, pas d'arc d'angle — périmètre
// #85-2b strict (placement seul). Texte avec contour noir pour lisibilité
// sur fonds clairs/sombres (ajout vs drawOverlay qui suppose fond vidéo).
function _drawMarkersOnly(ctx, canvas, markers, selIdx) {
  const W = canvas.width;
  markers.forEach((m, i) => {
    if (m.x === null || m.y === null) return;
    const r = Math.max(6, W / 72);
    const isSel = selIdx === i;
    ctx.save();
    ctx.beginPath(); ctx.arc(m.x, m.y, r + 4, 0, 2 * Math.PI);
    ctx.fillStyle = isSel ? 'rgba(245,166,35,.35)' : 'rgba(255,255,255,.18)';
    ctx.fill();
    ctx.beginPath(); ctx.arc(m.x, m.y, r, 0, 2 * Math.PI);
    ctx.fillStyle = m.color; ctx.fill();
    ctx.strokeStyle = isSel ? '#f5a623' : '#fff';
    ctx.lineWidth = isSel ? 2.5 : 1.5; ctx.stroke();
    ctx.restore();
    const fontPx = Math.max(10, W / 60);
    ctx.font = `bold ${fontPx}px DM Sans,sans-serif`;
    ctx.lineWidth = 3; ctx.strokeStyle = 'rgba(0,0,0,.7)';
    ctx.strokeText(m.name, m.x + r + 4, m.y + 4);
    ctx.fillStyle = '#fff';
    ctx.fillText(m.name, m.x + r + 4, m.y + 4);
  });
}

// Repeint l'image puis les overlays. Ordre Z (bas→haut) : image → fil à plomb
// → ligne de calibration → markers (les markers doivent rester au-dessus pour
// que le hit-test reste précis et que les labels restent lisibles). Appelé à
// chaque mouvement/placement (équivalent du startLiveDraw pour mesures, mais
// déclenché par événement au lieu de rAF — la photo est statique).
// #109-A1 — Helper partagé du tracé fil à plomb (gris-bleu neutre) + ligne
// de calibration sol (orange tiretée). Réutilisé par la modale ET par
// `_buildAnnotatedPosturePhoto` (rapports). Ancrage du plomb par vue :
//   face   → milieu(Cheville D, Cheville G)
//   dos    → milieu(Calcanéum inférieur D, Calcanéum inférieur G)
//   profil → Réf. cheville
// Si la paire / le point manque → pas d'ancre, pas de plomb dessiné.
// `markers` portent x/y en pixel dans le repère du canvas cible ; `calibration`
// idem (objets { p1: {x,y} | null, p2: {x,y} | null } | null). Le helper ne
// dépend d'aucune globale — entièrement portable hors modale.
function _drawPosturePlumb(ctx, W, H, markers, calibration, viewKey) {
  let plumbAnchor = null;
  if (viewKey === 'face') {
    const chD = markers.find(m => m.name === 'Cheville D');
    const chG = markers.find(m => m.name === 'Cheville G');
    if (chD && chD.x !== null && chD.y !== null && chG && chG.x !== null && chG.y !== null) {
      plumbAnchor = { x: (chD.x + chG.x) / 2, y: (chD.y + chG.y) / 2 };
    }
  } else if (viewKey === 'dos') {
    const cD = markers.find(m => m.name === 'Calcanéum inférieur D');
    const cG = markers.find(m => m.name === 'Calcanéum inférieur G');
    if (cD && cD.x !== null && cD.y !== null && cG && cG.x !== null && cG.y !== null) {
      plumbAnchor = { x: (cD.x + cG.x) / 2, y: (cD.y + cG.y) / 2 };
    }
  } else {
    const cheville = markers.find(m => m.name === 'Réf. cheville');
    if (cheville && cheville.x !== null && cheville.y !== null) {
      plumbAnchor = { x: cheville.x, y: cheville.y };
    }
  }
  // Vecteur plumb_up depuis la calibration (pure, pas d'accès _postureCalibration).
  let plumbUp = { x: 0, y: -1 };
  if (calibration && calibration.p1 && calibration.p2) {
    const dx = calibration.p2.x - calibration.p1.x;
    const dy = calibration.p2.y - calibration.p1.y;
    const len = Math.hypot(dx, dy);
    if (len > 0) {
      let perp = { x: -dy / len, y: dx / len };
      if (perp.y > 0) perp = { x: -perp.x, y: -perp.y };
      plumbUp = perp;
    }
  }
  if (plumbAnchor) {
    const t = Math.max(W, H) * 2;
    ctx.save();
    ctx.strokeStyle = 'rgba(100,116,139,0.75)';
    ctx.lineWidth = Math.max(1.5, W / 400);
    ctx.beginPath();
    ctx.moveTo(plumbAnchor.x - plumbUp.x * t, plumbAnchor.y - plumbUp.y * t);
    ctx.lineTo(plumbAnchor.x + plumbUp.x * t, plumbAnchor.y + plumbUp.y * t);
    ctx.stroke();
    ctx.restore();
  }
  // Calibration sol — affichée même partiellement placée (1 puce seulement)
  // pour feedback intermédiaire en modale ; intégrée à la photo annotée.
  if (calibration && (calibration.p1 || calibration.p2)) {
    ctx.save();
    if (calibration.p1 && calibration.p2) {
      ctx.strokeStyle = 'rgba(249,115,22,0.9)';
      ctx.lineWidth = Math.max(1.5, W / 400);
      ctx.setLineDash([Math.max(6, W / 100), Math.max(3, W / 200)]);
      ctx.beginPath();
      ctx.moveTo(calibration.p1.x, calibration.p1.y);
      ctx.lineTo(calibration.p2.x, calibration.p2.y);
      ctx.stroke();
      ctx.setLineDash([]);
    }
    [calibration.p1, calibration.p2].forEach(p => {
      if (!p) return;
      ctx.beginPath();
      ctx.arc(p.x, p.y, Math.max(5, W / 90), 0, 2 * Math.PI);
      ctx.fillStyle = '#f97316';
      ctx.fill();
      ctx.strokeStyle = '#fff';
      ctx.lineWidth = 1.8;
      ctx.stroke();
    });
    ctx.restore();
  }
}

// #109-B — Lignes de mesure 2 couleurs (rouge = hors-norme / vert = dans-norme).
// Dessinées entre `_drawPosturePlumb` et `_drawMarkersOnly` pour que les
// marqueurs (pastilles) restent au-dessus. Chaque segment prend la couleur de
// SA mesure : on s'appuie sur `_classifyPostureAngles` (profil) ou un compare
// direct au seuil POSTURE_THRESHOLDS (face/dos) pour décider rouge vs vert.
// Helper `over(v, s)` : true si v existe et |v| > s. `col(hn)` : RED si hors-
// norme, GREEN sinon. `seg(a, b, c)` trace une ligne avec gap-safe (au moins
// un point manquant → skip). `poly(names, c)` chaîne plusieurs points avec
// `prev=null` pour reprendre proprement après un trou. `dashSeg` pour les
// translations (face : Fourchette/EIAS → projection sur le plomb).
function _drawPostureLines(ctx, W, H, markers, calibration, viewKey, angles) {
  const RED = 'rgba(220,38,38,0.95)';
  const GREEN = 'rgba(22,163,74,0.95)';
  const HALO = 'rgba(255,255,255,0.7)';
  const lineWidth = Math.max(2.5, W / 240);
  const haloWidth = lineWidth + Math.max(2, W / 170);
  const byName = Object.fromEntries(markers.map(m => [m.name, m]));
  const pt = (name) => {
    const m = byName[name];
    return (m && m.x !== null && m.y !== null) ? { x: m.x, y: m.y } : null;
  };
  const over = (v, s) => v != null && !isNaN(v) && Math.abs(v) > s;
  const col = (hn) => hn ? RED : GREEN;
  const strokeLine = (a, b, color, width, dash) => {
    ctx.save();
    ctx.strokeStyle = color;
    ctx.lineWidth = width;
    if (dash) ctx.setLineDash(dash); else ctx.setLineDash([]);
    ctx.beginPath();
    ctx.moveTo(a.x, a.y);
    ctx.lineTo(b.x, b.y);
    ctx.stroke();
    ctx.restore();
  };
  const seg = (aName, bName, color) => {
    const a = pt(aName), b = pt(bName);
    if (!a || !b) return;
    strokeLine(a, b, HALO,  haloWidth, null);
    strokeLine(a, b, color, lineWidth, null);
  };
  const poly = (names, color) => {
    // Deux passes : halo blanc plein dessous, trait coloré dessus. On résout
    // d'abord la chaîne de segments (gap-safe via prev=null) puis on stroke
    // chaque segment en halo + couleur — évite que le halo d'un segment écrase
    // la couleur d'un segment voisin.
    const pairs = [];
    let prev = null;
    names.forEach((name) => {
      const p = pt(name);
      if (!p) { prev = null; return; }
      if (prev) pairs.push([prev, p]);
      prev = p;
    });
    pairs.forEach(([a, b]) => strokeLine(a, b, HALO,  haloWidth, null));
    pairs.forEach(([a, b]) => strokeLine(a, b, color, lineWidth, null));
  };
  const dashSeg = (p, q, color) => {
    if (!p || !q) return;
    const dashPattern = [Math.max(4, W / 150), Math.max(3, W / 250)];
    // Halo en plein (non tireté) pour mieux ressortir sous le tireté coloré.
    strokeLine(p, q, HALO,  haloWidth, null);
    strokeLine(p, q, color, lineWidth, dashPattern);
  };
  if (!angles) return;
  if (viewKey === 'profilG' || viewKey === 'profilD' || viewKey === 'profil') {
    const cls = _classifyPostureAngles(angles, POSTURE_THRESHOLDS);
    const tend = (k) => cls && cls[k] && cls[k].tendance && cls[k].tendance !== 'normes';
    poly(['Base crâne', 'Apex cervical', 'C7'],            col(tend('cervicale')));
    poly(['C7', 'Apex thoracique', 'T12'],                 col(tend('thoracique')));
    poly(['T12', 'Apex lombaire', 'Base sacrum'],          col(tend('lombaire')));
    seg('C7', 'Tragus',                                    col(tend('cva')));
    return;
  }
  if (viewKey === 'face') {
    const Tf = POSTURE_THRESHOLDS.face;
    seg('Acromion D',     'Acromion G',     col(over(angles.ligneEpaules,  Tf.epaules)));
    seg('EIAS D',         'EIAS G',         col(over(angles.basculeBassin, Tf.bassin)));
    seg('Oreille sup D',  'Oreille sup G',  col(over(angles.inclinaisonTete, Tf.tete)));
    poly(['Tête fémorale D', 'Genou D', 'Cheville D'], col(over(angles.valgumVarumD, Tf.valgumVarum)));
    poly(['Tête fémorale G', 'Genou G', 'Cheville G'], col(over(angles.valgumVarumG, Tf.valgumVarum)));
    // Translations — projection perpendiculaire sur le fil à plomb ancré au
    // milieu des chevilles. plumb_up vient de la calibration (sinon { 0, -1 }).
    let plumbUp = { x: 0, y: -1 };
    if (calibration && calibration.p1 && calibration.p2) {
      const dx = calibration.p2.x - calibration.p1.x;
      const dy = calibration.p2.y - calibration.p1.y;
      const len = Math.hypot(dx, dy);
      if (len > 0) {
        let perp = { x: -dy / len, y: dx / len };
        if (perp.y > 0) perp = { x: -perp.x, y: -perp.y };
        plumbUp = perp;
      }
    }
    const chD = pt('Cheville D'), chG = pt('Cheville G');
    const anchor = (chD && chG) ? { x: (chD.x + chG.x) / 2, y: (chD.y + chG.y) / 2 } : null;
    const footOf = (p) => {
      if (!p || !anchor) return null;
      const v = { x: p.x - anchor.x, y: p.y - anchor.y };
      const along = v.x * plumbUp.x + v.y * plumbUp.y;
      return { x: anchor.x + plumbUp.x * along, y: anchor.y + plumbUp.y * along };
    };
    const fourchette = pt('Fourchette sternale');
    dashSeg(fourchette, footOf(fourchette), col(over(angles.translationThorax, Tf.translation)));
    const eD = pt('EIAS D'), eG = pt('EIAS G');
    const midEIAS = (eD && eG) ? { x: (eD.x + eG.x) / 2, y: (eD.y + eG.y) / 2 } : null;
    dashSeg(midEIAS, footOf(midEIAS), col(over(angles.translationBassin, Tf.translation)));
    return;
  }
  if (viewKey === 'dos') {
    const Td = POSTURE_THRESHOLDS.dos;
    // Rachis : verdict global = apex au-dessus du seuil rachis (= scoliose).
    const rachisHN = !!(angles.rachisApex && angles.rachisOffsets
      && over(angles.rachisOffsets[angles.rachisApex], Td.rachis));
    poly([
      'Base du crâne', 'Épineuse C3', 'Épineuse C7',
      'Épineuse TH3', 'Épineuse TH6', 'Épineuse TH12',
      'Épineuse L3', 'Base du sacrum',
    ], col(rachisHN));
    seg('Acromion D', 'Acromion G', col(over(angles.ligneEpaules,  Td.epaules)));
    seg('EIPS D',     'EIPS G',     col(over(angles.basculeBassin, Td.bassin)));
    poly(['Genou D', 'Mi-mollet D', 'Calcanéum supérieur D'], col(over(angles.axeJambierD, Td.axeJambier)));
    poly(['Genou G', 'Mi-mollet G', 'Calcanéum supérieur G'], col(over(angles.axeJambierG, Td.axeJambier)));
    seg('Calcanéum supérieur D', 'Calcanéum inférieur D', col(over(angles.angleCalcaneenD, Td.calcaneen)));
    seg('Calcanéum supérieur G', 'Calcanéum inférieur G', col(over(angles.angleCalcaneenG, Td.calcaneen)));
    return;
  }
}

function _redrawPostureModal() {
  if (!_postureModalCanvas || !_postureModalImg || !_postureModalCtx) return;
  const ctx = _postureModalCtx;
  const W = _postureModalCanvas.width, H = _postureModalCanvas.height;
  ctx.drawImage(_postureModalImg, 0, 0);
  // #109-A1 — Plomb + calibration déléguées à `_drawPosturePlumb` (helper
  // partagé avec `_buildAnnotatedPosturePhoto`).
  _drawPosturePlumb(ctx, W, H, _postureModalMarkers, _postureCalibration, _postureModalViewKey);
  // #109-B — Lignes de mesure 2 couleurs. Recalcul des angles à chaque redraw
  // (live update pendant drag : la couleur suit immédiatement la position).
  let liveAngles = null;
  if (_postureModalViewKey === 'face') {
    liveAngles = _computeFaceAngles(_postureModalMarkers, _postureCalibration);
  } else if (_postureModalViewKey === 'dos') {
    liveAngles = _computeDosAngles(_postureModalMarkers, _postureCalibration);
  } else {
    liveAngles = _computePostureAngles(_postureModalMarkers, _postureCalibration);
  }
  _drawPostureLines(ctx, W, H, _postureModalMarkers, _postureCalibration, _postureModalViewKey, liveAngles);
  _drawMarkersOnly(ctx, _postureModalCanvas, _postureModalMarkers, _postureModalSelIdx);
  // Résultats live : recalculés à chaque redraw → mise à jour fluide pendant drag.
  _renderPosturePlacementResults();
}

// Side-panel : liste cliquable des 14 points. État visuel : pastille verte (placé),
// pastille numérotée grise (non placé), fond ambre clair (sélectionné). Font 12px,
// nom en #0e1f38 pour contraste lisible (cf demande UX #85-2b).
function _renderPostureMarkerList() {
  const list = document.getElementById('posture-mkr-list');
  if (!list) return;
  list.innerHTML = _postureModalMarkers.map((m, i) => {
    const placed = m.x !== null && m.y !== null;
    const isSel = _postureModalSelIdx === i;
    return `<div onclick="_selectPostureMarker(${i})" style="display:flex;align-items:center;gap:6px;padding:6px 8px;cursor:pointer;border-radius:4px;background:${isSel ? '#fff7e0' : (placed ? '#f0fdf4' : '#fff')};border-left:3px solid ${m.color};margin-bottom:3px;font-size:12px;">
      <span style="width:18px;text-align:center;color:${placed ? '#10b981' : '#999'};font-weight:700;">${placed ? '✓' : (i + 1)}</span>
      <span style="flex:1;color:#0e1f38;font-weight:500;">${m.name}</span>
    </div>`;
  }).join('');
  // Mise à jour bandeau + contrôle calibration + résultats couplés à la liste :
  // un seul site d'update à maintenir. Tous les changements de sélection
  // (select / placement / init / toggle calibration) passent par ici.
  _updatePosturePlacementBanner();
  _renderPostureCalibrationControl();
  _renderPosturePlacementResults();
}

// Bandeau au-dessus du canvas : « 👉 À placer : N/14 — [Nom] » en gros, couleur du point,
// + hint anatomique en italique dessous. Quand tout est placé (selIdx=-1), affiche
// l'état complet « ✓ 14/14 placés ». Couplé à _renderPostureMarkerList → s'auto-rafraîchit
// au moindre changement de sélection sans appels manuels supplémentaires.
function _updatePosturePlacementBanner() {
  const banner = document.getElementById('posture-placement-banner');
  if (!banner) return;
  // #85-2c-angles — pendant la calibration sol, le bandeau guide explicitement
  // l'action en cours pour ne pas créer de confusion avec le placement markers.
  if (_postureCalibrationMode) {
    const needP1 = !_postureCalibration?.p1;
    banner.innerHTML = `<div style="font-size:15px;font-weight:700;color:#f97316;">📐 ${needP1 ? 'Place le 1er point' : 'Place le 2e point'} sur l'horizontale du sol</div><div style="font-size:12px;color:#555;margin-top:4px;font-style:italic;line-height:1.35;">2 points alignés sur la même horizontale physique (jonction sol/mur, plinthe, etc.). Le fil à plomb deviendra perpendiculaire à cette horizontale.</div>`;
    banner.style.background = '#fff7ed';
    banner.style.borderLeftColor = '#f97316';
    return;
  }
  const total = _postureModalMarkers.length;
  const placedCount = _postureModalMarkers.filter(m => m.x !== null && m.y !== null).length;
  if (_postureModalSelIdx < 0 || _postureModalSelIdx >= total) {
    banner.innerHTML = `<div style="font-size:15px;font-weight:700;color:#10b981;">✓ ${placedCount}/${total} placés — cliquez un point pour ajuster</div>`;
    banner.style.background = '#f0fdf4';
    banner.style.borderLeftColor = '#10b981';
    return;
  }
  const m = _postureModalMarkers[_postureModalSelIdx];
  const isAdjust = (m.x !== null && m.y !== null);
  const action = isAdjust ? 'À ajuster' : 'À placer';
  const hint = m.hint ? `<div style="font-size:12px;color:#555;margin-top:4px;font-style:italic;line-height:1.35;">${m.hint}</div>` : '';
  banner.innerHTML = `<div style="font-size:15px;font-weight:700;color:${m.color};">👉 ${action} : ${_postureModalSelIdx + 1}/${total} — ${m.name}</div>${hint}`;
  banner.style.background = isAdjust ? '#fffbeb' : '#fff7ed';
  banner.style.borderLeftColor = m.color;
}

// Sélectionne un point depuis la liste (= équivalent du clic sur un marker
// déjà placé dans le canvas, mais accessible aussi pour les non-placés).
function _selectPostureMarker(i) {
  _postureModalSelIdx = i;
  _renderPostureMarkerList();
  _redrawPostureModal();
}

// Handlers canvas : pattern miroir setupPhotoCanvas L4334-4358. Clic = hit-test
// puis place le sélectionné OU le prochain non placé + avance selIdx. Move pendant
// drag = update du marker sélectionné. Tactile bridge identique.
function _setupPosturePlacementCanvas(canvas) {
  const handleDown = e => {
    e.preventDefault();
    const ev = (e.touches && e.touches[0]) ? { clientX: e.touches[0].clientX, clientY: e.touches[0].clientY } : e;
    const { x, y } = canvasXY(ev, canvas);
    // #85-2c-angles — mode calibration : les clics placent p1 puis p2 de la
    // calibration sol au lieu des markers. Auto-exit après p2 (le 3e clic
    // ré-amorce le cycle : remplace p1 et libère p2 pour repositionnement).
    if (_postureCalibrationMode) {
      if (!_postureCalibration) _postureCalibration = { p1: null, p2: null };
      if (!_postureCalibration.p1) {
        _postureCalibration.p1 = { x, y };
      } else if (!_postureCalibration.p2) {
        _postureCalibration.p2 = { x, y };
        _postureCalibrationMode = false;
      } else {
        _postureCalibration.p1 = { x, y };
        _postureCalibration.p2 = null;
      }
      _renderPostureMarkerList();
      _redrawPostureModal();
      return;
    }
    const hit = findMarkerAt(x, y, _postureModalMarkers, canvas.width);
    if (hit >= 0) {
      _postureModalSelIdx = hit;
      _postureModalDragging = true;
      _renderPostureMarkerList();
      _redrawPostureModal();
      return;
    }
    const idx = _postureModalSelIdx >= 0
      ? _postureModalSelIdx
      : _postureModalMarkers.findIndex(m => m.x === null);
    if (idx >= 0 && idx < _postureModalMarkers.length) {
      _postureModalMarkers[idx].x = x;
      _postureModalMarkers[idx].y = y;
      const next = _postureModalMarkers.findIndex((m, i) => i > idx && m.x === null);
      _postureModalSelIdx = next >= 0 ? next : -1;
      _renderPostureMarkerList();
      _redrawPostureModal();
    }
  };
  const handleMove = e => {
    if (!_postureModalDragging || _postureModalSelIdx < 0) return;
    e.preventDefault();
    const ev = (e.touches && e.touches[0]) ? { clientX: e.touches[0].clientX, clientY: e.touches[0].clientY } : e;
    const { x, y } = canvasXY(ev, canvas);
    _postureModalMarkers[_postureModalSelIdx].x = x;
    _postureModalMarkers[_postureModalSelIdx].y = y;
    _redrawPostureModal();
  };
  const handleUp = () => { _postureModalDragging = false; };
  canvas.onmousedown = handleDown;
  canvas.onmousemove = handleMove;
  canvas.onmouseup = handleUp;
  canvas.ontouchstart = handleDown;
  canvas.ontouchmove = handleMove;
  canvas.ontouchend = handleUp;
}

// Ouvre la modale plein écran : photo profil + side-panel + boutons. Le canvas
// est dimensionné à img.naturalWidth × img.naturalHeight (= taille capture full
// résolution post #85-P2a, ~810×1080) pour préserver la précision absolue des
// coords ; CSS max-width/max-height laisse le navigateur scaler en conservant
// l'aspect-ratio intrinsèque du canvas. Les markers existants (nx/ny ∈ [0,1])
// sont reconvertis en pixels canvas une fois img.naturalWidth/Height connus.
function openPosturePlacementModal(prefix, viewKey) {
  const bd = _getPostureBilanData(prefix);
  if (!bd) { alert('Aucun bilan ouvert — sélectionne un patient et ouvre un bilan.'); return; }
  const key = '_posture' + viewKey.charAt(0).toUpperCase() + viewKey.slice(1);
  const dataUrl = bd[key];
  if (!dataUrl) { alert('Capture d\'abord la photo profil avant de placer les points.'); return; }
  // #106-Final — Identité modale exposée au panneau pour lire curveInterp et
  // câbler les onchange des <select> avec le bon prefix/viewKey.
  _postureModalPrefix = prefix;
  _postureModalViewKey = viewKey;
  // Init markers : clone template (x:null, y:null), puis injection des coords
  // sauvegardées par nom (résilient au réordo / renommage futur des points).
  // #108 Étape 1 — template dépend du viewKey : face → posture-face (23 pts),
  // profilG/profilD → posture-profil (14 pts). Source unique via helper.
  _postureModalMarkers = cloneMarkers(_postureTemplateName(viewKey));
  const saved = bd._postureAnalysis?.[viewKey]?.markers || [];
  const savedByName = Object.fromEntries(saved.map(m => [m.name, m]));
  // #85-2c-angles — reset calibration au moment de l'ouverture. Restauration
  // depuis la sauvegarde (nx/ny → x/y) faite plus bas une fois canvas dimensionné.
  _postureCalibration = null;
  _postureCalibrationMode = false;
  const savedCalib = bd._postureAnalysis?.[viewKey]?.calibration || null;
  // Build modal DOM (fond sombre semi-transparent, dialog blanc centré).
  const overlay = document.createElement('div');
  overlay.id = 'posture-placement-modal';
  overlay.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.85);z-index:9999;display:flex;align-items:center;justify-content:center;padding:12px;';
  overlay.innerHTML = `<div style="background:#fff;border-radius:8px;padding:12px;max-width:96vw;max-height:96vh;display:flex;flex-direction:column;gap:8px;box-shadow:0 8px 32px rgba(0,0,0,.5);">
      <div style="display:flex;align-items:center;justify-content:space-between;gap:8px;">
        <div style="font-weight:700;color:#0e1f38;font-size:13px;">🎯 Placement des ${_postureModalMarkers.length} points — ${viewKey === 'face' ? 'Face' : viewKey === 'dos' ? 'Dos' : 'Profil ' + (viewKey === 'profilG' ? 'G' : 'D')}</div>
        <div style="display:flex;gap:6px;">
          <button class="btn" onclick="_cancelPosturePlacement()" style="font-size:11px;background:#888;color:#fff;padding:5px 12px;">Annuler</button>
          <button class="btn" onclick="_validatePosturePlacement('${prefix}','${viewKey}')" style="font-size:11px;background:#2a7a4e;color:#fff;padding:5px 12px;">✓ Valider</button>
        </div>
      </div>
      <div id="posture-placement-banner" style="padding:10px 12px;border-radius:6px;background:#fff7ed;border-left:4px solid #ccc;min-height:42px;flex:none;"></div>
      <div style="display:flex;gap:10px;flex:1;min-height:0;flex-wrap:wrap;overflow-y:auto;">
        <div style="flex:1 1 60%;min-width:280px;min-height:280px;max-height:82vh;display:flex;align-items:center;justify-content:center;background:#000;border-radius:6px;overflow:hidden;">
          <canvas id="posture-placement-canvas" style="max-width:100%;max-height:100%;display:block;cursor:crosshair;touch-action:none;"></canvas>
        </div>
        <div style="flex:0 0 280px;min-width:280px;max-height:82vh;overflow-y:auto;padding:6px;background:#f8f9fa;border-radius:6px;display:flex;flex-direction:column;gap:8px;">
          <div id="posture-placement-results" style="padding:6px 8px;border-radius:5px;background:#fff;border:1px solid #e2e8f0;font-size:12px;flex:none;"></div>
          <div style="font-size:11px;color:#666;line-height:1.4;padding:0 4px;flex:none;">Clic sur un nom pour sélectionner. Sur la photo : <b>clic</b> = placer ; <b>drag</b> = déplacer.</div>
          <div id="posture-calib-control" style="flex:none;"></div>
          <div id="posture-mkr-list" style="flex:none;"></div>
        </div>
      </div>
    </div>`;
  document.body.appendChild(overlay);
  // Charge l'image, puis dimensionne le canvas à la taille naturelle (full res
  // de la capture portrait). L'aspect-ratio intrinsèque du canvas + max-width/
  // max-height CSS = scaling navigateur sans distorsion. canvasXY (basé sur
  // rect.width et canvas.width) reste correct quel que soit le scale.
  const img = new Image();
  img.onload = () => {
    const canvas = document.getElementById('posture-placement-canvas');
    if (!canvas) return;
    canvas.width = img.naturalWidth;
    canvas.height = img.naturalHeight;
    _postureModalCanvas = canvas;
    _postureModalImg = img;
    _postureModalCtx = canvas.getContext('2d');
    // Injection des coords sauvegardées maintenant que les dimensions sont connues.
    _postureModalMarkers.forEach(m => {
      const s = savedByName[m.name];
      if (s && s.nx != null && s.ny != null) {
        m.x = s.nx * canvas.width;
        m.y = s.ny * canvas.height;
      }
    });
    // #85-2c-angles — restauration calibration sauvegardée (nx/ny → x/y).
    if (savedCalib) {
      _postureCalibration = {
        p1: savedCalib.p1 && savedCalib.p1.nx != null
          ? { x: savedCalib.p1.nx * canvas.width, y: savedCalib.p1.ny * canvas.height } : null,
        p2: savedCalib.p2 && savedCalib.p2.nx != null
          ? { x: savedCalib.p2.nx * canvas.width, y: savedCalib.p2.ny * canvas.height } : null,
      };
      // Si seulement p1 sauvegardé (cas dégradé), on conserve l'objet mais p2 null
      // → re-render affichera la puce orange et le statusMsg "Place le 2e point…".
      if (!_postureCalibration.p1 && !_postureCalibration.p2) _postureCalibration = null;
    }
    // Sélectionne le premier non placé (séquence guidée) ou -1 si tous placés.
    _postureModalSelIdx = _postureModalMarkers.findIndex(m => m.x === null);
    _setupPosturePlacementCanvas(canvas);
    _renderPostureMarkerList();
    _redrawPostureModal();
  };
  img.onerror = () => { alert('Erreur de chargement de la photo profil.'); _cancelPosturePlacement(); };
  img.src = dataUrl;
}

// Ferme la modale + reset complet de l'état module-level (évite les fuites
// inter-ouvertures si l'utilisateur enchaîne profilG → profilD).
function _cancelPosturePlacement() {
  const el = document.getElementById('posture-placement-modal');
  if (el) el.remove();
  _postureModalMarkers = [];
  _postureModalSelIdx = -1;
  _postureModalDragging = false;
  _postureModalCanvas = null;
  _postureModalImg = null;
  _postureModalCtx = null;
  _postureCalibration = null;
  _postureCalibrationMode = false;
  _postureModalPrefix = null;
  _postureModalViewKey = null;
}

// Persiste les coords en NORMALISÉ nx/ny ∈ [0,1] dans bd._postureAnalysis[viewKey].
// Pourquoi normalisé : indépendant de la résolution photo / taille d'affichage /
// device DPR — futur-proof pour rapport PDF, ré-ouverture sur autre device, etc.
// Pas d'upload Storage (struct JSON petite ~1-2 KB pour 14 points × 4 vues).
// Save silent selon le préfixe : saveBilanSilent (sport) syncronisera ensuite
// bilanData global → currentPatient.bilanData (cf L9273). savePosturoBilan(true)
// écrit directement dans currentPatient.bilanDataPosturo (cf L13311).
async function _validatePosturePlacement(prefix, viewKey) {
  const bd = _getPostureBilanData(prefix);
  if (!bd || !_postureModalCanvas) { _cancelPosturePlacement(); return; }
  const W = _postureModalCanvas.width, H = _postureModalCanvas.height;
  // #108 — face : _computeFaceAngles persiste les 11 mesures.
  // dos étape 2 : _computeDosAngles persiste les mesures vue postérieure
  // (tête, épaules/scapulas, rachis avec apex/convexité, bassin, membre inf.).
  // Pas de curveInterp pour face/dos (sémantique courbures rachidiennes
  // spécifique au profil — sera évaluée à part).
  // Profil G/D : flow inchangé — angles + curveInterp calculés au save.
  const isFace = viewKey === 'face';
  const isDos  = viewKey === 'dos';
  let angles = null;
  let curveInterp = null;
  if (isFace) {
    angles = _computeFaceAngles(_postureModalMarkers, _postureCalibration);
  } else if (isDos) {
    angles = _computeDosAngles(_postureModalMarkers, _postureCalibration);
  } else {
    // #85-2c-angles — angles recalculés au moment du save (recalculables à tout
    // moment depuis markers + calibration ; on les stocke quand même pour éviter
    // de refaire le calcul à chaque affichage rapport / liste / résumé).
    angles = _computePostureAngles(_postureModalMarkers, _postureCalibration);
    // #106-Final Volet 3d — curveInterp = source de vérité depuis les 3 <select>.
    // Si le select n'existe pas (état dégradé), on retombe sur la valeur sauvegardée
    // ou l'auto-mapping. cls calculé à partir des angles pour l'auto-mapping.
    const cls = _classifyPostureAngles(angles);
    const existing = bd._postureAnalysis?.[viewKey] || {};
    const readSelect = (courbure) => {
      const el = document.getElementById('posture-curve-interp-' + courbure);
      if (el && el.value) return el.value;
      return existing.curveInterp?.[courbure] || _autoCurveInterp(cls, courbure) || null;
    };
    curveInterp = {
      cervicale:  readSelect('cervicale'),
      thoracique: readSelect('thoracique'),
      lombaire:   readSelect('lombaire'),
    };
  }
  if (!bd._postureAnalysis) bd._postureAnalysis = {};
  bd._postureAnalysis[viewKey] = {
    markers: _postureModalMarkers.map(m => ({
      name: m.name,
      side: m.side,
      nx: (m.x !== null && W > 0) ? m.x / W : null,
      ny: (m.y !== null && H > 0) ? m.y / H : null,
    })),
    // Calibration en NORMALISÉ comme les markers (cohérent inter-device).
    calibration: _postureCalibration ? {
      p1: _postureCalibration.p1 ? { nx: _postureCalibration.p1.x / W, ny: _postureCalibration.p1.y / H } : null,
      p2: _postureCalibration.p2 ? { nx: _postureCalibration.p2.x / W, ny: _postureCalibration.p2.y / H } : null,
    } : null,
    angles,
    curveInterp,
  };
  _cancelPosturePlacement();
  _renderPostureSlot(prefix, viewKey);
  // Save silencieux pour persister sans clic "Enregistrer" séparé.
  try {
    if (prefix === 'sp' && typeof saveBilanSilent === 'function') {
      await saveBilanSilent();
    } else if (prefix === 'po' && typeof savePosturoBilan === 'function') {
      await savePosturoBilan(true);
    }
  } catch (e) {
    console.warn('[#85-2b] save silent posture analysis a échoué :', e?.message);
  }
}

// Active la caméra avec le deviceId sélectionné (ou fallback environment).
// Pattern miroir toggleVCam L3770-3796. Stream stocké dans _postureStreams[prefix].
async function _togglePostureCam(prefix) {
  if (_postureStreams[prefix]) { _stopPostureCam(prefix); return; }
  const sel = document.getElementById(`${prefix}-pc-camera-select`);
  const selVal = sel?.value;
  const constraints = {
    audio: false,
    video: selVal
      ? { deviceId: { exact: selVal }, width: { ideal: 1920 }, height: { ideal: 1080 } }
      : { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } }
  };
  try {
    _postureStreams[prefix] = await navigator.mediaDevices.getUserMedia(constraints);
    const video = document.getElementById(`${prefix}-pc-video`);
    if (video) {
      video.srcObject = _postureStreams[prefix];
      video.play().catch(() => {});
    }
    const btn = document.getElementById(`${prefix}-pc-cam-btn`);
    const st  = document.getElementById(`${prefix}-pc-cam-status`);
    if (btn) { btn.textContent = '⏹ Arrêter'; btn.style.background = '#c0392b'; }
    if (st)  { st.textContent  = 'Active';   st.className = 'badge bg'; }
    // #85-2c-grid — affiche la grille par défaut à l'activation caméra (aide
    // immédiate au cadrage). Masquable ensuite via le bouton ▦ Grille.
    const grid = document.getElementById(`${prefix}-pc-grid`);
    if (grid) grid.style.display = 'block';
    const gridBtn = document.getElementById(`${prefix}-pc-grid-btn`);
    if (gridBtn) gridBtn.style.background = '#0e7490';
    // Rafraîchir la liste maintenant que la permission est accordée (labels disponibles)
    enumerateCameras(`${prefix}-pc-camera-select`);
  } catch (e) {
    const st = document.getElementById(`${prefix}-pc-cam-status`);
    if (st) { st.textContent = 'Erreur'; st.className = 'badge br'; }
    console.warn('[#85] Caméra inaccessible :', e.message);
  }
}

// Switch caméra : stop le stream actuel, redémarre avec le nouveau deviceId.
async function _switchPostureCam(prefix) {
  if (!_postureStreams[prefix]) return; // pas de stream → l'utilisateur clique « Activer » d'abord
  _stopPostureCam(prefix);
  await _togglePostureCam(prefix);
}

function _stopPostureCam(prefix) {
  if (_postureStreams[prefix]) {
    _postureStreams[prefix].getTracks().forEach(t => t.stop());
    _postureStreams[prefix] = null;
  }
  const video = document.getElementById(`${prefix}-pc-video`);
  if (video) video.srcObject = null;
  const btn = document.getElementById(`${prefix}-pc-cam-btn`);
  const st  = document.getElementById(`${prefix}-pc-cam-status`);
  if (btn) { btn.textContent = '▶ Activer caméra'; btn.style.background = '#2a7a4e'; }
  if (st)  { st.textContent  = 'Inactive';         st.className = 'badge bd'; }
  // #85-2c-grid — masque la grille à l'arrêt (sinon overlay flottant sur fond noir).
  const grid = document.getElementById(`${prefix}-pc-grid`);
  if (grid) grid.style.display = 'none';
}

// #85-2c-grid — toggle manuel de la grille (état indépendant du stream caméra).
// Couleur du bouton : cyan foncé quand active, gris quand masquée — feedback visuel.
function _togglePostureGrid(prefix) {
  const grid = document.getElementById(`${prefix}-pc-grid`);
  if (!grid) return;
  const wasVisible = grid.style.display !== 'none';
  grid.style.display = wasVisible ? 'none' : 'block';
  const btn = document.getElementById(`${prefix}-pc-grid-btn`);
  if (btn) btn.style.background = wasVisible ? '#94a3b8' : '#0e7490';
}

// Capture frame courante du <video> → JPEG 0.88 → bilanData[`_posture<View>`].
async function capturePostureView(prefix, viewKey) {
  const video = document.getElementById(`${prefix}-pc-video`);
  if (!video || !video.videoWidth || !video.videoHeight) {
    alert('Activez la caméra avant de capturer.');
    return;
  }
  const bd = _getPostureBilanData(prefix);
  if (!bd) {
    alert('Aucun bilan ouvert — sélectionnez un patient et créez/ouvrez un bilan.');
    return;
  }
  // #85-P2a — crop centré portrait cohérent avec l'affichage object-fit:cover.
  // Le flux webcam est paysage (16/9 ou 4/3) ; on extrait la bande centrale
  // d'aspect POSTURE_CAPTURE_ASPECT. Sans ce crop, le preview cover masquait
  // les bords mais la capture sortait paysage → décalage entre cadrage praticien
  // et image stockée. Algorithme miroir CSS object-fit:cover (centré, jamais déformé).
  const vw = video.videoWidth, vh = video.videoHeight;
  let cropW, cropH, sx, sy;
  if (vw / vh > POSTURE_CAPTURE_ASPECT) {
    // Flux plus large que cible → on garde toute la hauteur, on rogne les côtés.
    cropH = vh;
    cropW = Math.round(vh * POSTURE_CAPTURE_ASPECT);
    sx = Math.round((vw - cropW) / 2);
    sy = 0;
  } else {
    // Flux déjà plus étroit (ou déjà portrait) → on garde toute la largeur,
    // on rogne haut/bas (borné à vh par sécurité).
    cropW = vw;
    cropH = Math.min(vh, Math.round(vw / POSTURE_CAPTURE_ASPECT));
    sx = 0;
    sy = Math.round((vh - cropH) / 2);
  }
  const tmp = document.createElement('canvas');
  tmp.width  = cropW;
  tmp.height = cropH;
  tmp.getContext('2d').drawImage(video, sx, sy, cropW, cropH, 0, 0, cropW, cropH);
  const dataUrl = tmp.toDataURL('image/jpeg', 0.88);
  const key = '_posture' + viewKey.charAt(0).toUpperCase() + viewKey.slice(1);
  bd[key] = dataUrl;
  // #85 Phase 1 — si un Path Storage existait pour une capture précédente, on
  // l'invalide (le delete .path force migrateSportBilanDataPhotos / migratePosturoPhotos
  // à ré-upload au prochain save ; l'ancien fichier devient orphelin, nettoyé par
  // ticket dédié — pattern miroir photoSlots[].path = null L3523).
  if (bd[key + 'Path']) delete bd[key + 'Path'];
  _renderPostureSlot(prefix, viewKey);
  // #85 — auto-save silencieux : sans ce save, la capture est perdue au refresh
  // (bd est en RAM uniquement jusqu'au prochain Enregistrer manuel). Pattern miroir
  // _validatePosturePlacement L4823-4831. onclick inline ignore la promesse retournée.
  try {
    if (prefix === 'sp' && typeof saveBilanSilent === 'function') {
      await saveBilanSilent();
    } else if (prefix === 'po' && typeof savePosturoBilan === 'function') {
      await savePosturoBilan(true);
    }
  } catch (e) {
    console.warn('[#85] auto-save capture posture échoué :', e?.message);
  }
}

async function deletePostureView(prefix, viewKey) {
  const bd = _getPostureBilanData(prefix);
  if (!bd) return;
  const key = '_posture' + viewKey.charAt(0).toUpperCase() + viewKey.slice(1);
  delete bd[key];
  if (bd[key + 'Path']) delete bd[key + 'Path'];
  // #117-incident — Effacer aussi les points de la vue (markers nx/ny, calibration,
  // angles calculés). Sans ça, ré-importer une photo fait réapparaître les markers
  // de la session précédente sur la nouvelle photo (mauvais cadrage anatomique →
  // angles faux). Ciblé sur viewKey uniquement — les autres vues conservent leurs
  // points et l'objet _postureAnalysis racine est préservé.
  if (bd._postureAnalysis && bd._postureAnalysis[viewKey]) {
    delete bd._postureAnalysis[viewKey];
  }
  _renderPostureSlot(prefix, viewKey);
  // #85 — auto-save silencieux : la suppression doit persister immédiatement
  // (sinon refresh ramène la capture supprimée depuis le bilan persisté).
  // #117-incident — Suppression VOLONTAIRE d'une vue posturale → suppress la garde
  // de richesse. Flag tenu pendant tout l'await (la sync part de savePatients
  // se déclenche après les awaits de migration photo).
  _intentionalReduction = true;
  try {
    if (prefix === 'sp' && typeof saveBilanSilent === 'function') {
      await saveBilanSilent();
    } else if (prefix === 'po' && typeof savePosturoBilan === 'function') {
      await savePosturoBilan(true);
    }
  } catch (e) {
    console.warn('[#85] auto-save delete posture échoué :', e?.message);
  } finally {
    _intentionalReduction = false;
  }
}

// #85-2c-import — lazy-load heic2any depuis CDN (Chrome/Firefox ne décodent pas
// HEIC nativement ; iOS Safari le convertit parfois côté OS, parfois pas).
// Idempotent : si déjà chargé, retourne resolved immédiatement ; si en cours de
// chargement (script tag avec marker data-heic2any présent), on s'attache à
// son load/error pour ne pas re-injecter.
function _loadHeic2anyIfNeeded() {
  if (window.heic2any) return Promise.resolve();
  return new Promise((resolve, reject) => {
    const existing = document.querySelector('script[data-heic2any]');
    if (existing) {
      existing.addEventListener('load', () => window.heic2any ? resolve() : reject(new Error('heic2any chargé mais window.heic2any absent')));
      existing.addEventListener('error', () => reject(new Error('Échec chargement heic2any (réseau ?)')));
      return;
    }
    const s = document.createElement('script');
    s.src = 'https://cdnjs.cloudflare.com/ajax/libs/heic2any/0.0.4/heic2any.min.js';
    s.dataset.heic2any = '1';
    s.async = true;
    s.onload = () => window.heic2any ? resolve() : reject(new Error('heic2any chargé mais window.heic2any absent'));
    s.onerror = () => reject(new Error('Échec chargement heic2any (réseau ?)'));
    document.head.appendChild(s);
  });
}

// #85-2c-import — import d'une image depuis l'app native (limite iOS : Safari
// n'expose pas l'ultra grand-angle via getUserMedia). L'image est stockée TELLE
// QUELLE (pas de crop POSTURE_CAPTURE_ASPECT) car cadrée par le praticien dans
// l'app caméra native. Le pipeline aval (slot rendering, modale placement
// _postureAnalysis nx/ny) est résolution-agnostique → marche identiquement.
// Support HEIC (format par défaut iPhone) : détection MIME OU extension (iOS
// envoie parfois MIME vide), conversion via heic2any chargée à la demande.
// Auto-save miroir capturePostureView : dispatch par préfixe (sp/po).
async function importPostureView(prefix, viewKey, input) {
  if (!input || !input.files || !input.files[0]) return;
  const file = input.files[0];
  // Détection HEIC avant le check MIME générique : file.type peut être vide
  // (iOS) ou image/heic|heif (desktop). Le nom de fichier complète la détection.
  const lcName = (file.name || '').toLowerCase();
  const isHeic = /^image\/hei[cf]$/i.test(file.type || '') || /\.(heic|heif)$/i.test(lcName);
  if (!isHeic && (!file.type || !file.type.startsWith('image/'))) {
    alert('Sélectionnez un fichier image (JPEG, PNG, WebP, HEIC).');
    input.value = '';
    return;
  }
  const bd = _getPostureBilanData(prefix);
  if (!bd) {
    alert('Aucun bilan ouvert — sélectionnez un patient et créez/ouvrez un bilan.');
    input.value = '';
    return;
  }
  // Conversion HEIC → JPEG si nécessaire. Le FileReader en aval lit indifféremment
  // un File ou un Blob → assignation à `blob` qui peut être l'un ou l'autre.
  let blob = file;
  if (isHeic) {
    try {
      await _loadHeic2anyIfNeeded();
      if (!window.heic2any) throw new Error('Bibliothèque heic2any indisponible');
      const out = await window.heic2any({ blob: file, toType: 'image/jpeg', quality: 0.9 });
      // heic2any retourne soit un Blob (image unique), soit un Array<Blob> (HEIC
      // multi-frame). On prend la première frame dans le cas array.
      blob = Array.isArray(out) ? out[0] : out;
      if (!blob) throw new Error('Conversion HEIC : sortie vide');
    } catch (e) {
      alert('Conversion HEIC échouée : ' + (e?.message || e) + '\n\nEnvoyez l\'image au format JPEG ou PNG (ou activez "Plus compatible" dans Réglages iOS → Appareil photo → Formats).');
      input.value = '';
      return;
    }
  }
  const dataUrl = await new Promise((resolve, reject) => {
    const r = new FileReader();
    r.onload = () => resolve(r.result);
    r.onerror = () => reject(r.error || new Error('FileReader error'));
    r.readAsDataURL(blob);
  }).catch(e => {
    alert('Erreur lecture fichier : ' + (e?.message || e));
    return null;
  });
  // Reset input.value SYSTÉMATIQUEMENT (succès ET échec) pour permettre la
  // ré-importation du même fichier après modification externe.
  input.value = '';
  if (!dataUrl) return;
  const key = '_posture' + viewKey.charAt(0).toUpperCase() + viewKey.slice(1);
  bd[key] = dataUrl;
  // Path Storage obsolète : la nouvelle image doit ré-uploader au prochain save.
  if (bd[key + 'Path']) delete bd[key + 'Path'];
  // #117-incident — Une nouvelle photo invalide les anciens points (cadrage
  // différent). Effacer les points de la vue → repart vierge, cohérent avec
  // deletePostureView. Évite les points fantômes sur une nouvelle photo.
  if (bd._postureAnalysis && bd._postureAnalysis[viewKey]) {
    delete bd._postureAnalysis[viewKey];
  }
  _renderPostureSlot(prefix, viewKey);
  // #117-incident — Réduction VOLONTAIRE (nouvelle photo qui remplace l'ancienne).
  // Suppress la garde de richesse pour ce save autosauve uniquement.
  _intentionalReduction = true;
  try {
    if (prefix === 'sp' && typeof saveBilanSilent === 'function') {
      await saveBilanSilent();
    } else if (prefix === 'po' && typeof savePosturoBilan === 'function') {
      await savePosturoBilan(true);
    }
  } catch (e) {
    console.warn('[#85] auto-save import posture échoué :', e?.message);
  } finally {
    _intentionalReduction = false;
  }
}

// Boot sport : peuple le container statique d'index.html avec le markup builder.
// Posturo ne nécessite pas d'équivalent — l'interpolation est dans getBilanPosturoHTML
// régénéré à chaque ouverture du bilan posturo.
function populateSportPostureCaptureBlock() {
  const container = document.getElementById('sp-posture-capture-container');
  if (!container) return;
  container.innerHTML = _buildPostureCaptureBlockHTML('sp');
}

function setupVidCanvas(player, vcanvas) {
  const view = TESTS[currentTestId]?.view || 'face';
  vcanvas.onmousedown = e => {
    const {x,y}=canvasXY(e,vcanvas);
    const hit=findMarkerAt(x,y,vidMarkers,vcanvas.width);
    if(hit>=0){
      selectedVidMkrIdx=hit;isVidDragging=true;
      vAutoDetect=false;
      const bv=document.getElementById('btn-vauto');
      if(bv){bv.textContent='Auto : OFF';bv.className='btn';}
      renderMkrList();return;
    }
    const idx=selectedVidMkrIdx>=0?selectedVidMkrIdx:vidMarkers.findIndex(m=>m.x===null);
    if(idx>=0&&idx<vidMarkers.length){
      vidMarkers[idx].x=x; vidMarkers[idx].y=y;
      const next=vidMarkers.findIndex((m,i)=>i>idx&&m.x===null);
      selectedVidMkrIdx=next>=0?next:-1;
      renderMkrList(); updateResults();
    }
  };
  vcanvas.onmousemove=e=>{
    if(!isVidDragging||selectedVidMkrIdx<0)return;
    const{x,y}=canvasXY(e,vcanvas);
    vidMarkers[selectedVidMkrIdx].x=x; vidMarkers[selectedVidMkrIdx].y=y;
    renderMkrList(); updateResults();
    // Redessiner immédiatement (important en pause)
    const ctx2=vcanvas.getContext('2d');
    ctx2.drawImage(player,0,0,vcanvas.width,vcanvas.height);
    drawOverlay(ctx2,vcanvas,vidMarkers,selectedVidMkrIdx,TESTS[currentTestId]?.view||'face');
    updateAngleOverlay('vid-angles',vidMarkers,TESTS[currentTestId]?.view||'face');
  };
  vcanvas.onmouseup=()=>isVidDragging=false;
  vcanvas.ontouchstart=e=>{e.preventDefault();const t=e.touches[0];vcanvas.onmousedown({clientX:t.clientX,clientY:t.clientY});};
  vcanvas.ontouchmove=e=>{e.preventDefault();const t=e.touches[0];vcanvas.onmousemove({clientX:t.clientX,clientY:t.clientY});};
  vcanvas.ontouchend=()=>vcanvas.onmouseup();

  player.ontimeupdate=()=>{
    const ctx=vcanvas.getContext('2d');
    ctx.drawImage(player,0,0,vcanvas.width,vcanvas.height);
    if(vAutoDetect) detectMarkersAuto(ctx,vcanvas,vidMarkers,view,()=>{renderMkrList();updateResults();});
    drawOverlay(ctx,vcanvas,vidMarkers,selectedVidMkrIdx,view);
    updateAngleOverlay('vid-angles',vidMarkers,view);
    const t2=player.currentTime,d=player.duration||1;
    document.getElementById('time-disp').textContent=`${t2.toFixed(2)}/${d.toFixed(2)}s`;
    document.getElementById('timeline').value=Math.round(t2/d*1000);
    updateResults();
  };
}

function togglePlay(){const p=document.getElementById('vid-el');if(p.paused){p.play();document.getElementById('btn-play').textContent='⏸';}else{p.pause();document.getElementById('btn-play').textContent='▶';}}
function stepFrame(dir){const p=document.getElementById('vid-el');p.pause();p.currentTime=Math.max(0,Math.min(p.duration||0,p.currentTime+dir/30));document.getElementById('btn-play').textContent='▶';}
function seekVid(val){const p=document.getElementById('vid-el');if(p.duration)p.currentTime=(val/1000)*p.duration;}

function toggleRec() {
  if(!vidStream){alert('Activez la caméra live.');return;}
  if(isRecording){
    mediaRec.stop();isRecording=false;document.getElementById('btn-vrec').textContent='⏺ Rec';
  } else {
    recChunks=[];
    mediaRec=new MediaRecorder(vidStream);
    mediaRec.ondataavailable=e=>{if(e.data.size>0)recChunks.push(e.data);};
    mediaRec.onstop=()=>{
      const blob=new Blob(recChunks,{type:'video/webm'});
      const player=document.getElementById('vid-el'); const vcanvas=document.getElementById('vid-canvas');
      player.srcObject=null; player.src=URL.createObjectURL(blob);
      player.onloadedmetadata=()=>{
        vcanvas.width=player.videoWidth; vcanvas.height=player.videoHeight;
        document.getElementById('vid-info').textContent=`Enreg. · ${player.duration.toFixed(1)}s`;
        setupVidCanvas(player,vcanvas);
      };
    };
    mediaRec.start();isRecording=true;document.getElementById('btn-vrec').textContent='⏹ Stop';
  }
}

function toggleVAutoDetect(){
  vAutoDetect=!vAutoDetect;
  document.getElementById('btn-vauto').textContent='Auto : '+(vAutoDetect?'ON':'OFF');
  document.getElementById('btn-vauto').className=vAutoDetect?'btn btn-green':'btn';
}

// ══════════════════════════════════════════════════════
// CAPTURE FRAME VIDEO
// ══════════════════════════════════════════════════════
function captureFrame() {
  const player=document.getElementById('vid-el');
  const vcanvas=document.getElementById('vid-canvas');
  const view=TESTS[currentTestId]?.view||'face';
  // Créer snapshot
  const tmp=document.createElement('canvas');
  tmp.width=vcanvas.width; tmp.height=vcanvas.height;
  const ctx=tmp.getContext('2d');
  ctx.drawImage(player,0,0,vcanvas.width,vcanvas.height);
  drawOverlay(ctx,tmp,vidMarkers,-1,view);
  const dataUrl=tmp.toDataURL('image/jpeg',0.88);

  // Calculer angles D et G
  const mkrD=vidMarkers.filter(m=>m.side==='D');
  const mkrG=vidMarkers.filter(m=>m.side==='G');
  const rawD=calcAngle3(mkrD), rawG=calcAngle3(mkrG);
  const angD=mkrD.length>=3?computeCorrectedAngle(rawD,'D',view,TESTS[currentTestId]?.type||'',mkrD):null;
  const angG=mkrG.length>=3?computeCorrectedAngle(rawG,'G',view,TESTS[currentTestId]?.type||'',mkrG):null;

  capturedFrames.push({
    time:player.currentTime||0, dataUrl, angD, angG,
    markers:JSON.parse(JSON.stringify(vidMarkers))
  });
  renderFrameStrip(); updateResults();
}

function deleteFrame(i) {
  capturedFrames.splice(i,1);
  if(selectedFrameIdx>=capturedFrames.length) selectedFrameIdx=capturedFrames.length-1;
  renderFrameStrip(); updateResults();
}
function resetAllFrames() {
  if(!confirm('Effacer toutes les frames ?')) return;
  capturedFrames=[]; selectedFrameIdx=-1; renderFrameStrip(); updateResults();
}
function selectFrame(i) {
  selectedFrameIdx=i;
  vidMarkers=JSON.parse(JSON.stringify(capturedFrames[i].markers));
  renderMkrList(); renderFrameStrip(); updateResults();
}
function renderFrameStrip() {
  document.getElementById('frame-count').textContent=capturedFrames.length;
  document.getElementById('frames-strip').innerHTML=capturedFrames.map((f,i)=>`
    <div class="fthumb ${selectedFrameIdx===i?'sel':''}">
      <img src="${f.dataUrl}" onclick="selectFrame(${i})" style="cursor:pointer;"/>
      <button class="ft-del" onclick="event.stopPropagation();deleteFrame(${i})">✕</button>
      <div class="ft-info">${f.time.toFixed(2)}s${f.angD!==null?' D:'+f.angD.toFixed(1)+'°':''}${f.angG!==null?' G:'+f.angG.toFixed(1)+'°':''}</div>
    </div>`).join('');
}

// ══════════════════════════════════════════════════════
// DÉTECTION & DESSIN
// ══════════════════════════════════════════════════════
function canvasXY(e, canvas) {
  const rect=canvas.getBoundingClientRect();
  return {x:(e.clientX-rect.left)*canvas.width/rect.width, y:(e.clientY-rect.top)*canvas.height/rect.height};
}

// feat-biomec-capteurs (A) — Handler oninput des sliders « Taille points ».
// Source de vérité unique = markerSizeFactor + clé localStorage. Sync visuelle
// des sliders et labels (photo + vidéo) pour cohérence quand l'utilisateur
// switch de mode. Redraw immédiat des canvases pour feedback live, même en
// pause vidéo (rAF du live cam couvre naturellement les cas actifs).
function setMarkerSizeFactor(val) {
  const n = parseFloat(val);
  if (isNaN(n)) return;
  markerSizeFactor = Math.min(MARKER_SIZE_MAX, Math.max(MARKER_SIZE_MIN, n));
  try { localStorage.setItem(MARKER_SIZE_KEY, String(markerSizeFactor)); } catch (e) { /* noop */ }
  // Sync sliders (au cas où un autre slider est visible aussi).
  document.querySelectorAll('.marker-size-slider').forEach(el => {
    if (parseFloat(el.value) !== markerSizeFactor) el.value = markerSizeFactor;
  });
  document.querySelectorAll('.marker-size-label').forEach(el => {
    el.textContent = 'Taille:' + markerSizeFactor.toFixed(2);
  });
  // Redraw immédiat — pour vidéo paused (live cam = rAF s'en charge).
  const view = (typeof TESTS !== 'undefined' && TESTS[currentTestId]?.view) || 'face';
  const vEl = document.getElementById('vid-el');
  const vC  = document.getElementById('vid-canvas');
  if (vEl && vC && vC.width > 0 && vEl.readyState >= 2) {
    const ctx = vC.getContext('2d');
    ctx.drawImage(vEl, 0, 0, vC.width, vC.height);
    drawOverlay(ctx, vC, vidMarkers, selectedVidMkrIdx, view);
  }
  // Photo : repeint juste l'overlay markers (live cam rAF couvre l'underlying).
  const phC = document.getElementById('ph-canvas');
  if (phC && phC.width > 0) {
    drawOverlay(phC.getContext('2d'), phC, liveMarkers, selectedMkrIdx, view);
  }
}

// feat-biomec-capteurs (B) — Handler oninput des sliders « Opacité ». Même
// contrat que setMarkerSizeFactor : clamp, persistance localStorage, sync des
// sliders + labels (photo + vidéo), redraw immédiat pour feedback live et pour
// les frames vidéo en pause (le rAF live cam couvre les flux actifs).
function setMarkerOpacity(val) {
  const n = parseFloat(val);
  if (isNaN(n)) return;
  markerOpacity = Math.min(MARKER_OPACITY_MAX, Math.max(MARKER_OPACITY_MIN, n));
  try { localStorage.setItem(MARKER_OPACITY_KEY, String(markerOpacity)); } catch (e) { /* noop */ }
  document.querySelectorAll('.marker-opacity-slider').forEach(el => {
    if (parseFloat(el.value) !== markerOpacity) el.value = markerOpacity;
  });
  document.querySelectorAll('.marker-opacity-label').forEach(el => {
    el.textContent = 'Opacité:' + markerOpacity.toFixed(2);
  });
  const view = (typeof TESTS !== 'undefined' && TESTS[currentTestId]?.view) || 'face';
  const vEl = document.getElementById('vid-el');
  const vC  = document.getElementById('vid-canvas');
  if (vEl && vC && vC.width > 0 && vEl.readyState >= 2) {
    const ctx = vC.getContext('2d');
    ctx.drawImage(vEl, 0, 0, vC.width, vC.height);
    drawOverlay(ctx, vC, vidMarkers, selectedVidMkrIdx, view);
  }
  const phC = document.getElementById('ph-canvas');
  if (phC && phC.width > 0) {
    drawOverlay(phC.getContext('2d'), phC, liveMarkers, selectedMkrIdx, view);
  }
}

function findMarkerAt(x, y, markers, cw) {
  // feat-biomec-capteurs (A) — hit-test scalé par markerSizeFactor MAIS avec
  // plancher confortable au touch (12px min). Le marqueur visuel rétrécit, on
  // doit toujours pouvoir l'attraper au doigt même quand markerSizeFactor=0.3.
  const r = Math.max(12, (cw / 40) * markerSizeFactor);
  for(let i=markers.length-1;i>=0;i--){
    const m=markers[i]; if(m.x===null)continue;
    if(Math.hypot(m.x-x,m.y-y)<r) return i;
  }
  return -1;
}

// Détection automatique des marqueurs réfléchissants
function detectMarkersAuto(ctx, canvas, markers, view, cb) {
  // Placement automatique intelligent selon le type de test
  const W=canvas.width, H=canvas.height;
  const testId = currentTestId || '';
  const markersType = TESTS[testId]?.markers || '';

  // ─── KFPPA (vue face) : lignes verticales EIAS→Rotule→Tarse
  // Vue face : côté D de la personne = gauche de l'image, côté G = droite
  if(markersType === 'genou-bi') {
    const midX = W / 2;
    // Côté D : ligne verticale à gauche de l'image (x ~25% de W)
    const xD = W * 0.25;
    const xG = W * 0.75;
    // EIAS en haut (y ~20%), Rotule au centre (y ~50%), Tarse en bas (y ~80%)
    const yTop = H * 0.20, yMid = H * 0.50, yBot = H * 0.80;

    const placed = { D: [{x:xD,y:yTop},{x:xD,y:yMid},{x:xD,y:yBot}],
                     G: [{x:xG,y:yTop},{x:xG,y:yMid},{x:xG,y:yBot}] };
    ['D','G'].forEach(side => {
      const mkrs = markers.filter(m=>m.side===side);
      placed[side].forEach((pos,i) => {
        // Ne placer que si pas encore placé manuellement
        if(mkrs[i] && mkrs[i].x===null) { mkrs[i].x=pos.x; mkrs[i].y=pos.y; }
      });
    });
    if(cb) cb(); return;
  }

  // ─── MLA (vue profil) : angle à sommet supérieur FMHp - TN - CAp
  // Ordre dans le template : CAp, TN, FMHp
  // FMHp à gauche, TN au sommet (haut centre), CAp à droite
  if(markersType === 'mla') {
    const fmhp = markers.find(m=>m.name.startsWith('FMHp')||m.name==='FMHp');
    const tn   = markers.find(m=>m.name.startsWith('TN')||m.name==='TN');
    const cap  = markers.find(m=>m.name.startsWith('CAp')||m.name==='CAp');
    if(fmhp && tn && cap) {
      if(fmhp.x===null){fmhp.x=W*0.20;fmhp.y=H*0.65;}
      if(tn.x===null){tn.x=W*0.50;tn.y=H*0.30;}
      if(cap.x===null){cap.x=W*0.80;cap.y=H*0.65;}
    }
    if(cb) cb(); return;
  }

  // ─── AP-BI (vue dos) : lignes verticales point1→4
  // Vue dos : côté D = droite image, côté G = gauche image
  // Point 1 (Milieu mollet) en haut, point 4 (Calca inf) en bas
  if(markersType === 'ap-bi') {
    const xD = W * 0.70; // droite image = côté D personne (vue dos)
    const xG = W * 0.30; // gauche image = côté G personne (vue dos)
    const yStep = H * 0.20;
    const yStart = H * 0.20;

    ['D','G'].forEach(side => {
      const xPos = side==='D' ? xD : xG;
      const mkrs = markers.filter(m=>m.side===side);
      // Ne placer que si pas encore placé manuellement
      mkrs.forEach((m,i) => { if(m.x===null) { m.x = xPos; m.y = yStart + i * yStep; } });
    });
    if(cb) cb(); return;
  }

  // ─── Détection visuelle générique (blobs lumineux)
  const data=ctx.getImageData(0,0,W,H).data;
  const blobs=[]; const vis=new Uint8Array(W*H);
  for(let y=2;y<H-2;y+=2){
    for(let x=2;x<W-2;x+=2){
      const i=(y*W+x)*4;
      const br=(data[i]+data[i+1]+data[i+2])/3;
      const sat=Math.max(data[i],data[i+1],data[i+2])-Math.min(data[i],data[i+1],data[i+2]);
      if(br>sensThr&&sat<45&&!vis[y*W+x]){
        let sx=0,sy2=0,cnt=0;const stack=[[x,y]];
        while(stack.length&&cnt<800){
          const[cx,cy]=stack.pop();
          if(cx<0||cy<0||cx>=W||cy>=H||vis[cy*W+cx])continue;
          const pi=(cy*W+cx)*4;
          const pb=(data[pi]+data[pi+1]+data[pi+2])/3;
          const ps=Math.max(data[pi],data[pi+1],data[pi+2])-Math.min(data[pi],data[pi+1],data[pi+2]);
          if(pb<sensThr-35||ps>55){vis[cy*W+cx]=1;continue;}
          vis[cy*W+cx]=1;sx+=cx;sy2+=cy;cnt++;
          stack.push([cx+2,cy],[cx-2,cy],[cx,cy+2],[cx,cy-2]);
        }
        if(cnt>3&&cnt<4000) blobs.push({x:sx/cnt,y:sy2/cnt,s:cnt});
      }
    }
  }

  const midX=W/2;
  if(view==='face'||view==='dos') {
    const blobsLeft=blobs.filter(b=>b.x<midX).sort((a,b2)=>a.y-b2.y);
    const blobsRight=blobs.filter(b=>b.x>=midX).sort((a,b2)=>a.y-b2.y);
    // Vue dos : D=droite image / Vue face : D=gauche image
    const blobsD = view==='dos' ? blobsRight : blobsLeft;
    const blobsG = view==='dos' ? blobsLeft  : blobsRight;
    const unplacedD=markers.filter(m=>m.side==='D'&&m.x===null);
    const unplacedG=markers.filter(m=>m.side==='G'&&m.x===null);
    blobsD.slice(0,unplacedD.length).forEach((b,i)=>{if(unplacedD[i]){unplacedD[i].x=b.x;unplacedD[i].y=b.y;}});
    blobsG.slice(0,unplacedG.length).forEach((b,i)=>{if(unplacedG[i]){unplacedG[i].x=b.x;unplacedG[i].y=b.y;}});
  } else {
    blobs.sort((a,b)=>a.y-b.y);
    const unplaced=markers.filter(m=>m.x===null);
    blobs.slice(0,unplaced.length).forEach((b,i)=>{if(unplaced[i]){unplaced[i].x=b.x;unplaced[i].y=b.y;}});
  }
  if(cb) cb();
}

// Dessin overlay avec SEGMENTS RECTANGULAIRES (style OPS)
function drawOverlay(ctx, canvas, markers, selIdx, view) {
  const W=canvas.width;
  const segW=Math.max(8,W/55); // largeur du rectangle segment

  // Dessiner segments par groupe (D et G)
  ['D','G',''].forEach(side=>{
    const grp=markers.filter(m=>m.side===side&&m.x!==null);
    if(grp.length<2) return;
    const col=side==='D'?'rgba(74,158,255,0.7)':side==='G'?'rgba(62,207,114,0.7)':'rgba(167,139,250,0.7)';
    // Dessiner rectangle entre chaque paire consécutive
    for(let i=0;i<grp.length-1;i++){
      drawSegmentRect(ctx,grp[i],grp[i+1],segW,col);
    }
  });

  // Points marqueurs
  // feat-biomec-capteurs (A) — rayon, halo et label scalés par markerSizeFactor.
  // Planchers (4 px rayon, 8 px label) garantissent la lisibilité même à 0.3.
  // Halo : ratio +4 d'origine remplacé par +Math.max(2, 4*factor) pour suivre
  // proportionnellement la réduction du point (un halo +4 sur un point de 4 px
  // dominerait visuellement le point lui-même).
  markers.forEach((m,i)=>{
    if(m.x===null) return;
    const r = Math.max(4, (W / 72) * markerSizeFactor);
    const haloPad = Math.max(2, 4 * markerSizeFactor);
    const isSel=selIdx===i;
    ctx.save();
    // Halo : alpha déjà très bas (0.15/0.3) — conservé tel quel pour repère.
    ctx.beginPath(); ctx.arc(m.x, m.y, r + haloPad, 0, 2 * Math.PI);
    ctx.fillStyle=isSel?'rgba(245,166,35,.3)':'rgba(255,255,255,.15)'; ctx.fill();
    // feat-biomec-capteurs (B) — remplissage coloré du point modulé par
    // markerOpacity (voir la pastille au travers) ; contour + label restent
    // pleine intensité pour conserver le repère exact du centre.
    ctx.beginPath(); ctx.arc(m.x, m.y, r, 0, 2 * Math.PI);
    ctx.fillStyle=m.color;
    ctx.globalAlpha = markerOpacity;
    ctx.fill();
    ctx.globalAlpha = 1;
    ctx.strokeStyle=isSel?'#f5a623':'#fff'; ctx.lineWidth=isSel?2.5:1.5; ctx.stroke();
    ctx.restore();
    ctx.fillStyle='#fff';
    ctx.font = `bold ${Math.max(8, (W / 60) * markerSizeFactor)}px DM Sans,sans-serif`;
    ctx.fillText(m.name, m.x + r + 3, m.y + 3);
  });

  // Arc d'angle pour chaque groupe de 3
  ['D','G',''].forEach(side=>{
    const grp=markers.filter(m=>m.side===side&&m.x!==null);
    if(grp.length>=3){
      const ang=calcAngle3(grp);
      if(ang!==null){
        const B=grp.length>=4?grp[2]:grp[1]; // AP: sommet=CalcaSup(idx2), sinon centre
        const grpPts=grp;
        const _mlaT=TESTS[currentTestId]?.markers==='mla'?'mla':(TESTS[currentTestId]?.type||"");
        const corrAng=computeCorrectedAngle(ang, side, view, _mlaT, grpPts);
        const r2=Math.max(16,W/24);
        const a1=Math.atan2(grp[0].y-B.y,grp[0].x-B.x),a2=Math.atan2(grp[2].y-B.y,grp[2].x-B.x);
        const col=side==='D'?'#4a9eff':side==='G'?'#3ecf72':'#FFD700';
        ctx.save(); ctx.beginPath(); ctx.arc(B.x,B.y,r2,a1,a2,false);
        ctx.strokeStyle=col; ctx.lineWidth=2.5; ctx.stroke(); ctx.restore();
        ctx.fillStyle=col; ctx.font=`bold 13px DM Mono,monospace`;
        ctx.fillText(corrAng.toFixed(1)+'°',B.x+r2+4,B.y-3);
      }
    }
  });
}

// Dessiner un segment rectangulaire entre 2 points (style OPS)
// feat-biomec-capteurs (B) — fill du segment modulé par markerOpacity ;
// contour blanc fin reste à pleine intensité pour conserver le tracé visible
// (le contour est l'indication de direction, indépendant du remplissage).
function drawSegmentRect(ctx, p1, p2, w, color) {
  const dx=p2.x-p1.x, dy=p2.y-p1.y;
  const len=Math.sqrt(dx*dx+dy*dy);
  if(len<1) return;
  const nx=-dy/len*w/2, ny=dx/len*w/2;
  ctx.save();
  ctx.beginPath();
  ctx.moveTo(p1.x+nx,p1.y+ny);
  ctx.lineTo(p2.x+nx,p2.y+ny);
  ctx.lineTo(p2.x-nx,p2.y-ny);
  ctx.lineTo(p1.x-nx,p1.y-ny);
  ctx.closePath();
  ctx.fillStyle=color;
  ctx.globalAlpha = markerOpacity;
  ctx.fill();
  ctx.globalAlpha = 1;
  ctx.strokeStyle='rgba(255,255,255,0.4)'; ctx.lineWidth=1; ctx.stroke();
  ctx.restore();
}

// Overlay d'angles en haut à droite
function updateAngleOverlay(elId, markers, view) {
  const el=document.getElementById(elId); if(!el) return;
  let html='';
  ['D','G'].forEach(side=>{
    const grp=markers.filter(m=>m.side===side&&m.x!==null);
    if(grp.length>=3){
      const ang=calcAngle3(grp);
      if(ang!==null){
        const corr=computeCorrectedAngle(ang, side, view, TESTS[currentTestId]?.type||"");
        const clr=side==='D'?'blue':'';
        html+=`<span class="angle-tag ${clr}" style="${side==='G'?'border-color:#3ecf72;color:#3ecf72;':''}">${side}: ${corr.toFixed(1)}°</span>`;
      }
    }
  });
  // Si marqueurs sans side
  const grpNone=markers.filter(m=>m.side===''&&m.x!==null);
  if(grpNone.length>=3){
    const ang=calcAngle3(grpNone);
    if(ang!==null){
      const corr=computeCorrectedAngle(ang, '', view, TESTS[currentTestId]?.type||"");
      html+=`<span class="angle-tag">${corr.toFixed(1)}°</span>`;
    }
  }
  el.innerHTML=html;
}

// ══════════════════════════════════════════════════════
// CALCULS GÉOMÉTRIQUES
// ══════════════════════════════════════════════════════
function calcAngle3(pts) {
  const placed=pts.filter(p=>p.x!==null);
  if(placed.length<3) return null;
  const [A,B,C] = placed.length>=4 ? [placed[1],placed[2],placed[3]] : placed;
  const v1={x:A.x-B.x,y:A.y-B.y},v2={x:C.x-B.x,y:C.y-B.y};
  const dot=v1.x*v2.x+v1.y*v2.y;
  const mag=Math.sqrt((v1.x**2+v1.y**2)*(v2.x**2+v2.y**2));
  return mag===0?null:Math.acos(Math.max(-1,Math.min(1,dot/mag)))*180/Math.PI;
}

// Détecte si l'angle des points AP s'ouvre à droite (+) ou à gauche (-)
// Couleur spécifique KFPPA : <20%=rouge, 20-60%=orange, 60-140%=vert, 140-180%=orange, >180%=rouge
function clrKfppa(pct) {
  if(pct==null||isNaN(pct)) return 'var(--mut)';
  const p=Math.abs(pct)*100;
  if(p<20||p>180) return 'var(--red)';
  if(p<60||p>140) return 'var(--orange)';
  return 'var(--green)';
}

// Détecter valgus/varus pour KFPPA
// Vue face : genou D pointe droite = valgus(+), gauche = varus(-)
// Vue face : genou G pointe droite = varus(-), gauche = valgus(+)
function kfppaLabel(ang, side) {
  if(ang==null) return '—';
  const deg = Math.abs(ang).toFixed(1)+'°';
  // Convention incl : valeur positive = valgus pour les 2 côtés
  return ang>=0 ? 'Valgus +'+deg : 'Varus −'+deg;
}

function calcAngleSign(pts) {
  const placed=pts.filter(p=>p.x!==null);
  if(placed.length<2) return 1;
  if(placed.length>=3) {
    // Point central (Rotule pour KFPPA, CalcaSup pour AP)
    // Détecter si le point central est à droite ou gauche de la ligne top→bot
    const top=placed[0];   // EIAS ou Milieu mollet
    const mid=placed[1];   // Rotule ou Jonction musculo-tend.
    const bot=placed[placed.length-1]; // Tarse ou CalcaInf
    // Position de mid par rapport à la ligne top→bot
    // Produit vectoriel : (bot-top) × (mid-top)
    // En coordonnées écran (y vers le bas), cross>0 = mid à droite
    const cross=(bot.x-top.x)*(mid.y-top.y)-(bot.y-top.y)*(mid.x-top.x);
    return cross<0?1:-1; // cross<0 en écran = point à droite
  }
  const top=placed[0];
  const bot=placed[placed.length-1];
  return bot.x>top.x?1:-1;
}

// Calculer l'angle corrigé selon le contexte
// MLA: angle aigu brut (pas de correction)
// KFPPA: 180 - angle (valgum=+, varum=-)
// Arrière-pied: angle brut avec signe (inversion=+, éversion=-)
function computeCorrectedAngle(rawAng, side, view, testType, pts) {
  if(rawAng===null) return null;
  if(testType==='mla') return rawAng;
  const incl = 180 - rawAng;
  // KFPPA : utiliser incl (180-rawAng) sans correction de signe latéral
  if(testType==='kfppa') return incl;
  // Vue dos : utiliser le cross product pour détecter le sens réel
  // cross > 0 = calca penche à droite
  // Pied D : droite = inversion(+), gauche = éversion(-)
  // Pied G : droite = éversion(-), gauche = inversion(+)
  if(view==='dos' && pts) {
    const sign = calcAngleSign(pts);
    // calcAngleSign: +1 = calca penche à gauche, -1 = calca penche à droite
    // Pied D : penche droite(-1) = inversion(+), penche gauche(+1) = éversion(-)
    // Pied G : penche gauche(+1) = inversion(+), penche droite(-1) = éversion(-)
    if(side==='D') return -sign * incl; // D: droite(-1)=Inv(+) → inverser signe
    if(side==='G') return sign * incl;  // G: gauche(+1)=Inv(+) → même signe
    return incl;
  }
  if(view==='dos' && side==='G') return -incl;
  // Vue face (KFPPA) : genou D pointe droite=valgus(+), genou G pointe droite=varus(-)
  if(view==='face' && pts) {
    const sign=calcAngleSign(pts);
    if(side==='D') return sign*incl;
    if(side==='G') return -sign*incl;
  }
  return incl;
}

function getAngleColor(ang) {
  if(ang===null) return '#FFD700';
  return '#FFD700'; // Surcharge par le résultat si besoin
}

// ══════════════════════════════════════════════════════
// CALCULS BILATÉRAUX & RÉSULTATS
// ══════════════════════════════════════════════════════
function calcBilateral(markers, view, side) {
  const grp = markers.filter(m=>m.side===side&&m.x!==null);
  const ang = calcAngle3(grp);
  return computeCorrectedAngle(ang, side, view, TESTS[currentTestId]?.type||'', TESTS[currentTestId]?.type||"");
}

