// Fix #89 — pile chronologique d'ordre des traits morpho. Permet à undoMorpho
// d'annuler le DERNIER trait peint, peu importe sur quel canvas (vs ancien
// bug d'ordre alphabétique fixe face → face2 → profilG → profilD). Réutilise
// le mécanisme _history existant (états APRÈS-trait, push à mouseup) — pas
// de pile parallèle d'instantanés. Partagée entre les 4 canvas morpho via
// canvas._undoOrderStack, ce qui en fait un noop strict pour pieds/posturo
// (non tagués → propriété undefined → push correspondant sauté).
let _morphoUndoOrder = [];

function initMorphoCanvas(canvasId) {
  const canvas = document.getElementById(canvasId);
  if(!canvas) return;
  const parent = canvas.parentElement;
  if(!parent) return;
  const r = parent.getBoundingClientRect();
  if(r.width === 0) return;
  canvas.width = Math.round(r.width * window.devicePixelRatio);
  canvas.height = Math.round(r.height * window.devicePixelRatio);
  canvas.style.width = r.width + 'px';
  canvas.style.height = r.height + 'px';
  const ctx = canvas.getContext('2d');
  ctx.scale(window.devicePixelRatio, window.devicePixelRatio);
  canvas._history = []; canvas._baseSnapshot = null; canvas._tempSnap = null;
  // Fix #89 — tag morpho pour la pile chronologique d'ordre. Pieds/posturo
  // ne sont pas tagués → _undoOrderStack reste undefined → push correspondant
  // dans setupDrawCanvas mouseup sauté pour eux (noop strict).
  canvas._undoOrderStack = _morphoUndoOrder;
  // NB: les images sont maintenant dans le DOM via <img>, pas dans le canvas
  // On ne restaure plus l'ancien format (image+dessin fusionnés)
  // #83 — capture _baseSnapshot SYNCHRONE (symétrie drawPiedsTemplate L8429). Le
  // canvas morpho est un overlay transparent (silhouettes dans <img> DOM, pas
  // gravées dans le canvas) → le base = transparent, capturable immédiatement.
  // Fiabilise _serializeDrawCanvas (soustraction base vs canvas) au save :
  // l'ancien setTimeout 100ms posait une fenêtre où le base était null, et
  // _drawMorphoCanvasesFromSource (restoration overlay) pouvait peindre AVANT
  // le base, contaminant la soustraction. Le fallback de setupDrawCanvas L8096
  // (if(!canvas._baseSnapshot)) reste inoffensif : base déjà posé ici.
  canvas._baseSnapshot = ctx.getImageData(0,0,canvas.width,canvas.height);
  setupDrawCanvas(canvas, canvasId);
}

function drawSilhouetteFace(ctx, W, H) {
  const s=H/230, cx=W/2;
  ctx.save(); ctx.fillStyle='#d4b896'; ctx.strokeStyle='#8b6914'; ctx.lineWidth=1.5;
  ctx.translate(cx, H*0.04); ctx.scale(s*0.52, s*0.52);
  // Tête
  ctx.beginPath(); ctx.ellipse(0,0,26,30,0,0,2*Math.PI); ctx.fill(); ctx.stroke();
  // Cou
  ctx.beginPath(); ctx.rect(-8,28,16,16); ctx.fill(); ctx.stroke();
  // Tronc
  ctx.beginPath(); ctx.moveTo(-30,44); ctx.bezierCurveTo(-36,56,-36,100,-30,138); ctx.lineTo(30,138); ctx.bezierCurveTo(36,100,36,56,30,44); ctx.closePath(); ctx.fill(); ctx.stroke();
  // Bras G
  ctx.beginPath(); ctx.moveTo(-30,48); ctx.bezierCurveTo(-52,70,-60,95,-54,118); ctx.lineTo(-42,114); ctx.bezierCurveTo(-48,92,-40,68,-26,52); ctx.fill(); ctx.stroke();
  // Bras D
  ctx.beginPath(); ctx.moveTo(30,48); ctx.bezierCurveTo(52,70,60,95,54,118); ctx.lineTo(42,114); ctx.bezierCurveTo(48,92,40,68,26,52); ctx.fill(); ctx.stroke();
  // Jambe G
  ctx.beginPath(); ctx.moveTo(-18,136); ctx.bezierCurveTo(-22,170,-22,195,-18,218); ctx.lineTo(-4,218); ctx.bezierCurveTo(0,195,0,170,-2,138); ctx.fill(); ctx.stroke();
  // Jambe D
  ctx.beginPath(); ctx.moveTo(18,136); ctx.bezierCurveTo(22,170,22,195,18,218); ctx.lineTo(4,218); ctx.bezierCurveTo(0,195,0,170,2,138); ctx.fill(); ctx.stroke();
  ctx.restore();
}

function drawSilhouetteProfil(ctx, W, H, facingRight) {
  const s=H/240, cx=facingRight?W*0.52:W*0.48;
  ctx.save(); ctx.fillStyle='#d4b896'; ctx.strokeStyle='#8b6914'; ctx.lineWidth=1.8;
  ctx.translate(cx, H*0.03); ctx.scale(s*0.48, s*0.48);
  if(!facingRight) { ctx.scale(-1,1); }
  // Tête profil
  ctx.beginPath();
  ctx.moveTo(0,-15); ctx.bezierCurveTo(20,-15,30,0,28,18);
  ctx.bezierCurveTo(26,34,16,42,0,40); ctx.bezierCurveTo(-10,38,-14,26,-10,16);
  ctx.bezierCurveTo(-8,6,-4,-2,0,-15); ctx.fill(); ctx.stroke();
  // Nez
  ctx.beginPath(); ctx.moveTo(28,10); ctx.bezierCurveTo(36,12,36,24,28,24); ctx.fill(); ctx.stroke();
  // Cou
  ctx.beginPath(); ctx.moveTo(-4,40); ctx.lineTo(-2,58); ctx.lineTo(14,58); ctx.lineTo(12,40); ctx.fill(); ctx.stroke();
  // Tronc
  ctx.beginPath(); ctx.moveTo(-16,58); ctx.bezierCurveTo(-20,80,-20,120,-14,158); ctx.lineTo(22,158); ctx.bezierCurveTo(26,120,26,80,20,58); ctx.fill(); ctx.stroke();
  // Bras (derrière)
  ctx.beginPath(); ctx.moveTo(-12,62); ctx.bezierCurveTo(-24,86,-26,112,-20,136); ctx.lineTo(-8,132); ctx.bezierCurveTo(-14,110,-12,86,-2,66); ctx.fill(); ctx.stroke();
  // Jambe avant
  ctx.beginPath(); ctx.moveTo(2,156); ctx.bezierCurveTo(6,182,8,208,4,232); ctx.lineTo(18,232); ctx.bezierCurveTo(22,208,20,182,16,156); ctx.fill(); ctx.stroke();
  // Jambe arrière
  ctx.beginPath(); ctx.moveTo(-12,156); ctx.bezierCurveTo(-16,180,-16,204,-12,228); ctx.lineTo(0,228); ctx.bezierCurveTo(2,204,2,180,0,158); ctx.fill(); ctx.stroke();
  // Pied
  ctx.beginPath(); ctx.moveTo(4,230); ctx.bezierCurveTo(6,238,22,242,32,240); ctx.bezierCurveTo(36,238,30,230,22,230); ctx.fill(); ctx.stroke();
  ctx.restore();
}

function setupDrawCanvas(canvas, canvasId) {
  if(!canvas._history) canvas._history = [];
  // Snapshot de base après le rendu initial (pour la gomme)
  setTimeout(() => {
    if(!canvas._baseSnapshot) {
      canvas._baseSnapshot = canvas.getContext('2d').getImageData(0,0,canvas.width,canvas.height);
    }
  }, 200);

  let drawing = false, startX = 0, startY = 0;

  const getPos = e => {
    const rect = canvas.getBoundingClientRect();
    const src2 = e.touches ? e.touches[0] : e;
    return {x: src2.clientX - rect.left, y: src2.clientY - rect.top};
  };

  canvas.onmousedown = e => {
    // #99 + Bug édition perdue (gating _restoreReady) — bloque les inputs user
    // tant que la restauration async n'a pas peint le dessin pré-édition. Sinon
    // le user dessine pendant la fenêtre de race, drawPiedsTemplate(canvas.width=…)
    // au .then() efface le DOM et le sweep ne capture pas le trait → édition perdue.
    if (canvas._restoreReady === false) return;
    e.preventDefault();
    drawing = true;
    const p = getPos(e);
    startX = p.x; startY = p.y;
    // Sauvegarder snapshot temp pour preview pendant le dessin
    canvas._tempSnap = canvas.getContext('2d').getImageData(0,0,canvas.width,canvas.height);
  };

  canvas.onmousemove = e => {
    if(!drawing) return;
    const ctx = canvas.getContext('2d');
    const p = getPos(e);

    if(drawTool === 'erase') {
      // Gomme douce: restaurer zone depuis snapshot de base
      const r = drawSize * 5;
      if(canvas._baseSnapshot) {
        // Méthode: copier depuis la base dans la zone gomme
        const base = canvas._baseSnapshot;
        const W = canvas.width, H = canvas.height;
        const x0 = Math.max(0, Math.round(p.x-r)), y0 = Math.max(0, Math.round(p.y-r));
        const w2 = Math.min(W-x0, r*2), h2 = Math.min(H-y0, r*2);
        if(w2 > 0 && h2 > 0) {
          // Extraire la zone de base et la remettre
          const tmp = document.createElement('canvas');
          tmp.width=W; tmp.height=H;
          tmp.getContext('2d').putImageData(base,0,0);
          // Effacer la zone dans le canvas courant
          ctx.save();
          ctx.clearRect(x0,y0,w2,h2);
          // Redessiner depuis la base dans cette zone
          ctx.drawImage(tmp, x0,y0,w2,h2, x0,y0,w2,h2);
          ctx.restore();
        }
      }
      return;
    }

    // Pour les outils vectoriels: restaurer le snapshot temp et redessiner
    if(canvas._tempSnap && drawTool !== 'erase') {
      ctx.putImageData(canvas._tempSnap, 0, 0);
    }

    ctx.strokeStyle = drawColor;
    ctx.fillStyle = drawColor;
    ctx.lineWidth = drawSize;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';

    if(drawTool === 'line') {
      ctx.beginPath(); ctx.moveTo(startX,startY); ctx.lineTo(p.x,p.y); ctx.stroke();
    } else if(drawTool === 'arrow') {
      drawArrow(ctx, startX, startY, p.x, p.y, drawColor, drawSize);
    } else if(drawTool === 'arrow-curve') {
      drawArrowCurved(ctx, startX, startY, p.x, p.y, drawColor, drawSize);
    } else if(drawTool === 'circle') {
      const rx = Math.abs(p.x-startX)/2, ry = Math.abs(p.y-startY)/2;
      const cx2 = (startX+p.x)/2, cy2 = (startY+p.y)/2;
      ctx.beginPath(); ctx.ellipse(cx2, cy2, Math.max(rx,2), Math.max(ry,2), 0, 0, 2*Math.PI);
      ctx.stroke();
    }
  };

  canvas.onmouseup = () => {
    if(drawing) {
      // Sauvegarder dans l'historique UNIQUEMENT à la fin du trait
      const snapshot = canvas.getContext('2d').getImageData(0,0,canvas.width,canvas.height);
      canvas._history.push(snapshot);
      if(canvas._history.length > 30) canvas._history.shift();
      // Fix #89 — push additif chronologique morpho uniquement. _undoOrderStack
      // est tagué dans initMorphoCanvas → truthy pour les 4 canvas morpho ;
      // undefined sur pieds/posturo → ligne sautée (noop strict, comportement
      // existant strictement préservé pour eux).
      if(canvas._undoOrderStack) canvas._undoOrderStack.push(canvas.id);
      // #99 + Bug édition perdue — flag de modification utilisateur insensible
      // aux ré-init DOM (initMorphoCanvas/drawPiedsTemplate/initPosturoBodyCanvas/
      // initPosturoFeetCanvas reset _history à chaque appel — déclenchés par nav
      // page et nav section. Sans ce flag, une édition pendant la fenêtre prefetch
      // async OU avant re-init section est silencieusement effacée → check
      // _history.length>0 au save = faux négatif → Path non invalidé → cleanup
      // post-migrate supprime la nouvelle dataURL = édition perdue au reload).
      // _userDirty n'est jamais reset par les opérations de restauration DOM.
      canvas._userDirty = true;
    }
    drawing = false;
    canvas._tempSnap = null;
  };
  canvas.onmouseleave = () => { drawing = false; canvas._tempSnap = null; };
  canvas.ontouchstart = e => { e.preventDefault(); canvas.onmousedown({clientX:e.touches[0].clientX,clientY:e.touches[0].clientY,preventDefault:()=>{}}); };
  canvas.ontouchmove = e => { e.preventDefault(); canvas.onmousemove({clientX:e.touches[0].clientX,clientY:e.touches[0].clientY}); };
  canvas.ontouchend = () => { canvas.onmouseup(); };
}

function toggleCurveDir(btnId) {
  curveDir = curveDir === 1 ? -1 : 1;
  // Mettre à jour tous les boutons de direction de courbure
  document.querySelectorAll('[id^="btn-curve-dir"]').forEach(btn => {
    btn.textContent = curveDir === 1 ? '⟳ Droite' : '⟲ Gauche';
    btn.style.background = curveDir === 1 ? 'var(--blue-d)' : 'var(--purple)';
    btn.style.color = curveDir === 1 ? 'var(--blue)' : '#a78bfa';
    btn.style.borderColor = curveDir === 1 ? 'var(--blue)' : '#a78bfa';
  });
}

function drawArrowCurved(ctx, x1, y1, x2, y2, color, size) {
  const dx=x2-x1, dy=y2-y1;
  const len = Math.sqrt(dx*dx+dy*dy);
  // Perpendiculaire: (-dy, dx) = côté gauche du tracé ; (dy, -dx) = côté droit
  // curveDir = +1 → courbe vers la droite du tracé ; -1 → vers la gauche
  const perp = curveDir || 1;
  const cx=(x1+x2)/2 + (-dy/len)*len*0.3*perp;
  const cy=(y1+y2)/2 + ( dx/len)*len*0.3*perp;
  const angle=Math.atan2(y2-cy, x2-cx);
  const hLen=Math.max(10, len*0.22);
  ctx.strokeStyle=color; ctx.fillStyle=color; ctx.lineWidth=size; ctx.lineCap='round';
  ctx.beginPath(); ctx.moveTo(x1,y1); ctx.quadraticCurveTo(cx,cy,x2,y2); ctx.stroke();
  ctx.beginPath();
  ctx.moveTo(x2,y2);
  ctx.lineTo(x2-hLen*Math.cos(angle-Math.PI/6), y2-hLen*Math.sin(angle-Math.PI/6));
  ctx.lineTo(x2-hLen*Math.cos(angle+Math.PI/6), y2-hLen*Math.sin(angle+Math.PI/6));
  ctx.closePath(); ctx.fill();
}

function drawArrow(ctx, x1, y1, x2, y2, color, size) {
  const angle = Math.atan2(y2-y1, x2-x1);
  const len = Math.sqrt((x2-x1)**2+(y2-y1)**2);
  const headLen = Math.max(10, len*0.25);
  ctx.strokeStyle=color; ctx.fillStyle=color; ctx.lineWidth=size; ctx.lineCap='round';
  ctx.beginPath(); ctx.moveTo(x1,y1); ctx.lineTo(x2,y2); ctx.stroke();
  ctx.beginPath();
  ctx.moveTo(x2,y2);
  ctx.lineTo(x2-headLen*Math.cos(angle-Math.PI/6), y2-headLen*Math.sin(angle-Math.PI/6));
  ctx.lineTo(x2-headLen*Math.cos(angle+Math.PI/6), y2-headLen*Math.sin(angle+Math.PI/6));
  ctx.closePath(); ctx.fill();
}

// Fix E — helper marquage état actif boutons plantaire sport (scope strict ssec-9).
// Liste fermée des 6 IDs ; reset tous les boutons puis marque l'actif. Aucun ID
// morpho (sans suffixe) ni posturo dans la liste → noop ailleurs (additif strict).
function _markPlantaireTool(activeId) {
  ['tool-pen2','tool-arrow2','tool-arrow-curve2','tool-circle2','tool-erase2','btn-curve-inv-semelles'].forEach(id => {
    const btn = document.getElementById(id);
    if(btn) btn.className = (id === activeId) ? 'btn btn-blue' : 'btn';
  });
}

// Fix F — helper marquage état actif boutons morpho sport (scope strict ssec-1).
// Symétrique à _markPlantaireTool : liste fermée des 6 IDs morpho ; reset tous
// puis marque l'actif. Aucun ID plantaire (suffixe "2") ni posturo (préfixe
// "ptool-") dans la liste → noop ailleurs (scope strict comme Fix E).
function _markMorphoTool(activeId) {
  ['tool-pen','tool-arrow','tool-arrow-curve','tool-circle','tool-erase','btn-curve-inv-morpho'].forEach(id => {
    const btn = document.getElementById(id);
    if(btn) btn.className = (id === activeId) ? 'btn btn-blue' : 'btn';
  });
}

// Fix #90 — helper marquage état actif boutons posturo body (scope strict psec-*).
// Symétrique à _markMorphoTool / _markPlantaireTool : liste fermée des 6 IDs body ;
// reset tous puis marque l'actif. Aucun ID morpho (sans suffixe), plantaire
// (suffixe "2") ni posturo feet (suffixe "-feet") dans la liste → noop ailleurs.
function _markPosturoBodyTool(activeId) {
  ['ptool-pen','ptool-arrow','ptool-arrow-curve','ptool-circle','ptool-erase','btn-curve-inv-posturo-body'].forEach(id => {
    const btn = document.getElementById(id);
    if(btn) btn.className = (id === activeId) ? 'btn btn-blue' : 'btn';
  });
}

// Fix #90 — helper marquage état actif boutons posturo feet (scope strict psec-8).
// Symétrique à _markPosturoBodyTool : liste fermée des 6 IDs feet (suffixe "-feet").
// Aucun ID body, morpho, plantaire dans la liste → noop ailleurs (scope strict).
function _markPosturoFeetTool(activeId) {
  ['ptool-pen-feet','ptool-arrow-feet','ptool-arrow-curve-feet','ptool-circle-feet','ptool-erase-feet','btn-curve-inv-posturo-feet'].forEach(id => {
    const btn = document.getElementById(id);
    if(btn) btn.className = (id === activeId) ? 'btn btn-blue' : 'btn';
  });
}

function setDrawTool(tool) {
  drawTool=tool;
  curveDir=1; // reset direction normale
  // Fix F — remplace l'ancienne boucle ['pen','arrow','erase'] qui butait sur la
  // dissonance outil interne 'line' vs ID 'tool-pen' (la boucle marquait
  // l'ID 'tool-line' inexistant — silencieusement noop sur Trait, et les 3 autres
  // outils Courbée/Cercle/Courbée-inv n'avaient jamais de marqueur). Le mapping
  // résout 'line' → 'tool-pen' et couvre désormais les 6 outils morpho.
  const _morphoMap = {'line':'tool-pen','arrow':'tool-arrow','arrow-curve':'tool-arrow-curve','circle':'tool-circle','erase':'tool-erase'};
  _markMorphoTool(_morphoMap[tool] || '');
  // Fix E — marquage additif plantaire sport (le helper morpho ci-dessus est
  // strictement scopé à ssec-1). Mapping outil interne → ID button plantaire
  // suffixé "2".
  const _plantaireMap = {'line':'tool-pen2','arrow':'tool-arrow2','arrow-curve':'tool-arrow-curve2','circle':'tool-circle2','erase':'tool-erase2'};
  _markPlantaireTool(_plantaireMap[tool] || '');
  // Fix #90 — marquage additif posturo body (le helper plantaire ci-dessus est
  // strictement scopé à ssec-9 sport ; les helpers morpho/plantaire ne touchent
  // pas les IDs ptool-). Mapping outil interne → ID button posturo body préfixé "ptool-".
  const _posturoBodyMap = {'line':'ptool-pen','arrow':'ptool-arrow','arrow-curve':'ptool-arrow-curve','circle':'ptool-circle','erase':'ptool-erase'};
  _markPosturoBodyTool(_posturoBodyMap[tool] || '');
  // Fix #90 — marquage additif posturo feet. Mêmes IDs que body avec suffixe "-feet".
  const _posturoFeetMap = {'line':'ptool-pen-feet','arrow':'ptool-arrow-feet','arrow-curve':'ptool-arrow-curve-feet','circle':'ptool-circle-feet','erase':'ptool-erase-feet'};
  _markPosturoFeetTool(_posturoFeetMap[tool] || '');
}

function setDrawToolCurveInv() {
  drawTool='arrow-curve';
  curveDir=-1; // direction inversée
  // Fix F — marqueur actif sur ↩ Courbée inv morpho (scope strict ssec-1 sport)
  _markMorphoTool('btn-curve-inv-morpho');
  // Fix E — marqueur actif sur ↩ Courbée inv plantaire (scope strict ssec-9 sport)
  _markPlantaireTool('btn-curve-inv-semelles');
  // Fix #90 — marqueur actif sur ↩ Courbée inv posturo body (scope strict psec-*)
  _markPosturoBodyTool('btn-curve-inv-posturo-body');
  // Fix #90 — marqueur actif sur ↩ Courbée inv posturo feet (scope strict psec-8)
  _markPosturoFeetTool('btn-curve-inv-posturo-feet');
}

function clearAllMorpho() {
  // Fix #89 — vide la pile chronologique d'ordre AVANT le forEach. Préserve
  // la référence (length=0 vs réaffectation) car canvas._undoOrderStack pointe
  // vers ce même tableau via le tag posé en initMorphoCanvas.
  _morphoUndoOrder.length = 0;
  ['morpho-face','morpho-face2','morpho-profilG','morpho-profilD'].forEach(id => {
    const c = document.getElementById(id);
    if(c) {
      c._history = [];
      c._baseSnapshot = null;
      c._tempSnap = null;
      // #99 + Bug édition perdue — clear user-triggered = édition. Force
      // l'invalidation Path au prochain save (sinon le clear ne serait pas
      // propagé puisque _history reste à [] après le reset).
      c._userDirty = true;
    }
    initMorphoCanvas(id);
  });
}

function undoMorpho() {
  // Fix #89 — annule le DERNIER trait peint (peu importe sur quel canvas).
  // Pattern sémantique repris de undoPosturoBody L10405 : pop discard
  // (= état APRÈS dernier trait = état courant à l'écran), peek l'état
  // précédent ou fallback _baseSnapshot si pile vide. Pile chronologique
  // _morphoUndoOrder alimentée à mouseup côté setupDrawCanvas.
  if(_morphoUndoOrder.length === 0) return;
  const canvasId = _morphoUndoOrder.pop();
  const c = document.getElementById(canvasId);
  if(!c) return;
  const ctx = c.getContext('2d');
  if(c._history && c._history.length > 0) {
    c._history.pop();
    const prev = c._history.length > 0 ? c._history[c._history.length-1] : c._baseSnapshot;
    if(prev) ctx.putImageData(prev, 0, 0);
  } else if(c._baseSnapshot) {
    ctx.putImageData(c._baseSnapshot, 0, 0);
  }
}

function undoPieds() {
  // Fix #89 (jumeau) — pattern repris de undoPosturoBody L10405 : pop discard
  // (= état APRÈS dernier trait = état courant), peek l'état précédent ou
  // fallback _baseSnapshot si pile vide. Pieds-canvas = 1 seul canvas → aucune
  // pile d'ordre nécessaire, l'historique suffit. Réparation du même Bug A
  // sémantique (pop+put = no-op) que undoMorpho.
  const c = document.getElementById('pieds-canvas');
  if(!c) return;
  const ctx = c.getContext('2d');
  if(c._history && c._history.length > 0) {
    c._history.pop();
    const prev = c._history.length > 0 ? c._history[c._history.length-1] : c._baseSnapshot;
    if(prev) ctx.putImageData(prev, 0, 0);
  } else if(c._baseSnapshot) {
    ctx.putImageData(c._baseSnapshot, 0, 0);
  }
}

// #99 + Bug édition perdue (gating _restoreReady) — paramètre optionnel `onReady`
// appelé déterministiquement APRÈS le drawImage du saved.onload (ou immédiatement
// si pas de savedData, ou dans onerror si dataURL corrompue). Le callback est
// utilisé par _restoreSportMorphoPiedsFromBilanData pour poser _restoreReady=true
// au moment où le dessin est effectivement peint sur le canvas.
//
// drawPiedsTemplate NE TOUCHE PAS `_restoreReady` lui-même — c'est le caller qui
// décide via onReady. Cela évite qu'un appel intermédiaire (chaîne nav setTimeout
// L2011, clearPiedsCanvas, showSportBilanSection idx===9) ouvre prématurément le
// gate alors qu'une restoration finale est encore en attente (prefetch.then).
function drawPiedsTemplate(savedData, onReady) {
  // Refactor #91 — pattern posturo (img DOM séparée + canvas transparent overlay).
  // Mirroir de initPosturoFeetCanvas L10511. Le canvas est désormais un OVERLAY
  // transparent par-dessus #sp-pieds-img (template visible directement dans le DOM,
  // pas gravé dans le canvas). Backing store calibré sur le parent rect × dpr,
  // comme initPosturoFeetCanvas. Labels Pied G/D supprimés du JS — désormais 2
  // <span> HTML absolus dans le conteneur (sport + posturo identiques).
  // Pas de retry : alignement strict pattern posturo (initPosturoFeetCanvas L10517
  // n'a pas de retry non plus, juste early return silent si rect=0). Le garde
  // idempotent showSportBilanSection idx===9 (`!pc._baseSnapshot`) fournit un
  // retry implicite au prochain switch onglet 9 si le premier essai échoue.
  const canvas = document.getElementById('pieds-canvas');
  if(!canvas) return;
  const parent = canvas.parentElement;
  if(!parent) return;
  const r = parent.getBoundingClientRect();
  if(r.width === 0) return;
  const dpr = window.devicePixelRatio || 1;
  canvas.width = Math.round(r.width * dpr);
  canvas.height = Math.round(r.height * dpr);
  canvas.style.width = r.width + 'px';
  canvas.style.height = r.height + 'px';
  const ctx = canvas.getContext('2d');
  ctx.scale(dpr, dpr);
  canvas._history = []; canvas._baseSnapshot = null; canvas._tempSnap = null;
  setupDrawCanvas(canvas, 'pieds-canvas');
  // _baseSnapshot = canvas vide/transparent. undoPieds (post #89) restaure cet
  // état au dernier clic → canvas redevient transparent → image DOM #sp-pieds-img
  // reste visible derrière (sans pollution). Sémantique identique à undoPosturoFeet.
  canvas._baseSnapshot = ctx.getImageData(0,0,canvas.width,canvas.height);
  // Restauration des dessins sauvegardés (format PNG transparent, post-soustraction
  // ou direct depuis canvas vide — tous deux compatibles avec drawImage par-dessus
  // canvas transparent : pixels opaques visibles, pixels transparents laissent voir
  // l'img DOM derrière).
  if(savedData) {
    const saved = new Image();
    saved.onload = () => {
      ctx.drawImage(saved, 0, 0, r.width, r.height);
      // Fix #94 auto-réparation — efface fond noir éventuel des bilans corrompus
      // pré-fix (saveBilanSilent JPEG produisait noir intégral sur canvas overlay
      // transparent). Idempotent sur PNG transparent propre.
      _stripBackgroundFromRestore(canvas);
      // #99 + gating _restoreReady — caller décide via onReady, déterministe après
      // le drawImage effectif (le dessin est peint sur le canvas à cet instant).
      if (typeof onReady === 'function') onReady();
    };
    saved.onerror = () => {
      // dataURL corrompue → débloque quand même pour ne pas geler l'édition.
      if (typeof onReady === 'function') onReady();
    };
    saved.src = savedData;
  } else if (typeof onReady === 'function') {
    // Pas de savedData → pas d'Image.onload → débloque immédiatement.
    onReady();
  }
}

function drawFoot(ctx, ox, oy, mirror) {
  ctx.save();
  ctx.translate(ox, oy);
  if(mirror) { ctx.translate(145, 0); ctx.scale(-1,1); }
  ctx.fillStyle='#f0d9c0'; ctx.strokeStyle='#8b6530'; ctx.lineWidth=2;
  // Corps
  ctx.beginPath();
  ctx.moveTo(68,220); ctx.bezierCurveTo(28,212,14,182,12,148);
  ctx.bezierCurveTo(8,108,16,68,26,44); ctx.bezierCurveTo(38,18,56,5,74,4);
  ctx.bezierCurveTo(92,2,112,14,124,38); ctx.bezierCurveTo(136,62,138,98,136,128);
  ctx.bezierCurveTo(134,168,126,204,104,218); ctx.bezierCurveTo(94,224,80,226,68,220);
  ctx.closePath(); ctx.fill(); ctx.stroke();
  // Talon
  ctx.beginPath(); ctx.ellipse(72,206,34,20,0,0,2*Math.PI);
  ctx.fillStyle='#e4cab0'; ctx.fill(); ctx.stroke();
  // Voute
  ctx.beginPath(); ctx.moveTo(22,152); ctx.bezierCurveTo(26,128,36,112,52,114);
  ctx.bezierCurveTo(62,116,66,134,64,158); ctx.fillStyle='#e0c4a0'; ctx.fill();
  // Orteils
  ctx.fillStyle='#f0d9c0';
  [[44,16,13,10],[64,8,10,8],[82,5,10,8],[99,8,9,7],[113,18,8,7]].forEach(([tx,ty,rw,rh])=>{
    ctx.beginPath(); ctx.ellipse(tx,ty,rw,rh,0,0,2*Math.PI); ctx.fill(); ctx.stroke();
    ctx.fillStyle='#ffeedd'; ctx.beginPath(); ctx.ellipse(tx,ty-rh*0.3,rw*0.6,rh*0.4,0,0,2*Math.PI); ctx.fill();
    ctx.fillStyle='#f0d9c0';
  });
  // Plis
  ctx.strokeStyle='#c4a882'; ctx.lineWidth=0.8;
  ctx.beginPath(); ctx.moveTo(40,40); ctx.bezierCurveTo(56,36,76,34,94,38); ctx.stroke();
  ctx.beginPath(); ctx.moveTo(38,56); ctx.bezierCurveTo(56,52,78,50,98,54); ctx.stroke();
  ctx.restore();
}

function setBilanField(field, value) {
  if(!bilanData) bilanData={};
  bilanData[field]=value;
  // Stocker aussi dans bilanDataPosturo si on est dans le contexte posturo
  const pgPosturo = document.getElementById('pg-bilan-posturo');
  if(pgPosturo && pgPosturo.classList.contains('active')) {
    if(!currentPatient) return;
    if(!currentPatient.bilanDataPosturo) currentPatient.bilanDataPosturo = {};
    if(!currentPatient.bilanDataPosturo.neuro4) currentPatient.bilanDataPosturo.neuro4 = {};
    currentPatient.bilanDataPosturo.neuro4[field] = value;
  }
}

// #95 — Persistance per-cb des cases neuro psec-3, parité sport setBilanField.
// Écriture directe dans currentPatient.bilanDataPosturo.neuro4[id] (autoritative,
// indépendamment du scrape global gardé par display:none de savePosturoBilan
// L11054). Sans pollution de bilanData (contrairement à setBilanField qui écrit
// aussi dedans). Le save sur disque arrive au prochain savePatients (manuel 💾,
// génération synthèse, etc.) — comme pour sport setBilanField.
function setPosturoNeuro(id, checked) {
  if(!currentPatient) return;
  if(!currentPatient.bilanDataPosturo) currentPatient.bilanDataPosturo = {};
  if(!currentPatient.bilanDataPosturo.neuro4) currentPatient.bilanDataPosturo.neuro4 = {};
  currentPatient.bilanDataPosturo.neuro4[id] = checked;
}

// Synchronise les modifications du bilan en cours d'édition vers son entrée
// dans bilansSport[]. À appeler après chaque savePatients() qui touche
// currentPatient.mesures ou currentPatient.bilanData.
function syncOpenedBilanToHistory() {
  if (currentOpenedBilanIdx == null) return;
  if (!currentPatient || !currentPatient.bilansSport) return;
  const target = currentPatient.bilansSport[currentOpenedBilanIdx];
  if (!target) return;
  target.mesures = JSON.parse(JSON.stringify(currentPatient.mesures || {}));
  target.bilanData = JSON.parse(JSON.stringify(currentPatient.bilanData || {}));
}

// Mirror posturo : synchronise les modifications du bilan posturo en cours
// d'édition vers son entrée dans bilansPosturo[]. À appeler après chaque
// savePatients() qui touche currentPatient.bilanDataPosturo.
function syncOpenedBilanPosturoToHistory() {
  if (currentOpenedBilanPosturoIdx == null) return;
  if (!currentPatient || !currentPatient.bilansPosturo) return;
  const target = currentPatient.bilansPosturo[currentOpenedBilanPosturoIdx];
  if (!target) return;
  target.bilanDataPosturo = JSON.parse(JSON.stringify(currentPatient.bilanDataPosturo || {}));
}

// ───────────────────────────────────────────
// Sport ttt — Traitements (Sprint A4 #73)
// 8 fonctions + 1 flag réentrant pour smart-detach Échauffement.
// Stack par exo = 3 sys + 3 sub (créés sync par updateExerciceSubMenu L9829-9851
// dans chaque .exo-pair) + 1 libre. Wrapper DOM : .exo-stack[data-sp-circuit][data-sp-idx].
// Detached définitif (Q5) stocké dans bilanData.ttt.ch[i].detached (variable live module).
// ───────────────────────────────────────────
let _sportTttCopying = false;

function _readSportTttExo(libreEl) {
  if(!libreEl) return { sys:[], sub:[], libre:'' };
  const wrap = libreEl.closest('.exo-stack');
  if(!wrap) return { sys:[], sub:[], libre: libreEl.value || '' };
  // Correction 1 : alignement sub↔sys via .exo-pair de chaque sys (pas un querySelectorAll
  // à plat). Système vide → pas de .exo-pair créé OU pair sans .exo-sub → '' à cet index.
  const sels = Array.from(wrap.querySelectorAll('select.exo-sys'));
  return {
    sys: sels.map(s => s.value),
    sub: sels.map(s => {
      const pair = s.closest('.exo-pair');
      if(!pair) return '';
      const sub = pair.querySelector('select.exo-sub');
      return sub ? sub.value : '';
    }),
    libre: libreEl.value || ''
  };
}

function _writeSportTttExo(libreEl, exo) {
  if(!libreEl || !exo) return;
  const wrap = libreEl.closest('.exo-stack');
  if(!wrap) return;
  const sels = Array.from(wrap.querySelectorAll('select.exo-sys'));
  // Correction 3 : updateExerciceSubMenu est synchrone → set sub directement après
  // dispatchEvent, dans la même tick. Pas de setTimeout. Try/finally synchrone.
  const prev = _sportTttCopying;
  _sportTttCopying = true;
  try {
    sels.forEach((sel, i) => {
      sel.value = (exo.sys && exo.sys[i]) || '';
      sel.dispatchEvent(new Event('change')); // updateExerciceSubMenu crée/supprime .exo-sub sync
      // Correction 1 : sub via .exo-pair du sys courant (alignement strict)
      if(exo.sub && exo.sub[i]) {
        const pair = sel.closest('.exo-pair');
        const sub = pair ? pair.querySelector('select.exo-sub') : null;
        if(sub) sub.value = exo.sub[i];
      }
    });
    libreEl.value = exo.libre || '';
  } finally {
    _sportTttCopying = prev;
  }
}

function _onSportTttExpressChange(circuit, idx) {
  if(_sportTttCopying) return;
  // Mapping verrouillé : CE1.ex1-4 → ch1-4 ; CE2.ex1-4 → ch5-8
  const chIdx = (circuit === 'c1' ? 0 : 4) + idx;
  // Correction 2 : detached lu depuis bilanData (variable live module), pas currentPatient
  const chSlot = bilanData && bilanData.ttt && bilanData.ttt.ch && bilanData.ttt.ch[chIdx - 1];
  if(chSlot && chSlot.detached) return;
  const srcLibre = document.getElementById('sp-' + circuit + '-ex' + idx + '-libre');
  const dstLibre = document.getElementById('sp-ch-ex' + chIdx + '-libre');
  if(!srcLibre || !dstLibre) return;
  const exo = _readSportTttExo(srcLibre);
  // Correction 3 : try/finally synchrone (pas de setTimeout, updateExerciceSubMenu est sync)
  const prev = _sportTttCopying;
  _sportTttCopying = true;
  try { _writeSportTttExo(dstLibre, exo); }
  finally { _sportTttCopying = prev; }
}

function _onSportTttEchauffementChange(idx) {
  if(_sportTttCopying) return;
  // Correction 2 + Q5 : détach DÉFINITIF stocké dans bilanData (variable live module).
  // Posé une fois, jamais retiré (ni quand user vide, ni à un autre user change).
  if(!bilanData) return;
  if(!bilanData.ttt) bilanData.ttt = {};
  if(!bilanData.ttt.ch) bilanData.ttt.ch = [];
  if(!bilanData.ttt.ch[idx - 1]) bilanData.ttt.ch[idx - 1] = { sys:[], sub:[], libre:'' };
  bilanData.ttt.ch[idx - 1].detached = true;
}

function collectSportTtt(d) {
  if(!d.ttt) d.ttt = {};
  // Correction 2 : préserve detached depuis bilanData.ttt.ch (variable live).
  // Capture la ref AVANT d'écraser d.ttt.ch (d === bilanData en pratique côté saveBilan).
  const prevCh = (bilanData && bilanData.ttt && bilanData.ttt.ch) ? bilanData.ttt.ch.slice() : [];
  d.ttt.c1 = [1,2,3,4].map(i =>
    _readSportTttExo(document.getElementById('sp-c1-ex' + i + '-libre'))
  );
  d.ttt.c2 = [1,2,3,4].map(i =>
    _readSportTttExo(document.getElementById('sp-c2-ex' + i + '-libre'))
  );
  d.ttt.ch = [1,2,3,4,5,6,7,8].map(i => {
    const exo = _readSportTttExo(document.getElementById('sp-ch-ex' + i + '-libre'));
    exo.detached = !!(prevCh[i - 1] && prevCh[i - 1].detached);
    // Fix B — ratio Échauffement 30/30 ÷ 45/15 (lu direct du DOM, non auto-reporté,
    // hors du contenu copié depuis CE → _writeSportTttExo ne le touche jamais)
    const ratioEl = document.getElementById('sp-ch-ex' + i + '-ratio');
    exo.ratio = ratioEl ? ratioEl.value : '30/30';
    return exo;
  });
  d.ttt.materiaux = Array.from(
    document.querySelectorAll('input[name="sp-materiaux"]:checked')
  ).map(e => e.value);
  d.ttt.recouvrement = Array.from(
    document.querySelectorAll('input[name="sp-recouvrement"]:checked')
  ).map(e => e.value);
  const descEl = document.getElementById('sp-semelles-desc');
  d.ttt.semellesDesc = descEl ? descEl.value : '';
  const rdvEl = document.getElementById('sp-prochain-rdv');
  d.ttt.prochainRdv = rdvEl ? rdvEl.value : '';
}

function restoreSportTtt(d) {
  if(!d || !d.ttt) return;
  const t = d.ttt;
  // Correction 3 : try/finally synchrone (updateExerciceSubMenu sync, set sub immédiat)
  const prev = _sportTttCopying;
  _sportTttCopying = true;
  try {
    [1,2,3,4].forEach(i => {
      const el = document.getElementById('sp-c1-ex' + i + '-libre');
      if(el && t.c1 && t.c1[i - 1]) _writeSportTttExo(el, t.c1[i - 1]);
    });
    [1,2,3,4].forEach(i => {
      const el = document.getElementById('sp-c2-ex' + i + '-libre');
      if(el && t.c2 && t.c2[i - 1]) _writeSportTttExo(el, t.c2[i - 1]);
    });
    [1,2,3,4,5,6,7,8].forEach(i => {
      const el = document.getElementById('sp-ch-ex' + i + '-libre');
      if(el && t.ch && t.ch[i - 1]) _writeSportTttExo(el, t.ch[i - 1]);
    });
  } finally {
    _sportTttCopying = prev;
  }
  // Fix B — restore ratio Échauffement (indépendant du write exo, hors auto-report)
  [1,2,3,4,5,6,7,8].forEach(i => {
    const r = document.getElementById('sp-ch-ex' + i + '-ratio');
    if(r && t.ch && t.ch[i - 1] && t.ch[i - 1].ratio) r.value = t.ch[i - 1].ratio;
  });
  if(t.materiaux) {
    document.querySelectorAll('input[name="sp-materiaux"]').forEach(e => {
      e.checked = t.materiaux.includes(e.value);
    });
  }
  if(t.recouvrement) {
    document.querySelectorAll('input[name="sp-recouvrement"]').forEach(e => {
      e.checked = t.recouvrement.includes(e.value);
    });
  }
  const descEl = document.getElementById('sp-semelles-desc');
  if(descEl) descEl.value = t.semellesDesc || '';
  const rdvEl = document.getElementById('sp-prochain-rdv');
  if(rdvEl) rdvEl.value = t.prochainRdv || '';
}

function clearSportTtt() {
  // Correction 3 : try/finally synchrone. _writeSportTttExo avec sys vides déclenche
  // updateExerciceSubMenu(this) qui supprime les .exo-sub automatiquement (early return L9845).
  const prev = _sportTttCopying;
  _sportTttCopying = true;
  try {
    ['c1','c2'].forEach(c => [1,2,3,4].forEach(i => {
      const el = document.getElementById('sp-' + c + '-ex' + i + '-libre');
      if(el) _writeSportTttExo(el, { sys:['','',''], sub:['','',''], libre:'' });
    }));
    [1,2,3,4,5,6,7,8].forEach(i => {
      const el = document.getElementById('sp-ch-ex' + i + '-libre');
      if(el) _writeSportTttExo(el, { sys:['','',''], sub:['','',''], libre:'' });
    });
  } finally {
    _sportTttCopying = prev;
  }
  document.querySelectorAll('input[name="sp-materiaux"]').forEach(e => e.checked = false);
  document.querySelectorAll('input[name="sp-recouvrement"]').forEach(e => e.checked = false);
  const descEl = document.getElementById('sp-semelles-desc');
  if(descEl) descEl.value = '';
  const rdvEl = document.getElementById('sp-prochain-rdv');
  if(rdvEl) rdvEl.value = '';
}

function setupSportTttAutoReport() {
  const ssec = document.getElementById('ssec-9');
  if(!ssec || ssec._sportTttBound) return;
  ssec._sportTttBound = true;
  // Fix A — délégation pour les select.exo-sub créés dynamiquement par
  // updateExerciceSubMenu. Les select.exo-sys ont leur onchange inline ; sans cette
  // délégation, choisir un exercice dans un sous-menu ne déclencherait l'auto-report
  // qu'au changement suivant. Scope strict : .exo-sub uniquement.
  ssec.addEventListener('change', function(e) {
    if(_sportTttCopying) return;
    if(!e.target || !e.target.matches || !e.target.matches('select.exo-sub')) return;
    const stack = e.target.closest('.exo-stack');
    if(!stack) return;
    const circuit = stack.dataset.spCircuit;
    const idx = parseInt(stack.dataset.spIdx, 10);
    if(!circuit || !idx) return;
    if(circuit === 'ch') _onSportTttEchauffementChange(idx);
    else _onSportTttExpressChange(circuit, idx);
  });
}

// Fix #94 — Boucle commune de soustraction RGB. Pour chaque pixel de imageData :
// si la diff RGB avec baseSnapshot (alpha non pris en compte) est inférieure au
// seuil (20 par canal) → met l'alpha à 0 (transparent). Modifie imageData.data
// in-place.
//
// Le seuil 20 est défini UNE SEULE FOIS ici pour éviter toute divergence future
// entre les call sites save/load — cause racine de la régression #94 où
// saveBilanSilent utilisait toDataURL('image/jpeg') au lieu de la soustraction
// baseSnapshot de saveBilan. En centralisant ici, save ET load utilisent la
// même logique de filtrage pixel.
//
// Fix dessin noir invisible — short-circuit alpha base : un pixel où le
// baseSnapshot est transparent (alpha=0) n'a RIEN à soustraire. Tout pixel
// courant opaque y est forcément un trait user (le canvas part d'un fond
// transparent post-#91 / drawPiedsTemplate / initMorphoCanvas). Sans ce
// check, le baseSnapshot RGBA=(0,0,0,0) — RGB noir + alpha 0 par défaut
// HTML5 — faisait que le diff RGB nul vs un trait noir pur user (0,0,0,255)
// passait sous le seuil 20 et l'alpha était mis à 0 → trait noir devenu
// invisible (fond blanc du <img> template transparaissait à la restauration).
// Les autres couleurs sont restées préservées (diff ≥ 20 sur ≥ 1 canal).
function _subtractBaseSnapshot(imageData, baseSnapshot) {
  const cd = imageData.data, bd = baseSnapshot.data;
  for(let i = 0; i < cd.length; i += 4) {
    if(bd[i+3] === 0) continue;
    const dr = Math.abs(cd[i] - bd[i]);
    const dg = Math.abs(cd[i+1] - bd[i+1]);
    const db = Math.abs(cd[i+2] - bd[i+2]);
    if(dr < 20 && dg < 20 && db < 20) cd[i+3] = 0;
  }
}

// Fix #94 — Sérialise un canvas de dessin (overlay drawings user) en PNG transparent.
// Soustrait canvas._baseSnapshot via _subtractBaseSnapshot, downscale à taille CSS
// (W/dpr × H/dpr) pour cohérence à la restauration via drawImage, retourne
// toDataURL('image/png').
//
// Retourne null si canvas manquant ou _baseSnapshot non encore capturé (cas
// drawPiedsTemplate/initMorphoCanvas early return rect=0 ou setTimeout pas encore
// exécuté). L'appelant DOIT skip et NE PAS écraser bilanData pour préserver les
// éventuelles données existantes — évite la régression où saveBilanSilent
// écrasait bilanData._pieds avec un JPEG noir (transparency non supportée par JPEG)
// sur un canvas désormais overlay transparent post-#91.
function _serializeDrawCanvas(canvas) {
  if(!canvas || !canvas._baseSnapshot) return null;
  const W = canvas.width, H = canvas.height;
  const tmp = document.createElement('canvas');
  tmp.width = W; tmp.height = H;
  const tctx = tmp.getContext('2d');
  tctx.drawImage(canvas, 0, 0);
  const current = tctx.getImageData(0, 0, W, H);
  _subtractBaseSnapshot(current, canvas._baseSnapshot);
  tctx.putImageData(current, 0, 0);
  // #83 — pleine résolution : pas de downscale CSS (l'ancien W/dpr perdait
  // la moitié des pixels à dpr=2, puis la restauration ré-upscalait → flou).
  // La restauration (drawImage) scale déjà vers le dest rect quel que soit
  // le source res → source pleine résolution = net. tmp est déjà W×H base soustraite.
  return tmp.toDataURL('image/png');
}

// Fix #94 auto-réparation — soustrait canvas._baseSnapshot in-place après un
// drawImage de restauration. Les pixels du canvas dont RGB ~ baseSnapshot
// (transparent post-#91) deviennent alpha 0. Efface le fond noir des bilans
// corrompus (saveBilanSilent JPEG pré-fix → JPEG noir intégral) tout en préservant
// les dessins colorés user. Idempotent sur PNG transparent propre (pixels déjà
// transparents → diff=0 → set alpha 0 = no-op).
function _stripBackgroundFromRestore(canvas) {
  if(!canvas || !canvas._baseSnapshot) return;
  const W = canvas.width, H = canvas.height;
  const ctx = canvas.getContext('2d');
  const current = ctx.getImageData(0, 0, W, H);
  _subtractBaseSnapshot(current, canvas._baseSnapshot);
  ctx.putImageData(current, 0, 0);
}

async function saveBilan() {
  if(!currentPatient) { alert('Aucun patient sélectionné.'); return; }
  if(!bilanData) bilanData = {};

  // 1. Capturer tous les champs texte/textarea (.bilan-field)
  document.querySelectorAll('.bilan-field').forEach(el => {
    const field = el.dataset.field;
    if(field) bilanData[field] = el.value || '';
  });

  // 2. Capturer tous les boutons radio du bilan (groupés par name)
  const radioGroups = {};
  document.querySelectorAll('#pg-bilan input[type=radio]').forEach(el => {
    if(el.checked && el.name) radioGroups[el.name] = el.value;
  });
  Object.assign(bilanData, radioGroups);

  // 3. Capturer toutes les checkboxes du bilan
  document.querySelectorAll('#pg-bilan input[type=checkbox]').forEach(el => {
    const onch = el.getAttribute('onchange') || '';
    const match = onch.match(/setBilanField\(['"]([^'"]+)['"]/);
    if(match) bilanData[match[1]] = el.checked;
  });

  // 4. Capturer le bloc traitements sport (Sprint A4) — stack exo hors regex auto
  collectSportTtt(bilanData);

  // 5. Capturer les canvas morpho et pieds (PNG transparent via helper #94).
  //    Effacer les anciennes données JPEG (format obsolète pré-#91).
  ['_morpho_face','_morpho_face2','_morpho_profilG','_morpho_profilD','_pieds'].forEach(k => {
    if(bilanData[k] && bilanData[k].startsWith('data:image/jpeg')) delete bilanData[k];
  });
  // Skip silencieux si _baseSnapshot pas encore capturé (canvas pas init) →
  // préserve la valeur existante de bilanData[key] (cf doc _serializeDrawCanvas).
  ['morpho-face','morpho-face2','morpho-profilG','morpho-profilD'].forEach(id => {
    const c = document.getElementById(id);
    const png = _serializeDrawCanvas(c);
    if(png !== null) {
      const key = '_' + id.replace(/-/g,'_');
      bilanData[key] = png;
      // #99 + Bug édition perdue (option iii) — invalide le Path sur édition
      // utilisateur réelle. _userDirty est insensible aux ré-init DOM (init/draw
      // restoration), contrairement à _history.length qui était reset par
      // drawPiedsTemplate/initMorphoCanvas au reload async post-prefetch et au
      // re-nav vers pg-bilan, causant la perte silencieuse des éditions.
      if (c && c._userDirty) delete bilanData[key + 'Path'];
    }
  });
  const pCanvas = document.getElementById('pieds-canvas');
  const piedsPng = _serializeDrawCanvas(pCanvas);
  if(piedsPng !== null) {
    bilanData._pieds = piedsPng;
    if (pCanvas && pCanvas._userDirty) delete bilanData._piedsPath;
  }
  // #99 + Bug édition perdue — reset _userDirty pour les 5 canvas APRÈS sweep.
  // Prépare le prochain cycle d'édition (un nouveau mouseup re-marquera dirty).
  ['morpho-face','morpho-face2','morpho-profilG','morpho-profilD','pieds-canvas'].forEach(id => {
    const c = document.getElementById(id);
    if(c) c._userDirty = false;
  });

  // #85 Phase 1 — migration Storage des captures Analyse posturale AVANT
  // sérialisation (sinon dataUrls JPEG 1080p polluent localStorage, régression #35).
  // Réutilise l'identifiant stable _bilanId géré par saveMesures L4968 — lazy-create
  // si saveBilan est appelé avant qu'une mesure ait été sauvegardée.
  if(!currentPatient.mesures) currentPatient.mesures = {};
  if(!currentPatient.mesures._bilanId) currentPatient.mesures._bilanId = crypto.randomUUID();
  const _postureStash = await migrateSportBilanDataPhotos(
    bilanData, currentPatient.id, currentPatient.mesures._bilanId
  );

  currentPatient.bilanData = JSON.parse(JSON.stringify(bilanData));
  syncOpenedBilanToHistory();
  savePatients();
  // Restaure les dataUrls RAM pour preserve display sans re-fetch Storage
  // (miroir restoreSportPhotosStash L3285 pour le flow mesures).
  restoreSportBilanDataPhotosStash(bilanData, _postureStash);
  alert('✓ Bilan clinique sauvegardé');
}

// B2 #73 — Config Schémas Moteurs sport ssec-7. Source unique de vérité des 3
// tableaux (Tests / Chaînes musculaires / Plans) + scoreOptions + threshold profil.
// Pilote 5 consommateurs : updateSchemaMoteursTotals (B2 Batch 2), rendu HTML
// ssec-7 (B2 Batch 3, statique mais aligné par grep d'intégrité), genererSyntheseSport
// (B2 Batch 5), buildRapport sport (B2 Batch 6), auto-cochage Terrain ssec-10 via
// toggleSportTerrain (déclenché dans updateSchemaMoteursTotals).
//
// Conventions :
//   - Tableau 1 : 6 clés legacy 'schema_<keyBase>_<active>' conservées (zéro
//     migration). L'autre colonne reste vide/grisée (cellule HTML non-éditable).
//   - Tableau 2 : 6 nouvelles clés 'sp_chaine_<code>' (codes cliniques PM/PA/PL/AM/AP/AL),
//     distinctes de 'chaine_*' déjà utilisées en ssec-10 NPC Régional.
//   - Tableau 3 : 14 nouvelles clés 'sp_plan_<group>_<row>_<a|t>'. Premier
//     descripteur du brief = Aérien, second = Terrien. Horizontal CPP sans
//     descripteur (juste un select par colonne).
//   - scoreOptions : 5 valeurs avec demi-points (0, 0.5, 1, 1.5, 2).
//     parseFloat partout (synthèse + rapport + totaux) — pas parseInt.
//   - threshold : |Aérien − Terrien| > 1 → profil dominant ; ≤ 1 → Mixte.
//   - Convention curseur : Aérien à droite (100%), Terrien à gauche (0%), Mixte
//     au milieu (50%). Garde 0/0 : position 50, profil null (pas d'auto-cochage).
// Total scorable : 6 + 6 + 14 = 26 cases Aérien et 26 Terrien.
//
// ⚠️ Emplacement : déclaré AVANT function loadBilan() (et donc avant le call
// top-level d'init `selectPatient(patients[patients.length-1])`) pour éviter
// le ReferenceError TDZ : loadBilan appelle updateSchemaMoteursTotals qui lit
// B2_SCHEMAS_MOTEURS, et cette chaîne est déclenchée pendant le bootstrap
// séquentiel du script avant la fin de l'évaluation top-level.
const B2_SCHEMAS_MOTEURS = {
  scoreOptions: [0, 0.5, 1, 1.5, 2],
  threshold: 1,
  // Tableau 1 — Tests des schémas moteurs (clés legacy, 1 colonne active/ligne)
  tests: [
    { keyBase: 'schema_extension',      label: "Test d'Extension",            active: 'aerien' },
    { keyBase: 'schema_supination_inf', label: 'Test de Supination Mbr inf.', active: 'aerien' },
    { keyBase: 'schema_supination_sup', label: 'Test de Supination Mbr sup.', active: 'aerien' },
    { keyBase: 'schema_pronation_inf',  label: 'Test de Pronation Mbr inf.',  active: 'terrien' },
    { keyBase: 'schema_ancrage_inf',    label: "Test d'Ancrage Mbr inf.",     active: 'terrien' },
    { keyBase: 'schema_pronation_sup',  label: 'Test de Pronation Mbr sup.',  active: 'terrien' }
  ],
  // Tableau 2 — Chaînes musculaires (nouvelles clés sp_, 1 colonne active/ligne)
  chaines: [
    { key: 'sp_chaine_pm', label: 'Extension (PM)',  active: 'aerien' },
    { key: 'sp_chaine_pa', label: 'Statique (PA)',   active: 'aerien' },
    { key: 'sp_chaine_pl', label: 'Ouverture (PL)',  active: 'aerien' },
    { key: 'sp_chaine_am', label: 'Flexion (AM)',    active: 'terrien' },
    { key: 'sp_chaine_ap', label: 'Statique (AP)',   active: 'terrien' },
    { key: 'sp_chaine_al', label: 'Fermeture (AL)',  active: 'terrien' }
  ],
  // Tableau 3 — Plans (14 nouvelles clés, 2 colonnes scorables/ligne, descripteur par cellule)
  plans: [
    { group: 'Frontal', rows: [
      { row: 'Rotation',          aerien: { desc: 'Externe', key: 'sp_plan_frontal_rotation_a' }, terrien: { desc: 'Interne',    key: 'sp_plan_frontal_rotation_t' } },
      { row: 'Rigide-Souple',     aerien: { desc: 'Rigide',  key: 'sp_plan_frontal_rigid_a'    }, terrien: { desc: 'Souple',     key: 'sp_plan_frontal_rigid_t'    } },
      { row: 'Flexion-Extension', aerien: { desc: 'Ext.',    key: 'sp_plan_frontal_fe_a'       }, terrien: { desc: 'Flex.',      key: 'sp_plan_frontal_fe_t'       } }
    ]},
    { group: 'Sagittal', rows: [
      { row: 'Appui',                   aerien: { desc: 'En Av.',  key: 'sp_plan_sagittal_appui_a' }, terrien: { desc: 'Axe corps', key: 'sp_plan_sagittal_appui_t' } },
      { row: 'Mouvements articulaires', aerien: { desc: 'Faibles', key: 'sp_plan_sagittal_mvt_a'   }, terrien: { desc: 'Élevés',    key: 'sp_plan_sagittal_mvt_t'   } },
      { row: 'Temps de contact au sol', aerien: { desc: 'Court',   key: 'sp_plan_sagittal_tps_a'   }, terrien: { desc: 'Long',      key: 'sp_plan_sagittal_tps_t'   } }
    ]},
    { group: 'Horizontal', rows: [
      // CPP sans descripteur : juste un select par colonne
      { row: 'CPP', aerien: { desc: '', key: 'sp_plan_horizontal_cpp_a' }, terrien: { desc: '', key: 'sp_plan_horizontal_cpp_t' } }
    ]}
  ]
};

function loadBilan() {
  if(!currentPatient) return;
  bilanData = currentPatient.bilanData ? JSON.parse(JSON.stringify(currentPatient.bilanData)) : {};
  // #99 + Bug édition perdue (gating _restoreReady) — fenêtre de restauration
  // ouverte. _restoreReady=false bloque les inputs user dans setupDrawCanvas
  // mousedown/touchstart jusqu'à ce que la restauration async (prefetch +
  // Image.onload) ait peint le dessin pré-édition sur le canvas. Sinon le
  // user dessine pendant la fenêtre, drawPiedsTemplate(canvas.width = …) au
  // .then() efface le DOM, et le sweep _serializeDrawCanvas capture l'ancien
  // dessin sans le trait user → édition perdue au reload.
  // Overlay deferred 150 ms (évite le flash pour les restorations rapides).
  // Fallback timeout 3000 ms : si prefetch fail / timeout réseau, débloque
  // quand même pour ne pas geler l'édition à jamais.
  ['morpho-face','morpho-face2','morpho-profilG','morpho-profilD','pieds-canvas'].forEach(id => {
    const c = document.getElementById(id);
    if (c) {
      c._restoreReady = false;
      _showRestoreOverlayDeferred(c);
    }
  });
  setTimeout(() => {
    ['morpho-face','morpho-face2','morpho-profilG','morpho-profilD','pieds-canvas'].forEach(id => {
      const c = document.getElementById(id);
      if (c && c._restoreReady === false) {
        c._restoreReady = true;
        _hideRestoreOverlay(c);
      }
    });
  }, 3000);
  if(!Object.keys(bilanData).length) {
    // Bilan vide (jamais sauvé) → rien à restaurer, ouvre le gate immédiatement.
    ['morpho-face','morpho-face2','morpho-profilG','morpho-profilD','pieds-canvas'].forEach(id => {
      const c = document.getElementById(id);
      if (c) { c._restoreReady = true; _hideRestoreOverlay(c); }
    });
    return;
  }

  // Remplir les champs texte/textarea
  document.querySelectorAll('.bilan-field').forEach(el => {
    const field = el.dataset.field;
    if(field && bilanData[field] !== undefined) el.value = bilanData[field];
  });

  // A1 — Rafraîchit l'affichage du span associé aux input range (ex: EVA score)
  // après restauration de la value : dispatch 'input' déclenche le oninput inline
  // qui met à jour le span dynamique (sp-an-eva-val).
  document.querySelectorAll('#pg-bilan input[type=range].bilan-field').forEach(r => r.dispatchEvent(new Event('input')));

  // Restaurer les boutons radio
  document.querySelectorAll('#pg-bilan input[type=radio]').forEach(el => {
    if(el.name && bilanData[el.name] !== undefined) {
      el.checked = (el.value === bilanData[el.name]);
    }
  });

  // Restaurer les checkboxes
  document.querySelectorAll('#pg-bilan input[type=checkbox]').forEach(el => {
    if(el.getAttribute('onchange')) {
      // Extraire le field depuis onchange="setBilanField('xxx', this.checked)"
      const match = el.getAttribute('onchange').match(/setBilanField\('([^']+)'/);
      if(match) {
        const field = match[1];
        el.checked = bilanData[field] === true;
      }
    }
  });

  // Restaurer le bloc traitements sport (Sprint A4) — stack exo hors regex auto
  restoreSportTtt(bilanData);

  // B1 #73 — Restauration UX des wrappers conditionnels sport ssec-2.
  // Le restore générique des cb/radios L7320-7335 ne dispatch pas l'event 'change'
  // (programmatique), donc les toggleSport* ne sont jamais déclenchés au reload →
  // les wrappers *-opts restent cachés visuellement même si la cb/radio parent
  // est cochée. Pattern miroir loadPosturoBilan (qui fait pareil avec toggleRomberg
  // et autres). Ordre cascade IMPÉRATIF pour le décubitus dorsal : parent TF avant
  // TFOs (sinon l'enfant flex reste invisible sous parent caché).

  // Repères en charge — toggleSportRepere si side ∈ {d, g}
  ['crete','eias','eips'].forEach(field => {
    const side = bilanData['sp_'+field+'_side'];
    if(side === 'd' || side === 'g') toggleSportRepere(field, side);
  });

  // Romberg — toggleSportRomberg si cb parent cochée
  ['lat','rot'].forEach(type => {
    if(bilanData['sp_romberg_'+type]) toggleSportRomberg(type, true);
  });

  // Stab monopodale — toggleSportStabMono si cb parent cochée
  ['pied','genou'].forEach(zone => {
    if(bilanData['sp_stab_'+zone]) toggleSportStabMono(zone, true);
  });

  // Décubitus dorsal — TF cascade : parent (d/g) AVANT enfants (femur/tibia)
  ['d','g'].forEach(side => {
    if(!bilanData['sp_dyn_tf_'+side]) return;
    toggleSportTF(side, true);
    ['femur','tibia'].forEach(os => {
      if(bilanData['sp_dyn_tf_'+side+'_'+os]) toggleSportTFOs(side, os, true);
    });
  });

  // Long MI dorsal/procubitus — toggleSportLongMI si val ∈ {court, long}
  ['dorsal','procubitus'].forEach(zone => {
    const val = bilanData['sp_dyn_long_mi_'+zone];
    if(val === 'court' || val === 'long') toggleSportLongMI(zone, val);
  });

  // Branches pubiennes — toggleSportPub si side défini
  if(bilanData.sp_dyn_pub === 'd' || bilanData.sp_dyn_pub === 'g') {
    toggleSportPub(bilanData.sp_dyn_pub);
  }

  // Downing D/G — toggleSportDowning si cb parent cochée
  ['d','g'].forEach(side => {
    if(bilanData['sp_dyn_downing_'+side]) toggleSportDowning(side, true);
  });

  // Inégalité longueur conclusion — toggleSportIneg si 'oui'
  if(bilanData.sp_dyn_ineg_long === 'oui') toggleSportIneg(true);

  // B2 #73 — Recalcul Schémas Moteurs ssec-7 au reload : totaux Aérien/Terrien
  // + position curseur tendance + libellé profil + auto-cochage Terrain ssec-10.
  // Les selects .bilan-field ont déjà leur .value restaurée L7405. La fonction
  // lit le DOM live (parseFloat sur chaque cellule active selon B2_SCHEMAS_MOTEURS),
  // met à jour les spans #sp-sm-total-a/-t + style.left du marker + textContent
  // du label, et propage l'auto-cochage Terrain via toggleSportTerrain (mutex
  // idempotent : recoche identique = no-op). Pattern miroir du dispatchEvent
  // 'input' L7411 sur le curseur EVA (range natif) et des toggles B1 L7435-7485.
  updateSchemaMoteursTotals();

  // Restaurer les canvas depuis les dataURLs sauvegardées
  const restoreCanvas = (id, key) => {
    const cvs = document.getElementById(id);
    if(!cvs || !bilanData[key]) return;
    const img = new Image();
    img.onload = () => {
      const ctx = cvs.getContext('2d');
      const dpr = window.devicePixelRatio || 1;
      const cssW = cvs.width/dpr, cssH = cvs.height/dpr;
      ctx.drawImage(img, 0, 0, cssW, cssH);
    };
    img.src = bilanData[key];
  };
  // Restaurer uniquement les dessins (les images de fond sont dans le DOM)
  // Les nouvelles sauvegardes contiennent juste le dessin transparent
  // Les anciennes sauvegardes (avec fond) sont ignorées car elles contiennent l'image en double
  // La restauration des canvas se fait séparément après initMorphoCanvas
  // #85 Phase 1 — prefetch des captures Analyse posturale depuis Storage
  // (dataUrls absentes de bilanData persisté car migrées par migrateSportBilanDataPhotos).
  // Fire-and-forget — render miniatures dès que les fetch répondent (non bloquant).
  // #99 — ajoute la restauration canvas morpho/pieds APRÈS prefetch : les 5 clés
  // _morpho_*/_pieds sont désormais migrées aussi → leur dataURL n'est plus dans
  // bilanData au load (juste Path). Sans ce .then(), les call-sites SYNC nav L2007
  // + L2013-2034 lisent undefined → calques morpho/pieds disparaissent au reload.
  // Fix racine (symétrisation pattern posturo) : prefetch sur currentPatient.bilanData
  // (objet persisté) au lieu du bilanData global (copie défensive). Pattern miroir
  // de prefetchPosturoPhotos(currentPatient.bilanDataPosturo). Le strip dans
  // savePatients (déjà en place sur p.bilanData pour SPORT_BILAN_PHOTO_KEYS)
  // garantit zéro re-bloat localStorage ; le restore-stash repose les dataURLs
  // en RAM pour l'affichage. Sites lecteurs (canvas restore, rapport composites)
  // qui lisent currentPatient.bilanData trouvent désormais les dataURLs.
  prefetchSportBilanDataPhotos(currentPatient.bilanData).then(() => {
    // #85-P2 — sync global ← currentPatient pour les photos réhydratées. Les slots
    // posture (_renderPostureSlot 'sp' L4519 via _getPostureBilanData L4480) et
    // saveBilan lisent le `bilanData` global ; le prefetch (fix racine #99) remplit
    // currentPatient.bilanData. Sans ce report, les captures sport sont invisibles
    // au reload (Path présent, dataURL absente du global → slots vides bien que
    // l'image soit en RAM ailleurs). Restreint à SPORT_BILAN_PHOTO_KEYS pour ne
    // pas écraser d'autres champs (texte, scores, neuro4) potentiellement édités.
    if (typeof bilanData !== 'undefined' && bilanData && currentPatient?.bilanData) {
      SPORT_BILAN_PHOTO_KEYS.forEach(k => {
        if (currentPatient.bilanData[k]) bilanData[k] = currentPatient.bilanData[k];
      });
    }
    _renderAllPostureSlots('sp');
    _restoreSportMorphoPiedsFromBilanData();
  });
}

function toggleDictaphone() {
  if(!('webkitSpeechRecognition' in window||'SpeechRecognition' in window)){
    alert('Dictaphone non supporté dans ce navigateur. Utilisez Chrome ou Edge.');return;
  }
  if(micActive) {
    micActive=false; if(micRecognition) micRecognition.stop();
    document.getElementById('mic-status').style.display='none';
    document.getElementById('btn-mic').className='btn';
    return;
  }
  micActive=true;
  document.getElementById('mic-status').style.display='block';
  document.getElementById('btn-mic').className='btn btn-red';
  const SR=window.SpeechRecognition||window.webkitSpeechRecognition;
  micRecognition=new SR();
  micRecognition.lang='fr-FR'; micRecognition.continuous=true; micRecognition.interimResults=false;
  micRecognition.onresult=e=>{
    const text=e.results[e.results.length-1][0].transcript;
    // Insérer dans le champ actif
    const active=document.activeElement;
    if(active&&(active.tagName==='TEXTAREA'||active.tagName==='INPUT')&&active.classList.contains('bilan-field')){
      active.value+=(active.value?' ':'')+text;
      setBilanField(active.dataset.field, active.value);
    }
  };
  micRecognition.onerror=()=>{micActive=false;document.getElementById('mic-status').style.display='none';};
  micRecognition.start();
}

function printBilan() {
  // Gating task #57 — bloque l'impression si pas full access.
  // (printReport a aussi un early-return en double sécurité, mais on stop ici
  // pour éviter saveBilanSilent inutile et le delay de 200ms.)
  if (window._accessLevel && window._accessLevel !== 'full') {
    showAccessRestrictedModal('export_pdf');
    return;
  }
  // Sauvegarder d'abord tous les champs
  saveBilanSilent();
  // Puis lancer l'impression du rapport complet
  setTimeout(() => printReport(), 200);
}

async function saveBilanSilent() {
  // Même que saveBilan mais sans alert.
  // #85 Phase 1 — async pour migrer les captures _postureXxx vers Storage AVANT
  // savePatients (sinon dataURLs JPEG 1080p écrites en localStorage par les
  // call-sites buildRapport/printReport/genererSyntheseSport → régression #35).
  // Le sweep DOM → bilanData reste SYNCHRONE en début de fonction : les call-sites
  // (qui n'awaitent pas) lisent bilanData RAM cohérent avec l'UI courante. La
  // migration + savePatients s'exécutent en background (fire-and-forget côté caller),
  // mais l'ordre interne sweep → migrate → savePatients → restore est strict.
  if(!currentPatient) return;
  if(!bilanData) bilanData = {};
  document.querySelectorAll('.bilan-field').forEach(el => {
    const field = el.dataset.field;
    if(field) bilanData[field] = el.value || '';
  });
  document.querySelectorAll('#pg-bilan input[type=radio]').forEach(el => {
    if(el.checked && el.name) bilanData[el.name] = el.value;
  });
  document.querySelectorAll('#pg-bilan input[type=checkbox]').forEach(el => {
    const onch = el.getAttribute('onchange') || '';
    const match = onch.match(/setBilanField\(['"]([^'"]+)['"]/);
    if(match) bilanData[match[1]] = el.checked;
  });
  collectSportTtt(bilanData);
  // Fix #94 — canvas via helper _serializeDrawCanvas (PNG transparent). Le JPEG
  // précédent produisait du noir intégral sur canvas désormais overlay transparent
  // post-#91 (JPEG ne supporte pas la transparence). Skip silencieux si
  // _baseSnapshot non encore capturé pour préserver la valeur existante de
  // bilanData[key].
  ['morpho-face','morpho-face2','morpho-profilG','morpho-profilD'].forEach(id => {
    const c = document.getElementById(id);
    const png = _serializeDrawCanvas(c);
    if(png !== null) {
      const key = '_' + id.replace(/-/g,'_');
      bilanData[key] = png;
      // #99 + Bug édition perdue (option iii) — miroir saveBilan : check _userDirty.
      if (c && c._userDirty) delete bilanData[key + 'Path'];
    }
  });
  const pc = document.getElementById('pieds-canvas');
  const piedsPng = _serializeDrawCanvas(pc);
  if(piedsPng !== null) {
    bilanData._pieds = piedsPng;
    if (pc && pc._userDirty) delete bilanData._piedsPath;
  }
  // #99 + Bug édition perdue — reset _userDirty pour les 5 canvas APRÈS sweep.
  ['morpho-face','morpho-face2','morpho-profilG','morpho-profilD','pieds-canvas'].forEach(id => {
    const c = document.getElementById(id);
    if(c) c._userDirty = false;
  });
  // #85 Phase 1 — migration Storage AVANT persistance (cf header de la fonction).
  if(!currentPatient.mesures) currentPatient.mesures = {};
  if(!currentPatient.mesures._bilanId) currentPatient.mesures._bilanId = crypto.randomUUID();
  const _postureStash = await migrateSportBilanDataPhotos(
    bilanData, currentPatient.id, currentPatient.mesures._bilanId
  );
  currentPatient.bilanData = JSON.parse(JSON.stringify(bilanData));
  syncOpenedBilanToHistory();
  savePatients();
  restoreSportBilanDataPhotosStash(bilanData, _postureStash);
}

function clearPiedsCanvas() {
  const c = document.getElementById('pieds-canvas');
  if(!c) return;
  c.getContext('2d').clearRect(0,0,c.width,c.height);
  // #99 + Bug édition perdue — clear user-triggered = édition (cf clearAllMorpho).
  c._userDirty = true;
  drawPiedsTemplate();
}

// ══════════════════════════════════════════════════════
// #85 Fix TDZ — déplacé avant le boot (cf learning #11 / fix B2 NEURO_BLOCKS).
// Raison : selectPatient(L8551 → ...) → loadBilan → restoreSportTtt → dispatchEvent
// change → updateExerciceSubMenu lit FICHES_SYSTEMES dès le 1er tick top-level.
// Si déclaré après, ReferenceError TDZ. Aucun nouveau TDZ créé par le déplacement :
// les autres consommateurs (_resolveFichesImagesFromPairs, getBilanPosturoHTML, etc.)
// sont des fonctions appelées au runtime. SPORT_SYSTEMES_LABELS dérivé reste valide
// car l'ordre relatif dans le bloc est préservé (FICHES_SYSTEMES déclaré au-dessus).
