function updateExerciceSubMenu(selEl) {
  const system = selEl.value;
  // Trouver ou créer le wrapper pour ce select
  let wrapper = selEl.closest('.exo-pair');
  if(!wrapper) {
    wrapper = document.createElement('div');
    wrapper.className = 'exo-pair';
    wrapper.style.cssText = 'display:flex;flex-direction:column;gap:2px;background:#f8f9fa;border:1px solid #ddd;border-radius:6px;padding:4px 6px;flex:1;min-width:120px;';
    selEl.parentNode.insertBefore(wrapper, selEl);
    wrapper.appendChild(selEl);
  }
  // Supprimer l'ancien sous-menu
  const oldSub = wrapper.querySelector('.exo-sub');
  if(oldSub) oldSub.remove();
  // #88 Source unique FICHES_SYSTEMES — anciens dicts inline supprimés.
  const opts = FICHES_SYSTEMES[system]?.subs || [];
  if(!opts.length) return;
  const sub = document.createElement('select');
  sub.className = 'inp exo-sub';
  sub.style.cssText = 'font-size:10px;background:#fff;color:#222;';
  sub.innerHTML = '<option value="">-- Exercice --</option>' + opts.map(o => '<option value="'+o+'">'+o+'</option>').join('');
  wrapper.appendChild(sub);
}

function toggleRessaut(enabled) {
  const opts = document.getElementById('po-ressaut-opts');
  if(!opts) return;
  opts.style.opacity = enabled ? '1' : '0.35';
  opts.style.pointerEvents = enabled ? 'auto' : 'none';
  if(!enabled) {
    document.getElementById('po-ressaut-dte').checked = false;
    document.getElementById('po-ressaut-gauche').checked = false;
  }
}
function toggleSerrage(type) {
  const aggOpts = document.getElementById('po-serrage-aggrav-opts');
  const amelOpts = document.getElementById('po-serrage-amelio-opts');
  if(!aggOpts || !amelOpts) return;
  if(type === 'aggravation') {
    aggOpts.style.display = 'flex';
    amelOpts.style.display = 'none';
    document.getElementById('po-amelio-contact').checked = false;
    document.getElementById('po-amelio-tension').checked = false;
  } else {
    amelOpts.style.display = 'flex';
    aggOpts.style.display = 'none';
    document.getElementById('po-aggr-dents').checked = false;
    document.getElementById('po-aggr-atm').checked = false;
  }
}

// SPORT — Toggle Ressaut méniscal (Sprint A3 #73)
// Affiche/masque les checkboxes Droite/Gauche du ressaut, décoche si désactivé.
// Calque toggleRessaut posturo (L9853) avec IDs sport sm-. Posturo intact.
function toggleSportRessaut(enabled) {
  const opts = document.getElementById('sm-ressaut-opts');
  if(!opts) return;
  opts.style.display = enabled ? 'flex' : 'none';
  if(!enabled) {
    const dte = document.getElementById('sm-ressaut-dte');
    const gauche = document.getElementById('sm-ressaut-gauche');
    if(dte) dte.checked = false;
    if(gauche) gauche.checked = false;
  }
}

// SPORT — Toggle Serrage de dent (Sprint A3 #73)
// Exclusion mutuelle Aggravation ↔ Amélioration + nettoyage des cb de l'autre
// groupe au switch. Calque toggleSerrage posturo (L9863) avec IDs sport sm-.
// Posturo intact.
function toggleSportSerrage(type) {
  const aggOpts = document.getElementById('sm-serrage-aggrav-opts');
  const amelOpts = document.getElementById('sm-serrage-amelio-opts');
  if(!aggOpts || !amelOpts) return;
  aggOpts.style.display  = (type === 'aggravation')  ? 'flex' : 'none';
  amelOpts.style.display = (type === 'amelioration') ? 'flex' : 'none';
  if(type !== 'aggravation') {
    const c1 = document.getElementById('sm-aggr-dents');   if(c1) c1.checked = false;
    const c2 = document.getElementById('sm-aggr-atm');     if(c2) c2.checked = false;
  }
  if(type !== 'amelioration') {
    const c3 = document.getElementById('sm-amelio-contact'); if(c3) c3.checked = false;
    const c4 = document.getElementById('sm-amelio-tension'); if(c4) c4.checked = false;
  }
}

// A5 — toggle conditionnel sub-block latéralisation Postural Global (miroir
// posturo togglePostureLater). Si décoché, reset des radios sp-posture-later-dir
// pour cohérence persistance (sweep name= dans saveBilan ne sauvegardera plus
// de valeur si tous les radios sont décochés).
function toggleSportPostureLater(checked) {
  const opts = document.getElementById('sp-posture-later-opts');
  if(!opts) return;
  opts.style.display = checked ? 'flex' : 'none';
  if(!checked) {
    document.querySelectorAll('input[name="sp-posture-later-dir"]').forEach(r => r.checked = false);
  }
}

// A5 — Mutex Terrain (Aérien / Terrien / Mixte). Sur coche d'une case, décoche
// les 2 autres dans le DOM ET synchronise bilanData pour cohérence persistance.
// Sur décoche d'une case active, met seulement cette case à false (les 2 autres
// étaient déjà à false par mutex). onchange="toggleSportTerrain('aerien'|'terrien'|'mixte')"
// remplace le setBilanField direct des onchange standards — le restore DOM des
// 3 cb se fait explicitement dans le hook showSportBilanSection idx===10
// (car le regex setBilanField de loadBilan ne match pas toggleSportTerrain).
function toggleSportTerrain(which) {
  const cb = document.getElementById('sp-terrain-' + which);
  if(!cb) return;
  if(cb.checked) {
    // Mutex : décoche les 2 autres + setBilanField cohérent sur les 3
    ['aerien','terrien','mixte'].forEach(k => {
      const target = document.getElementById('sp-terrain-' + k);
      if(target) target.checked = (k === which);
      setBilanField('terrain_' + k, k === which);
    });
  } else {
    // Décoche la case active → cette case à false (les 2 autres déjà à false)
    setBilanField('terrain_' + which, false);
  }
}

// B1 #73 — Toggles miroirs psec-2 posturo pour ssec-2 sport (Examen en charge /
// décharge). 7 miroirs (Romberg, TF, TFOs, LongMI, Pub, Downing, Ineg) +
// 2 nouveaux (Repere, StabMono). Aucun toggle posturo n'est paramétrable sur
// le préfixe d'ID, d'où la nécessité de répliquer côté sport — pattern déjà
// établi par toggleSportRessaut/Serrage/PostureLater/Terrain.
//
// Convention :
//   - ids DOM des wrappers conditionnels : tirets (sp-romberg-lat-opts, sp-dyn-tf-d-opts, …)
//   - name= des radios = clé bilanData = underscore (sp_romberg_lat_dir, sp_dyn_ineg_dir, …)
//   - Anti-résidu RAM #95 : quand un toggle décoche des sub-radios, il efface
//     aussi la clé bilanData correspondante (sinon le restore au refresh re-coche
//     une valeur fantôme — comportement #95 sur cb identique pour radios).

// Romberg (réplique psec-1 posturo toggleRomberg L9589) — show/hide sub-options
// direction selon cb. Reset radios + RAM si désactivé.
function toggleSportRomberg(type, checked) {
  const opts = document.getElementById('sp-romberg-'+type+'-opts');
  if(!opts) return;
  opts.style.display = checked ? 'flex' : 'none';
  if(!checked) {
    document.querySelectorAll('input[name="sp_romberg_'+type+'_dir"]').forEach(r => r.checked = false);
    setBilanField('sp_romberg_'+type+'_dir', '');
  }
}

