// B2 #73 — Tendance Schémas Moteurs sport (ssec-7).
// Calcule position curseur + libellé profil dominant à partir des totaux
// Aérien / Terrien. Convention : Aérien à droite (100 %), Terrien à gauche (0 %),
// Mixte au milieu (50 %). Garde 0/0 : aucun score saisi → position 50 + profil
// null (empêche l'auto-cochage Terrain qui préserverait la saisie manuelle).
function calcTendance(totalA, totalT) {
  const sum = totalA + totalT;
  if(sum === 0) return { position: 50, profil: null, libelle: '—' };
  const position = (totalA / sum) * 100;
  const delta = totalA - totalT;
  const thr = B2_SCHEMAS_MOTEURS.threshold;
  let profil, libelle;
  if(delta > thr)        { profil = 'aerien';  libelle = 'Schéma aérien';  }
  else if(delta < -thr)  { profil = 'terrien'; libelle = 'Schéma terrien'; }
  else                   { profil = 'mixte';   libelle = 'Mixte';          }
  return { position, profil, libelle };
}

// B2 #73 — Auto-cochage Terrain ssec-10 (mutex via toggleSportTerrain).
// Coche la cb sp-terrain-<profil> et délègue le mutex à la fonction existante
// (qui décoche les 2 autres + propage setBilanField sur les 3 clés).
// Garde profil null (0/0) : préserve l'état des cb saisies manuellement par le
// clinicien. Idempotent : recoche identique = no-op (setBilanField écrit la
// même valeur, aucun side-effect au reload ou recalcul live).
function applyTendanceToTerrain(profil) {
  if(!profil) return;
  const cb = document.getElementById('sp-terrain-' + profil);
  if(!cb) return;
  cb.checked = true;
  toggleSportTerrain(profil);
}

// B2 #73 — Recalcul live des totaux Schémas Moteurs ssec-7 + position curseur
// tendance + libellé profil + auto-cochage Terrain ssec-10. Itère
// B2_SCHEMAS_MOTEURS (tests + chaines + plans) en parseFloat sur les cellules
// actives par colonne (Aérien / Terrien). Pattern miroir updateNeuroTotals
// (totaux dérivés, pas persistés — recalculés à l'affichage). Déclenché par
// onchange inline sur chaque <select> du formulaire + appel direct dans
// loadBilan après le restore .bilan-field (Batch 4).
function updateSchemaMoteursTotals() {
  let totalA = 0, totalT = 0;
  B2_SCHEMAS_MOTEURS.tests.forEach(t => {
    const key = t.keyBase + '_' + t.active;
    const v = parseFloat(document.querySelector('[data-field="'+key+'"]')?.value) || 0;
    if(t.active === 'aerien') totalA += v; else totalT += v;
  });
  B2_SCHEMAS_MOTEURS.chaines.forEach(c => {
    const v = parseFloat(document.querySelector('[data-field="'+c.key+'"]')?.value) || 0;
    if(c.active === 'aerien') totalA += v; else totalT += v;
  });
  B2_SCHEMAS_MOTEURS.plans.forEach(g => {
    g.rows.forEach(r => {
      const vA = parseFloat(document.querySelector('[data-field="'+r.aerien.key+'"]')?.value) || 0;
      const vT = parseFloat(document.querySelector('[data-field="'+r.terrien.key+'"]')?.value) || 0;
      totalA += vA;
      totalT += vT;
    });
  });
  const elA = document.getElementById('sp-sm-total-a');
  const elT = document.getElementById('sp-sm-total-t');
  // Format français (point → virgule) pour cohérence avec synthèse + rapport B2.
  const fmt = n => String(n).replace('.', ',');
  if(elA) elA.textContent = fmt(totalA);
  if(elT) elT.textContent = fmt(totalT);
  const { position, profil, libelle } = calcTendance(totalA, totalT);
  const marker = document.getElementById('sp-sm-tendance-marker');
  if(marker) marker.style.left = position + '%';
  const label = document.getElementById('sp-sm-tendance-label');
  if(label) label.textContent = libelle;
  applyTendanceToTerrain(profil);
}

function showPosturoSection(idx) {
  document.querySelectorAll('.posturo-section').forEach((s,i) => {
    s.style.display = i === idx ? 'block' : 'none';
  });
  document.querySelectorAll('.posturo-tab').forEach((t,i) => {
    t.classList.toggle('act', i === idx);
  });
  if(typeof _injectMicButtons==='function') setTimeout(_injectMicButtons, 200);
  if(idx === 1) {
    // Attendre que psec-1 soit visible avant d'initialiser le canvas
    const psec1 = document.getElementById('psec-1');
    if(psec1) psec1.style.display = '';
    setTimeout(initPosturoBodyCanvas, 150);
  }
  if(idx === 3) {
    setTimeout(updateNeuroTotals, 100);
    setTimeout(() => {
      document.querySelectorAll('#psec-3 input[type=checkbox]').forEach(cb => {
        cb.addEventListener('change', updateNeuroTotals);
      });
    }, 200);
    // Restaurer neuro4 maintenant que le DOM est visible
    setTimeout(() => {
      const dn = currentPatient?.bilanDataPosturo?.neuro4;
      if(!dn) return;
      Object.assign(bilanData, dn);
      // Restaurer par ID direct (aps-, apd-, cf-, acd-, nc-, prop-, cerv-, vermis-, inter-, lat-)
      Object.entries(dn).forEach(([key, val]) => {
        if(typeof val === 'boolean') {
          const el = document.getElementById(key);
          if(el) el.checked = val;
        }
      });
      updateNeuroTotals();
    }, 400);
  }
  if(idx === 8) setTimeout(initPosturoFeetCanvas, 100);
}

// ───────────────────────────────────────────
// SPORT — Navigation onglets bilan clinique (Phase 1 #73)
// Toggle display des 10 sport-section + état actif des sport-tab.
// Re-init des canvas dépendants du DOM visible (morpho 4× idx=1 + pieds-canvas idx=9).
// Gardes synchrones obligatoires : initMorphoCanvas L6472 et drawPiedsTemplate L6722
// sont DESTRUCTIFS (effacent pixels via canvas.width=... + wipe _history/_baseSnapshot).
// Sans garde, switch onglet → perte des dessins user. On init UNIQUEMENT la 1ère fois.
// Motif uniforme : on garde sur _baseSnapshot pour les 5 canvas. clearBilanFields
// L2523-2527 nullifie synchroniquement _baseSnapshot au switch patient → garantit
// la ré-init propre du canvas du nouveau patient (style.width n'est pas reset par
// clearBilanFields donc utiliser !style.width laisserait les dessins de l'ancien
// patient si onglet morpho caché au moment du switch — bug évité par _baseSnapshot).
// ───────────────────────────────────────────
function showSportBilanSection(idx) {
  // 1. Toggle display block/none sur les 10 sections (scope strict #pg-bilan)
  document.querySelectorAll('#pg-bilan .sport-section').forEach((s, i) => {
    s.style.display = i === idx ? 'block' : 'none';
  });
  // #87 Batch 1 — Résolution id-based de la section affichée pour découpler les
  // hooks ci-dessous du DOM-order. Permet au Batch 2 (réordo onglets) de bouger
  // les sections sans casser les comportements section-spécifiques (canvas
  // morpho, mandibule, neuro, traitements, schémas). Comportement identique
  // au stade actuel : les ids sont toujours à leurs positions historiques.
  const shownId = document.querySelectorAll('#pg-bilan .sport-section')[idx]?.id;
  // 2. Toggle .act sur les 10 tabs
  document.querySelectorAll('.sport-tab').forEach((t, i) => {
    t.classList.toggle('act', i === idx);
  });
  // 3. Re-inject mic buttons (dictaphone) après affichage de la nouvelle section
  if(typeof _injectSportMicButtons === 'function') setTimeout(_injectSportMicButtons, 200);
  // 4. Section Morphostatique (ssec-1) — init 4 canvas morpho UNIQUEMENT si pas encore
  //    initialisés. _baseSnapshot est posé asynchrone par initMorphoCanvas L6488
  //    → flag idempotent uniforme avec pieds-canvas. Préserve les dessins user au
  //    switch onglet, et garantit la ré-init au switch patient via clearBilanFields.
  if(shownId === 'ssec-1') setTimeout(() => {
    // #83 — symétrie avec ssec-9 pieds : init + restore overlay des dessins
    // sauvegardés UNIQUEMENT à la (ré)initialisation. Sans restore ici, le
    // canvas morpho restait vide quand le user arrive sur ssec-1 (la chaîne
    // loadBilan → _drawMorphoCanvasesFromSource saute les canvas width===0
    // tant que la section n'a pas été affichée) → édition mal capturée
    // (soustraction _serializeDrawCanvas sans overlay sous-jacent) → perdue.
    // posesReadyFlag=false : ne touche pas _restoreReady, le gating est piloté
    // par loadBilan (fenêtre de restoration globale) ; ici on rejoue juste le
    // dessin par-dessus le base sync vide. Idempotent grâce au !_baseSnapshot.
    let needRestore = false;
    ['morpho-face','morpho-face2','morpho-profilG','morpho-profilD'].forEach(id => {
      const c = document.getElementById(id);
      if(c && !c._baseSnapshot && typeof initMorphoCanvas === 'function') {
        initMorphoCanvas(id);
        needRestore = true;
      }
    });
    if(needRestore && typeof _drawMorphoCanvasesFromSource === 'function') {
      _drawMorphoCanvasesFromSource(currentPatient?.bilanData, false);
    }
  }, 150);
  // Section Mandibule (ssec-5) — au load d'un bilan existant, restaurer l'affichage
  // conditionnel des toggles depuis l'état des radios. Pas de flag idempotence
  // nécessaire : les onchange inline gèrent les changements user, et le re-appel
  // au switch onglet n'a aucun effet de bord (rétablit le même état UI).
  if(shownId === 'ssec-5') setTimeout(() => {
    const rrChecked = document.querySelector('input[name="mand_ressaut"]:checked');
    if(rrChecked) toggleSportRessaut(rrChecked.value === 'oui');
    const ssChecked = document.querySelector('input[name="tonicite_serrage"]:checked');
    if(ssChecked) toggleSportSerrage(ssChecked.value);
  }, 150);
  // Section Neuro fonctionnel (ssec-8) — trigger updateSportNeuroTotals + addEventListener
  // change sur les checkboxes pour recalcul en temps réel. Idempotent via flag _sportNeuroBound.
  if(shownId === 'ssec-8') setTimeout(() => {
    const ssec8 = document.getElementById('ssec-8');
    if(!ssec8) return;
    if(!ssec8._sportNeuroBound) {
      ssec8.querySelectorAll('input[type=checkbox]').forEach(cb => {
        cb.addEventListener('change', updateSportNeuroTotals);
      });
      ssec8._sportNeuroBound = true;
    }
    updateSportNeuroTotals();
  }, 150);
  // 5. Section Traitements (ssec-9) — drawPiedsTemplate UNIQUEMENT la 1ère fois.
  //    _baseSnapshot est posé synchroniquement par drawPiedsTemplate L6744
  //    → flag idempotent. Préserve le dessin pieds au switch onglet.
  if(shownId === 'ssec-9') setTimeout(() => {
    const pc = document.getElementById('pieds-canvas');
    if(pc && !pc._baseSnapshot && typeof drawPiedsTemplate === 'function') {
      drawPiedsTemplate(currentPatient?.bilanData?._pieds);
    }
    // Sprint A4 — setup ttt + restore au switch onglet (idempotent via _sportTttBound)
    setupSportTttAutoReport();
    if(bilanData && bilanData.ttt) restoreSportTtt(bilanData);
  }, 150);
  // A5 — Section Schémas/Synthèse (ssec-10) : restore explicit des 3 cb Terrain
  // (onchange utilise toggleSportTerrain non matché par le regex setBilanField
  // de loadBilan) + restore affichage sub-block latéralisation Postural depuis
  // l'état de la cb sp-posture-later restaurée par le mécanisme standard.
  if(shownId === 'ssec-10') setTimeout(() => {
    ['aerien','terrien','mixte'].forEach(k => {
      const cb = document.getElementById('sp-terrain-' + k);
      if(cb) cb.checked = !!(bilanData && bilanData['terrain_' + k]);
    });
    const laterCb = document.getElementById('sp-posture-later');
    if(laterCb) toggleSportPostureLater(laterCb.checked);
  }, 150);
}

